        </button>
        <div className="flex flex-col items-center">
           <div className="bg-red-600 px-3 py-1.5 rounded-lg text-[10px] font-black flex items-center gap-2 shadow-lg shadow-red-900/20">
             <SignalIcon className="h-3 w-3 animate-pulse" /> AO VIVO
           </div>
           <p className="text-[10px] font-black uppercase mt-1 tracking-widest text-gray-400">{post.liveStream.title}</p>
        </div>
        <div className="flex items-center gap-2 bg-white/5 px-3 py-1.5 rounded-lg">
           <UsersIcon className="h-3 w-3 text-gray-400" />
           <span className="text-[10px] font-bold">42</span>
        </div>
      </nav>

      <main className="flex-1 flex relative items-center justify-center overflow-hidden p-2 md:p-6">
        <div className="w-full h-full max-w-5xl rounded-[2rem] md:rounded-[3rem] overflow-hidden bg-black border-4 border-white/5 relative shadow-2xl group">
          {isCamOn ? (
            <video ref={localVideoRef} autoPlay playsInline muted className="w-full h-full object-contain" />
          ) : (
            <div className="flex flex-col items-center justify-center h-full opacity-40 bg-gradient-to-br from-gray-900 to-black">
               <div className="w-32 h-32 md:w-48 md:h-48 rounded-[3rem] md:rounded-[4rem] bg-gray-800 flex items-center justify-center text-5xl md:text-7xl font-black border-4 border-white/5 shadow-inner">
                {creator.firstName[0]}
               </div>
               <p className="mt-8 font-black uppercase tracking-[0.3em] text-xs text-gray-500">Câmera Desligada</p>
            </div>
          )}

          {/* Overlay do Professor */}
          <div className="absolute bottom-8 left-8 flex items-center gap-4 bg-black/40 backdrop-blur-xl p-4 rounded-[2rem] border border-white/10">
             <img src={creator.profilePicture} className="w-12 h-12 rounded-2xl object-cover border-2 border-red-500" />
             <div>
                <p className="text-xs font-black uppercase tracking-widest">{creator.firstName} {creator.lastName}</p>
                <p className="text-[9px] font-bold text-gray-400">Professor Autor</p>
             </div>
          </div>
        </div>

        {activeSidebar === 'chat' && (
          <aside className="absolute right-0 top-0 bottom-0 w-full md:w-80 bg-black/95 backdrop-blur-3xl border-l border-white/10 z-40 flex flex-col animate-slide-left">
            <div className="p-6 border-b border-white/10 flex justify-between items-center">
