      <footer className="p-4 md:p-10 flex flex-col md:flex-row items-center justify-center gap-4 flex-shrink-0 relative">
        <div className="bg-darkcard/60 backdrop-blur-3xl px-6 py-4 rounded-[2.5rem] border border-white/10 flex items-center gap-4 md:gap-8 shadow-[0_20px_50px_rgba(0,0,0,0.5)]">
          <button 
