      <nav className="w-full flex items-center justify-between px-4 pt-4 pb-2 z-50 flex-shrink-0">
        <button onClick={() => onNavigate('feed')} className="p-2 bg-white/10 rounded-xl">
          <XMarkIcon className="h-5 w-5" />
        </button>
        <div className="flex flex-col items-center">
           <div className="bg-red-600 px-3 py-1 rounded-lg text-[9px] font-black flex items-center gap-2 shadow-lg">
             <SignalIcon className="h-3 w-3 animate-pulse" /> AO VIVO
           </div>
           <p className="text-[9px] font-black uppercase mt-1 tracking-widest text-gray-400">{post.liveStream.title}</p>
        </div>
        <div className="flex items-center gap-2 bg-white/5 px-3 py-1.5 rounded-lg">
           <UsersIcon className="h-3 w-3 text-gray-400" />
           <span className="text-[10px] font-bold">42</span>
        </div>
      </nav>

      <main className="flex-1 flex relative items-center justify-center overflow-hidden p-2 md:p-4">
        <div className="w-full h-full max-w-5xl rounded-[2rem] overflow-hidden bg-black border-4 border-white/5 relative shadow-2xl group">
          {isCamOn ? (
            <video ref={localVideoRef} autoPlay playsInline muted className="w-full h-full object-contain" />
          ) : (
            <div className="flex flex-col items-center justify-center h-full opacity-40 bg-gradient-to-br from-gray-900 to-black">
               <div className="w-32 h-32 rounded-[3rem] bg-gray-800 flex items-center justify-center text-5xl font-black border-4 border-white/5">
                {creator.firstName[0]}
               </div>
            </div>
          )}

          <div className="absolute bottom-6 left-6 flex items-center gap-4 bg-black/40 backdrop-blur-xl p-3 rounded-[1.5rem] border border-white/10">
             <img src={creator.profilePicture} className="w-10 h-10 rounded-xl object-cover border-2 border-red-500" />
             <div>
                <p className="text-[10px] font-black uppercase tracking-widest">{creator.firstName} {creator.lastName}</p>
                <p className="text-[8px] font-bold text-gray-400">Professor</p>
             </div>
          </div>

          {handRaiseNotification && (
            <div className="absolute top-6 left-1/2 -translate-x-1/2 z-[100] animate-bounce-in">
               <div className="bg-yellow-500/10 backdrop-blur-2xl px-6 py-3 rounded-[2rem] border-2 border-yellow-500/50 shadow-lg flex items-center gap-3">
                  <HandRaisedIcon className="h-4 w-4 text-yellow-500" />
                  <p className="font-black text-[10px] uppercase text-white whitespace-nowrap">
                    {handRaiseNotification.name} <span className="text-yellow-500">levantou a mão</span>
                  </p>
               </div>
            </div>
          )}
        </div>

        {activeSidebar === 'chat' && (
          <aside className="absolute right-0 top-0 bottom-0 w-full md:w-72 bg-black/95 backdrop-blur-3xl border-l border-white/10 z-40 flex flex-col animate-slide-left">
            <div className="p-4 border-b border-white/10 flex justify-between items-center">
              <h3 className="font-black text-[10px] uppercase tracking-widest text-blue-500">Chat</h3>
              <button onClick={() => setActiveSidebar(null)}><XMarkIcon className="h-5 w-5"/></button>
            </div>
            <div className="flex-1 overflow-y-auto p-4 space-y-4 custom-scrollbar">
               {chatMessages.map(m => (
                 <div key={m.id} className="bg-white/5 p-3 rounded-xl border border-white/5">
                    <p className="text-[8px] font-black text-blue-400 uppercase mb-1">{findUserById(m.senderId)?.firstName}</p>
                    {m.imageUrl && <img src={m.imageUrl} className="w-full rounded-lg mb-2 shadow-lg" />}
