      <footer className="p-3 md:p-6 flex flex-col md:flex-row items-center justify-center gap-4 flex-shrink-0">
        <div className="bg-darkcard/60 backdrop-blur-3xl px-4 py-2 rounded-[2rem] border border-white/10 flex items-center gap-3 shadow-2xl">
          <button onClick={toggleMic} className={`p-2.5 rounded-xl transition-all ${isMicOn ? 'bg-white/10' : 'bg-red-600'}`}>
            {isMicOn ? <MicrophoneIcon className="h-5 w-5" /> : <MicrophoneIconOutline className="h-5 w-5" />}
          </button>

          <button onClick={toggleCamera} className={`p-2.5 rounded-xl transition-all ${isCamOn ? 'bg-white/10' : 'bg-red-600'}`}>
            <VideoCameraIcon className="h-5 w-5" />
          </button>

          <button onClick={() => setActiveSidebar(activeSidebar === 'chat' ? null : 'chat')} className={`p-2.5 rounded-xl transition-all ${activeSidebar === 'chat' ? 'bg-blue-600' : 'bg-white/10'}`}>
            <ChatBubbleLeftRightIcon className="h-5 w-5" />
          </button>

          <button onClick={handleHandRaise} className={`p-2.5 rounded-xl transition-all ${handRaised ? 'bg-yellow-500 text-black' : 'bg-white/10'}`}>
            <HandRaisedIcon className="h-5 w-5" />
          </button>

          {!isTeacher && (
            <button onClick={() => setShowDonationModal(true)} className="p-2.5 rounded-xl bg-green-600 shadow-lg" title="Doar">
              <BanknotesIcon className="h-5 w-5" />
            </button>
          )}

          {isTeacher && (
            <button 
              onClick={() => isScreenSharing ? stopStreams() : setShowScreenShareSafety(true)} 
              className={`p-2.5 rounded-xl transition-all ${isScreenSharing ? 'bg-blue-600 shadow-lg' : 'bg-white/10 text-gray-400 hover:text-white'}`}
            >
              <ComputerDesktopIcon className="h-5 w-5" />
            </button>
          )}
        </div>

        {isTeacher && (
          <button onClick={() => { if(window.confirm("Encerrar aula?")) { deletePost(postId); onNavigate('feed'); } }} className="md:absolute md:right-6 bg-red-600 px-4 py-2.5 rounded-xl font-black text-[9px] uppercase tracking-widest flex items-center gap-2">
             <PowerIcon className="h-4 w-4" /> Encerrar
          </button>
        )}
      </footer>

      <style>{`
        @keyframes slide-left { from { transform: translateX(100%); } to { transform: translateX(0); } }
        @keyframes bounce-in { 0% { transform: translate(-50%, -100%); opacity: 0; } 100% { transform: translate(-50%, 0); opacity: 1; } }
        .animate-slide-left { animation: slide-left 0.3s ease-out forwards; }
        .animate-bounce-in { animation: bounce-in 0.5s cubic-bezier(0.34, 1.56, 0.64, 1) forwards; }
      `}</style>
    </div>
  );
};

