                <button onClick={() => handleUpgrade(false)} disabled={!canUnlockOrgannically} className="w-full py-5 bg-blue-600 text-white rounded-2xl font-black shadow-xl disabled:opacity-30">DESBLOQUEAR SELO</button>
            </div>

            <div className="bg-gray-900 p-10 rounded-[3rem] text-left text-white shadow-2xl relative overflow-hidden flex flex-col group">
                <div className="absolute top-0 right-0 w-32 h-32 bg-blue-600/30 rounded-full blur-[60px]"></div>
                <SparklesIcon className="h-10 w-10 text-yellow-400 mb-6" />
                <h4 className="text-2xl font-black mb-2 uppercase tracking-tighter">Modo Instantâneo</h4>
                <p className="text-gray-400 text-sm mb-8 font-medium">Libere ferramentas de venda e lives hoje mesmo.</p>
                <p className="text-5xl font-black mb-8 tracking-tighter">${CREATOR_UPGRADE_COST_USD.toFixed(2)}</p>

                <div className="space-y-3 mt-auto">
                  <button onClick={() => handleUpgrade(true)} className="w-full py-5 bg-white text-black rounded-2xl font-black shadow-xl active:scale-95 transition-all text-xs uppercase tracking-widest">
                    Pagar com Saldo CyBer
                  </button>
                  <button 
                    onClick={() => setShowCryptoUpgrade(true)}
                    className="w-full py-5 bg-purple-600 text-white rounded-2xl font-black shadow-xl active:scale-95 transition-all text-xs uppercase tracking-widest flex items-center justify-center gap-2"
