                </div>
            </div>
        </div>

        {/* MODAL OVERLAY PARA CRYPTOMUS */}
        {showCryptoUpgrade && (
          <div className="fixed inset-0 z-[500] bg-black/90 backdrop-blur-lg flex items-center justify-center p-4 animate-fade-in">
