          </button>
          <button onClick={onCancel} className="text-[10px] font-black text-gray-400 uppercase tracking-widest hover:text-red-500">Cancelar Transação</button>
        </div>
      </div>
    );
  }

  return (
    <div className="animate-fade-in space-y-6">
      {/* Header Centralizado e Genérico */}
