                <div className="flex flex-wrap gap-2">
                   {selectedCoin.networks.map(net => (
                     <button key={net} type="button" onClick={() => setSelectedNetwork(net)} className={`px-4 py-2 rounded-lg text-[9px] font-black uppercase transition-all ${selectedNetwork === net ? 'bg-red-600 text-white' : 'bg-gray-100 dark:bg-white/5 text-gray-400'}`}>{net}</button>
                   ))}
                </div>
             </div>
          </div>
        )}

        <div className="flex flex-col gap-3 pt-4">
           <button 
             type="submit"
             disabled={loading}
             className={`w-full py-5 rounded-[2rem] font-black text-sm uppercase shadow-xl transition-all active:scale-95 flex items-center justify-center gap-2 disabled:opacity-50 ${mode === 'deposit' ? 'bg-blue-600 text-white' : 'bg-gray-900 text-white'}`}
           >
             {loading ? <div className="w-5 h-5 border-2 border-white border-t-transparent animate-spin rounded-full" /> : <><GlobeAltIcon className="h-5 w-5" /> {mode === 'deposit' ? (method === 'crypto' ? 'Gerar Endereço' : 'Finalizar com Cartão') : 'Solicitar Resgate'}</>}
           </button>
           <button type="button" onClick={onCancel} className="w-full py-2 text-[9px] font-black text-gray-400 uppercase tracking-widest text-center">Voltar</button>
        </div>
      </form>
    </div>
  );
};

