import React, { useState, useRef } from 'react';
import { User } from '../types';
import { addStory } from '../services/storageService';
import { XMarkIcon, PhotoIcon, SparklesIcon, ArrowUpTrayIcon, CheckCircleIcon } from '@heroicons/react/24/solid';

interface CreateStoryModalProps {
  currentUser: User;
  onClose: () => void;
  onStoryCreated: () => void;
}

const CreateStoryModal: React.FC<CreateStoryModalProps> = ({ currentUser, onClose, onStoryCreated }) => {
  const [selectedImage, setSelectedImage] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    setError('');

    if (file) {
      if (!file.type.startsWith('image/')) {
        setError('Por favor, selecione apenas arquivos de imagem.');
        return;
      }

      const reader = new FileReader();
      reader.onloadend = () => {
        setSelectedImage(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedImage) return;

    setLoading(true);
    // Simula processamento de upload
    setTimeout(() => {
      addStory(currentUser.id, selectedImage);
      onStoryCreated();
      setLoading(false);
    }, 1200);
  };

  const triggerFileInput = () => {
    fileInputRef.current?.click();
  };

  return (
    <div className="fixed inset-0 z-[1000] bg-black/80 backdrop-blur-sm flex items-center justify-center p-4 animate-fade-in">
       <div className="bg-white dark:bg-darkcard w-full max-w-md rounded-[2.5rem] p-8 shadow-2xl relative border border-white/10">
          <button onClick={onClose} className="absolute top-6 right-6 text-gray-400 hover:text-gray-600 transition-colors">
             <XMarkIcon className="h-6 w-6" />
          </button>

          <div className="text-center mb-8">
             <div className="w-16 h-16 bg-blue-600/10 rounded-2xl flex items-center justify-center mx-auto mb-4">
                <SparklesIcon className="h-8 w-8 text-blue-600" />
             </div>
             <h3 className="text-xl font-black dark:text-white uppercase tracking-tighter">Novo History</h3>
             <p className="text-xs text-gray-500 font-bold uppercase tracking-widest mt-1">Compartilhe um momento do seu dia</p>
          </div>

          <form onSubmit={handleSubmit} className="space-y-6">
             <div className="space-y-2">
                <input 
                  type="file" 
                  ref={fileInputRef} 
                  onChange={handleFileChange} 
                  accept="image/*" 
                  className="hidden" 
                />

                {!selectedImage ? (
                  <div 
                    onClick={triggerFileInput}
                    className="w-full h-64 border-2 border-dashed border-gray-200 dark:border-white/10 rounded-[2rem] flex flex-col items-center justify-center gap-4 cursor-pointer hover:border-blue-500 hover:bg-blue-50/30 dark:hover:bg-blue-900/10 transition-all group"
                  >
                     <div className="bg-gray-100 dark:bg-white/5 p-4 rounded-full group-hover:scale-110 transition-transform">
                        <ArrowUpTrayIcon className="h-8 w-8 text-gray-400 group-hover:text-blue-600" />
                     </div>
                     <div className="text-center">
                        <p className="text-sm font-black text-gray-700 dark:text-gray-300 uppercase tracking-tighter">Escolha uma foto</p>
                        <p className="text-[10px] text-gray-400 font-bold uppercase mt-1">PNG, JPG ou WEBP</p>
                     </div>
                  </div>
                ) : (
                  <div className="relative rounded-[2rem] overflow-hidden border-2 border-blue-500 shadow-2xl h-80 group">
                    <img src={selectedImage} className="w-full h-full object-cover" alt="Preview" />
                    <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center">
                       <button 
                         type="button" 
                         onClick={triggerFileInput}
                         className="bg-white text-black px-4 py-2 rounded-xl font-black text-[10px] uppercase shadow-lg active:scale-95 transition-all"
                       >
                         Trocar Foto
                       </button>
                    </div>
                    <div className="absolute top-4 right-4 bg-green-500 text-white p-1.5 rounded-full shadow-lg">
                       <CheckCircleIcon className="h-5 w-5" />
                    </div>
                  </div>
                )}
             </div>

             {error && (
               <p className="text-red-500 text-[10px] font-black uppercase text-center bg-red-50 dark:bg-red-900/10 p-2 rounded-xl border border-red-100 dark:border-red-900/20">
                 {error}
               </p>
             )}

             <div className="flex gap-3">
                <button 
                  type="button"
                  onClick={onClose}
                  className="flex-1 py-5 rounded-2xl font-black text-[10px] uppercase tracking-widest text-gray-500 hover:bg-gray-100 dark:hover:bg-white/5 transition-all"
                >
                  Cancelar
                </button>
                <button 
                  type="submit" 
                  disabled={loading || !selectedImage}
                  className="flex-[2] bg-blue-600 hover:bg-blue-700 text-white py-5 rounded-2xl font-black text-[10px] uppercase tracking-widest shadow-xl disabled:opacity-30 transition-all flex items-center justify-center gap-2"
                >
                    {loading ? (
                      <div className="w-4 h-4 border-2 border-white border-t-transparent animate-spin rounded-full"></div>
                    ) : (
                      <>Publicar History</>
                    )}
                </button>
             </div>
          </form>
       </div>
    </div>
  );
};

