  const [scheduledTime, setScheduledTime] = useState('');
  const [showScheduleForm, setShowScheduleForm] = useState(false);

  const [loading, setLoading] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const isEditing = !!postId;
  const isCreator = currentUser.userType === UserType.CREATOR;

  // Carregar dados se for edição
  useEffect(() => {
    if (postId) {
      const posts = getPosts();
      const postToEdit = posts.find(p => p.id === postId);
      if (postToEdit) {
        setPostType(postToEdit.type);
        setContent(postToEdit.content || '');
        setImageUrl(postToEdit.imageUrl || '');
        if (postToEdit.type === PostType.REEL && postToEdit.reel) {
          setVideoUrl(postToEdit.reel.videoUrl || '');
          setSelectedAudioTrackId(postToEdit.reel.audioTrackId);
          setContent(postToEdit.reel.description || '');
        }
        if (postToEdit.type === PostType.LIVE && postToEdit.liveStream) {
          setContent(postToEdit.liveStream.title);
          setLiveDescription(postToEdit.liveStream.description);
          setIsLivePaid(postToEdit.liveStream.isPaid);
          setLivePrice(postToEdit.liveStream.price?.toString() || '0');
        }
        if (postToEdit.scheduledAt) {
          const date = new Date(postToEdit.scheduledAt);
          setScheduledDate(date.toISOString().split('T')[0]);
          setScheduledTime(date.toTimeString().split(' ')[0].slice(0, 5));
          setIsScheduled(true);
        }
      }
    }
  }, [postId]);

  const selectedTrack = selectedAudioTrackId ? findAudioTrackById(selectedAudioTrackId) : null;

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setImageUrl(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    // Validação básica baseada no tipo
    if (postType === PostType.TEXT && !content.trim()) return;
    if (postType === PostType.IMAGE && !imageUrl.trim()) return;
    if (postType === PostType.REEL && !videoUrl.trim()) return;
    if (postType === PostType.LIVE && (!content.trim() || !liveDescription.trim())) {
      alert("Título e descrição são obrigatórios para Aulas ao vivo.");
      return;
    }

    setLoading(true);

    let scheduledTimestamp: number | undefined = undefined;
    if (isScheduled && scheduledDate && scheduledTime) {
       scheduledTimestamp = new Date(`${scheduledDate}T${scheduledTime}`).getTime();
    }

    try {
      const posts = getPosts();
      const existingPost = isEditing ? posts.find(p => p.id === postId) : null;

      const postData: Post = {
        id: isEditing ? postId! : `post-${Date.now()}`,
        userId: currentUser.id,
        authorName: `${currentUser.firstName} ${currentUser.lastName}`,
        authorProfilePic: currentUser.profilePicture,
        type: postType,
        timestamp: isEditing && existingPost ? existingPost.timestamp : Date.now(),
        scheduledAt: scheduledTimestamp,
        content: (postType === PostType.TEXT || postType === PostType.IMAGE) ? content : undefined,
        imageUrl: postType === PostType.IMAGE ? imageUrl : undefined,
        reel: postType === PostType.REEL ? {
          title: content.split('\n')[0] || 'Novo Reel',
          description: content,
          videoUrl: videoUrl,
          audioTrackId: selectedAudioTrackId
        } : undefined,
        liveStream: postType === PostType.LIVE ? {
          title: content, // Usamos content como título da live
          description: liveDescription,
          isPaid: isLivePaid,
          price: isLivePaid ? parseFloat(livePrice) : 0
        } : undefined,
        likes: isEditing && existingPost ? existingPost.likes : [],
        comments: isEditing && existingPost ? existingPost.comments : [],
        shares: isEditing && existingPost ? existingPost.shares : [],
        saves: isEditing && existingPost ? existingPost.saves : [],
        indicatedUserIds: isEditing && existingPost ? existingPost.indicatedUserIds : [],
      };

      if (isEditing) {
        updatePost(postData);
      } else {
        addPost(postData);
      }

      // Resetar form
      if (!isEditing) {
        setContent(''); 
        setImageUrl(''); 
        setVideoUrl('');
        setLiveDescription('');
        setIsLivePaid(false);
        setLivePrice('0');
        setSelectedAudioTrackId(undefined);
        setIsExpanded(false); 
        setIsScheduled(false);
      }

      onPostCreated();
    } catch (err) {
      alert('Erro ao salvar.');
    } finally {
      setLoading(false);
    }
  };

  if (!isExpanded && !isEditing) {
    return (
      <div className="bg-white dark:bg-darkcard rounded-2xl md:rounded-[2rem] shadow-sm p-4 border border-gray-100 dark:border-white/10 animate-fade-in group hover:shadow-md transition-all flex flex-col gap-3">
         <div className="flex items-start gap-3">
            <img 
              src={currentUser.profilePicture} 
              className="w-10 h-10 rounded-xl object-cover shadow-sm group-hover:scale-105 transition-transform shrink-0" 
            />
            <button 
              onClick={() => setIsExpanded(true)}
              className="flex-1 text-left px-4 py-2.5 bg-slate-50 dark:bg-white/5 rounded-xl text-gray-400 dark:text-gray-500 font-bold hover:bg-slate-100 dark:hover:bg-white/10 transition-all text-xs md:text-sm"
            >
              O que você quer ensinar hoje, {currentUser.firstName}?
            </button>
         </div>

         <div className="flex items-center gap-4 md:gap-8 px-1 border-t border-gray-50 dark:border-white/5 pt-2 overflow-x-auto no-scrollbar">
            <button 
              onClick={() => { setIsExpanded(true); setPostType(PostType.IMAGE); }} 
              className="flex items-center gap-2 text-gray-500 hover:text-blue-600 transition-all shrink-0"
            >
               <PhotoIcon className="h-5 w-5 text-blue-500" />
               <span className="text-[10px] font-black uppercase tracking-widest">Imagem</span>
            </button>
            <button 
              onClick={() => { setIsExpanded(true); setPostType(PostType.REEL); }} 
              className="flex items-center gap-2 text-gray-500 hover:text-purple-600 transition-all shrink-0"
            >
               <FilmIcon className="h-5 w-5 text-purple-500" />
               <span className="text-[10px] font-black uppercase tracking-widest">Reel</span>
            </button>
            <button 
              onClick={() => { 
                if(!isCreator) {
                  alert("A função de Live é exclusiva para Criadores. Desbloqueie em 'Minha Loja'.");
                  return;
                }
                setIsExpanded(true); 
                setPostType(PostType.LIVE); 
              }} 
              className={`flex items-center gap-2 transition-all shrink-0 ${isCreator ? 'text-gray-500 hover:text-red-600' : 'text-gray-300 cursor-not-allowed'}`}
            >
               {isCreator ? <VideoCameraIcon className="h-5 w-5 text-red-500" /> : <LockClosedIcon className="h-4 w-4 text-gray-300" />}
               <span className="text-[10px] font-black uppercase tracking-widest">Live</span>
            </button>
         </div>
      </div>
    );
  }

  return (
    <div className="bg-white dark:bg-darkcard rounded-[2.5rem] shadow-2xl p-6 md:p-8 border border-blue-50 dark:border-white/5 animate-fade-in relative overflow-hidden">
      <div className="absolute top-0 left-0 w-2 h-full bg-blue-600"></div>

      <div className="flex items-center justify-between mb-8">
        <div className="flex items-center gap-4">
           <div className={`p-3 text-white rounded-2xl shadow-lg transform -rotate-3 ${postType === PostType.REEL ? 'bg-purple-600 shadow-purple-200' : postType === PostType.LIVE ? 'bg-red-600 shadow-red-200' : 'bg-blue-600 shadow-blue-200'}`}>
             {postType === PostType.REEL ? <FilmIcon className="h-6 w-6" /> : postType === PostType.LIVE ? <VideoCameraIcon className="h-6 w-6" /> : <SparklesIcon className="h-6 w-6" />}
           </div>
           <div>
              <h3 className="font-black text-gray-900 dark:text-white uppercase text-[10px] tracking-[0.2em]">{isEditing ? 'Editar Publicação' : 'Criar Publicação'}</h3>
              <p className="text-[8px] text-blue-500 font-black uppercase mt-0.5 tracking-widest">Comunidade Educacional</p>
           </div>
        </div>
        <button onClick={() => { if(isEditing) onPostCreated(); else setIsExpanded(false); }} className="p-2 hover:bg-gray-100 dark:hover:bg-white/5 rounded-xl transition-colors text-gray-300">
            <XMarkIcon className="h-6 w-6" />
        </button>
      </div>

      <form onSubmit={handleSubmit} className="space-y-6">
        <div className="flex flex-wrap gap-2 p-1.5 bg-slate-50 dark:bg-white/5 rounded-2xl w-fit border border-slate-100 dark:border-white/5">
           {[
             { id: PostType.TEXT, icon: DocumentTextIcon, label: 'Texto', color: 'blue', locked: false },
             { id: PostType.IMAGE, icon: PhotoIcon, label: 'Imagem', color: 'indigo', locked: false },
             { id: PostType.REEL, icon: FilmIcon, label: 'Reel', color: 'purple', locked: false },
             { id: PostType.LIVE, icon: VideoCameraIcon, label: 'Aula', color: 'red', locked: !isCreator }
           ].map(t => (
             <button 
               key={t.id} 
               type="button" 
               disabled={t.locked}
               onClick={() => setPostType(t.id)}
               className={`flex items-center gap-2 px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${postType === t.id ? `bg-white dark:bg-white/10 text-${t.color}-600 dark:text-white shadow-sm` : 'text-gray-400 hover:text-gray-600'} ${t.locked ? 'opacity-30 cursor-not-allowed' : ''}`}
             >
                {t.locked ? <LockClosedIcon className="h-3 w-3" /> : <t.icon className="h-4 w-4" />} 
                {t.label}
             </button>
           ))}
        </div>

        <div className="space-y-4">
            <input
              type="text"
              value={content}
              onChange={(e) => setContent(e.target.value)}
              className="w-full p-6 bg-slate-50 dark:bg-white/5 border-2 border-transparent focus:border-blue-500 focus:bg-white dark:focus:bg-darkcard rounded-2xl outline-none font-bold text-lg transition-all shadow-inner dark:text-white"
              placeholder={
                postType === PostType.LIVE ? "Título da sua aula ao vivo..." : 
                postType === PostType.REEL ? "Título do Reel..." :
                "O que você quer compartilhar?"
              }
            />

            {postType === PostType.LIVE && (
              <textarea
                value={liveDescription}
                onChange={(e) => setLiveDescription(e.target.value)}
                rows={4}
                className="w-full p-6 bg-slate-50 dark:bg-white/5 border-2 border-transparent focus:border-red-500 focus:bg-white dark:focus:bg-darkcard rounded-2xl outline-none font-medium text-base transition-all shadow-inner dark:text-white"
                placeholder="Descrição detalhada da aula (O que os alunos irão aprender?)..."
              />
            )}

            {(postType === PostType.TEXT || postType === PostType.IMAGE || postType === PostType.REEL) && postType !== PostType.LIVE && (
              <textarea
                value={postType === PostType.REEL ? content : content}
                onChange={(e) => postType !== PostType.LIVE && setContent(e.target.value)}
                rows={4}
                className={`w-full p-6 bg-slate-50 dark:bg-white/5 border-2 border-transparent focus:border-blue-500 focus:bg-white dark:focus:bg-darkcard rounded-2xl outline-none font-medium text-base transition-all shadow-inner dark:text-white ${postType === PostType.TEXT || postType === PostType.IMAGE ? '' : 'hidden'}`}
                placeholder="Desenvolva seu raciocínio aqui..."
              />
            )}
        </div>

        {postType === PostType.IMAGE && (
          <div className="animate-fade-in space-y-4">
             <input 
                type="file" 
                ref={fileInputRef} 
                onChange={handleFileChange} 
                accept="image/*" 
                className="hidden" 
             />

             {!imageUrl ? (
               <div 
                 onClick={() => fileInputRef.current?.click()}
                 className="w-full h-64 border-2 border-dashed border-gray-200 dark:border-white/10 rounded-[2rem] flex flex-col items-center justify-center gap-4 cursor-pointer hover:border-blue-500 hover:bg-blue-50/30 dark:hover:bg-blue-900/10 transition-all group"
               >
                  <div className="bg-gray-100 dark:bg-white/5 p-4 rounded-full group-hover:scale-110 transition-transform">
                     <ArrowUpTrayIcon className="h-8 w-8 text-gray-400 group-hover:text-blue-600" />
                  </div>
                  <div className="text-center px-4">
                     <p className="text-sm font-black text-gray-700 dark:text-gray-300 uppercase tracking-tighter">Escolher Foto do Post</p>
                     <p className="text-[10px] text-gray-400 font-bold uppercase mt-1">Sua aula ilustrada</p>
                  </div>
               </div>
             ) : (
               <div className="relative rounded-[2.5rem] overflow-hidden border-4 border-blue-500 shadow-2xl group animate-fade-in">
                  <img src={imageUrl} className="w-full h-auto max-h-[500px] object-cover" alt="Preview" />
                  <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center gap-4">
                     <button 
                       type="button" 
                       onClick={() => fileInputRef.current?.click()}
                       className="bg-white text-black px-6 py-3 rounded-xl font-black text-xs uppercase shadow-lg hover:scale-105 transition-all"
                     >
                       Trocar Imagem
                     </button>
                     <button 
                       type="button" 
                       onClick={() => setImageUrl('')}
                       className="bg-red-600 text-white px-6 py-3 rounded-xl font-black text-xs uppercase shadow-lg hover:scale-105 transition-all"
                     >
                       <TrashIcon className="h-5 w-5" />
                     </button>
                  </div>
               </div>
             )}
          </div>
        )}

        {postType === PostType.LIVE && (
          <div className="animate-fade-in p-6 bg-red-50/50 dark:bg-red-900/10 rounded-2xl border border-red-100 dark:border-red-900/20 space-y-4">
             <div className="flex items-center justify-between">
                <div className="flex items-center gap-3">
                   <CurrencyDollarIcon className="h-5 w-5 text-red-500" />
                   <span className="text-[10px] font-black text-red-600 uppercase">Aula Monetizada</span>
                </div>
                <button 
                  type="button" 
                  onClick={() => setIsLivePaid(!isLivePaid)}
                  className={`w-12 h-6 rounded-full transition-all relative ${isLivePaid ? 'bg-red-600' : 'bg-gray-200 dark:bg-white/10'}`}
                >
                  <div className={`absolute top-1 w-4 h-4 bg-white rounded-full transition-all ${isLivePaid ? 'right-1' : 'left-1'}`}></div>
                </button>
             </div>
             {isLivePaid && (
               <div className="flex items-center gap-3 animate-fade-in">
                  <span className="text-xl font-black text-gray-900 dark:text-white">$</span>
                  <input 
                    type="number" 
                    value={livePrice} 
                    onChange={e => setLivePrice(e.target.value)}
                    className="flex-1 p-3 bg-white dark:bg-darkcard rounded-xl outline-none border border-red-200 font-bold dark:text-white"
                    placeholder="0.00"
                  />
                  <span className="text-[9px] font-black text-gray-400 uppercase">Preço sugerido</span>
               </div>
             )}
          </div>
        )}

        {postType === PostType.REEL && (
          <div className="animate-fade-in space-y-4">
            <div className="p-4 bg-purple-50/50 dark:bg-purple-900/10 rounded-2xl border border-purple-100 dark:border-purple-900/20">
               <label className="block text-[8px] font-black text-purple-400 uppercase mb-2 ml-1">URL do Vídeo (MP4)</label>
               <div className="relative">
                  <FilmIcon className="h-5 w-5 absolute left-4 top-1/2 -translate-y-1/2 text-purple-300" />
                  <input 
                    type="text" 
                    value={videoUrl} 
                    onChange={e => setVideoUrl(e.target.value)} 
                    className="w-full pl-12 pr-4 py-3 bg-white dark:bg-darkcard rounded-xl outline-none font-bold border border-transparent focus:border-purple-400 text-xs shadow-sm dark:text-white" 
                    placeholder="Link do vídeo para o Reel..." 
                  />
               </div>
            </div>

            <div className="p-4 bg-slate-50 dark:bg-white/5 rounded-2xl border border-slate-100 dark:border-white/5 flex items-center justify-between">
                <div className="flex items-center gap-3">
                   <div className="p-2 bg-purple-100 dark:bg-purple-900/30 rounded-lg">
                      <MusicalNoteIcon className="h-4 w-4 text-purple-600" />
                   </div>
                   <div>
                      <p className="text-[8px] font-black text-gray-400 uppercase">Trilha Sonora</p>
                      <p className="text-xs font-bold dark:text-white">{selectedTrack ? `${selectedTrack.title} - ${selectedTrack.artist}` : 'Nenhuma selecionada'}</p>
                   </div>
                </div>
                <button 
                  type="button"
                  onClick={() => setShowAudioModal(true)}
                  className="px-4 py-2 bg-white dark:bg-white/10 text-purple-600 dark:text-purple-400 rounded-xl text-[10px] font-black uppercase border border-purple-100 dark:border-purple-900/30 shadow-sm"
                >
                  {selectedAudioTrackId ? 'Trocar' : 'Escolher Música'}
                </button>
            </div>
          </div>
        )}

        <div className="flex flex-col md:flex-row items-center justify-between gap-4 pt-6 border-t border-slate-50 dark:border-white/5">
           <div className="flex items-center gap-3">
              <button 
                type="button" 
                onClick={() => setShowScheduleForm(!showScheduleForm)}
                className={`flex items-center gap-2 px-4 py-3 rounded-xl text-[9px] font-black uppercase tracking-widest transition-all ${isScheduled ? 'bg-blue-600 text-white' : 'bg-slate-50 dark:bg-white/5 text-gray-500 border border-slate-100 dark:border-white/5'}`}
              >
                 <CalendarDaysIcon className="h-4 w-4" /> {isScheduled ? 'Agendado' : 'Agendar'}
              </button>
              {showScheduleForm && (
                <div className="flex items-center gap-2 animate-fade-in">
                   <input type="date" value={scheduledDate} onChange={e => {setScheduledDate(e.target.value); setIsScheduled(true);}} className="p-3 bg-slate-50 dark:bg-white/5 border border-slate-100 dark:border-white/5 rounded-xl text-[10px] font-black outline-none focus:border-blue-500 dark:text-white" />
                   <input type="time" value={scheduledTime} onChange={e => {setScheduledTime(e.target.value); setIsScheduled(true);}} className="p-3 bg-slate-50 dark:bg-white/5 border border-slate-100 dark:border-white/5 rounded-xl text-[10px] font-black outline-none focus:border-blue-500 dark:text-white" />
                </div>
              )}
           </div>

           <button
             type="submit"
             disabled={loading || (postType === PostType.TEXT && !content.trim()) || (postType === PostType.IMAGE && !imageUrl.trim()) || (postType === PostType.REEL && !videoUrl.trim()) || (postType === PostType.LIVE && (!content.trim() || !liveDescription.trim()))}
             className={`w-full md:w-auto px-8 py-4 rounded-2xl font-black text-sm shadow-xl active:scale-95 transition-all flex items-center justify-center gap-3 disabled:opacity-30 ${postType === PostType.REEL ? 'bg-purple-600 hover:bg-purple-700 text-white' : postType === PostType.LIVE ? 'bg-red-600 hover:bg-red-700 text-white' : 'bg-gray-900 dark:bg-white dark:text-black text-white hover:bg-blue-600'}`}
           >
             {loading ? <div className="w-5 h-5 border-3 border-white border-t-transparent animate-spin rounded-full"></div> : <>{isEditing ? 'Atualizar' : postType === PostType.LIVE ? 'Iniciar Aula' : 'Publicar'} <ChevronRightIcon className="h-5 w-5" /></>}
           </button>
        </div>
      </form>

      {showAudioModal && (
        <AudioSelectionModal 
          onClose={() => setShowAudioModal(false)}
          onSelectTrack={(id) => {
            setSelectedAudioTrackId(id);
            setShowAudioModal(false);
          }}
        />
      )}
    </div>
  );
};

export default CreatePost;

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { AdCampaign, User, AdLocation } from '../types';
import { saveAds, getAds, updateUserBalance } from '../services/storageService';
import { generateAdCopy } from '../services/geminiService';
import { MIN_AD_CAMPAIGN_USD_COST, DEFAULT_PROFILE_PIC } from '../constants';
import { 
  RocketLaunchIcon, 
  MegaphoneIcon, 
  EyeIcon, 
  CursorArrowRaysIcon, 
  PhotoIcon, 
  CurrencyDollarIcon,
  ChevronRightIcon,
  DevicePhoneMobileIcon,
  ComputerDesktopIcon,
  SparklesIcon,
  CheckCircleIcon,
  MapPinIcon,
  GlobeAltIcon,
  XMarkIcon,
  PlusIcon,
  InformationCircleIcon,
  UserGroupIcon,
  CalendarIcon,
  UsersIcon,
  ArrowUpTrayIcon,
  TrashIcon
} from '@heroicons/react/24/solid';

interface AdCampaignPageProps {
  currentUser: User;
  refreshUser: () => void;
  onNavigate?: (page: string) => void;
}

const AdCampaignPage: React.FC<AdCampaignPageProps> = ({ currentUser, refreshUser }) => {
  const [loading, setLoading] = useState(false);
  const [geminiLoading, setGeminiLoading] = useState(false);

  // Form State
  const [campaignName, setCampaignName] = useState('');
  const [objective, setObjective] = useState<'traffic' | 'awareness' | 'engagement'>('traffic');
  const [title, setTitle] = useState('');
  const [description, setDescription] = useState('');
  const [imageUrl, setImageUrl] = useState('');
  const [linkUrl, setLinkUrl] = useState('');
  const [ctaText, setCtaText] = useState('Saiba Mais');
  const [targetAudience, setTargetAudience] = useState('');
  const [placements, setPlacements] = useState<string[]>(['feed']);

  // Dynamic Budget State
  const [durationDays, setDurationDays] = useState<number>(7);
  const [dailyReachGoal, setDailyReachGoal] = useState<number>(5000);

  // Location Targeting State
  const [targetedLocations, setTargetedLocations] = useState<AdLocation[]>([]);
  const [locCountry, setLocCountry] = useState('');
  const [locProvince, setLocProvince] = useState('');
  const [locCity, setLocCity] = useState('');

  const [myAds, setMyAds] = useState<AdCampaign[]>([]);
  const [previewPlacement, setPreviewPlacement] = useState<'feed' | 'sidebar'>('feed');
  const fileInputRef = useRef<HTMLInputElement>(null);

  // CONSTANTES DE CÁLCULO (Simulação de CPM/CPC)
  const COST_PER_1K_REACH = 0.50; 

  const calculatedTotalBudget = useMemo(() => {
    const costPerDay = (dailyReachGoal / 1000) * COST_PER_1K_REACH;
    const total = costPerDay * durationDays;
    return Math.max(total, MIN_AD_CAMPAIGN_USD_COST);
  }, [dailyReachGoal, durationDays]);

  useEffect(() => {
    setMyAds(getAds().filter(ad => ad.professorId === currentUser.id));
  }, [currentUser.id]);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setImageUrl(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const addLocation = () => {
    if (!locCountry) return;
    const newLoc: AdLocation = {
      country: locCountry,
      province: locProvince || undefined,
      city: locCity || undefined
    };
    setTargetedLocations([...targetedLocations, newLoc]);
    setLocCountry('');
    setLocProvince('');
    setLocCity('');
  };

  const removeLocation = (index: number) => {
    setTargetedLocations(targetedLocations.filter((_, i) => i !== index));
  };

  const handleGeminiGen = async () => {
    setGeminiLoading(true);
    try {
      const prompt = `Crie um anúncio para: ${title || 'meu novo curso'}. Público: ${targetAudience || 'estudantes'}.`;
      const copy = await generateAdCopy(prompt);
      setDescription(copy);
    } finally {
      setGeminiLoading(false);
    }
  }

  const handlePublish = () => {
    if (!title || !description || targetedLocations.length === 0 || placements.length === 0 || !imageUrl) {
      alert("Por favor, preencha todos os campos, inclua uma imagem e pelo menos uma localização.");
      return;
    }

    if ((currentUser.balance || 0) < calculatedTotalBudget) {
      alert("Saldo insuficiente na carteira para esta configuração de alcance/duração.");
      return;
    }

    setLoading(true);
    setTimeout(() => {
      const newAd: AdCampaign = {
