        linkUrl: linkUrl || '#',
        ctaText,
        placements,
        timestamp: Date.now()
      };

      updateUserBalance(currentUser.id, -calculatedTotalBudget);
      const all = getAds();
      saveAds([...all, newAd]);
      setMyAds([newAd, ...myAds]);

      alert(`Campanha publicada! Orçamento total de $${calculatedTotalBudget.toFixed(2)} por ${durationDays} dias.`);
