const ReelVideo: React.FC<ReelVideoProps> = ({ post, currentUser, onNavigate, onFollowToggle, refreshUser, isIntersecting, onPostUpdate }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const audioRef = useRef<HTMLAudioElement>(null);

  const [isMuted, setIsMuted] = useState(true);
  const [showPlayIcon, setShowPlayIcon] = useState(false);
  const [isCommentsModalOpen, setIsCommentsModalOpen] = useState(false);
  const [likeHearts, setLikeHearts] = useState<{ id: number; x: number; y: number }[]>([]);

  const clickTimeout = useRef<number | null>(null);

  const postAuthor = findUserById(post.userId);
  const isFollowing = currentUser.followedUsers.includes(post.userId);
  const hasLiked = post.likes.includes(currentUser.id);
  const hasSaved = post.saves.includes(currentUser.id);
  const [audioTrack, setAudioTrack] = useState<AudioTrack | null>(null);

  useEffect(() => {
    if (post.reel?.audioTrackId) {
      setAudioTrack(findAudioTrackById(post.reel.audioTrackId) || null);
    } else {
      setAudioTrack(null);
    }
  }, [post.reel?.audioTrackId]);

  // Função robusta para tocar vídeo no mobile
  const syncPlay = useCallback(async () => {
    const video = videoRef.current;
    const audio = audioRef.current;

    if (!video) return;

    try {
      // Forçar propriedades necessárias para mobile
      video.muted = isMuted || !!audioTrack;
      if (video.paused) {
        await video.play();
      }

      if (audio && !video.muted) {
        audio.muted = false;
        if (audio.paused) await audio.play();
      }
    } catch (e) {
      console.log("Autoplay bloqueado pelo navegador, aguardando interação.");
    }
  }, [isMuted, audioTrack]);

  const syncPause = useCallback(() => {
    const video = videoRef.current;
    const audio = audioRef.current;
    if (video && !video.paused) video.pause();
    if (audio && !audio.paused) audio.pause();
  }, []);

  useEffect(() => {
    if (isIntersecting) {
      syncPlay();
    } else {
      syncPause();
    }
  }, [isIntersecting, syncPlay, syncPause]);

  // Efeito para mutar/desmutar
  useEffect(() => {
    if (videoRef.current) {
        videoRef.current.muted = isMuted || !!audioTrack;
    }
    if (audioRef.current) {
        audioRef.current.muted = isMuted;
    }
  }, [isMuted, audioTrack]);

  const togglePlayPause = () => {
    const video = videoRef.current;
    if (!video) return;
    if (video.paused) {
      syncPlay();
    } else {
      syncPause();
      setShowPlayIcon(true);
      setTimeout(() => setShowPlayIcon(false), 500);
    }
  };

  const handleLike = () => {
    updatePostLikes(post.id, currentUser.id);
    onPostUpdate();
    refreshUser();
  };

  const handleDoubleClick = (e: React.MouseEvent | React.TouchEvent) => {
    let x, y;
    if ('clientX' in e) {
        const rect = (e.currentTarget as HTMLElement).getBoundingClientRect();
        x = e.clientX - rect.left;
        y = e.clientY - rect.top;
    } else {
        const rect = (e.currentTarget as HTMLElement).getBoundingClientRect();
        x = e.touches[0].clientX - rect.left;
        y = e.touches[0].clientY - rect.top;
    }

    const newHeart = { id: Date.now(), x, y };
    setLikeHearts(prev => [...prev, newHeart]);

    if (!hasLiked) {
      handleLike();
    }

    setTimeout(() => {
      setLikeHearts(prev => prev.filter(h => h.id !== newHeart.id));
    }, 800);
  };

  const handleContainerClick = (e: React.MouseEvent) => {
    if (clickTimeout.current) {
      window.clearTimeout(clickTimeout.current);
      clickTimeout.current = null;
      handleDoubleClick(e);
    } else {
      clickTimeout.current = window.setTimeout(() => {
        togglePlayPause();
        clickTimeout.current = null;
      }, 250);
    }
  };

  if (!postAuthor || !post.reel) return null;

  return (
    <>
      <div
        className="relative w-full h-full flex-shrink-0 snap-start bg-black overflow-hidden touch-none"
        onClick={handleContainerClick}
      >
        <video
          ref={videoRef}
          src={post.reel.videoUrl}
          loop
          playsInline
          webkit-playsinline="true"
          preload="auto"
          className="absolute inset-0 w-full h-full object-cover"
        />

        {audioTrack && <audio ref={audioRef} src={audioTrack.url} loop preload="auto" />}

        {/* Play/Pause Overlay */}
        <div className={`absolute inset-0 flex items-center justify-center transition-opacity duration-300 pointer-events-none z-20 ${showPlayIcon ? 'opacity-100' : 'opacity-0'}`}>
          <div className="bg-black/20 p-6 rounded-full backdrop-blur-sm">
            <PlayIcon className="h-16 w-16 text-white" />
          </div>
        </div>

        {/* Double Click Like Hearts */}
        {likeHearts.map(heart => (
          <div 
            key={heart.id} 
            className="absolute z-50 pointer-events-none animate-like-heart"
            style={{ left: heart.x - 40, top: heart.y - 40 }}
          >
            <HeartIconSolid className="w-24 h-24 text-red-500 drop-shadow-2xl" />
          </div>
        ))}

        {/* Mute Button */}
        <button 
          onClick={(e) => { e.stopPropagation(); setIsMuted(!isMuted); }} 
          className="absolute top-4 right-4 z-40 p-3 bg-black/30 rounded-full text-white backdrop-blur-md border border-white/10 active:scale-90 transition-all"
        >
          {isMuted ? <SpeakerXMarkIcon className="h-6 w-6" /> : <SpeakerWaveIcon className="h-6 w-6" />}
        </button>

        {/* Informações (Bottom Left) */}
        <div className="absolute bottom-0 left-0 p-5 pb-8 text-white z-30 w-full pointer-events-none">
          <div className="flex flex-col space-y-3 pointer-events-auto max-w-[85%]">
            <div className="flex items-center gap-3">
               <h4 
                 className="font-black text-lg drop-shadow-lg cursor-pointer hover:underline"
                 onClick={(e) => { e.stopPropagation(); onNavigate('profile', { userId: post.userId }); }}
               >
                 @{post.authorName}
               </h4>
               <span className="text-[10px] bg-white/20 px-2 py-0.5 rounded-full backdrop-blur-md border border-white/10 font-black uppercase">Original</span>
            </div>

            <p className="text-sm font-medium drop-shadow-md leading-snug line-clamp-2">
              {post.reel.description}
            </p>

            {audioTrack && (
              <div className="flex items-center gap-2 bg-black/40 backdrop-blur-md px-3 py-2 rounded-full w-fit max-w-full overflow-hidden border border-white/10">
                <div className="bg-white/20 p-1 rounded-full">
                    <svg viewBox="0 0 24 24" className="w-3 h-3 fill-white"><path d="M12 3v10.55c-.59-.34-1.27-.55-2-.55-2.21 0-4 1.79-4 4s1.79 4 4 4 4-1.79 4-4V7h4V3h-6z"/></svg>
                </div>
                <div className="marquee text-[10px] font-black uppercase tracking-wider whitespace-nowrap overflow-hidden">
                   <span className="marquee-content">{audioTrack.title} - {audioTrack.artist}</span>
                </div>
              </div>
            )}
          </div>
        </div>

        {/* Sidebar (Right) */}
        <div className="absolute bottom-10 right-2 flex flex-col items-center space-y-6 z-40 w-14">

          <div className="relative mb-2">
             <div 
               className="w-12 h-12 rounded-2xl border-2 border-white overflow-hidden shadow-2xl cursor-pointer active:scale-95 transition-transform"
               onClick={(e) => { e.stopPropagation(); onNavigate('profile', { userId: post.userId }); }}
             >
                <img src={postAuthor.profilePicture || DEFAULT_PROFILE_PIC} className="w-full h-full object-cover" alt="" />
             </div>
             {!isFollowing && currentUser.id !== post.userId && (
               <button 
                 onClick={(e) => { e.stopPropagation(); onFollowToggle(post.userId); }}
                 className="absolute -bottom-2 left-1/2 -translate-x-1/2 bg-red-600 rounded-full p-1 border-2 border-black shadow-lg active:scale-125"
               >
                 <PlusIcon className="w-3 h-3 text-white" />
               </button>
             )}
          </div>

          <button onClick={(e) => { e.stopPropagation(); handleLike(); }} className="flex flex-col items-center group active:scale-125 transition-transform">
              <div className="p-1">
                {hasLiked ? <HeartIconSolid className="h-9 w-9 text-red-500 drop-shadow-lg" /> : <HeartIconSolid className="h-9 w-9 text-white/90 drop-shadow-lg" />}
              </div>
              <span className="text-[11px] font-black text-white drop-shadow-lg mt-0.5">{post.likes.length}</span>
          </button>

          <button onClick={(e) => { e.stopPropagation(); setIsCommentsModalOpen(true); }} className="flex flex-col items-center group active:scale-125 transition-transform">
              <div className="p-1">
                <ChatIconOutline className="h-9 w-9 text-white/90 fill-white/10 drop-shadow-lg" />
              </div>
              <span className="text-[11px] font-black text-white drop-shadow-lg mt-0.5">{post.comments.length}</span>
          </button>

          <button onClick={(e) => { e.stopPropagation(); updatePostSaves(post.id, currentUser.id); onPostUpdate(); }} className="flex flex-col items-center group active:scale-125 transition-transform">
              <div className="p-1">
                {hasSaved ? <BookmarkIconSolid className="h-9 w-9 text-yellow-400 drop-shadow-lg" /> : <BookmarkIconSolid className="h-9 w-9 text-white/90 drop-shadow-lg" />}
              </div>
              <span className="text-[11px] font-black text-white drop-shadow-lg mt-0.5">{post.saves.length}</span>
          </button>

          <button onClick={(e) => { e.stopPropagation(); alert('Link copiado!'); }} className="flex flex-col items-center group active:scale-125 transition-transform">
              <div className="p-1">
                <ShareIconOutline className="h-9 w-9 text-white/90 drop-shadow-lg" />
              </div>
              <span className="text-[11px] font-black text-white drop-shadow-lg mt-0.5">{post.shares.length}</span>
          </button>

          {/* Disco de música animado */}
          <div className="pt-2">
             <div className={`w-10 h-10 rounded-full bg-gradient-to-tr from-gray-900 to-gray-700 border-[4px] border-white/20 shadow-2xl flex items-center justify-center overflow-hidden ${isIntersecting ? 'animate-spin-slow' : ''}`}>
