          animation: spin-slow 4s linear infinite;
        }
        @keyframes like-heart {
          0% { transform: scale(0.5) rotate(-15deg); opacity: 0; }
          15% { transform: scale(1.3) rotate(10deg); opacity: 1; }
          40% { transform: scale(1.1) rotate(-5deg); opacity: 1; }
