const ReelsPage: React.FC<ReelsPageProps> = ({ currentUser, onNavigate, refreshUser }) => {
  const [reels, setReels] = useState<Post[]>([]);
  const [loading, setLoading] = useState(true);
  const containerRef = useRef<HTMLDivElement>(null);
  const [visibleVideoIndex, setVisibleVideoIndex] = useState(0);

  const fetchReels = useCallback(() => {
    const allPosts = getPosts();
    const reelPosts = allPosts.filter(post => post.type === PostType.REEL)
                                .sort((a, b) => b.timestamp - a.timestamp);
    setReels(reelPosts);
    setLoading(false);
  }, []);

  useEffect(() => {
    fetchReels();
  }, [fetchReels]);

  useEffect(() => {
    const observer = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry) => {
          if (entry.isIntersecting) {
            const index = parseInt((entry.target as HTMLElement).dataset.index || '0');
            setVisibleVideoIndex(index);
          }
        });
      },
      { threshold: 0.5, rootMargin: '0px' }
    );

    const currentContainer = containerRef.current;
    if (currentContainer) {
      // Filtrar apenas elementos de div que possuem data-index
      const children = Array.from(currentContainer.querySelectorAll('[data-index]'));
      children.forEach(child => observer.observe(child));
    }

    return () => {
      if (currentContainer) {
        const children = Array.from(currentContainer.querySelectorAll('[data-index]'));
        children.forEach(child => observer.unobserve(child));
      }
    };
  }, [reels]);

  const handleFollowToggle = (userIdToFollow: string) => {
    toggleFollowUser(currentUser.id, userIdToFollow);
    refreshUser();
    fetchReels();
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center w-full h-[calc(100dvh-72px)] bg-black">
        <div className="animate-spin h-10 w-10 border-4 border-white border-t-transparent rounded-full"></div>
      </div>
    );
  }

  if (reels.length === 0) {
      return (
        <div className="flex flex-col items-center justify-center w-full h-[calc(100dvh-72px)] bg-black text-white p-10 text-center">
            <PlayIcon className="h-20 w-20 text-gray-800 mb-6" />
            <h3 className="text-xl font-black uppercase tracking-widest">Nenhum Reel disponível</h3>
            <p className="text-gray-500 text-sm mt-2">Os professores ainda não publicaram vídeos curtos.</p>
            <button onClick={() => onNavigate('feed')} className="mt-8 px-8 py-3 bg-blue-600 rounded-2xl font-black text-xs uppercase tracking-widest">Ir para o Feed</button>
        </div>
      );
  }

  return (
    <div
      ref={containerRef}
      className="fixed inset-0 top-[64px] md:top-[72px] bottom-[64px] md:bottom-0 w-full overflow-y-scroll snap-y snap-mandatory bg-black no-scrollbar overscroll-none"
      style={{ scrollbarWidth: 'none', msOverflowStyle: 'none' }}
    >
      {reels.map((reelPost, index) => (
        <div key={reelPost.id} data-index={index} className="h-full w-full snap-start snap-always">
          <ReelVideo
            post={reelPost}
            currentUser={currentUser}
            onNavigate={onNavigate}
            onFollowToggle={handleFollowToggle}
            refreshUser={refreshUser}
            isIntersecting={index === visibleVideoIndex}
            onPostUpdate={fetchReels}
          />
        </div>
      ))}
      <style>{`
        .no-scrollbar::-webkit-scrollbar { display: none; }
        .no-scrollbar { -ms-overflow-style: none; scrollbar-width: none; }
      `}</style>
    </div>
  );
};

