          <button onClick={(e) => { e.stopPropagation(); handleLike(); }} className="flex flex-col items-center group active:scale-125 transition-transform">
              <div className="p-1">
                {hasLiked ? <HeartIconSolid className="h-9 w-9 text-red-500 drop-shadow-lg" /> : <HeartIconSolid className="h-9 w-9 text-white/90 drop-shadow-lg" />}
