        {/* Drag Handle indicator for mobile */}
        <div className="w-12 h-1.5 bg-gray-200 dark:bg-white/10 rounded-full mx-auto mt-4 mb-2 shrink-0"></div>

        <header className="flex items-center justify-between px-6 py-4 border-b border-gray-100 dark:border-white/5 sticky top-0 bg-white dark:bg-darkcard z-10">
          <div>
            <h2 className="text-xl font-black text-gray-900 dark:text-white tracking-tighter">Comentários</h2>
