          <button onClick={onClose} className="p-2 rounded-xl bg-gray-50 dark:bg-white/5 text-gray-400 hover:text-gray-900 dark:hover:text-white transition-all">
            <XMarkIcon className="h-6 w-6" />
          </button>
        </header>

        <div className="flex-grow p-6 overflow-y-auto space-y-6 custom-scrollbar bg-gray-50/50 dark:bg-black/20">
          {post.comments.length === 0 ? (
