            </div>
          ) : (
            [...post.comments].sort((a, b) => b.timestamp - a.timestamp).map(comment => (
              <div key={comment.id} className="flex items-start space-x-4 animate-fade-in">
                <img 
                  src={comment.profilePic || DEFAULT_PROFILE_PIC} 
                  alt={comment.userName} 
                  className="w-10 h-10 rounded-xl object-cover border-2 border-white dark:border-white/10 shadow-sm" 
                />
                <div className="flex-1">
                  <div className="bg-white dark:bg-white/5 p-4 rounded-2xl rounded-tl-none shadow-sm border border-gray-100 dark:border-white/5">
                    <p className="font-black text-[11px] text-blue-600 dark:text-blue-400 uppercase tracking-tighter mb-1">{comment.userName}</p>
                    <p className="text-sm text-gray-800 dark:text-gray-200 leading-relaxed font-medium">{comment.text}</p>
                  </div>
                  <span className="text-[9px] font-black text-gray-400 uppercase tracking-widest mt-2 ml-1">
                    {new Date(comment.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                  </span>
                </div>
              </div>
            ))
          )}
        </div>

        <footer className="p-6 border-t border-gray-100 dark:border-white/10 bg-white dark:bg-darkcard sticky bottom-0">
          <form onSubmit={handleAddComment} className="flex items-end gap-3">
            <img 
              src={currentUser.profilePicture || DEFAULT_PROFILE_PIC} 
              className="w-10 h-10 rounded-xl object-cover border-2 border-blue-500 shrink-0 hidden sm:block" 
              alt="Avatar" 
            />
            <div className="flex-1 relative group">
              <textarea
