import React, { useState, useEffect, useRef } from 'react';
import { Post, User, Message } from '../types';
import { getPosts, findUserById, updateUserBalance, deletePost } from '../services/storageService';
import { 
  MicrophoneIcon, 
  VideoCameraIcon, 
  ChatBubbleLeftRightIcon, 
  XMarkIcon,
  HandRaisedIcon,
  SignalIcon,
  UsersIcon,
  ComputerDesktopIcon,
  PhotoIcon,
  PaperAirplaneIcon,
  ShieldCheckIcon,
  ShieldExclamationIcon,
  PowerIcon,
  BanknotesIcon,
  HeartIcon,
  CheckCircleIcon,
  ExclamationCircleIcon,
  ExclamationTriangleIcon
} from '@heroicons/react/24/solid';
import { 
  MicrophoneIcon as MicrophoneIconOutline, 
  PhotoIcon as PhotoIconOutline,
  WalletIcon
} from '@heroicons/react/24/outline';
import { DEFAULT_PROFILE_PIC } from '../constants';

interface LiveStreamViewerProps {
  currentUser: User;
  postId: string;
  onNavigate: (page: string, params?: Record<string, string>) => void;
  refreshUser: () => void;
}

const LiveStreamViewer: React.FC<LiveStreamViewerProps> = ({ currentUser, postId, onNavigate, refreshUser }) => {
  const [post, setPost] = useState<Post | null>(null);
  const [creator, setCreator] = useState<User | null>(null);
  const [isMicOn, setIsMicOn] = useState(false);
  const [isCamOn, setIsCamOn] = useState(false);
  const [isScreenSharing, setIsScreenSharing] = useState(false);
  const [showScreenShareSafety, setShowScreenShareSafety] = useState(false);

  const [showDonationModal, setShowDonationModal] = useState(false);
  const [pendingAmount, setPendingAmount] = useState<number | null>(null);
  const [isProcessingDonation, setIsProcessingDonation] = useState(false);

  const [activeSidebar, setActiveSidebar] = useState<'chat' | null>(null);
  const [handRaised, setHandRaised] = useState(false);
  const [handRaiseNotification, setHandRaiseNotification] = useState<{id: string, name: string} | null>(null);

  const [chatMessages, setChatMessages] = useState<Message[]>([]);
  const [newMessage, setNewMessage] = useState('');
  const [selectedImage, setSelectedImage] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const localVideoRef = useRef<HTMLVideoElement>(null);
  const streamRef = useRef<MediaStream | null>(null);

  useEffect(() => {
    const foundPost = getPosts().find(p => p.id === postId);
    if (foundPost && foundPost.liveStream) {
      setPost(foundPost);
      const author = findUserById(foundPost.userId);
      setCreator(author || null);
    } else {
      onNavigate('feed');
    }
    return () => stopStreams();
  }, [postId, onNavigate, currentUser.id]);

  const stopStreams = () => {
    if (streamRef.current) {
      streamRef.current.getTracks().forEach(track => track.stop());
    }
    streamRef.current = null;
  };

  const startScreenShare = async () => {
    try {
      const screenStream = await (navigator.mediaDevices as any).getDisplayMedia({ video: true });
      const screenTrack = screenStream.getVideoTracks()[0];
      screenTrack.onended = () => {
        setIsScreenSharing(false);
        setIsCamOn(false);
      };
      if (streamRef.current) {
        const oldTrack = streamRef.current.getVideoTracks()[0];
        if (oldTrack) streamRef.current.removeTrack(oldTrack);
        streamRef.current.addTrack(screenTrack);
      } else {
        streamRef.current = new MediaStream([screenTrack]);
      }
      if (localVideoRef.current) localVideoRef.current.srcObject = streamRef.current;
      setIsScreenSharing(true);
      setIsCamOn(true);
      setShowScreenShareSafety(false);
    } catch (err) {
      setShowScreenShareSafety(false);
    }
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => setSelectedImage(reader.result as string);
      reader.readAsDataURL(file);
    }
  };

  const handleSendMessage = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newMessage.trim() && !selectedImage) return;

    const msg: Message = {
      id: `live-msg-${Date.now()}`,
      senderId: currentUser.id,
      receiverId: 'room',
      timestamp: Date.now(),
      text: newMessage,
      imageUrl: selectedImage || undefined
    };

    setChatMessages(prev => [...prev, msg]);
    setNewMessage('');
    setSelectedImage(null);
  };

  const prepareDonation = (amount: number) => {
    setPendingAmount(amount);
  };

  const executeDonation = () => {
    if (!pendingAmount || !creator) return;

    if ((currentUser.balance || 0) < pendingAmount) {
      setPendingAmount(null);
      return;
    }

    setIsProcessingDonation(true);

    setTimeout(() => {
      updateUserBalance(currentUser.id, -pendingAmount);
      updateUserBalance(creator.id, pendingAmount);
      refreshUser();

      const msg: Message = {
        id: `donation-msg-${Date.now()}`,
        senderId: currentUser.id,
        receiverId: 'room',
        timestamp: Date.now(),
        text: `🎁 Enviou um presente de $${pendingAmount.toFixed(2)} para o professor!`,
      };
      setChatMessages(prev => [...prev, msg]);

      setIsProcessingDonation(false);
      setPendingAmount(null);
      setShowDonationModal(false);
    }, 1200);
  };

  const toggleCamera = async () => {
    if (isCamOn) {
      if (streamRef.current) streamRef.current.getVideoTracks().forEach(track => track.stop());
      setIsCamOn(false);
      setIsScreenSharing(false);
    } else {
      try {
        const videoStream = await navigator.mediaDevices.getUserMedia({ video: true });
        const videoTrack = videoStream.getVideoTracks()[0];
        if (streamRef.current) {
          const oldTrack = streamRef.current.getVideoTracks()[0];
          if (oldTrack) streamRef.current.removeTrack(oldTrack);
          streamRef.current.addTrack(videoTrack);
        } else {
          streamRef.current = new MediaStream([videoTrack]);
        }
        if (localVideoRef.current) localVideoRef.current.srcObject = streamRef.current;
        setIsCamOn(true);
      } catch (err) {
        alert("Câmera indisponível.");
      }
    }
  };

  const toggleMic = async () => {
    if (isMicOn) {
      if (streamRef.current) streamRef.current.getAudioTracks().forEach(t => t.enabled = false);
      setIsMicOn(false);
    } else {
      try {
        const audioStream = await navigator.mediaDevices.getUserMedia({ audio: true });
        const audioTrack = audioStream.getAudioTracks()[0];
        if (streamRef.current) {
          streamRef.current.addTrack(audioTrack);
        } else {
          streamRef.current = new MediaStream([audioTrack]);
        }
        setIsMicOn(true);
      } catch (err) {
        alert("Microfone indisponível.");
      }
    }
  };

  const handleHandRaise = () => {
    const newState = !handRaised;
    setHandRaised(newState);
    if (newState) {
      setHandRaiseNotification({
        id: `hand-${Date.now()}`,
        name: `${currentUser.firstName} ${currentUser.lastName}`
      });
    } else {
      setHandRaiseNotification(null);
    }
  };

  if (!post || !post.liveStream || !creator) return null;
  const isTeacher = currentUser.id === creator.id;

  return (
    <div className="fixed inset-0 bg-[#020408] z-[60] flex flex-col overflow-hidden text-white font-sans">

      <nav className="w-full flex items-center justify-between px-4 pt-4 pb-2 z-50 flex-shrink-0">
        <button onClick={() => onNavigate('feed')} className="p-2 bg-white/10 rounded-xl">
          <XMarkIcon className="h-5 w-5" />
        </button>
        <div className="flex flex-col items-center">
           <div className="bg-red-600 px-3 py-1 rounded-lg text-[9px] font-black flex items-center gap-2 shadow-lg">
             <SignalIcon className="h-3 w-3 animate-pulse" /> AO VIVO
           </div>
           <p className="text-[9px] font-black uppercase mt-1 tracking-widest text-gray-400">{post.liveStream.title}</p>
        </div>
        <div className="flex items-center gap-4">
           {isTeacher && (
             <button onClick={() => { if(window.confirm("Encerrar aula?")) { deletePost(post.id); onNavigate('feed'); refreshUser(); } }} className="bg-white/10 p-2 rounded-xl flex items-center gap-2 hover:bg-red-600/20 transition-colors">
                <PowerIcon className="h-4 w-4 text-red-500" />
             </button>
           )}
           <div className="flex items-center gap-2 bg-white/5 px-3 py-1.5 rounded-lg">
              <UsersIcon className="h-3 w-3 text-gray-400" />
              <span className="text-[10px] font-bold">42</span>
           </div>
        </div>
      </nav>

      <main className="flex-1 flex relative items-center justify-center overflow-hidden p-2 md:p-4">
        <div className="w-full h-full max-w-5xl rounded-[2rem] overflow-hidden bg-black border-4 border-white/5 relative shadow-2xl group">
          {isCamOn ? (
            <video ref={localVideoRef} autoPlay playsInline muted className="w-full h-full object-contain" />
          ) : (
            <div className="flex flex-col items-center justify-center h-full opacity-40 bg-gradient-to-br from-gray-900 to-black">
               <div className="w-32 h-32 rounded-[3rem] bg-gray-800 flex items-center justify-center text-5xl font-black border-4 border-white/5">
                {creator.firstName[0]}
               </div>
            </div>
          )}

          <div className="absolute bottom-6 left-1/2 -translate-x-1/2 flex items-center gap-4 bg-black/60 backdrop-blur-xl p-3 rounded-3xl border border-white/10 group-hover:translate-y-0 translate-y-20 transition-all duration-500 z-40">
             <div className="flex gap-2">
                <button onClick={toggleMic} className={`p-3 rounded-xl transition-all ${isMicOn ? 'bg-blue-600 shadow-lg shadow-blue-600/30' : 'bg-white/10 hover:bg-white/20'}`}>
                   {isMicOn ? <MicrophoneIcon className="h-5 w-5" /> : <MicrophoneIconOutline className="h-5 w-5" />}
                </button>
                <button onClick={toggleCamera} className={`p-3 rounded-xl transition-all ${isCamOn ? 'bg-blue-600 shadow-lg shadow-blue-600/30' : 'bg-white/10 hover:bg-white/20'}`}>
                   <VideoCameraIcon className="h-5 w-5" />
                </button>
                <button onClick={() => setShowScreenShareSafety(true)} className={`p-3 rounded-xl transition-all ${isScreenSharing ? 'bg-blue-600 shadow-lg shadow-blue-600/30' : 'bg-white/10 hover:bg-white/20'}`}>
                   <ComputerDesktopIcon className="h-5 w-5" />
                </button>
                <button onClick={() => setShowDonationModal(true)} className="p-3 bg-yellow-500 rounded-xl hover:bg-yellow-400 transition-all shadow-lg shadow-yellow-500/30">
                   <BanknotesIcon className="h-5 w-5 text-black" />
                </button>
             </div>
          </div>

          <div className="absolute top-6 right-6 flex flex-col gap-3">
             <button onClick={() => setActiveSidebar(activeSidebar === 'chat' ? null : 'chat')} className={`p-4 rounded-2xl backdrop-blur-xl border border-white/10 transition-all shadow-2xl ${activeSidebar === 'chat' ? 'bg-blue-600' : 'bg-black/40 hover:bg-black/60'}`}>
                <ChatBubbleLeftRightIcon className="h-6 w-6" />
             </button>
             <button onClick={handleHandRaise} className={`p-4 rounded-2xl backdrop-blur-xl border border-white/10 transition-all shadow-2xl ${handRaised ? 'bg-purple-600 animate-bounce' : 'bg-black/40 hover:bg-black/60'}`}>
                <HandRaisedIcon className="h-6 w-6" />
             </button>
          </div>
        </div>
      </main>

      {/* CHAT SIDEBAR */}
      {activeSidebar === 'chat' && (
        <div className="w-full md:w-96 bg-[#0a0c10] border-l border-white/5 flex flex-col animate-slide-left fixed md:relative inset-y-0 right-0 z-[70]">
           <div className="p-6 border-b border-white/5 flex items-center justify-between">
              <h3 className="text-sm font-black uppercase tracking-widest">Chat da Aula</h3>
              <button onClick={() => setActiveSidebar(null)} className="p-2 hover:bg-white/5 rounded-lg"><XMarkIcon className="h-5 w-5" /></button>
           </div>

           <div className="flex-1 overflow-y-auto p-4 space-y-4 custom-scrollbar">
              {chatMessages.map(msg => {
                const sender = findUserById(msg.senderId);
                return (
                  <div key={msg.id} className="flex gap-3 animate-fade-in">
                     <img src={sender?.profilePicture || DEFAULT_PROFILE_PIC} className="w-8 h-8 rounded-lg shrink-0 object-cover" />
                     <div className="flex-1">
                        <p className="text-[10px] font-black text-gray-400 uppercase mb-1">{sender?.firstName || 'Aluno'}</p>
                        <div className="bg-white/5 p-3 rounded-2xl text-xs font-medium leading-relaxed border border-white/5">
                           {msg.imageUrl && <img src={msg.imageUrl} className="w-full rounded-lg mb-2" />}
                           {msg.text}
                        </div>
                     </div>
                  </div>
                );
              })}
           </div>

           <div className="p-4 bg-black/40 border-t border-white/5">
              <form onSubmit={handleSendMessage} className="space-y-3">
                 {selectedImage && (
                    <div className="relative w-16 h-16 rounded-xl overflow-hidden border-2 border-blue-500">
                       <img src={selectedImage} className="w-full h-full object-cover" />
                       <button onClick={() => setSelectedImage(null)} className="absolute top-0 right-0 bg-red-600 p-0.5"><XMarkIcon className="h-3 w-3" /></button>
                    </div>
                 )}
                 <div className="flex items-center gap-2 bg-white/5 p-2 rounded-2xl border border-white/10">
