import React, { useState, useMemo, useEffect } from 'react';
import { CartItem, Product, User, ShippingAddress, ProductType } from '../types';
import { getCart, updateCartItemQuantity, removeFromCart, processProductPurchase, updateUserBalance } from '../services/storageService';
import { XMarkIcon, PlusIcon, MinusIcon, TrashIcon, QrCodeIcon, BanknotesIcon, ShoppingBagIcon, ArrowRightIcon } from '@heroicons/react/24/outline';
import { CheckIcon, ShieldCheckIcon, BoltIcon, ExclamationTriangleIcon } from '@heroicons/react/24/solid';
import CryptomusPaymentForm from './CryptomusPaymentForm';

interface CartModalProps {
  isOpen: boolean;
  onClose: () => void;
  currentUser: User;
  onCartUpdate: () => void;
  refreshUser: () => void;
}

const CartModal: React.FC<CartModalProps> = ({ isOpen, onClose, currentUser, onCartUpdate, refreshUser }) => {
  const [cartItems, setCartItems] = useState<CartItem[]>([]);
  const [products, setProducts] = useState<Product[]>([]);
  const [view, setView] = useState<'cart' | 'shipping' | 'payment' | 'cryptomus' | 'processing' | 'success'>('cart');
  const [shippingDetails, setShippingDetails] = useState<ShippingAddress>({ address: '', city: '', state: '', zipCode: '' });
  const [selectedPayment, setSelectedPayment] = useState<'balance' | 'pix' | 'card' | 'cryptomus' | null>(null);
  const [formError, setFormError] = useState('');

  useEffect(() => {
    if (isOpen) {
      const cart = getCart();
      const allProducts = JSON.parse(localStorage.getItem('cyber_products') || '[]') as Product[];
      setCartItems(cart);
      setProducts(allProducts);
      setView('cart');
      setFormError('');
      setSelectedPayment(null);
    }
  }, [isOpen]);

  const syncCart = () => {
    setCartItems(getCart());
    onCartUpdate();
  };

  const detailedCartItems = useMemo(() => {
    return cartItems.map(item => {
      const product = products.find(p => p.id === item.productId);
      return product ? { ...item, product } : null;
    }).filter((item): item is (CartItem & { product: Product }) => item !== null);
  }, [cartItems, products]);

  const subtotal = useMemo(() => detailedCartItems.reduce((sum, item) => sum + item.product.price * item.quantity, 0), [detailedCartItems]);

  const hasInsufficientBalance = (currentUser.balance || 0) < subtotal;

  const handleConfirmPurchase = () => {
    if (selectedPayment === 'balance' && hasInsufficientBalance) {
      setFormError('Saldo insuficiente na sua carteira CyBer.');
      return;
    }

    if (selectedPayment === 'cryptomus') {
        setView('cryptomus');
        return;
    }

    executeFinalPurchase();
  };

  const executeFinalPurchase = () => {
    setView('processing');
    setTimeout(() => {
      // Se for saldo, desconta primeiro
      if (selectedPayment === 'balance') {
         updateUserBalance(currentUser.id, -subtotal);
      }

      const success = processProductPurchase(cartItems, currentUser.id, null, shippingDetails);
      if (success) {
        refreshUser();
        onCartUpdate();
        setView('success');
      } else {
        setFormError('Erro ao processar compra.');
        setView('payment');
      }
    }, 2500);
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 bg-black/60 backdrop-blur-sm z-[100] flex justify-end overflow-hidden" onClick={onClose}>
      <div 
        className="bg-white dark:bg-darkcard w-full max-w-md h-full shadow-2xl flex flex-col animate-slide-left relative" 
        onClick={e => e.stopPropagation()}
      >
        <div className="p-6 border-b border-gray-100 dark:border-white/10 flex justify-between items-center bg-white dark:bg-darkcard sticky top-0 z-10">
          <div className="flex items-center gap-3">
             <div className="bg-blue-600 p-2.5 rounded-2xl shadow-lg shadow-blue-100 dark:shadow-none">
                <ShoppingBagIcon className="h-6 w-6 text-white" />
             </div>
             <div>
                <h2 className="text-xl font-black text-gray-900 dark:text-white tracking-tighter">Minha Sacola</h2>
                <p className="text-[10px] text-gray-400 font-bold uppercase tracking-widest">{detailedCartItems.length} Itens</p>
             </div>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-gray-100 dark:hover:bg-white/5 rounded-full transition-colors group">
            <XMarkIcon className="h-6 w-6 text-gray-400 group-hover:text-gray-900 dark:group-hover:text-white" />
          </button>
        </div>

        <div className="flex-1 overflow-y-auto p-6 space-y-4 custom-scrollbar">
          {view === 'cart' && (
            <div className="space-y-4">
              {detailedCartItems.length === 0 ? (
                <div className="text-center py-24">
                  <ShoppingBagIcon className="h-12 w-12 text-gray-200 mx-auto mb-4" />
                  <p className="text-gray-400 font-black uppercase text-xs">Vazio</p>
                </div>
              ) : (
                detailedCartItems.map(item => (
                  <div key={item.productId} className="flex gap-4 p-4 bg-gray-50 dark:bg-white/5 rounded-[2rem] border border-transparent">
                    <img src={item.product.imageUrls[0]} className="w-16 h-16 rounded-xl object-cover" />
                    <div className="flex-1 min-w-0">
                       <p className="font-black text-sm text-gray-900 dark:text-white truncate">{item.product.name}</p>
                       <p className="text-blue-600 font-black text-base">${item.product.price.toFixed(2)}</p>
                       <div className="flex items-center justify-between mt-2">
                          <div className="flex items-center bg-white dark:bg-white/10 rounded-lg p-1">
                             <button onClick={() => { updateCartItemQuantity(item.productId, item.quantity - 1); syncCart(); }} className="p-1"><MinusIcon className="h-3 w-3"/></button>
                             <span className="w-6 text-center font-bold text-xs">{item.quantity}</span>
                             <button onClick={() => { updateCartItemQuantity(item.productId, item.quantity + 1); syncCart(); }} className="p-1"><PlusIcon className="h-3 w-3"/></button>
                          </div>
                          <button onClick={() => { removeFromCart(item.productId); syncCart(); }}><TrashIcon className="h-4 w-4 text-gray-300 hover:text-red-500"/></button>
                       </div>
                    </div>
                  </div>
                ))
              )}
            </div>
          )}

          {view === 'shipping' && (
            <div className="space-y-6">
              <h3 className="font-black text-xl text-gray-900 dark:text-white">Entrega</h3>
              <input type="text" placeholder="Endereço" value={shippingDetails.address} onChange={e => setShippingDetails({...shippingDetails, address: e.target.value})} className="w-full p-4 bg-gray-50 dark:bg-white/5 rounded-2xl outline-none" />
              <div className="grid grid-cols-2 gap-4">
                 <input type="text" placeholder="Cidade" value={shippingDetails.city} onChange={e => setShippingDetails({...shippingDetails, city: e.target.value})} className="p-4 bg-gray-50 dark:bg-white/5 rounded-2xl outline-none" />
                 <input type="text" placeholder="CEP" value={shippingDetails.zipCode} onChange={e => setShippingDetails({...shippingDetails, zipCode: e.target.value})} className="p-4 bg-gray-50 dark:bg-white/5 rounded-2xl outline-none" />
              </div>
            </div>
          )}

          {view === 'payment' && (
            <div className="space-y-6">
              <h3 className="font-black text-xl text-gray-900 dark:text-white">Pagamento</h3>
              <div className="space-y-3">
                {/* Carteira Interna */}
                <button 
                  onClick={() => setSelectedPayment('balance')} 
                  className={`w-full flex items-center justify-between p-5 border-2 rounded-3xl transition-all relative overflow-hidden ${selectedPayment === 'balance' ? 'border-blue-600 bg-blue-50 dark:bg-blue-600/10' : 'border-gray-50 dark:border-white/5'}`}
                >
                  <div className="flex items-center gap-4">
                     <div className="p-3 bg-blue-600 text-white rounded-xl"><BanknotesIcon className="h-6 w-6" /></div>
                     <div className="text-left">
                        <p className="font-black text-gray-900 dark:text-white text-sm">Saldo CyBer</p>
                        <p className={`text-[10px] font-black ${hasInsufficientBalance ? 'text-red-500' : 'text-gray-400'}`}>
                          Saldo: ${(currentUser.balance || 0).toFixed(2)} {hasInsufficientBalance && '(Insuficiente)'}
                        </p>
                     </div>
                  </div>
                  {selectedPayment === 'balance' && <CheckIcon className="h-5 w-5 text-blue-600" />}
                  {hasInsufficientBalance && (
                    <div className="absolute top-2 right-2">
                       <ExclamationTriangleIcon className="h-4 w-4 text-red-500" />
                    </div>
                  )}
                </button>

                {/* Cryptomus */}
                <button onClick={() => setSelectedPayment('cryptomus')} className={`w-full flex items-center justify-between p-5 border-2 rounded-3xl transition-all ${selectedPayment === 'cryptomus' ? 'border-purple-600 bg-purple-50 dark:bg-purple-600/10' : 'border-gray-50 dark:border-white/5'}`}>
                  <div className="flex items-center gap-4">
                     <div className="p-3 bg-purple-600 text-white rounded-xl"><BoltIcon className="h-6 w-6" /></div>
                     <div className="text-left"><p className="font-black text-gray-900 dark:text-white text-sm">Criptomoedas</p><p className="text-[10px] text-gray-400 font-black">Gate Cryptomus</p></div>
                  </div>
                  {selectedPayment === 'cryptomus' && <CheckIcon className="h-5 w-5 text-purple-600" />}
                </button>
              </div>

              {hasInsufficientBalance && selectedPayment === 'balance' && (
                <div className="p-4 bg-red-50 dark:bg-red-900/10 border border-red-100 rounded-2xl flex flex-col items-center text-center gap-3">
                   <p className="text-xs text-red-600 font-bold uppercase tracking-widest">Saldo insuficiente para completar este pedido.</p>
                   <button onClick={() => setView('cryptomus')} className="text-[10px] font-black text-white bg-blue-600 px-4 py-2 rounded-lg uppercase">Recarregar agora</button>
                </div>
              )}
              {formError && <p className="text-red-500 text-center text-xs font-bold">{formError}</p>}
            </div>
          )}

          {view === 'cryptomus' && (
            <CryptomusPaymentForm amount={subtotal} onConfirm={executeFinalPurchase} onCancel={() => setView('payment')} />
          )}

          {view === 'processing' && (
            <div className="flex flex-col items-center justify-center h-full gap-4">
              <div className="w-12 h-12 border-4 border-blue-600 border-t-transparent rounded-full animate-spin"></div>
              <h3 className="text-xl font-black">Validando Saldo...</h3>
            </div>
          )}

          {view === 'success' && (
            <div className="flex flex-col items-center justify-center h-full text-center gap-6">
              <CheckIcon className="h-16 w-16 text-green-500" />
              <h3 className="text-2xl font-black">Compra Efetuada!</h3>
              <button onClick={onClose} className="w-full bg-blue-600 text-white py-4 rounded-2xl font-black">Concluir</button>
            </div>
          )}
        </div>

        {view !== 'success' && view !== 'processing' && view !== 'cryptomus' && detailedCartItems.length > 0 && (
          <div className="p-8 border-t border-gray-100 dark:border-white/10">
            <div className="flex justify-between items-end mb-6">
               <span className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Total do Pedido</span>
               <span className="text-3xl font-black text-gray-900 dark:text-white tracking-tighter">${subtotal.toFixed(2)}</span>
            </div>

            {view === 'cart' && (
              <button onClick={() => setView(detailedCartItems.some(i => i.product.type === ProductType.PHYSICAL) ? 'shipping' : 'payment')} className="w-full bg-blue-600 text-white py-5 rounded-[2rem] font-black flex items-center justify-center gap-3">Prosseguir <ArrowRightIcon className="h-5 w-5"/></button>
            )}

            {view === 'shipping' && (
              <button onClick={() => setView('payment')} className="w-full bg-blue-600 text-white py-5 rounded-[2rem] font-black flex items-center justify-center gap-3">Confirmar Endereço</button>
            )}

            {view === 'payment' && (
              <button 
                onClick={handleConfirmPurchase} 
                disabled={!selectedPayment || (selectedPayment === 'balance' && hasInsufficientBalance)} 
                className={`w-full py-5 rounded-[2rem] font-black text-white shadow-xl transition-all ${selectedPayment === 'balance' && hasInsufficientBalance ? 'bg-gray-400' : 'bg-black dark:bg-white dark:text-black'}`}
              >
                {selectedPayment === 'balance' && hasInsufficientBalance ? 'Saldo Insuficiente' : 'Pagar Agora'}
              </button>
            )}
          </div>
        )}
      </div>
    </div>
  );
};

