import React, { useState, useEffect, useMemo, useRef } from 'react';
import { AdCampaign, User, AdLocation } from '../types';
import { saveAds, getAds, updateUserBalance } from '../services/storageService';
import { generateAdCopy } from '../services/geminiService';
import { MIN_DAILY_AD_BUDGET_USD, DEFAULT_PROFILE_PIC } from '../constants';
import { 
  RocketLaunchIcon, 
  MegaphoneIcon, 
  EyeIcon, 
  CursorArrowRaysIcon, 
  PhotoIcon, 
  CurrencyDollarIcon,
  ChevronRightIcon,
  DevicePhoneMobileIcon,
  ComputerDesktopIcon,
  SparklesIcon,
  CheckCircleIcon,
  MapPinIcon,
  GlobeAltIcon,
  XMarkIcon,
  PlusIcon,
  InformationCircleIcon,
  UserGroupIcon,
  CalendarIcon,
  UsersIcon,
  ArrowUpTrayIcon,
  TrashIcon,
  ExclamationTriangleIcon
} from '@heroicons/react/24/solid';

interface AdCampaignPageProps {
  currentUser: User;
  refreshUser: () => void;
  onNavigate?: (page: string) => void;
}

const AdCampaignPage: React.FC<AdCampaignPageProps> = ({ currentUser, refreshUser }) => {
  const [loading, setLoading] = useState(false);
  const [geminiLoading, setGeminiLoading] = useState(false);

  const [campaignName, setCampaignName] = useState('');
  const [objective, setObjective] = useState<'traffic' | 'awareness' | 'engagement'>('traffic');
  const [title, setTitle] = useState('');
  const [description, setDescription] = useState('');
  const [imageUrl, setImageUrl] = useState('');
  const [linkUrl, setLinkUrl] = useState('');
  const [ctaText, setCtaText] = useState('Saiba Mais');
  const [targetAudience, setTargetAudience] = useState('');
  const [placements, setPlacements] = useState<string[]>(['feed']);

  const [durationDays, setDurationDays] = useState<number>(7);
  const [dailyReachGoal, setDailyReachGoal] = useState<number>(5000);

  const [targetedLocations, setTargetedLocations] = useState<AdLocation[]>([]);
  const [locCountry, setLocCountry] = useState('');
  const [locProvince, setLocProvince] = useState('');
  const [locCity, setLocCity] = useState('');

  const [myAds, setMyAds] = useState<AdCampaign[]>([]);
  const [previewPlacement, setPreviewPlacement] = useState<'feed' | 'sidebar'>('feed');
  const fileInputRef = useRef<HTMLInputElement>(null);

  const COST_PER_1K_REACH = 0.50; 

  const calculatedTotalBudget = useMemo(() => {
    const costPerDay = (dailyReachGoal / 1000) * COST_PER_1K_REACH;
    const totalByReach = costPerDay * durationDays;
    const minTotalByDays = durationDays * MIN_DAILY_AD_BUDGET_USD;
    return Math.max(totalByReach, minTotalByDays);
  }, [dailyReachGoal, durationDays]);

  const hasInsufficientBalance = (currentUser.balance || 0) < calculatedTotalBudget;

  useEffect(() => {
    setMyAds(getAds().filter(ad => ad.professorId === currentUser.id));
  }, [currentUser.id]);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => setImageUrl(reader.result as string);
      reader.readAsDataURL(file);
    }
  };

  const handlePublish = () => {
    if (hasInsufficientBalance) return;
    if (!title || !description || targetedLocations.length === 0 || placements.length === 0 || !imageUrl) {
      alert("Preencha todos os campos obrigatórios.");
      return;
    }

    setLoading(true);
    setTimeout(() => {
      const newAd: AdCampaign = {
        id: `ad-${Date.now()}`,
        professorId: currentUser.id,
        title,
        description,
        targetAudience,
        locations: targetedLocations,
        budget: calculatedTotalBudget,
        isActive: true,
        imageUrl,
        linkUrl: linkUrl || '#',
        ctaText,
        placements,
        timestamp: Date.now()
      };

      updateUserBalance(currentUser.id, -calculatedTotalBudget);
      const all = getAds();
      saveAds([...all, newAd]);
      setMyAds([newAd, ...myAds]);

      alert(`Anúncio no ar!`);
      resetForm();
      setLoading(false);
      refreshUser();
    }, 2000);
  };

  const resetForm = () => {
    setCampaignName(''); setTitle(''); setDescription(''); setImageUrl('');
    setLinkUrl(''); setTargetAudience(''); setPlacements(['feed']); setTargetedLocations([]);
  };

  return (
