        <div className="flex flex-col md:flex-row md:items-center justify-between mb-8 gap-4 bg-white dark:bg-darkcard p-6 rounded-3xl shadow-sm border dark:border-white/5">
           <div>
              <h1 className="text-2xl font-black text-gray-900 dark:text-white tracking-tighter flex items-center gap-2">
                <RocketLaunchIcon className="h-8 w-8 text-blue-600" /> Gerenciador de Anúncios
              </h1>
