                 <p className={`text-lg font-black ${hasInsufficientBalance ? 'text-red-500' : 'text-blue-600'}`}>${(currentUser.balance || 0).toFixed(2)}</p>
              </div>
           </div>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
          <main className="lg:col-span-8 space-y-6">
             {/* Creative Form (Simplified for Brevity) */}
             <div className="bg-white dark:bg-darkcard rounded-[2rem] p-8 shadow-xl border dark:border-white/5">
                <div className="space-y-6">
                   <input type="text" placeholder="Título do Anúncio" value={title} onChange={e => setTitle(e.target.value)} className="w-full p-4 bg-gray-50 dark:bg-darkbg rounded-xl dark:text-white" />
                   <textarea placeholder="Texto do anúncio" value={description} onChange={e => setDescription(e.target.value)} className="w-full p-4 bg-gray-50 dark:bg-darkbg rounded-xl dark:text-white h-24" />
