                   <div className="bg-gray-50 dark:bg-darkbg p-8 rounded-3xl border dark:border-white/5 text-center">
                      <p className="text-[11px] font-black text-gray-400 uppercase mb-4">Investimento Total</p>
                      <p className="text-6xl font-black text-gray-900 dark:text-white tracking-tighter">${calculatedTotalBudget.toFixed(2)}</p>
                   </div>

                   {hasInsufficientBalance ? (
                     <div className="bg-red-50 dark:bg-red-900/10 p-6 rounded-[2rem] border border-red-100 dark:border-red-500/20 flex flex-col items-center gap-3">
                        <ExclamationTriangleIcon className="h-10 w-10 text-red-500" />
                        <p className="text-sm text-red-600 font-black uppercase tracking-widest">Saldo Insuficiente</p>
                        <p className="text-xs text-gray-500 text-center font-medium">Você precisa de mais ${(calculatedTotalBudget - (currentUser.balance || 0)).toFixed(2)} para esta campanha.</p>
