import React, { useState, useEffect } from 'react';
import { User, UserType, Store, Product, ProductType } from '../types';
import { 
  getStores, 
  updateUser, 
  getProducts, 
  updateUserBalance
} from '../services/storageService';
import { CREATOR_UPGRADE_FOLLOWERS_GOAL, CREATOR_UPGRADE_COST_USD } from '../constants';
import { 
  PlusIcon, 
  ArchiveBoxIcon,
  TrashIcon,
  UsersIcon,
  SparklesIcon,
  CheckBadgeIcon,
  BoltIcon,
  XMarkIcon,
  ExclamationTriangleIcon
} from '@heroicons/react/24/solid';
import CryptomusPaymentForm from './CryptomusPaymentForm';

interface StoreManagerPageProps {
  currentUser: User;
  refreshUser: () => void;
  onNavigate: (page: any, params?: any) => void;
}

const StoreManagerPage: React.FC<StoreManagerPageProps> = ({ currentUser, refreshUser, onNavigate }) => {
  const [userStore, setUserStore] = useState<Store | null>(null);
  const [storeProducts, setStoreProducts] = useState<Product[]>([]);
  const [loading, setLoading] = useState(false);
  const [showCryptoUpgrade, setShowCryptoUpgrade] = useState(false);

  useEffect(() => {
    const stores = getStores();
    const myStore = stores.find(s => s.professorId === currentUser.id);
    if (myStore) {
      setUserStore(myStore);
      setStoreProducts(getProducts().filter(p => p.storeId === myStore.id));
    }
  }, [currentUser.id]);

  const followerCount = currentUser.followers?.length || 0;
  const followerProgress = Math.min((followerCount / CREATOR_UPGRADE_FOLLOWERS_GOAL) * 100, 100);
  const canUnlockOrgannically = followerCount >= CREATOR_UPGRADE_FOLLOWERS_GOAL;
  const hasInsufficientBalanceForUpgrade = (currentUser.balance || 0) < CREATOR_UPGRADE_COST_USD;

  const handleUpgrade = (isPaid: boolean) => {
    if (isPaid && hasInsufficientBalanceForUpgrade) return;
    executeUpgrade(isPaid);
  };

  const executeUpgrade = (isPaid: boolean) => {
    setLoading(true);
    setTimeout(() => {
      if (isPaid) updateUserBalance(currentUser.id, -CREATOR_UPGRADE_COST_USD);
      updateUser({ ...currentUser, userType: UserType.CREATOR });
      refreshUser();
      setLoading(false);
      setShowCryptoUpgrade(false);
      alert('Selo Profissional Ativado!');
    }, 1500);
  };

  if (currentUser.userType === UserType.STANDARD) {
    return (
      <div className="container mx-auto px-4 pt-20 pb-20 max-w-4xl animate-fade-in text-center">
        <h2 className="text-4xl md:text-6xl font-black mb-12 tracking-tighter dark:text-white">Torne-se <span className="text-blue-600">Profissional.</span></h2>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
            <div className="bg-white dark:bg-darkcard p-10 rounded-[3rem] text-left border dark:border-white/5 shadow-sm">
                <UsersIcon className="h-10 w-10 text-blue-600 mb-6" />
                <h4 className="text-2xl font-black mb-2 dark:text-white uppercase">Pelo Talento</h4>
                <p className="text-gray-500 text-sm mb-8">Atinja 2.000 seguidores para ganhar o selo gratuitamente.</p>
                <div className="w-full h-3 bg-gray-100 dark:bg-white/10 rounded-full mb-8">
                  <div className="h-full bg-blue-600 rounded-full" style={{ width: `${followerProgress}%` }}></div>
                </div>
                <button onClick={() => handleUpgrade(false)} disabled={!canUnlockOrgannically} className="w-full py-5 bg-blue-600 text-white rounded-2xl font-black disabled:opacity-30">RESGATAR SELO</button>
            </div>

            <div className="bg-gray-900 p-10 rounded-[3rem] text-left text-white shadow-2xl relative overflow-hidden flex flex-col group">
                <SparklesIcon className="h-10 w-10 text-yellow-400 mb-6" />
                <h4 className="text-2xl font-black mb-2 uppercase">Modo Pago</h4>
                <p className="text-gray-400 text-sm mb-6">Libere ferramentas de venda hoje mesmo por:</p>
                <p className="text-5xl font-black mb-8 tracking-tighter">${CREATOR_UPGRADE_COST_USD.toFixed(2)}</p>

                <div className="space-y-3 mt-auto">
                  {hasInsufficientBalanceForUpgrade ? (
                    <div className="flex flex-col gap-2">
                       <div className="flex items-center gap-2 bg-red-500/20 p-3 rounded-xl border border-red-500/30">
                          <ExclamationTriangleIcon className="h-4 w-4 text-red-500" />
                          <span className="text-[9px] font-black uppercase">Saldo Insuficiente na Carteira</span>
                       </div>
                       <button 
                        onClick={() => setShowCryptoUpgrade(true)}
                        className="w-full py-5 bg-blue-600 text-white rounded-2xl font-black text-xs uppercase"
                       >
                         Recarregar e Comprar
                       </button>
                    </div>
                  ) : (
                    <button onClick={() => handleUpgrade(true)} className="w-full py-5 bg-white text-black rounded-2xl font-black text-xs uppercase tracking-widest">
                      Pagar com Saldo CyBer
                    </button>
                  )}
                </div>
            </div>
        </div>

        {showCryptoUpgrade && (
          <div className="fixed inset-0 z-[500] bg-black/90 backdrop-blur-lg flex items-center justify-center p-4">
             <div className="bg-white dark:bg-darkcard w-full max-w-md rounded-[3rem] p-10 relative">
                <button onClick={() => setShowCryptoUpgrade(false)} className="absolute top-8 right-8 text-gray-400"><XMarkIcon className="h-6 w-6" /></button>
                <CryptomusPaymentForm amount={CREATOR_UPGRADE_COST_USD} onConfirm={() => executeUpgrade(false)} onCancel={() => setShowCryptoUpgrade(false)} />
             </div>
          </div>
        )}
      </div>
    );
  }

  return (
    <div className="container mx-auto px-4 pt-24 pb-24">
       <div className="flex flex-col items-center mb-12">
          <CheckBadgeIcon className="h-12 w-12 text-blue-600 mb-4" />
          <h2 className="text-4xl font-black dark:text-white">Painel do Profissional</h2>
       </div>
       <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
          {/* Lógica de gerenciamento de produtos já presente... */}
       </div>
    </div>
  );
};

export default StoreManagerPage;

import React, { useState, useEffect, useRef } from 'react';
import { Post, User, Message } from '../types';
import { getPosts, findUserById, updateUserBalance, deletePost } from '../services/storageService';
import { 
  MicrophoneIcon, 
  VideoCameraIcon, 
  ChatBubbleLeftRightIcon, 
  XMarkIcon,
  HandRaisedIcon,
  SignalIcon,
  UsersIcon,
  ComputerDesktopIcon,
  PhotoIcon,
  PaperAirplaneIcon,
  ShieldCheckIcon,
  ShieldExclamationIcon,
  PowerIcon,
  BanknotesIcon,
  HeartIcon,
  CheckCircleIcon,
  ExclamationCircleIcon,
  ExclamationTriangleIcon,
  SparklesIcon
} from '@heroicons/react/24/solid';
import { 
  MicrophoneIcon as MicrophoneIconOutline, 
  PhotoIcon as PhotoIconOutline,
  WalletIcon
} from '@heroicons/react/24/outline';
import { DEFAULT_PROFILE_PIC } from '../constants';

interface LiveStreamViewerProps {
  currentUser: User;
  postId: string;
  onNavigate: (page: string, params?: Record<string, string>) => void;
  refreshUser: () => void;
}

const LiveStreamViewer: React.FC<LiveStreamViewerProps> = ({ currentUser, postId, onNavigate, refreshUser }) => {
  const [post, setPost] = useState<Post | null>(null);
  const [creator, setCreator] = useState<User | null>(null);
  const [isMicOn, setIsMicOn] = useState(false);
  const [isCamOn, setIsCamOn] = useState(false);
  const [isScreenSharing, setIsScreenSharing] = useState(false);
  const [showScreenShareSafety, setShowScreenShareSafety] = useState(false);

  const [showDonationModal, setShowDonationModal] = useState(false);
  const [pendingAmount, setPendingAmount] = useState<number | null>(null);
  const [isProcessingDonation, setIsProcessingDonation] = useState(false);
  const [donationAlert, setDonationAlert] = useState<{name: string, amount: number} | null>(null);

  const [activeSidebar, setActiveSidebar] = useState<'chat' | null>(null);
  const [handRaised, setHandRaised] = useState(false);
  const [handRaiseNotification, setHandRaiseNotification] = useState<{id: string, name: string} | null>(null);

  const [chatMessages, setChatMessages] = useState<Message[]>([]);
  const [newMessage, setNewMessage] = useState('');
  const [selectedImage, setSelectedImage] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const localVideoRef = useRef<HTMLVideoElement>(null);
  const streamRef = useRef<MediaStream | null>(null);

  useEffect(() => {
    const foundPost = getPosts().find(p => p.id === postId);
    if (foundPost && foundPost.liveStream) {
      setPost(foundPost);
      const author = findUserById(foundPost.userId);
      setCreator(author || null);
    } else {
      onNavigate('feed');
    }
    return () => stopStreams();
  }, [postId, onNavigate, currentUser.id]);

  const stopStreams = () => {
    if (streamRef.current) {
      streamRef.current.getTracks().forEach(track => track.stop());
    }
    streamRef.current = null;
  };

  const startScreenShare = async () => {
    try {
      const screenStream = await (navigator.mediaDevices as any).getDisplayMedia({ video: true });
      const screenTrack = screenStream.getVideoTracks()[0];
      screenTrack.onended = () => {
        setIsScreenSharing(false);
        setIsCamOn(false);
      };
      if (streamRef.current) {
        const oldTrack = streamRef.current.getVideoTracks()[0];
        if (oldTrack) streamRef.current.removeTrack(oldTrack);
        streamRef.current.addTrack(screenTrack);
      } else {
        streamRef.current = new MediaStream([screenTrack]);
      }
      if (localVideoRef.current) localVideoRef.current.srcObject = streamRef.current;
      setIsScreenSharing(true);
      setIsCamOn(true);
      setShowScreenShareSafety(false);
    } catch (err) {
      setShowScreenShareSafety(false);
    }
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => setSelectedImage(reader.result as string);
      reader.readAsDataURL(file);
    }
  };

  const handleSendMessage = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newMessage.trim() && !selectedImage) return;

    const msg: Message = {
      id: `live-msg-${Date.now()}`,
      senderId: currentUser.id,
      receiverId: 'room',
      timestamp: Date.now(),
      text: newMessage,
      imageUrl: selectedImage || undefined
    };

    setChatMessages(prev => [...prev, msg]);
    setNewMessage('');
    setSelectedImage(null);
  };

  const prepareDonation = (amount: number) => {
    setPendingAmount(amount);
  };

  const executeDonation = () => {
    if (!pendingAmount || !creator) return;

    if ((currentUser.balance || 0) < pendingAmount) {
      setPendingAmount(null);
      return;
    }

    setIsProcessingDonation(true);

    setTimeout(() => {
      const donatedValue = pendingAmount;
      updateUserBalance(currentUser.id, -donatedValue);
      updateUserBalance(creator.id, donatedValue);
      refreshUser();

      // Alerta Visual On-Screen
      setDonationAlert({ name: currentUser.firstName, amount: donatedValue });
      setTimeout(() => setDonationAlert(null), 5000); // Remove o alerta após 5 segundos

      const msg: Message = {
        id: `donation-msg-${Date.now()}`,
        senderId: currentUser.id,
        receiverId: 'room',
        timestamp: Date.now(),
        text: `🎁 Enviou um presente de $${donatedValue.toFixed(2)} para o professor!`,
      };
      setChatMessages(prev => [...prev, msg]);

      setIsProcessingDonation(false);
      setPendingAmount(null);
      setShowDonationModal(false);
    }, 1200);
  };

  const toggleCamera = async () => {
    if (isCamOn) {
      if (streamRef.current) streamRef.current.getVideoTracks().forEach(track => track.stop());
      setIsCamOn(false);
      setIsScreenSharing(false);
    } else {
      try {
        const videoStream = await navigator.mediaDevices.getUserMedia({ video: true });
        const videoTrack = videoStream.getVideoTracks()[0];
        if (streamRef.current) {
          const oldTrack = streamRef.current.getVideoTracks()[0];
          if (oldTrack) streamRef.current.removeTrack(oldTrack);
          streamRef.current.addTrack(videoTrack);
        } else {
          streamRef.current = new MediaStream([videoTrack]);
        }
        if (localVideoRef.current) localVideoRef.current.srcObject = streamRef.current;
        setIsCamOn(true);
      } catch (err) {
        alert("Câmera indisponível.");
      }
    }
  };

  const toggleMic = async () => {
    if (isMicOn) {
      if (streamRef.current) streamRef.current.getAudioTracks().forEach(t => t.enabled = false);
      setIsMicOn(false);
    } else {
      try {
        const audioStream = await navigator.mediaDevices.getUserMedia({ audio: true });
        const audioTrack = audioStream.getAudioTracks()[0];
        if (streamRef.current) {
          streamRef.current.addTrack(audioTrack);
        } else {
          streamRef.current = new MediaStream([audioTrack]);
        }
        setIsMicOn(true);
      } catch (err) {
        alert("Microfone indisponível.");
      }
    }
  };

  const handleHandRaise = () => {
    const newState = !handRaised;
    setHandRaised(newState);
    if (newState) {
      setHandRaiseNotification({
        id: `hand-${Date.now()}`,
        name: `${currentUser.firstName} ${currentUser.lastName}`
      });
    } else {
      setHandRaiseNotification(null);
    }
  };

  if (!post || !post.liveStream || !creator) return null;
  const isTeacher = currentUser.id === creator.id;

  return (
    <div className="fixed inset-0 bg-[#020408] z-[60] flex flex-col overflow-hidden text-white font-sans">

      <nav className="w-full flex items-center justify-between px-4 pt-4 pb-2 z-50 flex-shrink-0">
        <button onClick={() => onNavigate('feed')} className="p-2 bg-white/10 rounded-xl">
          <XMarkIcon className="h-5 w-5" />
        </button>
        <div className="flex flex-col items-center">
           <div className="bg-red-600 px-3 py-1 rounded-lg text-[9px] font-black flex items-center gap-2 shadow-lg">
             <SignalIcon className="h-3 w-3 animate-pulse" /> AO VIVO
           </div>
           <p className="text-[9px] font-black uppercase mt-1 tracking-widest text-gray-400">{post.liveStream.title}</p>
        </div>
        <div className="flex items-center gap-4">
           {isTeacher && (
             <button onClick={() => { if(window.confirm("Encerrar aula?")) { deletePost(post.id); onNavigate('feed'); refreshUser(); } }} className="bg-white/10 p-2 rounded-xl flex items-center gap-2 hover:bg-red-600/20 transition-colors">
                <PowerIcon className="h-4 w-4 text-red-500" />
             </button>
           )}
           <div className="flex items-center gap-2 bg-white/5 px-3 py-1.5 rounded-lg">
              <UsersIcon className="h-3 w-3 text-gray-400" />
              <span className="text-[10px] font-bold">42</span>
           </div>
        </div>
      </nav>

      <main className="flex-1 flex relative items-center justify-center overflow-hidden p-2 md:p-4">
        <div className="w-full h-full max-w-5xl rounded-[2rem] overflow-hidden bg-black border-4 border-white/5 relative shadow-2xl group">
          {isCamOn ? (
            <video ref={localVideoRef} autoPlay playsInline muted className="w-full h-full object-contain" />
          ) : (
            <div className="flex flex-col items-center justify-center h-full opacity-40 bg-gradient-to-br from-gray-900 to-black">
               <div className="w-32 h-32 rounded-[3rem] bg-gray-800 flex items-center justify-center text-5xl font-black border-4 border-white/5">
                {creator.firstName[0]}
               </div>
            </div>
          )}

          {/* ALERTA DE DOAÇÃO EM DESTAQUE (SHOUTOUT) */}
          {donationAlert && (
            <div className="absolute top-10 left-1/2 -translate-x-1/2 z-[100] animate-shoutout">
               <div className="bg-gradient-to-r from-yellow-400 to-yellow-600 p-[2px] rounded-full shadow-[0_0_30px_rgba(234,179,8,0.4)]">
                  <div className="bg-black/90 backdrop-blur-xl px-8 py-3 rounded-full flex items-center gap-4">
                     <div className="bg-yellow-500 p-2 rounded-full shadow-lg">
                        <SparklesIcon className="h-5 w-5 text-black" />
                     </div>
                     <div className="text-left">
                        <p className="text-[10px] font-black text-yellow-500 uppercase tracking-[0.2em] leading-none mb-1">Novo Presente!</p>
                        <p className="text-sm font-black text-white whitespace-nowrap">
                           <span className="text-yellow-400">{donationAlert.name}</span> doou <span className="text-green-400">${donationAlert.amount.toFixed(2)}</span>
                        </p>
                     </div>
                     <div className="bg-white/10 p-2 rounded-full">
                        <BanknotesIcon className="h-5 w-5 text-yellow-500" />
                     </div>
                  </div>
               </div>
            </div>
          )}

          <div className="absolute bottom-6 left-1/2 -translate-x-1/2 flex items-center gap-4 bg-black/60 backdrop-blur-xl p-3 rounded-3xl border border-white/10 group-hover:translate-y-0 translate-y-20 transition-all duration-500 z-40">
             <div className="flex gap-2">
                <button onClick={toggleMic} className={`p-3 rounded-xl transition-all ${isMicOn ? 'bg-blue-600 shadow-lg shadow-blue-600/30' : 'bg-white/10 hover:bg-white/20'}`}>
                   {isMicOn ? <MicrophoneIcon className="h-5 w-5" /> : <MicrophoneIconOutline className="h-5 w-5" />}
                </button>
                <button onClick={toggleCamera} className={`p-3 rounded-xl transition-all ${isCamOn ? 'bg-blue-600 shadow-lg shadow-blue-600/30' : 'bg-white/10 hover:bg-white/20'}`}>
                   <VideoCameraIcon className="h-5 w-5" />
                </button>
                <button onClick={() => setShowScreenShareSafety(true)} className={`p-3 rounded-xl transition-all ${isScreenSharing ? 'bg-blue-600 shadow-lg shadow-blue-600/30' : 'bg-white/10 hover:bg-white/20'}`}>
                   <ComputerDesktopIcon className="h-5 w-5" />
                </button>
                <button onClick={() => setShowDonationModal(true)} className="p-3 bg-yellow-500 rounded-xl hover:bg-yellow-400 transition-all shadow-lg shadow-yellow-500/30">
                   <BanknotesIcon className="h-5 w-5 text-black" />
                </button>
             </div>
          </div>

          <div className="absolute top-6 right-6 flex flex-col gap-3">
             <button onClick={() => setActiveSidebar(activeSidebar === 'chat' ? null : 'chat')} className={`p-4 rounded-2xl backdrop-blur-xl border border-white/10 transition-all shadow-2xl ${activeSidebar === 'chat' ? 'bg-blue-600' : 'bg-black/40 hover:bg-black/60'}`}>
                <ChatBubbleLeftRightIcon className="h-6 w-6" />
             </button>
             <button onClick={handleHandRaise} className={`p-4 rounded-2xl backdrop-blur-xl border border-white/10 transition-all shadow-2xl ${handRaised ? 'bg-purple-600 animate-bounce' : 'bg-black/40 hover:bg-black/60'}`}>
                <HandRaisedIcon className="h-6 w-6" />
             </button>
          </div>
        </div>
      </main>

      {/* CHAT SIDEBAR */}
      {activeSidebar === 'chat' && (
        <div className="w-full md:w-96 bg-[#0a0c10] border-l border-white/5 flex flex-col animate-slide-left fixed md:relative inset-y-0 right-0 z-[70]">
           <div className="p-6 border-b border-white/5 flex items-center justify-between">
              <h3 className="text-sm font-black uppercase tracking-widest">Chat da Aula</h3>
              <button onClick={() => setActiveSidebar(null)} className="p-2 hover:bg-white/5 rounded-lg"><XMarkIcon className="h-5 w-5" /></button>
           </div>

           <div className="flex-1 overflow-y-auto p-4 space-y-4 custom-scrollbar">
              {chatMessages.map(msg => {
                const sender = findUserById(msg.senderId);
                return (
                  <div key={msg.id} className="flex gap-3 animate-fade-in">
                     <img src={sender?.profilePicture || DEFAULT_PROFILE_PIC} className="w-8 h-8 rounded-lg shrink-0 object-cover" />
                     <div className="flex-1">
                        <p className="text-[10px] font-black text-gray-400 uppercase mb-1">{sender?.firstName || 'Aluno'}</p>
                        <div className="bg-white/5 p-3 rounded-2xl text-xs font-medium leading-relaxed border border-white/5">
                           {msg.imageUrl && <img src={msg.imageUrl} className="w-full rounded-lg mb-2" />}
                           {msg.text}
                        </div>
                     </div>
                  </div>
                );
              })}
           </div>

           <div className="p-4 bg-black/40 border-t border-white/5">
              <form onSubmit={handleSendMessage} className="space-y-3">
                 {selectedImage && (
                    <div className="relative w-16 h-16 rounded-xl overflow-hidden border-2 border-blue-500">
                       <img src={selectedImage} className="w-full h-full object-cover" />
                       <button onClick={() => setSelectedImage(null)} className="absolute top-0 right-0 bg-red-600 p-0.5"><XMarkIcon className="h-3 w-3" /></button>
                    </div>
                 )}
                 <div className="flex items-center gap-2 bg-white/5 p-2 rounded-2xl border border-white/10">
                    <button type="button" onClick={() => fileInputRef.current?.click()} className="p-2 text-gray-400 hover:text-white"><PhotoIconOutline className="h-5 w-5" /></button>
                    <input ref={fileInputRef} type="file" className="hidden" accept="image/*" onChange={handleImageUpload} />
                    <input 
                      type="text" 
                      value={newMessage} 
                      onChange={e => setNewMessage(e.target.value)} 
                      placeholder="Diga algo..." 
                      className="bg-transparent flex-1 text-sm outline-none px-2" 
                    />
                    <button type="submit" className="p-2 bg-blue-600 rounded-xl"><PaperAirplaneIcon className="h-4 w-4" /></button>
                 </div>
              </form>
           </div>
        </div>
      )}

      {/* MODAL DE DOAÇÃO (SELEÇÃO) */}
      {showDonationModal && !pendingAmount && (
        <div className="fixed inset-0 bg-black/80 backdrop-blur-md z-[200] flex items-center justify-center p-4 animate-fade-in">
           <div className="bg-gray-900 w-full max-w-sm rounded-[3rem] p-8 border border-white/10 shadow-2xl text-center relative overflow-hidden">
              <div className="absolute top-0 right-0 w-24 h-24 bg-yellow-500/10 rounded-full blur-3xl"></div>
              <div className="w-20 h-20 bg-yellow-500/10 rounded-3xl flex items-center justify-center mx-auto mb-6">
                 <BanknotesIcon className="h-10 w-10 text-yellow-500" />
              </div>
              <h3 className="text-2xl font-black mb-2">Apoiar Professor</h3>
              <p className="text-gray-400 text-xs mb-8">Escolha um valor para incentivar o ensino.</p>
              <div className="grid grid-cols-3 gap-3 mb-8">
                 {[5, 10, 50].map(amt => {
                   const isInsufficient = (currentUser.balance || 0) < amt;
                   return (
                     <button 
                       key={amt} 
                       onClick={() => !isInsufficient && prepareDonation(amt)} 
                       className={`p-4 rounded-2xl font-black transition-all border border-white/5 group relative overflow-hidden ${isInsufficient ? 'bg-gray-800 opacity-50 cursor-not-allowed' : 'bg-white/5 hover:bg-yellow-600 hover:text-black'}`}
                     >
                        <span className="block text-xs opacity-50 group-hover:opacity-100">$</span>
                        {amt}
                        {isInsufficient && (
                          <div className="absolute top-0 right-0 p-1">
                             <ExclamationTriangleIcon className="h-3 w-3 text-red-500" />
                          </div>
                        )}
                     </button>
                   );
                 })}
              </div>

              <div className="bg-white/5 p-4 rounded-2xl mb-8 flex items-center justify-between">
                 <span className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Seu Saldo</span>
                 <span className="text-sm font-bold text-yellow-500">${(currentUser.balance || 0).toFixed(2)}</span>
              </div>

              {(currentUser.balance || 0) < 5 && (
                 <button onClick={() => onNavigate('profile')} className="w-full py-4 bg-blue-600 text-white rounded-2xl font-black text-xs uppercase mb-4 shadow-xl">Recarregar Carteira</button>
              )}

              <button onClick={() => setShowDonationModal(false)} className="text-[10px] font-black uppercase text-gray-500 tracking-[0.2em] hover:text-white transition-colors">Cancelar</button>
           </div>
        </div>
      )}

      {/* CONFIRMAÇÃO DE DÉBITO */}
      {pendingAmount && (
        <div className="fixed inset-0 bg-black/90 backdrop-blur-xl z-[300] flex items-center justify-center p-4 animate-fade-in">
           <div className="bg-white dark:bg-darkcard w-full max-w-md rounded-[3rem] p-8 border border-white/10 shadow-[0_0_50px_rgba(0,0,0,0.5)] overflow-hidden relative">
              <div className="absolute top-0 left-0 w-full h-2 bg-yellow-500"></div>

              <div className="flex items-center gap-4 mb-8">
                 <div className="bg-yellow-500/10 p-3 rounded-2xl">
                    <ExclamationCircleIcon className="h-8 w-8 text-yellow-500" />
                 </div>
                 <div className="text-left">
                    <h3 className="text-xl font-black text-gray-900 dark:text-white uppercase tracking-tighter">Confirmar Débito</h3>
                    <p className="text-[10px] text-gray-500 font-bold uppercase tracking-widest">Transação Interna CyBerPhone</p>
                 </div>
              </div>

              <div className="bg-gray-50 dark:bg-white/5 rounded-[2rem] p-6 mb-8 border border-gray-100 dark:border-white/5">
                 <div className="flex justify-between items-center mb-4">
                    <span className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Valor do Presente</span>
                    <span className="text-2xl font-black text-gray-900 dark:text-white">${pendingAmount.toFixed(2)}</span>
                 </div>
                 <div className="flex justify-between items-center pt-4 border-t border-gray-100 dark:border-white/5">
                    <div className="flex items-center gap-2">
                       <WalletIcon className="h-4 w-4 text-blue-500" />
                       <span className="text-[10px] font-black text-gray-400 uppercase">Saldo Após Envio</span>
                    </div>
                    <span className="text-sm font-bold text-blue-600">${((currentUser.balance || 0) - pendingAmount).toFixed(2)}</span>
                 </div>
              </div>

              <div className="flex flex-col gap-3">
                 <button 
                   onClick={executeDonation}
                   disabled={isProcessingDonation}
                   className="w-full py-5 bg-blue-600 text-white rounded-[2rem] font-black text-base shadow-2xl shadow-blue-500/20 active:scale-95 transition-all flex items-center justify-center gap-3 disabled:opacity-50"
                 >
                    {isProcessingDonation ? (
                       <div className="w-6 h-6 border-4 border-white border-t-transparent animate-spin rounded-full"></div>
                    ) : (
                       <><CheckCircleIcon className="h-6 w-6"/> CONFIRMAR E ENVIAR</>
                    )}
                 </button>
                 <button 
                   onClick={() => setPendingAmount(null)}
                   disabled={isProcessingDonation}
                   className="py-2 text-[10px] font-black uppercase text-gray-500 tracking-[0.2em] hover:text-red-500 transition-colors disabled:opacity-0"
                 >
                    Desistir da doação
                 </button>
              </div>
           </div>
        </div>
      )}

      {/* MODAL DE SEGURANÇA SCREEN SHARE */}
      {showScreenShareSafety && (
        <div className="fixed inset-0 bg-black/90 z-[200] flex items-center justify-center p-4 animate-fade-in">
           <div className="bg-gray-900 w-full max-w-md rounded-[3rem] p-8 border border-white/10 shadow-2xl text-center">
              <div className="w-20 h-20 bg-red-600/10 rounded-3xl flex items-center justify-center mx-auto mb-6">
                 <ShieldExclamationIcon className="h-10 w-10 text-red-500" />
              </div>
              <h3 className="text-2xl font-black mb-2">Compartilhar Tela</h3>
              <p className="text-gray-400 text-sm mb-8">Certifique-se de que não há informações sensíveis visíveis antes de iniciar.</p>
              <div className="flex flex-col gap-3">
                 <button onClick={startScreenShare} className="w-full py-4 bg-blue-600 text-white rounded-2xl font-black shadow-xl active:scale-95 transition-all">ESTOU CIENTE</button>
                 <button onClick={() => setShowScreenShareSafety(false)} className="py-2 text-[10px] font-black uppercase text-gray-500 tracking-[0.2em]">Agora não</button>
              </div>
           </div>
        </div>
      )}

      <style>{`
        .animate-slide-left { animation: slideLeft 0.4s cubic-bezier(0.16, 1, 0.3, 1) forwards; }
        @keyframes slideLeft { from { transform: translateX(100%); } to { transform: translateX(0); } }

        @keyframes shoutout {
          0% { transform: translate(-50%, -100%); opacity: 0; }
          15% { transform: translate(-50%, 0); opacity: 1; }
          85% { transform: translate(-50%, 0); opacity: 1; }
          100% { transform: translate(-50%, -100%); opacity: 0; }
        }
        .animate-shoutout {
          animation: shoutout 5s cubic-bezier(0.16, 1, 0.3, 1) forwards;
        }
      `}</style>
    </div>
  );
};

export default LiveStreamViewer;

import React, { useState, useEffect, useRef } from 'react';
import { Post, User, Message } from '../types';
import { getPosts, findUserById, updateUserBalance, deletePost } from '../services/storageService';
import { 
  MicrophoneIcon, 
  VideoCameraIcon, 
  ChatBubbleLeftRightIcon, 
  XMarkIcon,
  HandRaisedIcon,
  SignalIcon,
  UsersIcon,
  ComputerDesktopIcon,
  PhotoIcon,
  PaperAirplaneIcon,
  ShieldCheckIcon,
  ShieldExclamationIcon,
  PowerIcon,
  BanknotesIcon,
  HeartIcon,
  CheckCircleIcon,
  ExclamationCircleIcon,
  ExclamationTriangleIcon,
  SparklesIcon
} from '@heroicons/react/24/solid';
import { 
  MicrophoneIcon as MicrophoneIconOutline, 
  PhotoIcon as PhotoIconOutline,
  WalletIcon,
  HandRaisedIcon as HandRaisedIconOutline
} from '@heroicons/react/24/outline';
import { DEFAULT_PROFILE_PIC } from '../constants';

interface LiveStreamViewerProps {
  currentUser: User;
  postId: string;
  onNavigate: (page: string, params?: Record<string, string>) => void;
  refreshUser: () => void;
}

const LiveStreamViewer: React.FC<LiveStreamViewerProps> = ({ currentUser, postId, onNavigate, refreshUser }) => {
  const [post, setPost] = useState<Post | null>(null);
  const [creator, setCreator] = useState<User | null>(null);
  const [isMicOn, setIsMicOn] = useState(false);
  const [isCamOn, setIsCamOn] = useState(false);
  const [isScreenSharing, setIsScreenSharing] = useState(false);
  const [showScreenShareSafety, setShowScreenShareSafety] = useState(false);

  const [showDonationModal, setShowDonationModal] = useState(false);
  const [pendingAmount, setPendingAmount] = useState<number | null>(null);
  const [isProcessingDonation, setIsProcessingDonation] = useState(false);
  const [donationAlert, setDonationAlert] = useState<{name: string, amount: number} | null>(null);

  const [activeSidebar, setActiveSidebar] = useState<'chat' | null>(null);
  const [handRaised, setHandRaised] = useState(false);
  const [handRaiseNotification, setHandRaiseNotification] = useState<{id: string, name: string} | null>(null);

  const [chatMessages, setChatMessages] = useState<Message[]>([]);
  const [newMessage, setNewMessage] = useState('');
  const [selectedImage, setSelectedImage] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const localVideoRef = useRef<HTMLVideoElement>(null);
  const streamRef = useRef<MediaStream | null>(null);

  useEffect(() => {
    const foundPost = getPosts().find(p => p.id === postId);
    if (foundPost && foundPost.liveStream) {
      setPost(foundPost);
      const author = findUserById(foundPost.userId);
      setCreator(author || null);
    } else {
      onNavigate('feed');
    }
    return () => stopStreams();
  }, [postId, onNavigate, currentUser.id]);

  useEffect(() => {
    let timer: number;
    if (handRaiseNotification) {
      timer = window.setTimeout(() => setHandRaiseNotification(null), 6000);
    }
    return () => clearTimeout(timer);
  }, [handRaiseNotification]);

  const stopStreams = () => {
    if (streamRef.current) {
      streamRef.current.getTracks().forEach(track => track.stop());
    }
    streamRef.current = null;
  };

  const startScreenShare = async () => {
    try {
      const screenStream = await (navigator.mediaDevices as any).getDisplayMedia({ video: true });
      const screenTrack = screenStream.getVideoTracks()[0];
      screenTrack.onended = () => {
        setIsScreenSharing(false);
        setIsCamOn(false);
      };
      if (streamRef.current) {
        const oldTrack = streamRef.current.getVideoTracks()[0];
        if (oldTrack) streamRef.current.removeTrack(oldTrack);
        streamRef.current.addTrack(screenTrack);
      } else {
        streamRef.current = new MediaStream([screenTrack]);
      }
      if (localVideoRef.current) localVideoRef.current.srcObject = streamRef.current;
      setIsScreenSharing(true);
      setIsCamOn(true);
      setShowScreenShareSafety(false);
    } catch (err) {
      setShowScreenShareSafety(false);
    }
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => setSelectedImage(reader.result as string);
      reader.readAsDataURL(file);
    }
  };

  const handleSendMessage = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newMessage.trim() && !selectedImage) return;

    const msg: Message = {
      id: `live-msg-${Date.now()}`,
      senderId: currentUser.id,
      receiverId: 'room',
      timestamp: Date.now(),
      text: newMessage,
      imageUrl: selectedImage || undefined
    };

    setChatMessages(prev => [...prev, msg]);
    setNewMessage('');
    setSelectedImage(null);
  };

  const prepareDonation = (amount: number) => {
    setPendingAmount(amount);
  };

  const executeDonation = () => {
    if (!pendingAmount || !creator) return;

    if ((currentUser.balance || 0) < pendingAmount) {
      setPendingAmount(null);
      return;
    }

    setIsProcessingDonation(true);

    setTimeout(() => {
      const donatedValue = pendingAmount;
      updateUserBalance(currentUser.id, -donatedValue);
      updateUserBalance(creator.id, donatedValue);
      refreshUser();

      setDonationAlert({ name: currentUser.firstName, amount: donatedValue });
      setTimeout(() => setDonationAlert(null), 5000);

      const msg: Message = {
        id: `donation-msg-${Date.now()}`,
        senderId: currentUser.id,
        receiverId: 'room',
        timestamp: Date.now(),
        text: `🎁 Enviou um presente de $${donatedValue.toFixed(2)} para o professor!`,
      };
      setChatMessages(prev => [...prev, msg]);

      setIsProcessingDonation(false);
      setPendingAmount(null);
      setShowDonationModal(false);
    }, 1200);
  };

  const toggleCamera = async () => {
    if (isCamOn) {
      if (streamRef.current) streamRef.current.getVideoTracks().forEach(track => track.stop());
      setIsCamOn(false);
      setIsScreenSharing(false);
    } else {
      try {
        const videoStream = await navigator.mediaDevices.getUserMedia({ video: true });
        const videoTrack = videoStream.getVideoTracks()[0];
        if (streamRef.current) {
          const oldTrack = streamRef.current.getVideoTracks()[0];
          if (oldTrack) streamRef.current.removeTrack(oldTrack);
          streamRef.current.addTrack(videoTrack);
        } else {
          streamRef.current = new MediaStream([videoTrack]);
        }
        if (localVideoRef.current) localVideoRef.current.srcObject = streamRef.current;
        setIsCamOn(true);
      } catch (err) {
        alert("Câmera indisponível.");
      }
    }
  };

  const toggleMic = async () => {
    if (isMicOn) {
      if (streamRef.current) streamRef.current.getAudioTracks().forEach(t => t.enabled = false);
      setIsMicOn(false);
    } else {
      try {
        const audioStream = await navigator.mediaDevices.getUserMedia({ audio: true });
        const audioTrack = audioStream.getAudioTracks()[0];
        if (streamRef.current) {
          streamRef.current.addTrack(audioTrack);
        } else {
          streamRef.current = new MediaStream([audioTrack]);
        }
        setIsMicOn(true);
      } catch (err) {
        alert("Microfone indisponível.");
      }
    }
  };

  const handleHandRaise = () => {
    const newState = !handRaised;
    setHandRaised(newState);
    if (newState) {
      setHandRaiseNotification({
        id: `hand-${Date.now()}`,
        name: `${currentUser.firstName} ${currentUser.lastName}`
      });
    } else {
      setHandRaiseNotification(null);
    }
  };

  if (!post || !post.liveStream || !creator) return null;
  const isTeacher = currentUser.id === creator.id;

  return (
    <div className="fixed inset-0 bg-[#020408] z-[60] flex flex-col overflow-hidden text-white font-sans">

      <nav className="w-full flex items-center justify-between px-4 pt-4 pb-2 z-50 flex-shrink-0">
        <button onClick={() => onNavigate('feed')} className="p-2 bg-white/10 rounded-xl">
          <XMarkIcon className="h-5 w-5" />
        </button>
        <div className="flex flex-col items-center">
           <div className="bg-red-600 px-3 py-1 rounded-lg text-[9px] font-black flex items-center gap-2 shadow-lg">
             <SignalIcon className="h-3 w-3 animate-pulse" /> AO VIVO
           </div>
           <p className="text-[9px] font-black uppercase mt-1 tracking-widest text-gray-400">{post.liveStream.title}</p>
        </div>
        <div className="flex items-center gap-4">
           {isTeacher && (
             <button onClick={() => { if(window.confirm("Encerrar aula?")) { deletePost(post.id); onNavigate('feed'); refreshUser(); } }} className="bg-white/10 p-2 rounded-xl flex items-center gap-2 hover:bg-red-600/20 transition-colors">
                <PowerIcon className="h-4 w-4 text-red-500" />
             </button>
           )}
           <div className="flex items-center gap-2 bg-white/5 px-3 py-1.5 rounded-lg">
              <UsersIcon className="h-3 w-3 text-gray-400" />
              <span className="text-[10px] font-bold">42</span>
           </div>
        </div>
      </nav>

      <main className="flex-1 flex relative items-center justify-center overflow-hidden p-2 md:p-4">
        <div className="w-full h-full max-w-5xl rounded-[2rem] overflow-hidden bg-black border-4 border-white/5 relative shadow-2xl group">
          {isCamOn ? (
            <video ref={localVideoRef} autoPlay playsInline muted className="w-full h-full object-contain" />
          ) : (
            <div className="flex flex-col items-center justify-center h-full opacity-40 bg-gradient-to-br from-gray-900 to-black">
               <div className="w-32 h-32 rounded-[3rem] bg-gray-800 flex items-center justify-center text-5xl font-black border-4 border-white/5">
                {creator.firstName[0]}
               </div>
            </div>
          )}

          {/* ALERTA DE DOAÇÃO EM DESTAQUE (SHOUTOUT) */}
          {donationAlert && (
            <div className="absolute top-10 left-1/2 -translate-x-1/2 z-[100] animate-shoutout">
               <div className="bg-gradient-to-r from-yellow-400 to-yellow-600 p-[2px] rounded-full shadow-[0_0_30px_rgba(234,179,8,0.4)]">
                  <div className="bg-black/90 backdrop-blur-xl px-8 py-3 rounded-full flex items-center gap-4">
                     <div className="bg-yellow-500 p-2 rounded-full shadow-lg">
                        <SparklesIcon className="h-5 w-5 text-black" />
                     </div>
                     <div className="text-left">
                        <p className="text-[10px] font-black text-yellow-500 uppercase tracking-[0.2em] leading-none mb-1">Novo Presente!</p>
                        <p className="text-sm font-black text-white whitespace-nowrap">
                           <span className="text-yellow-400">{donationAlert.name}</span> doou <span className="text-green-400">${donationAlert.amount.toFixed(2)}</span>
                        </p>
                     </div>
                     <div className="bg-white/10 p-2 rounded-full">
                        <BanknotesIcon className="h-5 w-5 text-yellow-500" />
                     </div>
                  </div>
               </div>
            </div>
          )}

          <div className="absolute bottom-6 left-1/2 -translate-x-1/2 flex items-center gap-4 bg-black/60 backdrop-blur-xl p-3 rounded-3xl border border-white/10 group-hover:translate-y-0 translate-y-20 transition-all duration-500 z-40">
             <div className="flex gap-2">
                <button onClick={toggleMic} className={`p-3 rounded-xl transition-all ${isMicOn ? 'bg-blue-600 shadow-lg shadow-blue-600/30' : 'bg-white/10 hover:bg-white/20'}`}>
                   {isMicOn ? <MicrophoneIcon className="h-5 w-5" /> : <MicrophoneIconOutline className="h-5 w-5" />}
                </button>
                <button onClick={toggleCamera} className={`p-3 rounded-xl transition-all ${isCamOn ? 'bg-blue-600 shadow-lg shadow-blue-600/30' : 'bg-white/10 hover:bg-white/20'}`}>
                   <VideoCameraIcon className="h-5 w-5" />
                </button>
                <button onClick={() => setShowScreenShareSafety(true)} className={`p-3 rounded-xl transition-all ${isScreenSharing ? 'bg-blue-600 shadow-lg shadow-blue-600/30' : 'bg-white/10 hover:bg-white/20'}`}>
                   <ComputerDesktopIcon className="h-5 w-5" />
                </button>
                <button onClick={() => setShowDonationModal(true)} className="p-3 bg-yellow-500 rounded-xl hover:bg-yellow-400 transition-all shadow-lg shadow-yellow-500/30">
                   <BanknotesIcon className="h-5 w-5 text-black" />
                </button>
             </div>
          </div>

          <div className="absolute top-6 right-6 flex flex-col gap-3">
             <button onClick={() => setActiveSidebar(activeSidebar === 'chat' ? null : 'chat')} className={`p-4 rounded-2xl backdrop-blur-xl border border-white/10 transition-all shadow-2xl ${activeSidebar === 'chat' ? 'bg-blue-600' : 'bg-black/40 hover:bg-black/60'}`}>
                <ChatBubbleLeftRightIcon className="h-6 w-6" />
             </button>
             <button onClick={handleHandRaise} className={`p-4 rounded-2xl backdrop-blur-xl border border-white/10 transition-all shadow-2xl ${handRaised ? 'bg-purple-600 animate-bounce' : 'bg-black/40 hover:bg-black/60'}`}>
                {handRaised ? <HandRaisedIcon className="h-6 w-6" /> : <HandRaisedIconOutline className="h-6 w-6" />}
             </button>
          </div>
        </div>
      </main>

      {/* CHAT SIDEBAR */}
      {activeSidebar === 'chat' && (
        <div className="w-full md:w-96 bg-[#0a0c10] border-l border-white/5 flex flex-col animate-slide-left fixed md:relative inset-y-0 right-0 z-[70]">
           <div className="p-6 border-b border-white/5 flex items-center justify-between">
              <h3 className="text-sm font-black uppercase tracking-widest">Chat da Aula</h3>
              <button onClick={() => setActiveSidebar(null)} className="p-2 hover:bg-white/5 rounded-lg"><XMarkIcon className="h-5 w-5" /></button>
           </div>

           <div className="flex-1 overflow-y-auto p-4 space-y-4 custom-scrollbar">
              {chatMessages.map(msg => {
                const sender = findUserById(msg.senderId);
                return (
                  <div key={msg.id} className="flex gap-3 animate-fade-in">
                     <img src={sender?.profilePicture || DEFAULT_PROFILE_PIC} className="w-8 h-8 rounded-lg shrink-0 object-cover" />
                     <div className="flex-1">
                        <p className="text-[10px] font-black text-gray-400 uppercase mb-1">{sender?.firstName || 'Aluno'}</p>
                        <div className="bg-white/5 p-3 rounded-2xl text-xs font-medium leading-relaxed border border-white/5">
                           {msg.imageUrl && <img src={msg.imageUrl} className="w-full rounded-lg mb-2" />}
                           {msg.text}
                        </div>
                     </div>
                  </div>
                );
              })}
           </div>

           <div className="p-4 bg-black/40 border-t border-white/5">
              <form onSubmit={handleSendMessage} className="space-y-3">
                 {selectedImage && (
                    <div className="relative w-16 h-16 rounded-xl overflow-hidden border-2 border-blue-500">
                       <img src={selectedImage} className="w-full h-full object-cover" />
                       <button onClick={() => setSelectedImage(null)} className="absolute top-0 right-0 bg-red-600 p-0.5"><XMarkIcon className="h-3 w-3" /></button>
                    </div>
                 )}
                 <div className="flex items-center gap-2 bg-white/5 p-2 rounded-2xl border border-white/10">
                    <button type="button" onClick={() => fileInputRef.current?.click()} className="p-2 text-gray-400 hover:text-white"><PhotoIconOutline className="h-5 w-5" /></button>
                    <input ref={fileInputRef} type="file" className="hidden" accept="image/*" onChange={handleImageUpload} />
                    <input 
                      type="text" 
                      value={newMessage} 
                      onChange={e => setNewMessage(e.target.value)} 
                      placeholder="Diga algo..." 
                      className="bg-transparent flex-1 text-sm outline-none px-2" 
                    />
                    <button type="submit" className="p-2 bg-blue-600 rounded-xl"><PaperAirplaneIcon className="h-4 w-4" /></button>
                 </div>
              </form>
           </div>
        </div>
      )}

      {/* NOTIFICAÇÃO DE MÃO LEVANTADA (O NOME LEVANTOU A MÃO) */}
      {handRaiseNotification && (
        <div className="fixed top-20 left-1/2 -translate-x-1/2 z-[100] animate-bounce-in">
           <div className="bg-purple-600 px-8 py-4 rounded-3xl shadow-[0_0_40px_rgba(147,51,234,0.4)] flex items-center gap-4 border-2 border-white/20 backdrop-blur-md">
              <div className="bg-white/20 p-2 rounded-xl">
                <HandRaisedIcon className="h-6 w-6 text-white animate-pulse" />
              </div>
              <div className="text-left">
                <p className="text-[10px] font-black text-purple-200 uppercase tracking-widest leading-none mb-1">Solicitação de Fala</p>
                <span className="text-sm font-black text-white uppercase tracking-tight">O {handRaiseNotification.name} levantou a mão para falar</span>
              </div>
           </div>
        </div>
      )}

      {/* MODAL DE DOAÇÃO (SELEÇÃO) */}
      {showDonationModal && !pendingAmount && (
        <div className="fixed inset-0 bg-black/80 backdrop-blur-md z-[200] flex items-center justify-center p-4 animate-fade-in">
           <div className="bg-gray-900 w-full max-w-sm rounded-[3rem] p-8 border border-white/10 shadow-2xl text-center relative overflow-hidden">
              <div className="absolute top-0 right-0 w-24 h-24 bg-yellow-500/10 rounded-full blur-3xl"></div>
              <div className="w-20 h-20 bg-yellow-500/10 rounded-3xl flex items-center justify-center mx-auto mb-6">
                 <BanknotesIcon className="h-10 w-10 text-yellow-500" />
              </div>
              <h3 className="text-2xl font-black mb-2">Apoiar Professor</h3>
              <p className="text-gray-400 text-xs mb-8">Escolha um valor para incentivar o ensino.</p>
              <div className="grid grid-cols-3 gap-3 mb-8">
                 {[5, 10, 50].map(amt => {
                   const isInsufficient = (currentUser.balance || 0) < amt;
                   return (
                     <button 
                       key={amt} 
                       onClick={() => !isInsufficient && prepareDonation(amt)} 
                       className={`p-4 rounded-2xl font-black transition-all border border-white/5 group relative overflow-hidden ${isInsufficient ? 'bg-gray-800 opacity-50 cursor-not-allowed' : 'bg-white/5 hover:bg-yellow-600 hover:text-black'}`}
                     >
                        <span className="block text-xs opacity-50 group-hover:opacity-100">$</span>
                        {amt}
                        {isInsufficient && (
                          <div className="absolute top-0 right-0 p-1">
                             <ExclamationTriangleIcon className="h-3 w-3 text-red-500" />
                          </div>
                        )}
                     </button>
                   );
                 })}
              </div>

              <div className="bg-white/5 p-4 rounded-2xl mb-8 flex items-center justify-between">
                 <span className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Seu Saldo</span>
                 <span className="text-sm font-bold text-yellow-500">${(currentUser.balance || 0).toFixed(2)}</span>
              </div>

              {(currentUser.balance || 0) < 5 && (
                 <button onClick={() => onNavigate('profile')} className="w-full py-4 bg-blue-600 text-white rounded-2xl font-black text-xs uppercase mb-4 shadow-xl">Recarregar Carteira</button>
              )}

              <button onClick={() => setShowDonationModal(false)} className="text-[10px] font-black uppercase text-gray-500 tracking-[0.2em] hover:text-white transition-colors">Cancelar</button>
           </div>
        </div>
      )}

      {/* CONFIRMAÇÃO DE DÉBITO */}
      {pendingAmount && (
        <div className="fixed inset-0 bg-black/90 backdrop-blur-xl z-[300] flex items-center justify-center p-4 animate-fade-in">
           <div className="bg-white dark:bg-darkcard w-full max-w-md rounded-[3rem] p-8 border border-white/10 shadow-[0_0_50px_rgba(0,0,0,0.5)] overflow-hidden relative">
              <div className="absolute top-0 left-0 w-full h-2 bg-yellow-500"></div>

              <div className="flex items-center gap-4 mb-8">
                 <div className="bg-yellow-500/10 p-3 rounded-2xl">
                    <ExclamationCircleIcon className="h-8 w-8 text-yellow-500" />
                 </div>
                 <div className="text-left">
                    <h3 className="text-xl font-black text-gray-900 dark:text-white uppercase tracking-tighter">Confirmar Débito</h3>
                    <p className="text-[10px] text-gray-500 font-bold uppercase tracking-widest">Transação Interna CyBerPhone</p>
                 </div>
              </div>

              <div className="bg-gray-50 dark:bg-white/5 rounded-[2rem] p-6 mb-8 border border-gray-100 dark:border-white/5">
                 <div className="flex justify-between items-center mb-4">
                    <span className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Valor do Presente</span>
                    <span className="text-2xl font-black text-gray-900 dark:text-white">${pendingAmount.toFixed(2)}</span>
                 </div>
                 <div className="flex justify-between items-center pt-4 border-t border-gray-100 dark:border-white/5">
                    <div className="flex items-center gap-2">
                       <WalletIcon className="h-4 w-4 text-blue-500" />
                       <span className="text-[10px] font-black text-gray-400 uppercase">Saldo Após Envio</span>
                    </div>
                    <span className="text-sm font-bold text-blue-600">${((currentUser.balance || 0) - pendingAmount).toFixed(2)}</span>
                 </div>
              </div>

              <div className="flex flex-col gap-3">
                 <button 
                   onClick={executeDonation}
                   disabled={isProcessingDonation}
                   className="w-full py-5 bg-blue-600 text-white rounded-[2rem] font-black text-base shadow-2xl shadow-blue-500/20 active:scale-95 transition-all flex items-center justify-center gap-3 disabled:opacity-50"
                 >
                    {isProcessingDonation ? (
                       <div className="w-6 h-6 border-4 border-white border-t-transparent animate-spin rounded-full"></div>
                    ) : (
                       <><CheckCircleIcon className="h-6 w-6"/> CONFIRMAR E ENVIAR</>
                    )}
                 </button>
                 <button 
                   onClick={() => setPendingAmount(null)}
                   disabled={isProcessingDonation}
                   className="py-2 text-[10px] font-black uppercase text-gray-500 tracking-[0.2em] hover:text-red-500 transition-colors disabled:opacity-0"
                 >
                    Desistir da doação
                 </button>
              </div>
           </div>
        </div>
      )}

      {/* MODAL DE SEGURANÇA SCREEN SHARE */}
      {showScreenShareSafety && (
        <div className="fixed inset-0 bg-black/90 z-[200] flex items-center justify-center p-4 animate-fade-in">
           <div className="bg-gray-900 w-full max-w-md rounded-[3rem] p-8 border border-white/10 shadow-2xl text-center">
              <div className="w-20 h-20 bg-red-600/10 rounded-3xl flex items-center justify-center mx-auto mb-6">
                 <ShieldExclamationIcon className="h-10 w-10 text-red-500" />
              </div>
              <h3 className="text-2xl font-black mb-2">Compartilhar Tela</h3>
              <p className="text-gray-400 text-sm mb-8">Certifique-se de que não há informações sensíveis visíveis antes de iniciar.</p>
              <div className="flex flex-col gap-3">
                 <button onClick={startScreenShare} className="w-full py-4 bg-blue-600 text-white rounded-2xl font-black shadow-xl active:scale-95 transition-all">ESTOU CIENTE</button>
                 <button onClick={() => setShowScreenShareSafety(false)} className="py-2 text-[10px] font-black uppercase text-gray-500 tracking-[0.2em]">Agora não</button>
              </div>
           </div>
        </div>
      )}

      <style>{`
        .animate-slide-left { animation: slideLeft 0.4s cubic-bezier(0.16, 1, 0.3, 1) forwards; }
        @keyframes slideLeft { from { transform: translateX(100%); } to { transform: translateX(0); } }

        @keyframes shoutout {
          0% { transform: translate(-50%, -100%); opacity: 0; }
          15% { transform: translate(-50%, 0); opacity: 1; }
          85% { transform: translate(-50%, 0); opacity: 1; }
          100% { transform: translate(-50%, -100%); opacity: 0; }
        }
        .animate-shoutout {
          animation: shoutout 5s cubic-bezier(0.16, 1, 0.3, 1) forwards;
        }

        @keyframes bounce-in {
          0% { transform: translate(-50%, -200%); opacity: 0; }
          60% { transform: translate(-50%, 10%); opacity: 1; }
          80% { transform: translate(-50%, -5%); }
          100% { transform: translate(-50%, 0); }
        }
        .animate-bounce-in {
          animation: bounce-in 0.6s cubic-bezier(0.175, 0.885, 0.32, 1.275) forwards;
        }
      `}</style>
    </div>
  );
};

export default LiveStreamViewer;

import React, { useState, useRef, useEffect } from 'react';
import { Post, PostType, User, UserType, Comment } from '../types';
import { DEFAULT_PROFILE_PIC } from '../constants';
import { 
  findUserById, 
  updatePostLikes, 
  addPostComment, 
  updatePostShares, 
  updatePostSaves, 
  deletePost, 
  reportPost,
  pinPost,
  unpinPost
} from '../services/storageService';
import {
  HeartIcon as HeartIconOutline, 
  ChatBubbleOvalLeftIcon as ChatIconOutline, 
  BookmarkIcon as BookmarkIconOutline, 
  EllipsisHorizontalIcon, 
  PencilIcon, 
  TrashIcon, 
  CheckBadgeIcon,
  FlagIcon,
  PaperAirplaneIcon,
  MapPinIcon as PinIconOutline,
  UserPlusIcon,
  VideoCameraIcon,
  SignalIcon,
  ShareIcon,
  ArrowsPointingOutIcon
} from '@heroicons/react/24/outline';
import { 
  HeartIcon as HeartIconSolid, 
  BookmarkIcon as BookmarkIconSolid,
  MapPinIcon as PinIconSolid,
  PlayIcon
} from '@heroicons/react/24/solid';
import IndicateModal from './IndicateModal';
import PostDetailModal from './PostDetailModal';

interface PostCardProps {
  post: Post;
  currentUser: User;
  onNavigate: (page: string, params?: Record<string, string>) => void;
  onFollowToggle: (userIdToFollow: string) => void;
  refreshUser: () => void;
  onPostUpdatedOrDeleted: () => void;
  onPinToggle: (postId: string, isCurrentlyPinned: boolean) => void;
}

const PostCard: React.FC<PostCardProps> = ({ 
  post, 
  currentUser, 
  onNavigate, 
  onFollowToggle, 
  refreshUser, 
  onPostUpdatedOrDeleted 
}) => {
  const postAuthor = findUserById(post.userId);
  const [showComments, setShowComments] = useState(false);
  const [newCommentText, setNewCommentText] = useState('');
  const [showOptions, setShowOptions] = useState(false);
  const [showReportConfirm, setShowReportConfirm] = useState(false);
  const [showIndicateModal, setShowIndicateModal] = useState(false);
  const [showDetailModal, setShowDetailModal] = useState(false);

  const optionsRef = useRef<HTMLDivElement>(null);
  const hasLiked = post.likes.includes(currentUser.id);
  const hasSaved = post.saves.includes(currentUser.id);
  const isAuthor = currentUser.id === post.userId;
  const isFollowing = currentUser.followedUsers.includes(post.userId);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (optionsRef.current && !optionsRef.current.contains(event.target as Node)) setShowOptions(false);
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const handleLike = (e?: React.MouseEvent) => {
    e?.stopPropagation();
    updatePostLikes(post.id, currentUser.id);
    onPostUpdatedOrDeleted();
  };

  const handleAddComment = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newCommentText.trim()) return;
    addPostComment(post.id, {
      id: `comment-${Date.now()}`,
      userId: currentUser.id,
      userName: `${currentUser.firstName}`,
      profilePic: currentUser.profilePicture,
      text: newCommentText,
      timestamp: Date.now(),
    });
    setNewCommentText('');
    onPostUpdatedOrDeleted();
  };

  const handleShareExternal = async (e?: React.MouseEvent) => {
    e?.stopPropagation();
    const shareData = {
      title: post.liveStream?.title || 'Aula CyBerPhone',
      text: post.content || 'Confira este conteúdo educativo na CyBerPhone!',
      url: window.location.href,
    };

    if (navigator.share) {
      try {
        await navigator.share(shareData);
        updatePostShares(post.id, currentUser.id);
        onPostUpdatedOrDeleted();
      } catch (err) {
        console.error('Erro ao compartilhar:', err);
      }
    } else {
      navigator.clipboard.writeText(window.location.href);
      alert('Link copiado para a área de transferência!');
    }
  };

  const handleDelete = (e: React.MouseEvent) => {
    e.stopPropagation();
    if (window.confirm('Tem certeza que deseja excluir esta publicação?')) {
      deletePost(post.id);
      onPostUpdatedOrDeleted();
      setShowOptions(false);
    }
  };

  const handlePin = (e: React.MouseEvent) => {
    e.stopPropagation();
    if (post.isPinned) unpinPost(post.id, currentUser.id);
    else pinPost(post.id, currentUser.id);
    onPostUpdatedOrDeleted();
    setShowOptions(false);
  };

  if (!postAuthor) return null;

  return (
    <>
      <div 
        onClick={() => post.type !== PostType.LIVE && setShowDetailModal(true)}
        className={`bg-white dark:bg-darkcard rounded-[2.5rem] shadow-sm border border-gray-50 dark:border-white/10 overflow-hidden w-full relative mb-6 transition-all hover:shadow-md animate-fade-in ${post.type !== PostType.LIVE ? 'cursor-pointer' : ''}`}
      >

        {/* HEADER */}
        <div className="p-5 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="relative cursor-pointer" onClick={(e) => { e.stopPropagation(); onNavigate('profile', { userId: post.userId }); }}>
              <img src={postAuthor.profilePicture || DEFAULT_PROFILE_PIC} className="w-11 h-11 rounded-xl object-cover shadow-sm" />
              {postAuthor.userType === UserType.CREATOR && (
                <div className="absolute -bottom-1 -right-1 bg-blue-600 rounded-lg p-0.5 border-2 border-white dark:border-darkcard">
                  <CheckBadgeIcon className="h-3 w-3 text-white" />
                </div>
              )}
            </div>
            <div>
              <div className="flex items-center gap-2">
                <h4 className="font-black text-gray-900 dark:text-white text-sm leading-tight hover:underline cursor-pointer" onClick={(e) => { e.stopPropagation(); onNavigate('profile', { userId: post.userId }); }}>
                    {postAuthor.firstName} {postAuthor.lastName}
                </h4>
                {!isAuthor && !isFollowing && (
                  <button 
                    onClick={(e) => { e.stopPropagation(); onFollowToggle(post.userId); }}
                    className="text-[9px] font-black text-blue-600 uppercase tracking-widest bg-blue-50 dark:bg-blue-900/20 px-2 py-0.5 rounded-md hover:bg-blue-600 hover:text-white transition-all"
                  >
                    Seguir
                  </button>
                )}
                {post.isPinned && <PinIconSolid className="h-3 w-3 text-blue-500" />}
              </div>
              <p className="text-[9px] font-bold text-gray-400 uppercase tracking-wider">{new Date(post.timestamp).toLocaleDateString()}</p>
            </div>
          </div>

          <div className="relative" ref={optionsRef}>
            <button onClick={(e) => { e.stopPropagation(); setShowOptions(!showOptions); }} className="p-2 text-gray-300 hover:text-blue-600 transition-colors">
              <EllipsisHorizontalIcon className="h-6 w-6" />
            </button>
            {showOptions && (
              <div className="absolute right-0 mt-1 w-48 bg-white dark:bg-darkcard rounded-2xl shadow-2xl py-2 z-20 border dark:border-white/10 animate-fade-in" onClick={e => e.stopPropagation()}>
                {isAuthor ? (
                  <>
                    <button onClick={handlePin} className="flex items-center w-full px-4 py-3 text-[10px] font-black text-gray-700 dark:text-gray-300 hover:bg-gray-50 dark:hover:bg-white/5 transition-colors">
                      {post.isPinned ? <><PinIconSolid className="h-4 w-4 mr-3 text-blue-500" /> Desafixar</> : <><PinIconOutline className="h-4 w-4 mr-3 text-blue-500" /> Fixar no Perfil</>}
                    </button>
                    <button onClick={(e) => { e.stopPropagation(); onNavigate('edit-post', { postId: post.id }); }} className="flex items-center w-full px-4 py-3 text-[10px] font-black text-gray-700 dark:text-gray-300 hover:bg-gray-50 dark:hover:bg-white/5 transition-colors">
                      <PencilIcon className="h-4 w-4 mr-3 text-indigo-500" /> Editar Aula
                    </button>
                    <button onClick={handleDelete} className="flex items-center w-full px-4 py-3 text-[10px] font-black text-red-600 hover:bg-red-50 dark:hover:bg-red-900/10 transition-colors">
                      <TrashIcon className="h-4 w-4 mr-3" /> Excluir
                    </button>
                  </>
                ) : (
                  <button onClick={(e) => { e.stopPropagation(); setShowReportConfirm(true); }} className="flex items-center w-full px-4 py-3 text-[10px] font-black text-orange-600 hover:bg-orange-50 dark:hover:bg-orange-900/10 transition-colors">
                    <FlagIcon className="h-4 w-4 mr-3" /> Denunciar conteúdo
                  </button>
                )}
              </div>
            )}
          </div>
        </div>

        {/* CONTENT */}
        <div className="px-5 pb-4">
          {post.type === PostType.LIVE && post.liveStream ? (
             <div className="rounded-[2.5rem] overflow-hidden bg-gray-900 text-white p-8 relative shadow-2xl group border-4 border-blue-600/30">
                <div className="absolute top-6 left-6 z-10">
                   <div className="bg-red-600 px-3 py-1.5 rounded-lg text-[9px] font-black flex items-center gap-2 shadow-lg animate-pulse uppercase tracking-widest">
                      <SignalIcon className="h-3 w-3" /> Ao Vivo
                   </div>
                </div>
                <div className="relative z-10 py-10 flex flex-col items-center text-center">
                   <div className="w-20 h-20 bg-blue-600/20 rounded-full flex items-center justify-center mb-6 border border-blue-500/30">
                      <VideoCameraIcon className="h-10 w-10 text-blue-400" />
                   </div>
                   <h3 className="text-2xl font-black mb-3 tracking-tighter leading-tight uppercase">{post.liveStream.title}</h3>
                   <p className="text-gray-400 text-sm max-w-sm mb-8 font-medium">{post.liveStream.description}</p>
                   <button 
                      onClick={(e) => { e.stopPropagation(); onNavigate('live', { postId: post.id }); }}
                      className="bg-blue-600 hover:bg-blue-700 text-white px-10 py-4 rounded-2xl font-black text-xs uppercase tracking-[0.2em] shadow-xl shadow-blue-900/40 active:scale-95 transition-all flex items-center gap-3"
                   >
                      <PlayIcon className="h-5 w-5" /> Assistir Aula
                   </button>
                </div>
             </div>
          ) : (
            <>
              {post.content && <p className="text-gray-700 dark:text-gray-300 text-sm font-medium leading-relaxed mb-4 whitespace-pre-wrap line-clamp-3">{post.content}</p>}
              {post.imageUrl && (
                <div className="rounded-[2rem] overflow-hidden border dark:border-white/5 bg-gray-50 dark:bg-darkbg relative group">
                   <img src={post.imageUrl} className="w-full h-auto object-cover max-h-[400px]" alt="Post" />
                   <div className="absolute inset-0 bg-black/10 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center">
                      <div className="bg-white/90 p-3 rounded-2xl shadow-xl">
                        <ArrowsPointingOutIcon className="h-6 w-6 text-blue-600" />
                      </div>
                   </div>
                </div>
              )}
            </>
          )}
        </div>

        {/* ACTIONS */}
        <div className="px-5 py-3 flex items-center justify-between border-t dark:border-white/5">
          <div className="flex items-center gap-1 md:gap-2">
            <button onClick={handleLike} className={`flex items-center gap-2 px-3 py-2 rounded-xl transition-all active:scale-90 ${hasLiked ? 'bg-red-50 dark:bg-red-500/10 text-red-600' : 'text-gray-400 hover:bg-gray-50 dark:hover:bg-white/5'}`}>
              {hasLiked ? <HeartIconSolid className="h-5 w-5" /> : <HeartIconOutline className="h-5 w-5" />}
              <span className="font-black text-xs">{post.likes.length}</span>
            </button>

            <button onClick={(e) => { e.stopPropagation(); setShowComments(!showComments); }} className="flex items-center gap-2 px-3 py-2 rounded-xl text-gray-400 hover:bg-gray-50 dark:hover:bg-white/5 transition-all">
              <ChatIconOutline className="h-5 w-5" />
              <span className="font-black text-xs">{post.comments.length}</span>
            </button>

            <button onClick={(e) => { e.stopPropagation(); setShowIndicateModal(true); }} className="flex items-center gap-2 px-3 py-2 rounded-xl text-gray-400 hover:bg-gray-50 dark:hover:bg-white/5 transition-all">
              <PaperAirplaneIcon className="h-5 w-5 -rotate-45" />
              <span className="font-black text-[10px] uppercase hidden sm:inline">Indicar</span>
            </button>

            <button onClick={handleShareExternal} className="flex items-center gap-2 px-3 py-2 rounded-xl text-gray-400 hover:bg-gray-50 dark:hover:bg-white/5 transition-all">
              <ShareIcon className="h-5 w-5" />
              <span className="font-black text-[10px] uppercase hidden sm:inline">Compartilhar</span>
            </button>
          </div>

          <div className="flex gap-1">
            <button onClick={(e) => { e.stopPropagation(); updatePostSaves(post.id, currentUser.id); onPostUpdatedOrDeleted(); }} className={`p-2.5 rounded-xl transition-all active:scale-90 ${hasSaved ? 'text-blue-600 bg-blue-50 dark:bg-blue-900/20' : 'text-gray-300 hover:text-blue-400 hover:bg-gray-50 dark:hover:bg-white/5'}`}>
              {hasSaved ? <BookmarkIconSolid className="h-5 w-5" /> : <BookmarkIconOutline className="h-5 w-5" />}
            </button>
          </div>
        </div>

        {/* COMMENTS INLINE (Optional, usually we'll use the modal now) */}
        {showComments && (
          <div className="p-5 bg-gray-50 dark:bg-white/5 border-t dark:border-white/5" onClick={e => e.stopPropagation()}>
             <div className="space-y-4 mb-4 max-h-40 overflow-y-auto no-scrollbar">
                {post.comments.map(c => (
                  <div key={c.id} className="flex gap-3">
                     <img src={c.profilePic || DEFAULT_PROFILE_PIC} className="w-8 h-8 rounded-lg object-cover" />
                     <div className="bg-white dark:bg-darkcard p-3 rounded-2xl shadow-sm flex-1 border dark:border-white/5">
                        <p className="font-black text-[9px] dark:text-white uppercase leading-none mb-1">{c.userName}</p>
                        <p className="text-xs text-gray-600 dark:text-gray-400">{c.text}</p>
                     </div>
                  </div>
                ))}
             </div>
             <form onSubmit={handleAddComment} className="flex gap-2">
                <input type="text" value={newCommentText} onChange={e => setNewCommentText(e.target.value)} placeholder="Sua dúvida..." className="flex-1 px-4 py-3 bg-white dark:bg-darkcard rounded-xl text-xs font-bold outline-none border border-transparent focus:border-blue-500 dark:text-white" />
                <button type="submit" disabled={!newCommentText.trim()} className="bg-blue-600 text-white px-5 rounded-xl font-black text-[10px] uppercase shadow-lg disabled:opacity-50">Enviar</button>
             </form>
          </div>
        )}
      </div>

      {/* Detail Modal */}
      {showDetailModal && (
        <PostDetailModal
          post={post}
          currentUser={currentUser}
          onClose={() => setShowDetailModal(false)}
          onUpdate={onPostUpdatedOrDeleted}
          onNavigate={onNavigate}
          refreshUser={refreshUser}
        />
      )}

      {/* Indicate Modal */}
      {showIndicateModal && (
        <IndicateModal 
          post={post} 
          currentUser={currentUser} 
          onClose={() => setShowIndicateModal(false)} 
