        {/* ACTIONS */}
        <div className="px-4 md:px-5 py-3 flex items-center justify-between border-t dark:border-white/5">
          <div className="flex items-center gap-1 md:gap-2">
            <button onClick={handleLike} className={`flex items-center gap-2 px-3 py-2 rounded-xl transition-all active:scale-90 ${hasLiked ? 'text-blue-600 bg-blue-50 dark:bg-blue-500/10' : 'text-gray-400 hover:bg-gray-50 dark:hover:bg-white/5'}`}>
              {hasLiked ? <HandThumbUpIcon className="h-5 w-5" /> : <HandThumbUpIcon className="h-5 w-5" />}
              <span className="font-black text-xs">{post.likes.length}</span>
            </button>

            <button onClick={(e) => { e.stopPropagation(); setShowDetailModal(true); }} className="flex items-center gap-2 px-3 py-2 rounded-xl text-gray-400 hover:bg-gray-50 dark:hover:bg-white/5 transition-all">
              <ChatIconOutline className="h-5 w-5" />
              <span className="font-black text-xs">{post.comments.length}</span>
            </button>

            <button onClick={(e) => { e.stopPropagation(); setShowIndicateModal(true); }} className="flex items-center gap-2 px-3 py-2 rounded-xl text-gray-400 hover:bg-gray-50 dark:hover:bg-white/5">
              <PaperAirplaneIcon className="h-5 w-5 -rotate-45" />
            </button>
          </div>

          <button onClick={(e) => { e.stopPropagation(); updatePostSaves(post.id, currentUser.id); onPostUpdatedOrDeleted(); }} className={`p-2.5 rounded-xl transition-all ${hasSaved ? 'text-blue-600 bg-blue-50 dark:bg-blue-900/20' : 'text-gray-300 hover:bg-gray-50 dark:hover:bg-white/5'}`}>
            {hasSaved ? <BookmarkIconSolid className="h-5 w-5" /> : <BookmarkIconOutline className="h-5 w-5" />}
          </button>
        </div>
      </div>

      {showDetailModal && (
        <PostDetailModal
          post={post}
          currentUser={currentUser}
          onClose={() => setShowDetailModal(false)}
          onUpdate={onPostUpdatedOrDeleted}
          onNavigate={onNavigate}
          refreshUser={refreshUser}
        />
      )}

      {showIndicateModal && (
        <IndicateModal 
          post={post} 
          currentUser={currentUser} 
          onClose={() => setShowIndicateModal(false)} 
          onPostUpdated={onPostUpdatedOrDeleted}
        />
      )}
    </>
  );
};

