import React, { useState, useRef, useEffect } from 'react';
import { XMarkIcon, VideoCameraIcon, StopIcon, ArrowPathIcon, MusicalNoteIcon, SparklesIcon, CheckIcon } from '@heroicons/react/24/solid';
import { AudioTrack } from '../types';
import { getAudioTracks } from '../services/storageService';
import AudioSelectionModal from './AudioSelectionModal';

interface RecordReelModalProps {
  onClose: () => void;
  onSave: (videoBlob: Blob, audioTrackId?: string, aiPrompt?: string, filter?: string) => void;
}

const VIDEO_FILTERS = [
  { id: 'none', label: 'Normal', css: '' },
  { id: 'grayscale(100%)', label: 'P&B', css: 'grayscale(1)' },
  { id: 'sepia(100%)', label: 'Sépia', css: 'sepia(1)' },
  { id: 'sepia(50%) brightness(80%) contrast(120%)', label: 'Retrô', css: 'sepia(0.5) brightness(0.8) contrast(1.2)' },
  { id: 'saturate(200%) brightness(110%)', label: 'Vibrante', css: 'saturate(2) brightness(1.1)' },
  { id: 'invert(100%)', label: 'Invertido', css: 'invert(1)' },
];

const RecordReelModal: React.FC<RecordReelModalProps> = ({ onClose, onSave }) => {
  const [isRecording, setIsRecording] = useState(false);
  const [recordedVideo, setRecordedVideo] = useState<Blob | null>(null);
  const [stream, setStream] = useState<MediaStream | null>(null);
  const [timer, setTimer] = useState(0);
  const [showAudioModal, setShowAudioModal] = useState(false);
  const [showFilters, setShowFilters] = useState(false);
  const [selectedAudioId, setSelectedAudioId] = useState<string | undefined>(undefined);
  const [selectedFilter, setSelectedFilter] = useState(VIDEO_FILTERS[0]);
  const [aiPrompt, setAiPrompt] = useState('');

  const videoRef = useRef<HTMLVideoElement>(null);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const chunksRef = useRef<Blob[]>([]);
  const timerIntervalRef = useRef<number | null>(null);

  useEffect(() => {
    startCamera();
    return () => {
      stopCamera();
      if (timerIntervalRef.current) clearInterval(timerIntervalRef.current);
    };
  }, []);

  const startCamera = async () => {
    try {
      const mediaStream = await navigator.mediaDevices.getUserMedia({ 
        video: { facingMode: 'user', aspectRatio: 9/16 }, 
        audio: true 
      });
      setStream(mediaStream);
      if (videoRef.current) videoRef.current.srcObject = mediaStream;
    } catch (err) {
      alert("Erro ao acessar câmera: " + err);
    }
  };

  const stopCamera = () => {
    if (stream) {
      stream.getTracks().forEach(track => track.stop());
    }
  };

  const startRecording = () => {
    if (!stream) return;
    chunksRef.current = [];
    const recorder = new MediaRecorder(stream);
    recorder.ondataavailable = (e) => chunksRef.current.push(e.data);
    recorder.onstop = () => {
      const blob = new Blob(chunksRef.current, { type: 'video/mp4' });
      setRecordedVideo(blob);
    };

    recorder.start();
    mediaRecorderRef.current = recorder;
    setIsRecording(true);
    setTimer(0);

    timerIntervalRef.current = window.setInterval(() => {
      setTimer(prev => {
        if (prev >= 30) {
          stopRecording();
          return 30;
        }
        return prev + 1;
      });
    }, 1000);
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current && isRecording) {
      mediaRecorderRef.current.stop();
      setIsRecording(false);
      if (timerIntervalRef.current) clearInterval(timerIntervalRef.current);
    }
  };

  const handleSave = () => {
    if (recordedVideo) {
      onSave(recordedVideo, selectedAudioId, aiPrompt, selectedFilter.id);
    }
  };

  return (
    <div className="fixed inset-0 bg-black z-[200] flex flex-col animate-fade-in">
      {/* Header */}
      <div className="absolute top-0 left-0 w-full p-6 flex justify-between items-center z-50 bg-gradient-to-b from-black/60 to-transparent">
        <button onClick={onClose} className="p-2 bg-white/10 rounded-full text-white backdrop-blur-md">
          <XMarkIcon className="h-6 w-6" />
        </button>
        <div className="bg-red-600 px-3 py-1 rounded-full text-[10px] font-black text-white uppercase tracking-widest animate-pulse">
          {isRecording ? `Gravando: ${timer}s` : 'Pronto'}
        </div>
        <div className="w-10"></div>
      </div>

      {/* Camera View */}
      <div className="flex-1 relative bg-black flex items-center justify-center overflow-hidden">
        {!recordedVideo ? (
          <video 
            ref={videoRef} 
            autoPlay 
            muted 
            playsInline 
            className="w-full h-full object-cover scale-x-[-1]" 
            style={{ filter: selectedFilter.id === 'none' ? 'none' : selectedFilter.id }}
          />
        ) : (
          <video 
            src={URL.createObjectURL(recordedVideo)} 
            autoPlay 
            loop 
            playsInline 
            className="w-full h-full object-cover" 
            style={{ filter: selectedFilter.id === 'none' ? 'none' : selectedFilter.id }}
          />
        )}

        {/* Overlay Controls (Right Sidebar) */}
        {!isRecording && !recordedVideo && (
          <div className="absolute right-4 top-1/2 -translate-y-1/2 flex flex-col gap-6 z-40">
             <button onClick={() => setShowAudioModal(true)} className="flex flex-col items-center gap-1 group">
                <div className="p-3 bg-black/40 rounded-2xl backdrop-blur-xl border border-white/10 group-active:scale-90 transition-all">
                  <MusicalNoteIcon className="h-6 w-6 text-white" />
                </div>
                <span className="text-[9px] font-black text-white uppercase shadow-lg">Música</span>
             </button>
             <button onClick={() => setShowFilters(!showFilters)} className="flex flex-col items-center gap-1 group">
                <div className={`p-3 bg-black/40 rounded-2xl backdrop-blur-xl border border-white/10 group-active:scale-90 transition-all ${showFilters ? 'ring-2 ring-blue-500' : ''}`}>
                  <SparklesIcon className="h-6 w-6 text-white" />
                </div>
                <span className="text-[9px] font-black text-white uppercase shadow-lg">Filtros</span>
             </button>
          </div>
        )}

        {/* Filters Picker */}
        {showFilters && !isRecording && !recordedVideo && (
          <div className="absolute bottom-32 left-0 w-full z-40 animate-fade-in">
             <div className="flex gap-4 px-6 overflow-x-auto no-scrollbar py-4 bg-black/20 backdrop-blur-md">
                {VIDEO_FILTERS.map(filter => (
                  <button 
                    key={filter.id}
                    onClick={() => setSelectedFilter(filter)}
                    className="flex flex-col items-center gap-2 flex-shrink-0"
                  >
                    <div 
                      className={`w-14 h-14 rounded-full border-2 transition-all overflow-hidden ${selectedFilter.id === filter.id ? 'border-blue-500 scale-110 shadow-lg shadow-blue-500/30' : 'border-white/50'}`}
                      style={{ filter: filter.id === 'none' ? 'none' : filter.id }}
                    >
                       <div className="w-full h-full bg-gray-600"></div>
                    </div>
                    <span className={`text-[8px] font-black uppercase tracking-widest ${selectedFilter.id === filter.id ? 'text-blue-400' : 'text-white'}`}>{filter.label}</span>
                  </button>
                ))}
             </div>
          </div>
        )}
      </div>

      {/* Bottom Controls */}
      <div className="p-8 bg-gradient-to-t from-black to-transparent z-50 flex flex-col items-center gap-6">
        {!recordedVideo ? (
          <button 
            onClick={isRecording ? stopRecording : startRecording}
            className={`w-20 h-20 rounded-full border-4 flex items-center justify-center transition-all ${isRecording ? 'border-red-600 bg-red-600/20' : 'border-white bg-white/10 hover:scale-105'}`}
          >
            {isRecording ? <StopIcon className="h-10 w-10 text-red-600" /> : <div className="w-14 h-14 bg-red-600 rounded-full shadow-xl shadow-red-900/50" />}
          </button>
        ) : (
          <div className="w-full max-w-md space-y-6">
            <div className="bg-white/10 backdrop-blur-xl rounded-[2rem] p-6 border border-white/10">
               <div className="flex items-center gap-3 mb-4">
                  <SparklesIcon className="h-5 w-5 text-purple-400" />
                  <span className="text-[10px] font-black text-white uppercase tracking-widest">Efeito IA Dinâmico</span>
               </div>
               <input 
                type="text" 
                value={aiPrompt}
                onChange={e => setAiPrompt(e.target.value)}
                placeholder="Ex: Transformar em anime, Estilo neon..."
                className="w-full bg-black/40 border-none rounded-xl p-3 text-sm text-white placeholder-gray-500 focus:ring-2 focus:ring-purple-500"
               />
            </div>

            <div className="flex gap-4">
              <button 
                onClick={() => setRecordedVideo(null)} 
                className="flex-1 py-4 bg-white/10 rounded-2xl text-white font-black text-xs uppercase tracking-widest hover:bg-white/20 transition-all flex items-center justify-center gap-2"
              >
                <ArrowPathIcon className="h-4 w-4" /> Refazer
              </button>
              <button 
                onClick={handleSave} 
                className="flex-[2] py-4 bg-blue-600 rounded-2xl text-white font-black text-xs uppercase tracking-widest shadow-xl shadow-blue-900/50 active:scale-95 transition-all flex items-center justify-center gap-2"
              >
                <CheckIcon className="h-5 w-5" /> Concluir Reel
              </button>
            </div>
          </div>
        )}
      </div>

      {showAudioModal && (
        <AudioSelectionModal 
          onClose={() => setShowAudioModal(false)} 
          onSelectTrack={(id) => { setSelectedAudioId(id); setShowAudioModal(false); }} 
        />
      )}
    </div>
  );
};

