  const [scheduledTime, setScheduledTime] = useState('');
  const [showScheduleForm, setShowScheduleForm] = useState(false);

  const [loading, setLoading] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const isEditing = !!postId;
  const isCreator = currentUser.userType === UserType.CREATOR;

  useEffect(() => {
    if (postId) {
      const posts = getPosts();
      const postToEdit = posts.find(p => p.id === postId);
      if (postToEdit) {
        setPostType(postToEdit.type);
        setContent(postToEdit.content || '');
        setImageUrl(postToEdit.imageUrl || '');
        if (postToEdit.type === PostType.REEL && postToEdit.reel) {
          setVideoUrl(postToEdit.reel.videoUrl || '');
          setSelectedAudioTrackId(postToEdit.reel.audioTrackId);
          setContent(postToEdit.reel.description || '');
          setAiEffectPrompt(postToEdit.reel.aiEffectPrompt || '');
          setActiveFilter(postToEdit.reel.filter);
        }
        if (postToEdit.type === PostType.LIVE && postToEdit.liveStream) {
          setContent(postToEdit.liveStream.title);
          setLiveDescription(postToEdit.liveStream.description);
          setIsLivePaid(postToEdit.liveStream.isPaid);
          setLivePrice(postToEdit.liveStream.price?.toString() || '0');
        }
      }
    }
  }, [postId]);

  const handleRecordSave = (blob: Blob, audioId?: string, prompt?: string, filter?: string) => {
    const url = URL.createObjectURL(blob);
    setVideoUrl(url);
    setSelectedAudioTrackId(audioId);
    setAiEffectPrompt(prompt || '');
    setActiveFilter(filter);
    setShowRecorder(false);
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        if (postType === PostType.IMAGE) setImageUrl(reader.result as string);
        else if (postType === PostType.REEL) setVideoUrl(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);

    let scheduledTimestamp: number | undefined = undefined;
    if (isScheduled && scheduledDate && scheduledTime) {
       scheduledTimestamp = new Date(`${scheduledDate}T${scheduledTime}`).getTime();
    }

    try {
      const postData: Post = {
        id: isEditing ? postId! : `post-${Date.now()}`,
        userId: currentUser.id,
        authorName: `${currentUser.firstName} ${currentUser.lastName}`,
        authorProfilePic: currentUser.profilePicture,
        type: postType,
        timestamp: Date.now(),
        scheduledAt: scheduledTimestamp,
        content: (postType === PostType.TEXT || postType === PostType.IMAGE) ? content : undefined,
        imageUrl: postType === PostType.IMAGE ? imageUrl : undefined,
        reel: postType === PostType.REEL ? {
          title: content.split('\n')[0] || 'Novo Reel',
          description: content,
          videoUrl: videoUrl,
          audioTrackId: selectedAudioTrackId,
          aiEffectPrompt: aiEffectPrompt,
          filter: activeFilter
        } : undefined,
        liveStream: postType === PostType.LIVE ? {
          title: content,
          description: liveDescription,
          isPaid: isLivePaid,
          price: isLivePaid ? parseFloat(livePrice) : 0
        } : undefined,
        likes: [],
        comments: [],
        shares: [],
        saves: [],
        indicatedUserIds: [],
      };

      if (isEditing) updatePost(postData);
      else addPost(postData);

      onPostCreated();
      if (!isEditing) setIsExpanded(false);
    } catch (err) {
      alert('Erro ao salvar.');
    } finally {
      setLoading(false);
    }
  };

  if (showRecorder) {
    return <RecordReelModal onClose={() => setShowRecorder(false)} onSave={handleRecordSave} />;
  }

  if (!isExpanded && !isEditing) {
    return (
      <div className="bg-white dark:bg-darkcard rounded-[2rem] shadow-sm p-4 border border-gray-100 dark:border-white/10 flex flex-col gap-3">
         <div className="flex items-start gap-3">
            <img src={currentUser.profilePicture} className="w-10 h-10 rounded-xl object-cover shrink-0" />
            <button onClick={() => setIsExpanded(true)} className="flex-1 text-left px-4 py-2.5 bg-slate-50 dark:bg-white/5 rounded-xl text-gray-400 font-bold text-xs md:text-sm">
              O que você quer compartilhar hoje, {currentUser.firstName}?
            </button>
         </div>
         <div className="flex items-center gap-6 px-1 border-t border-gray-50 dark:border-white/5 pt-2">
            <button onClick={() => { setIsExpanded(true); setPostType(PostType.IMAGE); }} className="flex items-center gap-2 text-gray-500 hover:text-blue-600 transition-all">
               <PhotoIcon className="h-5 w-5 text-blue-500" />
               <span className="text-[10px] font-black uppercase tracking-widest">Imagem</span>
            </button>
            <button onClick={() => { setIsExpanded(true); setPostType(PostType.REEL); }} className="flex items-center gap-2 text-gray-500 hover:text-purple-600 transition-all">
               <FilmIcon className="h-5 w-5 text-purple-500" />
               <span className="text-[10px] font-black uppercase tracking-widest">Reel</span>
            </button>
            <button onClick={() => { if(isCreator) { setIsExpanded(true); setPostType(PostType.LIVE); } }} className={`flex items-center gap-2 transition-all ${isCreator ? 'text-gray-500 hover:text-red-600' : 'text-gray-300 opacity-50 cursor-not-allowed'}`}>
               <VideoCameraIcon className="h-5 w-5 text-red-500" />
               <span className="text-[10px] font-black uppercase tracking-widest">Live</span>
            </button>
         </div>
      </div>
    );
  }

  return (
    <div className="bg-white dark:bg-darkcard rounded-[2.5rem] shadow-2xl p-6 md:p-8 border border-blue-50 dark:border-white/5 animate-fade-in relative overflow-hidden">
      <div className="absolute top-0 left-0 w-2 h-full bg-blue-600"></div>

      <div className="flex items-center justify-between mb-8">
        <div className="flex items-center gap-4">
           <div className={`p-3 text-white rounded-2xl shadow-lg ${postType === PostType.REEL ? 'bg-purple-600' : postType === PostType.LIVE ? 'bg-red-600' : 'bg-blue-600'}`}>
             {postType === PostType.REEL ? <FilmIcon className="h-6 w-6" /> : postType === PostType.LIVE ? <VideoCameraIcon className="h-6 w-6" /> : <SparklesIcon className="h-6 w-6" />}
           </div>
           <div>
              <h3 className="font-black text-gray-900 dark:text-white uppercase text-[10px] tracking-[0.2em]">{isEditing ? 'Editar Post' : 'Novo Conteúdo'}</h3>
              <p className="text-[8px] text-blue-500 font-black uppercase mt-0.5 tracking-widest">Compartilhe conhecimento</p>
           </div>
        </div>
        <button onClick={() => setIsExpanded(false)} className="p-2 text-gray-300 hover:text-red-500 transition-colors"><XMarkIcon className="h-6 w-6" /></button>
      </div>

      <form onSubmit={handleSubmit} className="space-y-6">
        <div className="flex flex-wrap gap-2 p-1.5 bg-slate-50 dark:bg-white/5 rounded-2xl w-fit">
           {[
             { id: PostType.TEXT, icon: DocumentTextIcon, label: 'Texto', locked: false },
             { id: PostType.IMAGE, icon: PhotoIcon, label: 'Imagem', locked: false },
             { id: PostType.REEL, icon: FilmIcon, label: 'Reel', locked: false },
             { id: PostType.LIVE, icon: VideoCameraIcon, label: 'Aula', locked: !isCreator }
           ].map(t => (
             <button key={t.id} type="button" disabled={t.locked} onClick={() => setPostType(t.id)} className={`flex items-center gap-2 px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${postType === t.id ? 'bg-white dark:bg-white/10 text-blue-600 dark:text-white shadow-sm' : 'text-gray-400'} ${t.locked ? 'opacity-30' : ''}`}>
                {t.locked ? <LockClosedIcon className="h-3 w-3" /> : <t.icon className="h-4 w-4" />} {t.label}
             </button>
           ))}
        </div>

        <input
          type="text"
          value={content}
          onChange={(e) => setContent(e.target.value)}
          className="w-full p-6 bg-slate-50 dark:bg-white/5 border-2 border-transparent focus:border-blue-500 rounded-2xl outline-none font-bold text-lg dark:text-white"
          placeholder={postType === PostType.LIVE ? "Título da Aula..." : postType === PostType.REEL ? "Descrição do Reel..." : "O que você quer ensinar?"}
        />

        {postType === PostType.REEL && (
          <div className="space-y-4 animate-fade-in">
             {!videoUrl ? (
               <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <button type="button" onClick={() => setShowRecorder(true)} className="p-10 border-2 border-dashed border-purple-200 dark:border-white/10 rounded-3xl flex flex-col items-center gap-4 hover:bg-purple-50 dark:hover:bg-white/5 transition-all">
                     <VideoCameraIcon className="h-10 w-10 text-purple-600" />
                     <span className="text-[10px] font-black uppercase text-purple-600">Gravar Agora</span>
                  </button>
                  <button type="button" onClick={() => fileInputRef.current?.click()} className="p-10 border-2 border-dashed border-gray-200 dark:border-white/10 rounded-3xl flex flex-col items-center gap-4 hover:bg-gray-50 dark:hover:bg-white/5 transition-all">
                     <ArrowUpTrayIcon className="h-10 w-10 text-gray-400" />
                     <span className="text-[10px] font-black uppercase text-gray-500">Subir Arquivo</span>
                  </button>
                  <input ref={fileInputRef} type="file" accept="video/*" className="hidden" onChange={handleFileChange} />
               </div>
             ) : (
               <div className="relative rounded-3xl overflow-hidden border-4 border-purple-500 shadow-2xl aspect-[9/16] max-h-[400px] mx-auto group">
                  <video src={videoUrl} className="w-full h-full object-cover" style={{ filter: activeFilter || 'none' }} controls />
                  <button onClick={() => { setVideoUrl(''); setActiveFilter(undefined); }} className="absolute top-4 right-4 p-2 bg-red-600 text-white rounded-full opacity-0 group-hover:opacity-100 transition-opacity"><TrashIcon className="h-5 w-5"/></button>
                  {aiEffectPrompt && (
                    <div className="absolute bottom-4 left-4 bg-purple-600/90 text-white px-3 py-1 rounded-lg text-[8px] font-black uppercase backdrop-blur-md">
                      Prompt IA: {aiEffectPrompt}
                    </div>
                  )}
               </div>
             )}
          </div>
        )}

        {postType === PostType.IMAGE && (
          <div className="space-y-4 animate-fade-in">
             <input type="file" ref={fileInputRef} onChange={handleFileChange} accept="image/*" className="hidden" />
             {!imageUrl ? (
               <div onClick={() => fileInputRef.current?.click()} className="w-full h-64 border-2 border-dashed border-gray-200 dark:border-white/10 rounded-3xl flex flex-col items-center justify-center gap-4 cursor-pointer hover:border-blue-500 transition-all group">
                  <ArrowUpTrayIcon className="h-8 w-8 text-gray-400 group-hover:text-blue-600" />
                  <span className="text-[10px] font-black text-gray-400 uppercase">Escolher Imagem</span>
               </div>
             ) : (
               <div className="relative rounded-3xl overflow-hidden border-2 border-blue-500 group">
                  <img src={imageUrl} className="w-full h-auto max-h-[400px] object-cover" alt="Preview" />
                  <button onClick={() => setImageUrl('')} className="absolute top-4 right-4 p-2 bg-red-600 text-white rounded-full opacity-0 group-hover:opacity-100 transition-opacity"><TrashIcon className="h-5 w-5"/></button>
               </div>
             )}
          </div>
        )}

        <div className="flex justify-end gap-3 pt-6 border-t dark:border-white/5">
           <button type="submit" disabled={loading || !content} className="bg-blue-600 text-white px-10 py-4 rounded-2xl font-black text-xs uppercase shadow-xl hover:bg-blue-700 active:scale-95 transition-all flex items-center gap-2">
              {loading ? 'Publicando...' : 'Publicar'} <ChevronRightIcon className="h-4 w-4" />
           </button>
        </div>
      </form>
    </div>
  );
};

export default CreatePost;

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { Post, User, PostType, AudioTrack } from '../types';
import { 
  getPosts, 
  findUserById, 
  updatePostLikes, 
  updatePostShares, 
  toggleFollowUser, 
  findAudioTrackById, 
  updatePostSaves 
} from '../services/storageService';
import { DEFAULT_PROFILE_PIC } from '../constants';
import {
  HeartIcon as HeartIconOutline,
  ChatBubbleOvalLeftIcon as ChatIconOutline,
  ShareIcon as ShareIconOutline,
  SpeakerWaveIcon,
  SpeakerXMarkIcon,
  PlayIcon,
  BookmarkIcon as BookmarkIconOutline,
  PaperAirplaneIcon,
  EyeIcon
} from '@heroicons/react/24/outline';
import {
  HeartIcon as HeartIconSolid,
  BookmarkIcon as BookmarkIconSolid,
  PlusIcon
} from '@heroicons/react/24/solid';
import CommentsModal from './CommentsModal';
import IndicateModal from './IndicateModal';

interface ReelsPageProps {
  currentUser: User;
  onNavigate: (page: string, params?: Record<string, string>) => void;
  refreshUser: () => void;
}

interface ReelVideoProps {
  post: Post;
  currentUser: User;
  onNavigate: (page: string, params?: Record<string, string>) => void;
  onFollowToggle: (userIdToFollow: string) => void;
  refreshUser: () => void;
  isIntersecting: boolean;
  onPostUpdate: () => void;
}

const ReelVideo: React.FC<ReelVideoProps> = ({ post, currentUser, onNavigate, onFollowToggle, refreshUser, isIntersecting, onPostUpdate }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const audioRef = useRef<HTMLAudioElement>(null);

  const [isMuted, setIsMuted] = useState(true);
  const [showPlayIcon, setShowPlayIcon] = useState(false);
  const [isCommentsModalOpen, setIsCommentsModalOpen] = useState(false);
  const [isIndicateModalOpen, setIsIndicateModalOpen] = useState(false);
  const [likeHearts, setLikeHearts] = useState<{ id: number; x: number; y: number }[]>([]);
  const [videoProgress, setVideoProgress] = useState(0);

  const clickTimeout = useRef<number | null>(null);

  const postAuthor = findUserById(post.userId);
  const isFollowing = currentUser.followedUsers.includes(post.userId);
  const hasLiked = post.likes.includes(currentUser.id);
  const hasSaved = post.saves.includes(currentUser.id);
  const [audioTrack, setAudioTrack] = useState<AudioTrack | null>(null);

  useEffect(() => {
    if (post.reel?.audioTrackId) {
      setAudioTrack(findAudioTrackById(post.reel.audioTrackId) || null);
    } else {
      setAudioTrack(null);
    }
  }, [post.reel?.audioTrackId]);

  const syncPlay = useCallback(async () => {
    const video = videoRef.current;
    const audio = audioRef.current;
    if (!video) return;

    try {
      video.muted = isMuted || !!audioTrack;
      if (video.paused) await video.play();
      if (audio && !video.muted) {
        audio.muted = false;
        if (audio.paused) await audio.play();
      }
    } catch (e) {
      console.log("Autoplay bloqueado");
    }
  }, [isMuted, audioTrack]);

  const syncPause = useCallback(() => {
    const video = videoRef.current;
    const audio = audioRef.current;
    if (video && !video.paused) video.pause();
    if (audio && !audio.paused) audio.pause();
  }, []);

  useEffect(() => {
    if (isIntersecting) {
      syncPlay();
    } else {
      syncPause();
    }
  }, [isIntersecting, syncPlay, syncPause]);

  useEffect(() => {
    if (videoRef.current) videoRef.current.muted = isMuted || !!audioTrack;
    if (audioRef.current) audioRef.current.muted = isMuted;
  }, [isMuted, audioTrack]);

  const handleTimeUpdate = () => {
    if (videoRef.current) {
      const progress = (videoRef.current.currentTime / videoRef.current.duration) * 100;
      setVideoProgress(progress);
    }
  };

  const togglePlayPause = () => {
    const video = videoRef.current;
    if (!video) return;
    if (video.paused) {
      syncPlay();
    } else {
      syncPause();
      setShowPlayIcon(true);
      setTimeout(() => setShowPlayIcon(false), 500);
    }
  };

  const handleLike = () => {
    updatePostLikes(post.id, currentUser.id);
    onPostUpdate();
    refreshUser();
  };

  const handleDoubleClick = (e: React.MouseEvent | React.TouchEvent) => {
    const rect = (e.currentTarget as HTMLElement).getBoundingClientRect();
    const x = ('clientX' in e ? e.clientX : e.touches[0].clientX) - rect.left;
    const y = ('clientY' in e ? e.clientY : e.touches[0].clientY) - rect.top;

    const newHeart = { id: Date.now(), x, y };
    setLikeHearts(prev => [...prev, newHeart]);
    if (!hasLiked) handleLike();
    setTimeout(() => setLikeHearts(prev => prev.filter(h => h.id !== newHeart.id)), 800);
  };

  const handleContainerClick = (e: React.MouseEvent) => {
    if (clickTimeout.current) {
      window.clearTimeout(clickTimeout.current);
      clickTimeout.current = null;
      handleDoubleClick(e);
    } else {
      clickTimeout.current = window.setTimeout(() => {
        togglePlayPause();
        clickTimeout.current = null;
      }, 250);
    }
  };

  const handleShare = async (e: React.MouseEvent) => {
    e.stopPropagation();
    if (navigator.share) {
      try {
        await navigator.share({
          title: post.reel?.title || 'Video CyBerPhone',
          text: post.reel?.description,
          url: window.location.href
        });
        updatePostShares(post.id, currentUser.id);
        onPostUpdate();
      } catch (err) {}
    } else {
      alert('Link copiado!');
    }
  };

  if (!postAuthor || !post.reel) return null;

  return (
    <>
      <div
        className="relative w-full h-full flex-shrink-0 snap-start bg-black overflow-hidden touch-none group/reel"
        onClick={handleContainerClick}
      >
        <video
          ref={videoRef}
          src={post.reel.videoUrl}
          loop
          playsInline
          webkit-playsinline="true"
          preload="auto"
          onTimeUpdate={handleTimeUpdate}
          className="absolute inset-0 w-full h-full object-cover"
          style={{ filter: post.reel.filter || 'none' }}
        />

        {audioTrack && <audio ref={audioRef} src={audioTrack.url} loop preload="auto" />}

        {/* Barra de Progresso */}
        <div className="absolute bottom-0 left-0 w-full h-0.5 bg-white/20 z-50">
           <div 
             className="h-full bg-blue-500 transition-all duration-100 ease-linear shadow-[0_0_8px_rgba(59,130,246,0.8)]" 
             style={{ width: `${videoProgress}%` }}
           />
        </div>

        {/* Play/Pause Overlay */}
        <div className={`absolute inset-0 flex items-center justify-center transition-opacity duration-300 pointer-events-none z-20 ${showPlayIcon ? 'opacity-100' : 'opacity-0'}`}>
          <div className="bg-black/20 p-6 rounded-full backdrop-blur-sm">
            <PlayIcon className="h-16 w-16 text-white" />
          </div>
        </div>

        {/* Like Hearts */}
        {likeHearts.map(heart => (
          <div key={heart.id} className="absolute z-50 pointer-events-none animate-like-heart" style={{ left: heart.x - 40, top: heart.y - 40 }}>
            <HeartIconSolid className="w-24 h-24 text-blue-500 drop-shadow-2xl" />
          </div>
        ))}

        {/* Mute Button */}
        <button 
          onClick={(e) => { e.stopPropagation(); setIsMuted(!isMuted); }} 
          className="absolute top-4 right-4 z-40 p-3 bg-black/30 rounded-full text-white backdrop-blur-md border border-white/10 active:scale-90 transition-all"
        >
          {isMuted ? <SpeakerXMarkIcon className="h-6 w-6" /> : <SpeakerWaveIcon className="h-6 w-6" />}
        </button>

        {/* Informações (Bottom Left) */}
        <div className="absolute bottom-0 left-0 p-5 pb-10 text-white z-30 w-full pointer-events-none">
          <div className="flex flex-col space-y-3 pointer-events-auto max-w-[80%]">
            <div className="flex items-center gap-3">
               <h4 className="font-black text-lg drop-shadow-lg cursor-pointer hover:underline" onClick={(e) => { e.stopPropagation(); onNavigate('profile', { userId: post.userId }); }}>
                 @{post.authorName}
               </h4>
               <span className="text-[10px] bg-blue-600 px-2 py-0.5 rounded-lg font-black uppercase">Expert</span>
            </div>

            <p className="text-sm font-medium drop-shadow-md leading-snug line-clamp-2">{post.reel.description}</p>

            <div className="flex items-center gap-4">
              <div className="flex items-center gap-1 opacity-80">
                <EyeIcon className="h-3.5 w-3.5" />
                <span className="text-[10px] font-black">{Math.floor(post.likes.length * 12.5)} visualizações</span>
              </div>
              {audioTrack && (
                <div className="flex items-center gap-2 bg-black/40 backdrop-blur-md px-3 py-1.5 rounded-full overflow-hidden border border-white/10">
                  <div className="marquee text-[9px] font-black uppercase tracking-wider whitespace-nowrap overflow-hidden max-w-[120px]">
                    <span className="marquee-content">{audioTrack.title} - {audioTrack.artist}</span>
                  </div>
                </div>
              )}
            </div>
          </div>
        </div>

        {/* Sidebar (Right) */}
        <div className="absolute bottom-12 right-2 flex flex-col items-center space-y-5 z-40 w-14">
          <div className="relative mb-2">
             <div className="w-12 h-12 rounded-2xl border-2 border-white overflow-hidden shadow-2xl cursor-pointer active:scale-95 transition-transform" onClick={(e) => { e.stopPropagation(); onNavigate('profile', { userId: post.userId }); }}>
                <img src={postAuthor.profilePicture || DEFAULT_PROFILE_PIC} className="w-full h-full object-cover" alt="" />
             </div>
             {!isFollowing && currentUser.id !== post.userId && (
               <button onClick={(e) => { e.stopPropagation(); onFollowToggle(post.userId); }} className="absolute -bottom-2 left-1/2 -translate-x-1/2 bg-blue-600 rounded-full p-1 border-2 border-black shadow-lg active:scale-125 transition-transform">
                 <PlusIcon className="w-3.5 h-3.5 text-white" />
               </button>
             )}
          </div>

          <button onClick={(e) => { e.stopPropagation(); handleLike(); }} className="flex flex-col items-center group active:scale-125 transition-transform">
              <div className="p-1">
                {hasLiked ? <HeartIconSolid className="h-9 w-9 text-blue-500 drop-shadow-lg" /> : <HeartIconSolid className="h-9 w-9 text-white/90 drop-shadow-lg" />}
              </div>
              <span className="text-[11px] font-black text-white drop-shadow-lg mt-0.5">{post.likes.length}</span>
          </button>

          <button onClick={(e) => { e.stopPropagation(); setIsCommentsModalOpen(true); }} className="flex flex-col items-center group active:scale-125 transition-transform">
              <div className="p-1">
                <ChatIconOutline className="h-9 w-9 text-white/90 drop-shadow-lg" />
              </div>
              <span className="text-[11px] font-black text-white drop-shadow-lg mt-0.5">{post.comments.length}</span>
          </button>

          <button onClick={(e) => { e.stopPropagation(); setIsIndicateModalOpen(true); }} className="flex flex-col items-center group active:scale-125 transition-transform">
              <div className="p-1">
                <PaperAirplaneIcon className="h-9 w-9 text-white/90 drop-shadow-lg -rotate-45" />
              </div>
              <span className="text-[11px] font-black text-white drop-shadow-lg mt-0.5">Indicar</span>
          </button>

          <button onClick={(e) => { e.stopPropagation(); updatePostSaves(post.id, currentUser.id); onPostUpdate(); }} className="flex flex-col items-center group active:scale-125 transition-transform">
              <div className="p-1">
                {hasSaved ? <BookmarkIconSolid className="h-9 w-9 text-yellow-400 drop-shadow-lg" /> : <BookmarkIconSolid className="h-9 w-9 text-white/90 drop-shadow-lg" />}
              </div>
              <span className="text-[11px] font-black text-white drop-shadow-lg mt-0.5">{post.saves.length}</span>
          </button>

          <button onClick={handleShare} className="flex flex-col items-center group active:scale-125 transition-transform">
              <div className="p-1">
                <ShareIconOutline className="h-9 w-9 text-white/90 drop-shadow-lg" />
              </div>
              <span className="text-[11px] font-black text-white drop-shadow-lg mt-0.5">{post.shares.length}</span>
