          <div className="pt-2">
             <div className={`w-10 h-10 rounded-full bg-gradient-to-tr from-gray-900 to-gray-700 border-[3px] border-white/20 shadow-2xl flex items-center justify-center overflow-hidden ${isIntersecting ? 'animate-spin-slow' : ''}`}>
                <img src={postAuthor.profilePicture || DEFAULT_PROFILE_PIC} className="w-full h-full opacity-50 object-cover" alt="" />
                <div className="absolute inset-0 flex items-center justify-center"><div className="w-2 h-2 bg-white rounded-full"></div></div>
             </div>
          </div>
        </div>

        <div className="absolute bottom-0 left-0 w-full h-60 bg-gradient-to-t from-black/90 via-black/30 to-transparent z-10 pointer-events-none"></div>
