import React, { useState, useRef, useEffect } from 'react';
import { XMarkIcon, VideoCameraIcon, StopIcon, ArrowPathIcon, MusicalNoteIcon, SparklesIcon, CheckIcon, MagicWandIcon } from '@heroicons/react/24/solid';
import { AudioTrack } from '../types';
import { getAudioTracks } from '../services/storageService';
import AudioSelectionModal from './AudioSelectionModal';

interface RecordReelModalProps {
  onClose: () => void;
  onSave: (videoBlob: Blob, audioTrackId?: string, aiPrompt?: string, filter?: string) => void;
}

const VIDEO_FILTERS = [
  { id: 'none', label: 'Normal', css: '' },
  { id: 'grayscale(1) contrast(1.2)', label: 'Noir', css: 'grayscale(1) contrast(1.2)' },
  { id: 'sepia(0.4) saturate(1.8) brightness(1.1)', label: 'Dourado', css: 'sepia(0.4) saturate(1.8) brightness(1.1)' },
  { id: 'hue-rotate(180deg) saturate(1.2)', label: 'Gelo', css: 'hue-rotate(180deg) saturate(1.2)' },
  { id: 'contrast(1.4) brightness(0.9) saturate(1.1)', label: 'Drama', css: 'contrast(1.4) brightness(0.9) saturate(1.1)' },
  { id: 'hue-rotate(90deg) brightness(1.2)', label: 'Pop Art', css: 'hue-rotate(90deg) brightness(1.2)' },
  { id: 'invert(0.9) hue-rotate(180deg)', label: 'Raio-X', css: 'invert(0.9) hue-rotate(180deg)' },
  { id: 'blur(2px) saturate(2)', label: 'Sonho', css: 'blur(1px) saturate(2)' },
];

const RecordReelModal: React.FC<RecordReelModalProps> = ({ onClose, onSave }) => {
  const [isRecording, setIsRecording] = useState(false);
  const [recordedVideo, setRecordedVideo] = useState<Blob | null>(null);
  const [stream, setStream] = useState<MediaStream | null>(null);
  const [timer, setTimer] = useState(0);
  const [showAudioModal, setShowAudioModal] = useState(false);
  const [showFilters, setShowFilters] = useState(false);
  const [selectedAudioId, setSelectedAudioId] = useState<string | undefined>(undefined);
  const [selectedFilter, setSelectedFilter] = useState(VIDEO_FILTERS[0]);
  const [aiPrompt, setAiPrompt] = useState('');

  const videoRef = useRef<HTMLVideoElement>(null);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const chunksRef = useRef<Blob[]>([]);
  const timerIntervalRef = useRef<number | null>(null);

  useEffect(() => {
    startCamera();
    return () => {
      stopCamera();
      if (timerIntervalRef.current) clearInterval(timerIntervalRef.current);
    };
  }, []);

  const startCamera = async () => {
    try {
      const mediaStream = await navigator.mediaDevices.getUserMedia({ 
        video: { facingMode: 'user', aspectRatio: 9/16 }, 
        audio: true 
      });
      setStream(mediaStream);
      if (videoRef.current) videoRef.current.srcObject = mediaStream;
    } catch (err) {
      alert("Permissão de câmera negada ou erro no hardware.");
    }
  };

  const stopCamera = () => {
    if (stream) {
      stream.getTracks().forEach(track => track.stop());
    }
  };

  const startRecording = () => {
    if (!stream) return;
    chunksRef.current = [];
    const recorder = new MediaRecorder(stream);
    recorder.ondataavailable = (e) => chunksRef.current.push(e.data);
    recorder.onstop = () => {
      const blob = new Blob(chunksRef.current, { type: 'video/mp4' });
      setRecordedVideo(blob);
    };

    recorder.start();
    mediaRecorderRef.current = recorder;
    setIsRecording(true);
    setTimer(0);

    timerIntervalRef.current = window.setInterval(() => {
      setTimer(prev => {
        if (prev >= 60) {
          stopRecording();
          return 60;
        }
        return prev + 1;
      });
    }, 1000);
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current && isRecording) {
      mediaRecorderRef.current.stop();
      setIsRecording(false);
      if (timerIntervalRef.current) clearInterval(timerIntervalRef.current);
    }
  };

  const handleSave = () => {
    if (recordedVideo) {
      onSave(recordedVideo, selectedAudioId, aiPrompt, selectedFilter.id);
    }
  };

  return (
    <div className="fixed inset-0 bg-black z-[200] flex flex-col animate-fade-in overflow-hidden">
      {/* Header Bar */}
      <div className="absolute top-0 left-0 w-full p-6 flex justify-between items-center z-50 bg-gradient-to-b from-black/80 to-transparent">
        <button onClick={onClose} className="p-3 bg-white/10 rounded-full text-white backdrop-blur-md hover:bg-white/20 transition-all">
          <XMarkIcon className="h-6 w-6" />
        </button>

        <div className="flex flex-col items-center">
           <div className={`px-4 py-1.5 rounded-full text-[10px] font-black text-white uppercase tracking-[0.2em] transition-colors ${isRecording ? 'bg-red-600 animate-pulse' : 'bg-white/20 backdrop-blur-md'}`}>
             {isRecording ? `Gravando • ${timer}s` : 'Pronto para Gravar'}
           </div>
        </div>

        <div className="w-12"></div>
      </div>

      {/* Viewport */}
      <div className="flex-1 relative bg-[#050505] flex items-center justify-center">
        {!recordedVideo ? (
          <video 
            ref={videoRef} 
            autoPlay 
            muted 
            playsInline 
            className="w-full h-full object-cover scale-x-[-1]" 
            style={{ filter: selectedFilter.id === 'none' ? 'none' : selectedFilter.id }}
          />
        ) : (
          <video 
            src={URL.createObjectURL(recordedVideo)} 
            autoPlay 
            loop 
            playsInline 
            className="w-full h-full object-cover" 
            style={{ filter: selectedFilter.id === 'none' ? 'none' : selectedFilter.id }}
          />
        )}

        {/* Sidebar Tools */}
        {!isRecording && !recordedVideo && (
          <div className="absolute right-5 top-1/2 -translate-y-1/2 flex flex-col gap-6 z-40">
             <button onClick={() => setShowAudioModal(true)} className="flex flex-col items-center gap-1.5 group">
                <div className={`p-4 rounded-2xl backdrop-blur-xl border border-white/20 transition-all shadow-2xl ${selectedAudioId ? 'bg-blue-600' : 'bg-black/40 group-hover:bg-black/60'}`}>
                  <MusicalNoteIcon className="h-6 w-6 text-white" />
                </div>
                <span className="text-[8px] font-black text-white uppercase tracking-widest shadow-lg">Música</span>
             </button>

             <button onClick={() => setShowFilters(!showFilters)} className="flex flex-col items-center gap-1.5 group">
                <div className={`p-4 rounded-2xl backdrop-blur-xl border border-white/20 transition-all shadow-2xl ${showFilters ? 'bg-purple-600 scale-110' : 'bg-black/40 group-hover:bg-black/60'}`}>
                  <SparklesIcon className="h-6 w-6 text-white" />
                </div>
                <span className="text-[8px] font-black text-white uppercase tracking-widest shadow-lg">Efeitos</span>
             </button>
          </div>
        )}

        {/* Bottom Horizontal Filter Picker */}
        {showFilters && !isRecording && !recordedVideo && (
          <div className="absolute bottom-36 left-0 w-full z-40 animate-slide-up-fade">
             <div className="flex gap-5 px-8 overflow-x-auto no-scrollbar py-6">
                {VIDEO_FILTERS.map(filter => (
                  <button 
                    key={filter.id}
                    onClick={() => setSelectedFilter(filter)}
                    className="flex flex-col items-center gap-3 flex-shrink-0 group"
                  >
                    <div 
                      className={`w-16 h-16 rounded-2xl border-2 transition-all duration-300 overflow-hidden relative ${selectedFilter.id === filter.id ? 'border-white scale-115 shadow-[0_0_20px_rgba(255,255,255,0.3)]' : 'border-white/20 opacity-60 group-hover:opacity-100'}`}
                    >
                       <div className="w-full h-full bg-gradient-to-tr from-gray-800 to-gray-600" style={{ filter: filter.id === 'none' ? 'none' : filter.id }}></div>
                       {selectedFilter.id === filter.id && (
                         <div className="absolute inset-0 flex items-center justify-center bg-white/10">
                            <CheckIcon className="h-6 w-6 text-white" />
                         </div>
                       )}
                    </div>
                    <span className={`text-[9px] font-black uppercase tracking-widest transition-colors ${selectedFilter.id === filter.id ? 'text-white' : 'text-white/40'}`}>{filter.label}</span>
                  </button>
                ))}
             </div>
          </div>
        )}
      </div>

      {/* Footer Controls */}
      <div className="p-10 bg-gradient-to-t from-black via-black/60 to-transparent z-50 flex flex-col items-center gap-8">
        {!recordedVideo ? (
          <div className="flex items-center gap-10">
             <div className="w-12"></div> {/* Spacer for symmetry */}
             <button 
                onClick={isRecording ? stopRecording : startRecording}
                className={`relative group transition-all duration-500 ${isRecording ? 'scale-110' : 'hover:scale-105'}`}
             >
                <div className={`absolute inset-0 rounded-full blur-xl opacity-50 group-hover:opacity-100 transition-opacity ${isRecording ? 'bg-red-600' : 'bg-white'}`}></div>
                <div className={`w-20 h-20 rounded-full border-4 flex items-center justify-center relative z-10 ${isRecording ? 'border-red-600 bg-red-600/20' : 'border-white bg-white/10'}`}>
                  {isRecording ? <StopIcon className="h-10 w-10 text-red-600" /> : <div className="w-14 h-14 bg-red-600 rounded-full shadow-2xl" />}
                </div>
             </button>
             <button className="p-3 bg-white/10 rounded-full text-white/40 hover:text-white transition-all">
                <ArrowPathIcon className="h-6 w-6" />
             </button>
          </div>
        ) : (
          <div className="w-full max-w-lg animate-fade-in space-y-8">
            <div className="bg-white/10 backdrop-blur-2xl rounded-[2.5rem] p-8 border border-white/10 shadow-2xl">
               <div className="flex items-center gap-3 mb-5">
                  <div className="bg-purple-600 p-2 rounded-xl"><SparklesIcon className="h-5 w-5 text-white" /></div>
                  <span className="text-[10px] font-black text-white uppercase tracking-[0.2em]">Estilo por Inteligência Artificial</span>
               </div>
               <p className="text-white/40 text-[10px] mb-4 font-medium uppercase tracking-widest px-1">Descreva o clima ou estilo visual desejado:</p>
               <div className="relative group">
                  <input 
                    type="text" 
                    value={aiPrompt}
                    onChange={e => setAiPrompt(e.target.value)}
                    placeholder="Ex: Cyberpunk Neon, Estilo Ghibli, Retrô 80s..."
                    className="w-full bg-black/40 border-2 border-white/5 rounded-2xl p-5 text-sm text-white placeholder-white/20 focus:ring-0 focus:border-purple-500 transition-all font-bold"
                  />
                  <div className="absolute right-4 top-1/2 -translate-y-1/2 opacity-20 group-hover:opacity-100 transition-opacity">
                    <SparklesIcon className="h-5 w-5 text-purple-400" />
                  </div>
               </div>
            </div>

            <div className="flex gap-4">
              <button 
                onClick={() => { setRecordedVideo(null); setAiPrompt(''); }} 
                className="flex-1 py-5 bg-white/10 rounded-3xl text-white font-black text-xs uppercase tracking-[0.2em] hover:bg-white/20 transition-all flex items-center justify-center gap-3 border border-white/5"
              >
                <ArrowPathIcon className="h-4 w-4" /> Descartar
              </button>
              <button 
                onClick={handleSave} 
                className="flex-[2] py-5 bg-blue-600 rounded-3xl text-white font-black text-xs uppercase tracking-[0.2em] shadow-[0_20px_40px_rgba(37,99,235,0.4)] active:scale-95 transition-all flex items-center justify-center gap-3"
              >
                <CheckIcon className="h-5 w-5" /> Compartilhar Reel
              </button>
            </div>
          </div>
        )}
      </div>

      {showAudioModal && (
        <AudioSelectionModal 
          onClose={() => setShowAudioModal(false)} 
          onSelectTrack={(id) => { setSelectedAudioId(id); setShowAudioModal(false); }} 
        />
      )}

      <style>{`
        @keyframes slide-up-fade {
          from { transform: translateY(20px); opacity: 0; }
          to { transform: translateY(0); opacity: 1; }
        }
        .animate-slide-up-fade { animation: slide-up-fade 0.4s cubic-bezier(0.16, 1, 0.3, 1) forwards; }
        .no-scrollbar::-webkit-scrollbar { display: none; }
        .no-scrollbar { -ms-overflow-style: none; scrollbar-width: none; }
      `}</style>
    </div>
  );
};

export default RecordReelModal;

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { Post, User, PostType, AudioTrack } from '../types';
import { 
  getPosts, 
  findUserById, 
  updatePostLikes, 
  updatePostShares, 
  toggleFollowUser, 
  findAudioTrackById, 
  updatePostSaves 
} from '../services/storageService';
import { DEFAULT_PROFILE_PIC } from '../constants';
import {
  HeartIcon as HeartIconOutline,
  ChatBubbleOvalLeftIcon as ChatIconOutline,
  ShareIcon as ShareIconOutline,
  SpeakerWaveIcon,
  SpeakerXMarkIcon,
  PlayIcon,
  BookmarkIcon as BookmarkIconOutline,
  PaperAirplaneIcon,
  EyeIcon,
  SparklesIcon
} from '@heroicons/react/24/outline';
import {
  HeartIcon as HeartIconSolid,
  BookmarkIcon as BookmarkIconSolid,
  PlusIcon
} from '@heroicons/react/24/solid';
import CommentsModal from './CommentsModal';
import IndicateModal from './IndicateModal';

interface ReelsPageProps {
  currentUser: User;
  onNavigate: (page: string, params?: Record<string, string>) => void;
  refreshUser: () => void;
}

interface ReelVideoProps {
  post: Post;
  currentUser: User;
  onNavigate: (page: string, params?: Record<string, string>) => void;
  onFollowToggle: (userIdToFollow: string) => void;
  refreshUser: () => void;
  isIntersecting: boolean;
  onPostUpdate: () => void;
}

const ReelVideo: React.FC<ReelVideoProps> = ({ post, currentUser, onNavigate, onFollowToggle, refreshUser, isIntersecting, onPostUpdate }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const audioRef = useRef<HTMLAudioElement>(null);

  const [isMuted, setIsMuted] = useState(true);
  const [showPlayIcon, setShowPlayIcon] = useState(false);
  const [isCommentsModalOpen, setIsCommentsModalOpen] = useState(false);
  const [isIndicateModalOpen, setIsIndicateModalOpen] = useState(false);
  const [likeHearts, setLikeHearts] = useState<{ id: number; x: number; y: number }[]>([]);
  const [videoProgress, setVideoProgress] = useState(0);

  const clickTimeout = useRef<number | null>(null);

  const postAuthor = findUserById(post.userId);
  const isFollowing = currentUser.followedUsers.includes(post.userId);
  const hasLiked = post.likes.includes(currentUser.id);
  const hasSaved = post.saves.includes(currentUser.id);
  const [audioTrack, setAudioTrack] = useState<AudioTrack | null>(null);

  useEffect(() => {
    if (post.reel?.audioTrackId) {
      setAudioTrack(findAudioTrackById(post.reel.audioTrackId) || null);
    } else {
      setAudioTrack(null);
    }
  }, [post.reel?.audioTrackId]);

  const syncPlay = useCallback(async () => {
    const video = videoRef.current;
    const audio = audioRef.current;
    if (!video) return;

    try {
      video.muted = isMuted || !!audioTrack;
      if (video.paused) await video.play();
      if (audio && !video.muted) {
        audio.muted = false;
        if (audio.paused) await audio.play();
      }
    } catch (e) {
      // Ignora erro de interrupção de autoplay
    }
  }, [isMuted, audioTrack]);

  const syncPause = useCallback(() => {
    const video = videoRef.current;
    const audio = audioRef.current;
    if (video && !video.paused) video.pause();
    if (audio && !audio.paused) audio.pause();
  }, []);

  useEffect(() => {
    if (isIntersecting) {
      syncPlay();
    } else {
      syncPause();
    }
  }, [isIntersecting, syncPlay, syncPause]);

  useEffect(() => {
    if (videoRef.current) videoRef.current.muted = isMuted || !!audioTrack;
    if (audioRef.current) audioRef.current.muted = isMuted;
  }, [isMuted, audioTrack]);

  const handleTimeUpdate = () => {
    if (videoRef.current) {
      const progress = (videoRef.current.currentTime / videoRef.current.duration) * 100;
      setVideoProgress(progress);
    }
  };

  const togglePlayPause = () => {
    const video = videoRef.current;
    if (!video) return;
    if (video.paused) {
      syncPlay();
    } else {
      syncPause();
      setShowPlayIcon(true);
      setTimeout(() => setShowPlayIcon(false), 500);
    }
  };

  const handleLike = () => {
    updatePostLikes(post.id, currentUser.id);
    onPostUpdate();
    refreshUser();
  };

  const handleDoubleClick = (e: React.MouseEvent | React.TouchEvent) => {
    const rect = (e.currentTarget as HTMLElement).getBoundingClientRect();
    const x = ('clientX' in e ? e.clientX : e.touches[0].clientX) - rect.left;
    const y = ('clientY' in e ? e.clientY : e.touches[0].clientY) - rect.top;

    const newHeart = { id: Date.now(), x, y };
    setLikeHearts(prev => [...prev, newHeart]);
    if (!hasLiked) handleLike();
    setTimeout(() => setLikeHearts(prev => prev.filter(h => h.id !== newHeart.id)), 800);
  };

  const handleContainerClick = (e: React.MouseEvent) => {
    if (clickTimeout.current) {
      window.clearTimeout(clickTimeout.current);
      clickTimeout.current = null;
      handleDoubleClick(e);
    } else {
      clickTimeout.current = window.setTimeout(() => {
        togglePlayPause();
        clickTimeout.current = null;
      }, 250);
    }
  };

  if (!postAuthor || !post.reel) return null;

  return (
    <>
      <div
        className="relative w-full h-full flex-shrink-0 snap-start bg-black overflow-hidden touch-none group/reel"
        onClick={handleContainerClick}
      >
        {/* Camada de Vídeo com Filtro Dinâmico */}
        <div className="absolute inset-0 w-full h-full">
           <video
            ref={videoRef}
            src={post.reel.videoUrl}
            loop
            playsInline
            webkit-playsinline="true"
            preload="auto"
            onTimeUpdate={handleTimeUpdate}
            className="w-full h-full object-cover transition-all duration-700"
            style={{ filter: post.reel.filter || 'none' }}
          />
          {/* Overlay de Brilho IA (se houver prompt) */}
          {post.reel.aiEffectPrompt && (
            <div className="absolute inset-0 pointer-events-none bg-purple-500/5 mix-blend-overlay animate-pulse"></div>
          )}
        </div>

        {audioTrack && <audio ref={audioRef} src={audioTrack.url} loop preload="auto" />}

        {/* Barra de Progresso Superior (Estilo Moderno) */}
        <div className="absolute top-0 left-0 w-full h-1 bg-white/10 z-50">
           <div 
             className="h-full bg-white transition-all duration-100 ease-linear shadow-[0_0_10px_rgba(255,255,255,0.5)]" 
             style={{ width: `${videoProgress}%` }}
           />
        </div>

        {/* Play/Pause Overlay */}
        <div className={`absolute inset-0 flex items-center justify-center transition-opacity duration-300 pointer-events-none z-20 ${showPlayIcon ? 'opacity-100' : 'opacity-0'}`}>
          <div className="bg-black/30 p-8 rounded-full backdrop-blur-md border border-white/10">
            <PlayIcon className="h-12 w-12 text-white" />
          </div>
        </div>

        {/* Like Hearts */}
        {likeHearts.map(heart => (
          <div key={heart.id} className="absolute z-50 pointer-events-none animate-like-heart" style={{ left: heart.x - 50, top: heart.y - 50 }}>
            <HeartIconSolid className="w-24 h-24 text-blue-500 drop-shadow-[0_0_30px_rgba(59,130,246,0.6)]" />
          </div>
        ))}

        {/* Mute/Sound Button */}
        <button 
          onClick={(e) => { e.stopPropagation(); setIsMuted(!isMuted); }} 
          className="absolute top-8 right-6 z-40 p-4 bg-black/40 rounded-2xl text-white backdrop-blur-xl border border-white/10 active:scale-90 transition-all shadow-2xl"
        >
          {isMuted ? <SpeakerXMarkIcon className="h-5 w-5" /> : <SpeakerWaveIcon className="h-5 w-5" />}
        </button>

        {/* Informações (Bottom Left) */}
        <div className="absolute bottom-0 left-0 p-6 pb-12 text-white z-30 w-full pointer-events-none">
          <div className="flex flex-col space-y-4 pointer-events-auto max-w-[85%]">
            <div className="flex items-center gap-3">
               <h4 className="font-black text-xl drop-shadow-2xl cursor-pointer hover:underline tracking-tight" onClick={(e) => { e.stopPropagation(); onNavigate('profile', { userId: post.userId }); }}>
                 @{post.authorName}
               </h4>
               <span className="text-[9px] bg-white/20 backdrop-blur-md px-3 py-1 rounded-lg font-black uppercase tracking-widest border border-white/10">Pro</span>
            </div>

            <p className="text-base font-medium drop-shadow-2xl leading-snug line-clamp-2">{post.reel.description}</p>

            <div className="flex items-center gap-4">
              <div className="flex items-center gap-2 px-3 py-1.5 bg-black/30 backdrop-blur-md rounded-xl border border-white/10">
                <EyeIcon className="h-4 w-4 text-blue-400" />
                <span className="text-[10px] font-black uppercase tracking-widest">{Math.floor(post.likes.length * 15.2)} Visualizações</span>
              </div>

              {post.reel.aiEffectPrompt && (
                <div className="flex items-center gap-2 px-3 py-1.5 bg-purple-600/40 backdrop-blur-md rounded-xl border border-purple-500/30">
                  <SparklesIcon className="h-4 w-4 text-purple-200" />
                  <span className="text-[10px] font-black uppercase tracking-widest truncate max-w-[120px]">{post.reel.aiEffectPrompt}</span>
                </div>
              )}
            </div>
          </div>
        </div>

        {/* Floating Actions Sidebar (Right) */}
        <div className="absolute bottom-16 right-4 flex flex-col items-center space-y-7 z-40 w-16">
          <div className="relative mb-4">
             <div className="w-14 h-14 rounded-2xl border-2 border-white shadow-2xl overflow-hidden cursor-pointer active:scale-95 transition-transform" onClick={(e) => { e.stopPropagation(); onNavigate('profile', { userId: post.userId }); }}>
                <img src={postAuthor.profilePicture || DEFAULT_PROFILE_PIC} className="w-full h-full object-cover" alt="" />
             </div>
             {!isFollowing && currentUser.id !== post.userId && (
               <button onClick={(e) => { e.stopPropagation(); onFollowToggle(post.userId); }} className="absolute -bottom-2.5 left-1/2 -translate-x-1/2 bg-blue-600 rounded-full p-1.5 border-2 border-black shadow-xl active:scale-125 transition-transform hover:bg-blue-500">
                 <PlusIcon className="w-3.5 h-3.5 text-white stroke-[4]" />
               </button>
             )}
          </div>

          <button onClick={(e) => { e.stopPropagation(); handleLike(); }} className="flex flex-col items-center group active:scale-125 transition-transform">
              <div className={`p-1.5 rounded-full transition-all ${hasLiked ? 'text-blue-500' : 'text-white/90 hover:text-white'}`}>
                <HeartIconSolid className="h-10 w-10 drop-shadow-2xl" />
              </div>
              <span className="text-xs font-black text-white drop-shadow-2xl mt-1">{post.likes.length}</span>
          </button>

          <button onClick={(e) => { e.stopPropagation(); setIsCommentsModalOpen(true); }} className="flex flex-col items-center group active:scale-125 transition-transform">
              <div className="p-1.5 text-white/90 hover:text-white transition-all">
                <ChatIconOutline className="h-10 w-10 drop-shadow-2xl" />
              </div>
              <span className="text-xs font-black text-white drop-shadow-2xl mt-1">{post.comments.length}</span>
          </button>

          <button onClick={(e) => { e.stopPropagation(); setIsIndicateModalOpen(true); }} className="flex flex-col items-center group active:scale-125 transition-transform">
              <div className="p-1.5 text-white/90 hover:text-white transition-all">
                <PaperAirplaneIcon className="h-10 w-10 drop-shadow-2xl -rotate-45" />
              </div>
              <span className="text-[10px] font-black text-white drop-shadow-2xl mt-1">Indicar</span>
          </button>

          <button onClick={(e) => { e.stopPropagation(); updatePostSaves(post.id, currentUser.id); onPostUpdate(); }} className="flex flex-col items-center group active:scale-125 transition-transform">
              <div className={`p-1.5 transition-all ${hasSaved ? 'text-yellow-400' : 'text-white/90 hover:text-white'}`}>
                <BookmarkIconSolid className="h-10 w-10 drop-shadow-2xl" />
              </div>
          </button>

          <div className="pt-4">
             <div className={`w-11 h-11 rounded-full bg-gradient-to-tr from-gray-900 via-blue-900 to-gray-800 border-2 border-white/30 shadow-2xl flex items-center justify-center overflow-hidden ${isIntersecting ? 'animate-spin-slow' : ''}`}>
                <img src={postAuthor.profilePicture || DEFAULT_PROFILE_PIC} className="w-full h-full opacity-40 object-cover" alt="" />
                <div className="absolute inset-0 flex items-center justify-center"><div className="w-1.5 h-1.5 bg-white rounded-full shadow-[0_0_10px_white]"></div></div>
             </div>
          </div>
        </div>

        {/* Gradiente de fundo para legibilidade */}
        <div className="absolute bottom-0 left-0 w-full h-80 bg-gradient-to-t from-black/100 via-black/40 to-transparent z-10 pointer-events-none"></div>
      </div>

      {isCommentsModalOpen && (
        <CommentsModal postId={post.id} currentUser={currentUser} onClose={() => setIsCommentsModalOpen(false)} onCommentsUpdated={onPostUpdate} />
      )}

      {isIndicateModalOpen && (
        <IndicateModal post={post} currentUser={currentUser} onClose={() => setIsIndicateModalOpen(false)} onPostUpdated={onPostUpdate} />
      )}

      <style>{`
        @keyframes spin-slow { from { transform: rotate(0deg); } to { transform: rotate(360deg); } }
        .animate-spin-slow { animation: spin-slow 8s linear infinite; }
        @keyframes like-heart {
          0% { transform: scale(0.4) rotate(-20deg); opacity: 0; }
          20% { transform: scale(1.4) rotate(15deg); opacity: 1; }
          40% { transform: scale(1.2) rotate(-10deg); opacity: 1; }
          100% { transform: scale(2.2) rotate(0deg); opacity: 0; }
        }
        .animate-like-heart { animation: like-heart 0.8s cubic-bezier(0.17, 0.89, 0.32, 1.28) forwards; }
      `}</style>
    </>
  );
};

