import React, { useState, useRef, useEffect } from 'react';
import { XMarkIcon, StopIcon, ArrowPathIcon, MusicalNoteIcon, SparklesIcon, CheckIcon } from '@heroicons/react/24/solid';
import { AudioTrack } from '../types';
import AudioSelectionModal from './AudioSelectionModal';

interface RecordReelModalProps {
  onClose: () => void;
  onSave: (videoBlob: Blob, audioTrackId?: string, aiPrompt?: string, filter?: string) => void;
}

const FILTERS = [
  { id: 'none', label: 'Normal', css: '' },
  { id: 'grayscale(1)', label: 'Noir', css: 'grayscale(1)' },
  { id: 'sepia(0.6)', label: 'Vintage', css: 'sepia(0.6)' },
  { id: 'saturate(2)', label: 'Vibrante', css: 'saturate(2)' },
  { id: 'hue-rotate(90deg)', label: 'Neon', css: 'hue-rotate(90deg)' },
  { id: 'invert(1)', label: 'Invertido', css: 'invert(1)' },
];

const RecordReelModal: React.FC<RecordReelModalProps> = ({ onClose, onSave }) => {
  const [isRecording, setIsRecording] = useState(false);
  const [recordedVideo, setRecordedVideo] = useState<Blob | null>(null);
  const [stream, setStream] = useState<MediaStream | null>(null);
  const [timer, setTimer] = useState(0);
  const [showAudioModal, setShowAudioModal] = useState(false);
  const [selectedAudioId, setSelectedAudioId] = useState<string | undefined>(undefined);
  const [selectedFilter, setSelectedFilter] = useState(FILTERS[0]);
  const [aiPrompt, setAiPrompt] = useState('');

  const videoRef = useRef<HTMLVideoElement>(null);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const chunksRef = useRef<Blob[]>([]);
  const timerIntervalRef = useRef<number | null>(null);

  useEffect(() => {
    startCamera();
    return () => {
      stopCamera();
      if (timerIntervalRef.current) clearInterval(timerIntervalRef.current);
    };
  }, []);

  const startCamera = async () => {
    try {
      const mediaStream = await navigator.mediaDevices.getUserMedia({ 
        video: { facingMode: 'user', aspectRatio: 9/16 }, 
        audio: true 
      });
      setStream(mediaStream);
      if (videoRef.current) videoRef.current.srcObject = mediaStream;
    } catch (err) {
      alert("Câmera indisponível.");
    }
  };

  const stopCamera = () => {
    if (stream) {
      stream.getTracks().forEach(track => track.stop());
    }
  };

  const startRecording = () => {
    if (!stream) return;
    chunksRef.current = [];
    const recorder = new MediaRecorder(stream);
    recorder.ondataavailable = (e) => chunksRef.current.push(e.data);
    recorder.onstop = () => {
      const blob = new Blob(chunksRef.current, { type: 'video/mp4' });
      setRecordedVideo(blob);
    };

    recorder.start();
    mediaRecorderRef.current = recorder;
    setIsRecording(true);
    setTimer(0);

    timerIntervalRef.current = window.setInterval(() => {
      setTimer(prev => {
        if (prev >= 30) {
          stopRecording();
          return 30;
        }
        return prev + 1;
      });
    }, 1000);
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current && isRecording) {
      mediaRecorderRef.current.stop();
      setIsRecording(false);
      if (timerIntervalRef.current) clearInterval(timerIntervalRef.current);
    }
  };

  const handleSave = () => {
    if (recordedVideo) {
      onSave(recordedVideo, selectedAudioId, aiPrompt, selectedFilter.id);
    }
  };

  return (
    <div className="fixed inset-0 bg-black z-[200] flex flex-col animate-fade-in overflow-hidden">
      <div className="absolute top-0 left-0 w-full p-6 flex justify-between items-center z-50">
        <button onClick={onClose} className="p-3 bg-white/10 rounded-full text-white backdrop-blur-md">
          <XMarkIcon className="h-6 w-6" />
        </button>
        <div className={`px-4 py-1.5 rounded-full text-[10px] font-black text-white uppercase tracking-widest ${isRecording ? 'bg-red-600 animate-pulse' : 'bg-white/20'}`}>
          {isRecording ? `Gravando ${timer}s` : 'Câmera Pronta'}
        </div>
        <div className="w-12"></div>
      </div>

      <div className="flex-1 relative bg-black flex items-center justify-center">
        {!recordedVideo ? (
          <video 
            ref={videoRef} 
            autoPlay 
            muted 
            playsInline 
            className="w-full h-full object-cover scale-x-[-1]" 
            style={{ filter: selectedFilter.id === 'none' ? 'none' : selectedFilter.id }}
          />
        ) : (
          <video 
            src={URL.createObjectURL(recordedVideo)} 
            autoPlay 
            loop 
            playsInline 
            className="w-full h-full object-cover" 
            style={{ filter: selectedFilter.id === 'none' ? 'none' : selectedFilter.id }}
          />
        )}

        {!isRecording && !recordedVideo && (
          <div className="absolute right-5 top-1/2 -translate-y-1/2 flex flex-col gap-6 z-40">
             <button onClick={() => setShowAudioModal(true)} className="flex flex-col items-center gap-1">
                <div className="p-4 bg-black/40 rounded-2xl backdrop-blur-xl border border-white/10">
                  <MusicalNoteIcon className="h-6 w-6 text-white" />
                </div>
                <span className="text-[8px] font-black text-white uppercase">Áudio</span>
             </button>
             <button className="flex flex-col items-center gap-1 opacity-50 cursor-not-allowed">
                <div className="p-4 bg-black/40 rounded-2xl backdrop-blur-xl border border-white/10">
                  <SparklesIcon className="h-6 w-6 text-white" />
                </div>
                <span className="text-[8px] font-black text-white uppercase">IA Efeitos</span>
             </button>
          </div>
        )}

        {!isRecording && !recordedVideo && (
          <div className="absolute bottom-32 left-0 w-full z-40">
             <div className="flex gap-4 px-6 overflow-x-auto no-scrollbar py-4 bg-gradient-to-t from-black/80 to-transparent">
                {FILTERS.map(f => (
                  <button 
                    key={f.id}
                    onClick={() => setSelectedFilter(f)}
                    className="flex flex-col items-center gap-2 flex-shrink-0"
                  >
                    <div 
                      className={`w-14 h-14 rounded-full border-2 transition-all ${selectedFilter.id === f.id ? 'border-blue-500 scale-110' : 'border-white/30'}`}
                      style={{ filter: f.id === 'none' ? 'none' : f.id, backgroundColor: '#333' }}
                    />
                    <span className={`text-[8px] font-black uppercase ${selectedFilter.id === f.id ? 'text-blue-400' : 'text-white/60'}`}>{f.label}</span>
                  </button>
                ))}
             </div>
          </div>
        )}
      </div>

      <div className="p-10 bg-gradient-to-t from-black to-transparent z-50 flex flex-col items-center gap-6">
        {!recordedVideo ? (
          <button 
            onClick={isRecording ? stopRecording : startRecording}
            className={`w-20 h-20 rounded-full border-4 flex items-center justify-center transition-all ${isRecording ? 'border-red-600 bg-red-600/20' : 'border-white bg-white/10'}`}
          >
            {isRecording ? <StopIcon className="h-10 w-10 text-red-600" /> : <div className="w-14 h-14 bg-red-600 rounded-full" />}
          </button>
        ) : (
          <div className="w-full max-w-md space-y-4">
            <div className="bg-white/10 backdrop-blur-xl rounded-[1.5rem] p-4 border border-white/10">
               <input 
                type="text" 
                value={aiPrompt}
                onChange={e => setAiPrompt(e.target.value)}
                placeholder="Título ou descrição do Reel..."
                className="w-full bg-black/40 border-none rounded-xl p-3 text-sm text-white placeholder-gray-500"
               />
            </div>
            <div className="flex gap-3">
              <button onClick={() => setRecordedVideo(null)} className="flex-1 py-4 bg-white/10 rounded-2xl text-white font-black text-xs uppercase flex items-center justify-center gap-2"><ArrowPathIcon className="h-4 w-4" /> Refazer</button>
              <button onClick={handleSave} className="flex-[2] py-4 bg-blue-600 rounded-2xl text-white font-black text-xs uppercase flex items-center justify-center gap-2"><CheckIcon className="h-5 w-5" /> Salvar Reel</button>
            </div>
          </div>
        )}
      </div>

      {showAudioModal && (
        <AudioSelectionModal 
          onClose={() => setShowAudioModal(false)} 
          onSelectTrack={(id) => { setSelectedAudioId(id); setShowAudioModal(false); }} 
        />
      )}
    </div>
  );
};

