import React, { useState, useEffect, useRef, useCallback } from 'react';
import { Post, User, PostType, AudioTrack } from '../types';
import { 
  getPosts, 
  findUserById, 
  updatePostLikes, 
  updatePostShares, 
  toggleFollowUser, 
  findAudioTrackById, 
  updatePostSaves 
} from '../services/storageService';
import { DEFAULT_PROFILE_PIC } from '../constants';
import {
  HeartIcon as HeartIconOutline,
  ChatBubbleOvalLeftIcon as ChatIconOutline,
  ShareIcon as ShareIconOutline,
  SpeakerWaveIcon,
  SpeakerXMarkIcon,
  PlayIcon,
  BookmarkIcon as BookmarkIconOutline,
  PaperAirplaneIcon,
  EyeIcon
} from '@heroicons/react/24/outline';
import {
  HeartIcon as HeartIconSolid,
  BookmarkIcon as BookmarkIconSolid,
  PlusIcon
} from '@heroicons/react/24/solid';
import CommentsModal from './CommentsModal';
import IndicateModal from './IndicateModal';

interface ReelsPageProps {
  currentUser: User;
  onNavigate: (page: string, params?: Record<string, string>) => void;
  refreshUser: () => void;
}

interface ReelVideoProps {
  post: Post;
  currentUser: User;
  onNavigate: (page: string, params?: Record<string, string>) => void;
  onFollowToggle: (userIdToFollow: string) => void;
  refreshUser: () => void;
  isIntersecting: boolean;
  onPostUpdate: () => void;
}

const ReelVideo: React.FC<ReelVideoProps> = ({ post, currentUser, onNavigate, onFollowToggle, refreshUser, isIntersecting, onPostUpdate }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const audioRef = useRef<HTMLAudioElement>(null);

  const [isMuted, setIsMuted] = useState(true);
  const [showPlayIcon, setShowPlayIcon] = useState(false);
  const [isCommentsModalOpen, setIsCommentsModalOpen] = useState(false);
  const [isIndicateModalOpen, setIsIndicateModalOpen] = useState(false);
  const [videoProgress, setVideoProgress] = useState(0);

  const postAuthor = findUserById(post.userId);
  const isFollowing = currentUser.followedUsers.includes(post.userId);
  const hasLiked = post.likes.includes(currentUser.id);
  const hasSaved = post.saves.includes(currentUser.id);
  const [audioTrack, setAudioTrack] = useState<AudioTrack | null>(null);

  useEffect(() => {
    if (post.reel?.audioTrackId) {
      setAudioTrack(findAudioTrackById(post.reel.audioTrackId) || null);
    }
  }, [post.reel?.audioTrackId]);

  const syncPlay = useCallback(async () => {
    if (!videoRef.current) return;
    try {
      videoRef.current.muted = isMuted || !!audioTrack;
      if (videoRef.current.paused) await videoRef.current.play();
      if (audioRef.current && !isMuted) await audioRef.current.play();
    } catch (e) {}
  }, [isMuted, audioTrack]);

  useEffect(() => {
    if (isIntersecting) syncPlay();
    else {
      videoRef.current?.pause();
      audioRef.current?.pause();
    }
  }, [isIntersecting, syncPlay]);

  const handleTimeUpdate = () => {
    if (videoRef.current) {
      setVideoProgress((videoRef.current.currentTime / videoRef.current.duration) * 100);
    }
  };

  const handleLike = (e: React.MouseEvent) => {
    e.stopPropagation();
    updatePostLikes(post.id, currentUser.id);
    onPostUpdate();
    refreshUser();
  };

  if (!postAuthor || !post.reel) return null;

  return (
    <div className="relative w-full h-full flex-shrink-0 snap-start bg-black overflow-hidden">
      <video
        ref={videoRef}
        src={post.reel.videoUrl}
        loop
        playsInline
        onTimeUpdate={handleTimeUpdate}
        className="absolute inset-0 w-full h-full object-cover"
        style={{ filter: post.reel.filter || 'none' }}
      />

      {audioTrack && <audio ref={audioRef} src={audioTrack.url} loop />}

      <div className="absolute bottom-0 left-0 w-full h-1 bg-white/20 z-50">
         <div className="h-full bg-blue-500" style={{ width: `${videoProgress}%` }} />
      </div>

      <button 
        onClick={(e) => { e.stopPropagation(); setIsMuted(!isMuted); }} 
        className="absolute top-6 right-6 z-40 p-3 bg-black/30 rounded-full text-white backdrop-blur-md"
      >
        {isMuted ? <SpeakerXMarkIcon className="h-6 w-6" /> : <SpeakerWaveIcon className="h-6 w-6" />}
      </button>

      <div className="absolute bottom-10 left-6 text-white z-30 max-w-[70%]">
        <h4 className="font-black text-lg mb-2" onClick={() => onNavigate('profile', { userId: post.userId })}>@{post.authorName}</h4>
        <p className="text-sm font-medium leading-snug">{post.reel.description}</p>
      </div>

      <div className="absolute bottom-20 right-4 flex flex-col items-center gap-6 z-40">
        <div className="relative mb-4">
           <img src={postAuthor.profilePicture || DEFAULT_PROFILE_PIC} className="w-12 h-12 rounded-2xl border-2 border-white object-cover" />
           {!isFollowing && currentUser.id !== post.userId && (
             <button onClick={() => onFollowToggle(post.userId)} className="absolute -bottom-2 left-1/2 -translate-x-1/2 bg-blue-600 rounded-full p-1 border-2 border-black">
               <PlusIcon className="w-3 h-3 text-white" />
             </button>
           )}
        </div>

        <button onClick={handleLike} className="flex flex-col items-center gap-1">
          {hasLiked ? <HeartIconSolid className="h-8 w-8 text-blue-500" /> : <HeartIconSolid className="h-8 w-8 text-white/90" />}
          <span className="text-[10px] font-black">{post.likes.length}</span>
        </button>

        <button onClick={() => setIsCommentsModalOpen(true)} className="flex flex-col items-center gap-1">
          <ChatIconOutline className="h-8 w-8 text-white/90" />
          <span className="text-[10px] font-black">{post.comments.length}</span>
        </button>

        <button onClick={() => setIsIndicateModalOpen(true)} className="flex flex-col items-center gap-1">
          <PaperAirplaneIcon className="h-8 w-8 text-white/90 -rotate-45" />
          <span className="text-[10px] font-black">Indicar</span>
        </button>
      </div>

      {isCommentsModalOpen && (
        <CommentsModal postId={post.id} currentUser={currentUser} onClose={() => setIsCommentsModalOpen(false)} onCommentsUpdated={onPostUpdate} />
      )}
      {isIndicateModalOpen && (
        <IndicateModal post={post} currentUser={currentUser} onClose={() => setIsIndicateModalOpen(false)} onPostUpdated={onPostUpdate} />
      )}
    </div>
  );
};

const ReelsPage: React.FC<ReelsPageProps> = ({ currentUser, onNavigate, refreshUser }) => {
  const [reels, setReels] = useState<Post[]>([]);
  const containerRef = useRef<HTMLDivElement>(null);
  const [visibleIdx, setVisibleIdx] = useState(0);

  useEffect(() => {
    setReels(getPosts().filter(p => p.type === PostType.REEL));
  }, []);

  useEffect(() => {
    const observer = new IntersectionObserver(entries => {
      entries.forEach(e => {
        if (e.isIntersecting) setVisibleIdx(Number((e.target as HTMLElement).dataset.idx));
      });
    }, { threshold: 0.8 });

    const kids = containerRef.current?.children;
    if (kids) Array.from(kids).forEach(k => observer.observe(k));
    return () => observer.disconnect();
  }, [reels]);

  const handleFollow = (id: string) => {
    toggleFollowUser(currentUser.id, id);
    refreshUser();
  };

  return (
    <div ref={containerRef} className="fixed inset-0 top-[72px] bg-black overflow-y-auto snap-y snap-mandatory no-scrollbar">
      {reels.map((r, i) => (
        <div key={r.id} data-idx={i} className="h-full w-full snap-start">
          <ReelVideo 
            post={r} 
            currentUser={currentUser} 
            onNavigate={onNavigate} 
            onFollowToggle={handleFollow} 
            refreshUser={refreshUser} 
            isIntersecting={i === visibleIdx}
            onPostUpdate={() => setReels(getPosts().filter(p => p.type === PostType.REEL))}
          />
        </div>
      ))}
    </div>
  );
};

export default ReelsPage;

