import { DEFAULT_PROFILE_PIC } from '../constants';
import { 
  findUserById, 
  updatePostLikes, 
  updatePostShares, 
  updatePostSaves, 
  deletePost, 
  pinPost,
  unpinPost
} from '../services/storageService';
import {
  HeartIcon as HeartIconOutline, 
  ChatBubbleOvalLeftIcon as ChatIconOutline, 
  BookmarkIcon as BookmarkIconOutline, 
  EllipsisHorizontalIcon, 
  PencilIcon, 
  TrashIcon, 
  CheckBadgeIcon,
  FlagIcon,
  PaperAirplaneIcon,
  MapPinIcon as PinIconOutline,
  VideoCameraIcon,
  SignalIcon,
  ShareIcon,
  ArrowsPointingOutIcon
} from '@heroicons/react/24/outline';
import { 
  HeartIcon as HeartIconSolid, 
  BookmarkIcon as BookmarkIconSolid,
  MapPinIcon as PinIconSolid,
  PlayIcon
} from '@heroicons/react/24/solid';
import IndicateModal from './IndicateModal';
import PostDetailModal from './PostDetailModal';

interface PostCardProps {
  post: Post;
  currentUser: User;
  onNavigate: (page: string, params?: Record<string, string>) => void;
  onFollowToggle: (userIdToFollow: string) => void;
  refreshUser: () => void;
  onPostUpdatedOrDeleted: () => void;
  onPinToggle: (postId: string, isCurrentlyPinned: boolean) => void;
}

const PostCard: React.FC<PostCardProps> = ({ 
  post, 
  currentUser, 
  onNavigate, 
  onFollowToggle,
  refreshUser, 
  onPostUpdatedOrDeleted,
  onPinToggle
}) => {
  // Safety check to prevent "Cannot read properties of undefined" errors
  if (!post || !currentUser) return null;

  const postAuthor = findUserById(post.userId);
  const [showOptions, setShowOptions] = useState(false);
  const [showIndicateModal, setShowIndicateModal] = useState(false);
  const [showDetailModal, setShowDetailModal] = useState(false);

  const optionsRef = useRef<HTMLDivElement>(null);
  const hasLiked = post.likes?.includes(currentUser.id);
  const hasSaved = post.saves?.includes(currentUser.id);
  const isAuthor = currentUser.id === post.userId;
  const isFollowing = currentUser.followedUsers?.includes(post.userId);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (optionsRef.current && !optionsRef.current.contains(event.target as Node)) setShowOptions(false);
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const handleLike = (e: React.MouseEvent) => {
    e.stopPropagation();
    updatePostLikes(post.id, currentUser.id);
    onPostUpdatedOrDeleted();
  };

  const handleShareExternal = async (e: React.MouseEvent) => {
    e.stopPropagation();
    const shareData = {
      title: post.liveStream?.title || 'Conteúdo CyBerPhone',
      text: post.content || 'Confira este conteúdo educativo!',
      url: window.location.href,
    };
    if (navigator.share) {
      try {
        await navigator.share(shareData);
        updatePostShares(post.id, currentUser.id);
        onPostUpdatedOrDeleted();
      } catch (err) {}
    }
  };

  const handleDelete = (e: React.MouseEvent) => {
    e.stopPropagation();
    if (window.confirm('Excluir esta aula?')) {
      deletePost(post.id);
      onPostUpdatedOrDeleted();
    }
  };

  const handlePin = (e: React.MouseEvent) => {
    e.stopPropagation();
    if (post.isPinned) unpinPost(post.id, currentUser.id);
    else pinPost(post.id, currentUser.id);
    onPostUpdatedOrDeleted();
    setShowOptions(false);
  };

  if (!postAuthor) return null;

  return (
    <>
      <div 
        onClick={() => post.type !== PostType.LIVE && setShowDetailModal(true)}
        className={`bg-white dark:bg-darkcard rounded-[2rem] md:rounded-[2.5rem] shadow-sm border border-gray-100 dark:border-white/5 overflow-hidden w-full relative mb-6 transition-all hover:shadow-md animate-fade-in ${post.type !== PostType.LIVE ? 'cursor-pointer' : ''}`}
      >

        {/* HEADER */}
        <div className="p-4 md:p-5 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="relative cursor-pointer" onClick={(e) => { e.stopPropagation(); onNavigate('profile', { userId: post.userId }); }}>
              <img src={postAuthor.profilePicture || DEFAULT_PROFILE_PIC} className="w-10 h-10 md:w-11 md:h-11 rounded-xl object-cover shadow-sm" />
              {postAuthor.userType === UserType.CREATOR && (
                <div className="absolute -bottom-1 -right-1 bg-blue-600 rounded-lg p-0.5 border-2 border-white dark:border-darkcard">
                  <CheckBadgeIcon className="h-3 w-3 text-white" />
                </div>
              )}
            </div>
            <div>
              <div className="flex items-center gap-2">
                <h4 className="font-black text-gray-900 dark:text-white text-xs md:text-sm leading-tight hover:underline cursor-pointer" onClick={(e) => { e.stopPropagation(); onNavigate('profile', { userId: post.userId }); }}>
                    {postAuthor.firstName} {postAuthor.lastName}
                </h4>
                {post.isPinned && <PinIconSolid className="h-3 w-3 text-blue-500" />}
              </div>
              <p className="text-[9px] font-bold text-gray-400 uppercase tracking-wider">{new Date(post.timestamp).toLocaleDateString()}</p>
            </div>
          </div>

          <div className="relative" ref={optionsRef}>
            <button onClick={(e) => { e.stopPropagation(); setShowOptions(!showOptions); }} className="p-2 text-gray-300 hover:text-blue-600 transition-colors">
              <EllipsisHorizontalIcon className="h-6 w-6" />
            </button>
            {showOptions && (
              <div className="absolute right-0 mt-1 w-48 bg-white dark:bg-darkcard rounded-2xl shadow-2xl py-2 z-20 border dark:border-white/10 animate-fade-in" onClick={e => e.stopPropagation()}>
                {isAuthor ? (
                  <>
                    <button onClick={handlePin} className="flex items-center w-full px-4 py-3 text-[10px] font-black text-gray-700 dark:text-gray-300 hover:bg-gray-50 dark:hover:bg-white/5">
                      {post.isPinned ? <><PinIconSolid className="h-4 w-4 mr-3 text-blue-500" /> Desafixar</> : <><PinIconOutline className="h-4 w-4 mr-3 text-blue-500" /> Fixar</>}
                    </button>
                    <button onClick={handleDelete} className="flex items-center w-full px-4 py-3 text-[10px] font-black text-red-600 hover:bg-red-50 dark:hover:bg-red-900/10">
                      <TrashIcon className="h-4 w-4 mr-3" /> Excluir
                    </button>
                  </>
                ) : (
                  <>
                    {!isFollowing && (
                      <button onClick={(e) => { e.stopPropagation(); onFollowToggle(post.userId); setShowOptions(false); }} className="flex items-center w-full px-4 py-3 text-[10px] font-black text-blue-600 hover:bg-blue-50 dark:hover:bg-blue-900/10">
                        Seguir Professor
                      </button>
                    )}
                    <button onClick={(e) => e.stopPropagation()} className="flex items-center w-full px-4 py-3 text-[10px] font-black text-orange-600 hover:bg-orange-50">
                      <FlagIcon className="h-4 w-4 mr-3" /> Denunciar
                    </button>
                  </>
                )}
              </div>
            )}
          </div>
        </div>

        {/* CONTENT */}
        <div className="px-4 md:px-5 pb-4">
          {post.type === PostType.LIVE && post.liveStream ? (
             <div className="rounded-[2.5rem] overflow-hidden bg-gray-900 text-white p-6 md:p-8 relative shadow-2xl border-4 border-blue-600/30">
                <div className="absolute top-4 left-4 z-10">
                   <div className="bg-red-600 px-3 py-1.5 rounded-lg text-[8px] md:text-[9px] font-black flex items-center gap-2 shadow-lg animate-pulse uppercase tracking-widest">
                      <SignalIcon className="h-3 w-3" /> Ao Vivo
                   </div>
                </div>
                <div className="relative z-10 py-6 md:py-10 flex flex-col items-center text-center">
                   <div className="w-16 h-16 md:w-20 md:h-20 bg-blue-600/20 rounded-full flex items-center justify-center mb-6 border border-blue-500/30">
                      <VideoCameraIcon className="h-8 w-8 md:h-10 md:w-10 text-blue-400" />
                   </div>
                   <h3 className="text-xl md:text-2xl font-black mb-3 tracking-tighter leading-tight uppercase">{post.liveStream.title}</h3>
                   <p className="text-gray-400 text-xs md:text-sm max-w-sm mb-8 font-medium">{post.liveStream.description}</p>
                   <button 
                      onClick={(e) => { e.stopPropagation(); onNavigate('live', { postId: post.id }); }}
                      className="bg-blue-600 hover:bg-blue-700 text-white px-8 py-3.5 md:px-10 md:py-4 rounded-2xl font-black text-xs uppercase tracking-[0.2em] shadow-xl active:scale-95 transition-all flex items-center justify-center gap-3"
                   >
                      <PlayIcon className="h-5 w-5" /> Assistir Aula
                   </button>
                </div>
             </div>
          ) : (
            <>
              {post.content && <p className="text-gray-700 dark:text-gray-300 text-sm font-medium leading-relaxed mb-4 whitespace-pre-wrap line-clamp-3">{post.content}</p>}
              {post.imageUrl && (
                <div className="rounded-[1.5rem] md:rounded-[2rem] overflow-hidden border dark:border-white/5 bg-gray-50 dark:bg-darkbg relative group">
                   <img src={post.imageUrl} className="w-full h-auto object-cover max-h-[500px]" alt="Post" />
                   <div className="absolute inset-0 bg-black/5 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center">
                      <div className="bg-white/90 p-3 rounded-2xl shadow-xl">
                        <ArrowsPointingOutIcon className="h-6 w-6 text-blue-600" />
                      </div>
                   </div>
                </div>
              )}
            </>
          )}
        </div>

        {/* ACTIONS */}
        <div className="px-4 md:px-5 py-3 flex items-center justify-between border-t dark:border-white/5">
          <div className="flex items-center gap-1 md:gap-2">
            <button onClick={handleLike} className={`flex items-center gap-2 px-3 py-2 rounded-xl transition-all active:scale-90 ${hasLiked ? 'text-blue-600 bg-blue-50 dark:bg-blue-500/10 font-black' : 'text-gray-400 hover:bg-gray-50 dark:hover:bg-white/5'}`}>
              {hasLiked ? <HeartIconSolid className="h-5 w-5" /> : <HeartIconOutline className="h-5 w-5" />}
              <span className="text-xs font-black">{post.likes?.length || 0}</span>
            </button>

            <button onClick={(e) => { e.stopPropagation(); setShowDetailModal(true); }} className="flex items-center gap-2 px-3 py-2 rounded-xl text-gray-400 hover:bg-gray-50 dark:hover:bg-white/5 transition-all">
              <ChatIconOutline className="h-5 w-5" />
              <span className="font-black text-xs">{post.comments?.length || 0}</span>
            </button>

            <button onClick={(e) => { e.stopPropagation(); setShowIndicateModal(true); }} className="flex items-center gap-2 px-3 py-2 rounded-xl text-gray-400 hover:bg-gray-50 dark:hover:bg-white/5">
              <PaperAirplaneIcon className="h-5 w-5 -rotate-45" />
            </button>
          </div>

          <button onClick={(e) => { e.stopPropagation(); updatePostSaves(post.id, currentUser.id); onPostUpdatedOrDeleted(); }} className={`p-2.5 rounded-xl transition-all ${hasSaved ? 'text-blue-600 bg-blue-50 dark:bg-blue-900/20' : 'text-gray-300 hover:bg-gray-50 dark:hover:bg-white/5'}`}>
            {hasSaved ? <BookmarkIconSolid className="h-5 w-5" /> : <BookmarkIconOutline className="h-5 w-5" />}
          </button>
        </div>
      </div>

      {showDetailModal && (
        <PostDetailModal
          post={post}
          currentUser={currentUser}
          onClose={() => setShowDetailModal(false)}
          onUpdate={onPostUpdatedOrDeleted}
          onNavigate={onNavigate}
          refreshUser={refreshUser}
        />
      )}

      {showIndicateModal && (
        <IndicateModal 
          post={post} 
          currentUser={currentUser} 
          onClose={() => setShowIndicateModal(false)} 
          onPostUpdated={onPostUpdatedOrDeleted}
        />
      )}
    </>
  );
};

export default PostCard;

import React, { useState } from 'react';
import { Post, User, UserType } from '../types';
import { findUserById, updateUser, addPostComment, updatePostLikes } from '../services/storageService';
import { DEFAULT_PROFILE_PIC } from '../constants';
import { 
  XMarkIcon, 
  ArrowDownTrayIcon, 
  UserCircleIcon,
  CheckBadgeIcon,
  ChatBubbleOvalLeftIcon,
  ShareIcon,
  EllipsisHorizontalIcon,
  ArrowLeftIcon,
  PaperAirplaneIcon,
  HeartIcon as HeartIconOutline
} from '@heroicons/react/24/outline';
import { 
  HeartIcon as HeartIconSolid,
  BookmarkIcon as BookmarkIconSolid
} from '@heroicons/react/24/solid';

interface PostDetailModalProps {
  post: Post;
  currentUser: User;
  onClose: () => void;
  onUpdate: () => void;
  onNavigate: (page: string, params?: Record<string, string>) => void;
  refreshUser: () => void;
}

const PostDetailModal: React.FC<PostDetailModalProps> = ({ post, currentUser, onClose, onUpdate, onNavigate, refreshUser }) => {
  // Safety Check
  if (!post || !currentUser) return null;

  const [showLightbox, setShowLightbox] = useState(false);
  const [commentText, setCommentText] = useState('');
  const author = findUserById(post.userId);
  const isOwner = currentUser.id === post.userId;
  const hasLiked = post.likes?.includes(currentUser.id);

  const handleLike = (e: React.MouseEvent) => {
    e.stopPropagation();
    updatePostLikes(post.id, currentUser.id);
    onUpdate();
  };

  const handleDownload = (e: React.MouseEvent) => {
    e.stopPropagation();
    if (!post.imageUrl) return;
    const link = document.createElement('a');
    link.href = post.imageUrl;
    link.download = `cyberphone_${post.id}.jpg`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const handleSetProfilePic = (e: React.MouseEvent) => {
    e.stopPropagation();
    if (!post.imageUrl) return;
    updateUser({ ...currentUser, profilePicture: post.imageUrl });
    refreshUser();
    alert("Nova foto de perfil definida!");
  };

  const handleSendComment = (e: React.FormEvent) => {
    e.preventDefault();
    if (!commentText.trim()) return;
    addPostComment(post.id, {
      id: `comment-${Date.now()}`,
      userId: currentUser.id,
      userName: currentUser.firstName,
      profilePic: currentUser.profilePicture,
      text: commentText,
      timestamp: Date.now()
    });
    setCommentText('');
    onUpdate();
  };

  return (
    <>
      <div className="fixed inset-0 z-[200] bg-black/90 md:bg-black/80 backdrop-blur-sm flex items-center justify-center animate-fade-in" onClick={onClose}>
        <div 
          className="bg-white dark:bg-darkcard w-full h-full md:w-[95%] md:h-[90%] md:rounded-[1.5rem] overflow-hidden flex flex-col md:flex-row shadow-2xl relative" 
          onClick={e => e.stopPropagation()}
        >
          {/* BOTÃO VOLTAR MOBILE */}
          <button onClick={onClose} className="absolute top-4 left-4 z-50 md:hidden p-2 bg-black/20 rounded-full text-white">
            <ArrowLeftIcon className="h-6 w-6" />
          </button>

          {/* ÁREA DA MÍDIA (LADO ESQUERDO) */}
          <div 
            className={`w-full h-[40vh] md:h-full md:flex-1 bg-black flex items-center justify-center relative group ${post.imageUrl ? 'cursor-zoom-in' : 'hidden'}`}
            onClick={() => setShowLightbox(true)}
          >
            {post.imageUrl && (
              <img src={post.imageUrl} className="max-w-full max-h-full object-contain" alt="Post" />
            )}
            <div className="absolute inset-0 bg-black/20 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center pointer-events-none">
                <span className="bg-black/60 text-white px-4 py-2 rounded-full text-xs font-bold uppercase tracking-widest border border-white/20">Clique para expandir</span>
            </div>
          </div>

          {/* BARRA LATERAL (LADO DIREITO - INFOS E COMENTÁRIOS) */}
          <div className="flex-1 md:w-[450px] md:flex-none flex flex-col bg-white dark:bg-darkcard h-full overflow-hidden border-l border-gray-100 dark:border-white/5">

            {/* CABEÇALHO DO POST */}
            <div className="p-4 md:p-6 border-b border-gray-50 dark:border-white/5 flex items-center justify-between">
              <div className="flex items-center gap-3 cursor-pointer" onClick={() => { onClose(); onNavigate('profile', { userId: post.userId }); }}>
                <div className="relative">
                  <img src={author?.profilePicture || DEFAULT_PROFILE_PIC} className="w-10 h-10 md:w-12 md:h-12 rounded-full object-cover border dark:border-white/10" />
                  {author?.userType === UserType.CREATOR && <CheckBadgeIcon className="h-4 w-4 text-blue-600 absolute -bottom-1 -right-1 fill-white dark:fill-darkcard" />}
                </div>
                <div>
                  <h4 className="font-black text-sm md:text-base dark:text-white leading-tight">{author?.firstName} {author?.lastName}</h4>
                  <p className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">{new Date(post.timestamp).toLocaleDateString()}</p>
                </div>
              </div>
              <div className="flex items-center gap-2">
                <button onClick={onClose} className="hidden md:block p-2 text-gray-300 hover:text-gray-600 dark:hover:text-white"><XMarkIcon className="h-7 w-7" /></button>
              </div>
            </div>

            {/* CONTEÚDO TEXTUAL E COMENTÁRIOS */}
            <div className="flex-1 overflow-y-auto custom-scrollbar p-4 md:p-6 space-y-6">
              {post.content && (
                <p className="text-gray-800 dark:text-gray-200 text-sm md:text-base leading-relaxed whitespace-pre-wrap font-medium">
                  {post.content}
                </p>
              )}

              {/* BOTÕES DE AÇÃO RÁPIDA */}
              <div className="flex items-center gap-4 py-1 border-y border-gray-50 dark:border-white/5">
                <button onClick={handleLike} className={`flex-1 flex items-center justify-center gap-2 py-3 rounded-xl transition-all active:scale-90 ${hasLiked ? 'text-blue-600 bg-blue-50 dark:bg-blue-600/10 font-black' : 'text-gray-500 hover:bg-gray-50 dark:hover:bg-white/5 font-bold'}`}>
                   {hasLiked ? <HeartIconSolid className="h-5 w-5" /> : <HeartIconOutline className="h-5 w-5" />}
                   <span className="text-xs">Curtir</span>
                </button>
                <button className="flex-1 flex items-center justify-center gap-2 py-3 rounded-xl text-gray-500 hover:bg-gray-50 dark:hover:bg-white/5 font-bold">
                   <ChatBubbleOvalLeftIcon className="h-5 w-5" />
                   <span className="text-xs">Comentar</span>
                </button>
                <button className="flex-1 flex items-center justify-center gap-2 py-3 rounded-xl text-gray-500 hover:bg-gray-50 dark:hover:bg-white/5 font-bold">
                   <ShareIcon className="h-5 w-5" />
                   <span className="text-xs">Enviar</span>
                </button>
              </div>

              {/* STATS */}
              <div className="flex items-center justify-between pb-4">
                 <div className="flex items-center gap-1.5 text-blue-600">
                    <div className="bg-blue-600 p-1 rounded-full"><HeartIconSolid className="h-3 w-3 text-white" /></div>
                    <span className="text-xs font-black">{post.likes?.length || 0} curtidas</span>
                 </div>
                 <div className="text-xs font-bold text-gray-400 uppercase tracking-widest">
                    {post.comments?.length || 0} comentários
                 </div>
              </div>

              {/* LISTA DE COMENTÁRIOS */}
              <div className="space-y-5">
                {(!post.comments || post.comments.length === 0) ? (
                  <div className="text-center py-10 opacity-30">
                    <ChatBubbleOvalLeftIcon className="h-10 w-10 mx-auto mb-2" />
                    <p className="text-[10px] font-black uppercase tracking-widest">Seja o primeiro a comentar</p>
                  </div>
                ) : (
                  post.comments.map(c => (
                    <div key={c.id} className="flex gap-3 group">
                       <img src={c.profilePic || DEFAULT_PROFILE_PIC} className="w-8 h-8 rounded-full object-cover" />
                       <div className="flex-1">
                          <div className="bg-gray-100 dark:bg-white/5 p-3 rounded-2xl rounded-tl-none">
                             <p className="text-[10px] font-black text-gray-900 dark:text-white uppercase mb-1">{c.userName}</p>
                             <p className="text-xs text-gray-700 dark:text-gray-300 font-medium">{c.text}</p>
                          </div>
                          <p className="text-[8px] font-black text-gray-400 uppercase mt-1 ml-2">{new Date(c.timestamp).toLocaleTimeString([], {hour:'2-digit', minute:'2-digit'})}</p>
                       </div>
                    </div>
                  ))
                )}
              </div>
            </div>

            {/* BARRA DE INPUT COMENTÁRIO */}
            <div className="p-4 border-t border-gray-100 dark:border-white/5 bg-gray-50/50 dark:bg-black/10">
               <form onSubmit={handleSendComment} className="flex items-center gap-3">
                  <img src={currentUser.profilePicture || DEFAULT_PROFILE_PIC} className="w-8 h-8 rounded-full hidden md:block" />
                  <div className="flex-1 relative">
                    <input 
                      type="text" 
                      value={commentText}
                      onChange={e => setCommentText(e.target.value)}
                      placeholder="Escreva um comentário..." 
                      className="w-full pl-4 pr-10 py-3 bg-white dark:bg-darkcard border dark:border-white/10 rounded-full text-xs font-bold dark:text-white outline-none focus:border-blue-500 transition-all"
                    />
                    <button type="submit" className="absolute right-2 top-1/2 -translate-y-1/2 text-blue-600 p-1.5"><PaperAirplaneIcon className="h-4 w-4 -rotate-45" /></button>
                  </div>
               </form>
            </div>
          </div>
        </div>
      </div>

      {/* LIGHTBOX FULLSCREEN (CLIQUE NA IMAGEM) */}
      {showLightbox && post.imageUrl && (
        <div className="fixed inset-0 z-[1000] bg-black flex flex-col animate-fade-in" onClick={() => setShowLightbox(false)}>
           {/* CONTROLES SUPERIORES */}
           <div className="absolute top-0 left-0 w-full p-4 md:p-8 flex justify-between items-center z-[1010] bg-gradient-to-b from-black/80 to-transparent">
              <button onClick={() => setShowLightbox(false)} className="p-3 bg-white/10 hover:bg-white/20 rounded-full text-white backdrop-blur-md transition-all">
                 <XMarkIcon className="h-7 w-7" />
              </button>

              <div className="flex gap-2">
                 <button onClick={handleDownload} className="flex items-center gap-2 bg-white/10 hover:bg-white/20 px-6 py-3 rounded-xl text-xs font-black uppercase text-white backdrop-blur-md transition-all">
                    <ArrowDownTrayIcon className="h-5 w-5" /> Download
                 </button>
                 {isOwner && (
                    <button onClick={handleSetProfilePic} className="flex items-center gap-2 bg-blue-600 hover:bg-blue-700 px-6 py-3 rounded-xl text-xs font-black uppercase text-white transition-all shadow-xl">
                       <UserCircleIcon className="h-5 w-5" /> Usar no Perfil
                    </button>
                 )}
              </div>
           </div>

           {/* IMAGEM CENTRALIZADA */}
           <div className="flex-1 flex items-center justify-center p-4">
              <img src={post.imageUrl} className="max-w-full max-h-full object-contain shadow-[0_0_100px_rgba(0,0,0,0.5)] animate-scale-up" onClick={e => e.stopPropagation()} />
           </div>

           {/* INFO NO RODAPÉ */}
           <div className="absolute bottom-0 left-0 w-full p-8 text-white bg-gradient-to-t from-black/80 to-transparent pointer-events-none">
              <p className="text-[10px] font-black text-gray-400 uppercase tracking-[0.2em] mb-1">Publicado por</p>
              <p className="text-xl font-black">{author?.firstName} {author?.lastName}</p>
           </div>
        </div>
      )}

      <style>{`
        @keyframes scale-up { from { transform: scale(0.9); opacity: 0; } to { transform: scale(1); opacity: 1; } }
        .animate-scale-up { animation: scale-up 0.3s cubic-bezier(0.16, 1, 0.3, 1) forwards; }
      `}</style>
    </>
  );
};

export default PostDetailModal;

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { Post, User, PostType, AudioTrack } from '../types';
import { 
  getPosts, 
  findUserById, 
  updatePostLikes, 
  updatePostShares, 
  toggleFollowUser, 
  findAudioTrackById, 
  updatePostSaves 
} from '../services/storageService';
import { DEFAULT_PROFILE_PIC } from '../constants';
import {
  HeartIcon as HeartIconOutline,
  ChatBubbleOvalLeftIcon as ChatIconOutline,
  ShareIcon as ShareIconOutline,
  SpeakerWaveIcon,
  SpeakerXMarkIcon,
  PlayIcon,
  BookmarkIcon as BookmarkIconOutline,
  PaperAirplaneIcon,
  EyeIcon,
  SparklesIcon
} from '@heroicons/react/24/outline';
import {
  HeartIcon as HeartIconSolid,
  BookmarkIcon as BookmarkIconSolid,
  PlusIcon
} from '@heroicons/react/24/solid';
import CommentsModal from './CommentsModal';
import IndicateModal from './IndicateModal';

interface ReelsPageProps {
  currentUser: User;
  onNavigate: (page: string, params?: Record<string, string>) => void;
  refreshUser: () => void;
}

interface ReelVideoProps {
  post: Post;
  currentUser: User;
  onNavigate: (page: string, params?: Record<string, string>) => void;
  onFollowToggle: (userIdToFollow: string) => void;
  refreshUser: () => void;
  isIntersecting: boolean;
  onPostUpdate: () => void;
}

const ReelVideo: React.FC<ReelVideoProps> = ({ post, currentUser, onNavigate, onFollowToggle, refreshUser, isIntersecting, onPostUpdate }) => {
  // Critical Safety Guard
  if (!post || !currentUser) return null;

  const videoRef = useRef<HTMLVideoElement>(null);
  const audioRef = useRef<HTMLAudioElement>(null);

  const [isMuted, setIsMuted] = useState(true);
  const [showPlayIcon, setShowPlayIcon] = useState(false);
  const [isCommentsModalOpen, setIsCommentsModalOpen] = useState(false);
  const [isIndicateModalOpen, setIsIndicateModalOpen] = useState(false);
  const [likeHearts, setLikeHearts] = useState<{ id: number; x: number; y: number }[]>([]);
  const [videoProgress, setVideoProgress] = useState(0);

  const clickTimeout = useRef<number | null>(null);

  const postAuthor = findUserById(post.userId);
  const isFollowing = currentUser.followedUsers?.includes(post.userId);
  const hasLiked = post.likes?.includes(currentUser.id);
  const hasSaved = post.saves?.includes(currentUser.id);
  const [audioTrack, setAudioTrack] = useState<AudioTrack | null>(null);

  useEffect(() => {
    if (post.reel?.audioTrackId) {
      setAudioTrack(findAudioTrackById(post.reel.audioTrackId) || null);
    } else {
      setAudioTrack(null);
    }
  }, [post.reel?.audioTrackId]);

  const syncPlay = useCallback(async () => {
    const video = videoRef.current;
    const audio = audioRef.current;
    if (!video) return;

    try {
      video.muted = isMuted || !!audioTrack;
      if (video.paused) await video.play();
      if (audio && !video.muted) {
        audio.muted = false;
        if (audio.paused) await audio.play();
      }
    } catch (e) {
      // Ignora erro de interrupção de autoplay
    }
  }, [isMuted, audioTrack]);

  const syncPause = useCallback(() => {
    const video = videoRef.current;
    const audio = audioRef.current;
    if (video && !video.paused) video.pause();
    if (audio && !audio.paused) audio.paused = true; // Fix: use property if exists or pause() method
    if (audio && typeof audio.pause === 'function') audio.pause();
  }, []);

  useEffect(() => {
    if (isIntersecting) {
      syncPlay();
    } else {
      syncPause();
    }
  }, [isIntersecting, syncPlay, syncPause]);

  useEffect(() => {
    if (videoRef.current) videoRef.current.muted = isMuted || !!audioTrack;
    if (audioRef.current) audioRef.current.muted = isMuted;
  }, [isMuted, audioTrack]);

  const handleTimeUpdate = () => {
    if (videoRef.current) {
      const progress = (videoRef.current.currentTime / videoRef.current.duration) * 100;
      setVideoProgress(progress);
    }
  };

  const togglePlayPause = () => {
    const video = videoRef.current;
    if (!video) return;
    if (video.paused) {
      syncPlay();
    } else {
      syncPause();
      setShowPlayIcon(true);
      setTimeout(() => setShowPlayIcon(false), 500);
    }
  };

  const handleLike = () => {
    updatePostLikes(post.id, currentUser.id);
    onPostUpdate();
    refreshUser();
  };

  const handleDoubleClick = (e: React.MouseEvent | React.TouchEvent) => {
    const rect = (e.currentTarget as HTMLElement).getBoundingClientRect();
    const x = ('clientX' in e ? e.clientX : (e as React.TouchEvent).touches[0].clientX) - rect.left;
    const y = ('clientY' in e ? e.clientY : (e as React.TouchEvent).touches[0].clientY) - rect.top;

    const newHeart = { id: Date.now(), x, y };
    setLikeHearts(prev => [...prev, newHeart]);
    if (!hasLiked) handleLike();
    setTimeout(() => setLikeHearts(prev => prev.filter(h => h.id !== newHeart.id)), 800);
  };

  const handleContainerClick = (e: React.MouseEvent) => {
    if (clickTimeout.current) {
      window.clearTimeout(clickTimeout.current);
      clickTimeout.current = null;
      handleDoubleClick(e);
    } else {
      clickTimeout.current = window.setTimeout(() => {
        togglePlayPause();
        clickTimeout.current = null;
      }, 250);
    }
  };

  if (!postAuthor || !post.reel) return null;

  return (
    <>
      <div
        className="relative w-full h-full flex-shrink-0 snap-start bg-black overflow-hidden touch-none group/reel"
        onClick={handleContainerClick}
      >
        {/* Camada de Vídeo com Filtro Dinâmico */}
        <div className="absolute inset-0 w-full h-full">
           <video
            ref={videoRef}
            src={post.reel.videoUrl}
            loop
            playsInline
            webkit-playsinline="true"
            preload="auto"
            onTimeUpdate={handleTimeUpdate}
            className="w-full h-full object-cover transition-all duration-700"
            style={{ filter: post.reel.filter || 'none' }}
          />
          {/* Overlay de Brilho IA (se houver prompt) */}
          {post.reel.aiEffectPrompt && (
            <div className="absolute inset-0 pointer-events-none bg-purple-500/5 mix-blend-overlay animate-pulse"></div>
          )}
        </div>

        {audioTrack && <audio ref={audioRef} src={audioTrack.url} loop preload="auto" />}

        {/* Barra de Progresso Superior (Estilo Moderno) */}
        <div className="absolute top-0 left-0 w-full h-1 bg-white/10 z-50">
           <div 
             className="h-full bg-white transition-all duration-100 ease-linear shadow-[0_0_10px_rgba(255,255,255,0.5)]" 
             style={{ width: `${videoProgress}%` }}
           />
        </div>

        {/* Play/Pause Overlay */}
        <div className={`absolute inset-0 flex items-center justify-center transition-opacity duration-300 pointer-events-none z-20 ${showPlayIcon ? 'opacity-100' : 'opacity-0'}`}>
          <div className="bg-black/30 p-8 rounded-full backdrop-blur-md border border-white/10">
            <PlayIcon className="h-12 w-12 text-white" />
          </div>
        </div>

        {/* Like Hearts */}
        {likeHearts.map(heart => (
          <div key={heart.id} className="absolute z-50 pointer-events-none animate-like-heart" style={{ left: heart.x - 50, top: heart.y - 50 }}>
            <HeartIconSolid className="w-24 h-24 text-blue-500 drop-shadow-[0_0_30px_rgba(59,130,246,0.6)]" />
          </div>
        ))}

        {/* Mute/Sound Button */}
        <button 
          onClick={(e) => { e.stopPropagation(); setIsMuted(!isMuted); }} 
          className="absolute top-8 right-6 z-40 p-4 bg-black/40 rounded-2xl text-white backdrop-blur-xl border border-white/10 active:scale-90 transition-all shadow-2xl"
        >
          {isMuted ? <SpeakerXMarkIcon className="h-5 w-5" /> : <SpeakerWaveIcon className="h-5 w-5" />}
        </button>

        {/* Informações (Bottom Left) */}
        <div className="absolute bottom-0 left-0 p-6 pb-12 text-white z-30 w-full pointer-events-none">
          <div className="flex flex-col space-y-4 pointer-events-auto max-w-[85%]">
            <div className="flex items-center gap-3">
               <h4 className="font-black text-xl drop-shadow-2xl cursor-pointer hover:underline tracking-tight" onClick={(e) => { e.stopPropagation(); onNavigate('profile', { userId: post.userId }); }}>
                 @{post.authorName}
               </h4>
               <span className="text-[9px] bg-white/20 backdrop-blur-md px-3 py-1 rounded-lg font-black uppercase tracking-widest border border-white/10">Pro</span>
            </div>

            <p className="text-base font-medium drop-shadow-2xl leading-snug line-clamp-2">{post.reel.description}</p>

            <div className="flex items-center gap-4">
              <div className="flex items-center gap-2 px-3 py-1.5 bg-black/30 backdrop-blur-md rounded-xl border border-white/10">
                <EyeIcon className="h-4 w-4 text-blue-400" />
                <span className="text-[10px] font-black uppercase tracking-widest">{Math.floor((post.likes?.length || 0) * 15.2)} Visualizações</span>
              </div>

              {post.reel.aiEffectPrompt && (
                <div className="flex items-center gap-2 px-3 py-1.5 bg-purple-600/40 backdrop-blur-md rounded-xl border border-purple-500/30">
                  <SparklesIcon className="h-4 w-4 text-purple-200" />
                  <span className="text-[10px] font-black uppercase tracking-widest truncate max-w-[120px]">{post.reel.aiEffectPrompt}</span>
                </div>
              )}
            </div>
          </div>
        </div>

        {/* Floating Actions Sidebar (Right) */}
        <div className="absolute bottom-16 right-4 flex flex-col items-center space-y-7 z-40 w-16">
          <div className="relative mb-4">
             <div className="w-14 h-14 rounded-2xl border-2 border-white shadow-2xl overflow-hidden cursor-pointer active:scale-95 transition-transform" onClick={(e) => { e.stopPropagation(); onNavigate('profile', { userId: post.userId }); }}>
                <img src={postAuthor.profilePicture || DEFAULT_PROFILE_PIC} className="w-full h-full object-cover" alt="" />
             </div>
             {!isFollowing && currentUser.id !== post.userId && (
               <button onClick={(e) => { e.stopPropagation(); onFollowToggle(post.userId); }} className="absolute -bottom-2.5 left-1/2 -translate-x-1/2 bg-blue-600 rounded-full p-1.5 border-2 border-black shadow-xl active:scale-125 transition-transform hover:bg-blue-500">
                 <PlusIcon className="w-3.5 h-3.5 text-white stroke-[4]" />
               </button>
             )}
          </div>

          <button onClick={(e) => { e.stopPropagation(); handleLike(); }} className="flex flex-col items-center group active:scale-125 transition-transform">
              <div className={`p-1.5 rounded-full transition-all ${hasLiked ? 'text-blue-500' : 'text-white/90 hover:text-white'}`}>
                <HeartIconSolid className="h-10 w-10 drop-shadow-2xl" />
              </div>
              <span className="text-xs font-black text-white drop-shadow-2xl mt-1">{post.likes?.length || 0}</span>
          </button>

          <button onClick={(e) => { e.stopPropagation(); setIsCommentsModalOpen(true); }} className="flex flex-col items-center group active:scale-125 transition-transform">
              <div className="p-1.5 text-white/90 hover:text-white transition-all">
                <ChatIconOutline className="h-10 w-10 drop-shadow-2xl" />
              </div>
              <span className="text-xs font-black text-white drop-shadow-2xl mt-1">{post.comments?.length || 0}</span>
          </button>

          <button onClick={(e) => { e.stopPropagation(); setIsIndicateModalOpen(true); }} className="flex flex-col items-center group active:scale-125 transition-transform">
              <div className="p-1.5 text-white/90 hover:text-white transition-all">
                <PaperAirplaneIcon className="h-10 w-10 drop-shadow-2xl -rotate-45" />
              </div>
              <span className="text-[10px] font-black text-white drop-shadow-2xl mt-1">Indicar</span>
          </button>

          <button onClick={(e) => { e.stopPropagation(); updatePostSaves(post.id, currentUser.id); onPostUpdate(); }} className="flex flex-col items-center group active:scale-125 transition-transform">
              <div className={`p-1.5 transition-all ${hasSaved ? 'text-yellow-400' : 'text-white/90 hover:text-white'}`}>
                <BookmarkIconSolid className="h-10 w-10 drop-shadow-2xl" />
              </div>
          </button>

          <div className="pt-4">
             <div className={`w-11 h-11 rounded-full bg-gradient-to-tr from-gray-900 via-blue-900 to-gray-800 border-2 border-white/30 shadow-2xl flex items-center justify-center overflow-hidden ${isIntersecting ? 'animate-spin-slow' : ''}`}>
                <img src={postAuthor.profilePicture || DEFAULT_PROFILE_PIC} className="w-full h-full opacity-40 object-cover" alt="" />
                <div className="absolute inset-0 flex items-center justify-center"><div className="w-1.5 h-1.5 bg-white rounded-full shadow-[0_0_10px_white]"></div></div>
             </div>
          </div>
        </div>

        {/* Gradiente de fundo para legibilidade */}
        <div className="absolute bottom-0 left-0 w-full h-80 bg-gradient-to-t from-black/100 via-black/40 to-transparent z-10 pointer-events-none"></div>
      </div>

      {isCommentsModalOpen && (
        <CommentsModal postId={post.id} currentUser={currentUser} onClose={() => setIsCommentsModalOpen(false)} onCommentsUpdated={onPostUpdate} />
      )}

      {isIndicateModalOpen && (
        <IndicateModal post={post} currentUser={currentUser} onClose={() => setIsIndicateModalOpen(false)} onPostUpdated={onPostUpdate} />
      )}

      <style>{`
        @keyframes spin-slow { from { transform: rotate(0deg); } to { transform: rotate(360deg); } }
        .animate-spin-slow { animation: spin-slow 8s linear infinite; }
        @keyframes like-heart {
          0% { transform: scale(0.4) rotate(-20deg); opacity: 0; }
          20% { transform: scale(1.4) rotate(15deg); opacity: 1; }
          40% { transform: scale(1.2) rotate(-10deg); opacity: 1; }
          100% { transform: scale(2.2) rotate(0deg); opacity: 0; }
        }
        .animate-like-heart { animation: like-heart 0.8s cubic-bezier(0.17, 0.89, 0.32, 1.28) forwards; }
      `}</style>
    </>
  );
};

const ReelsPage: React.FC<ReelsPageProps> = ({ currentUser, onNavigate, refreshUser }) => {
  const [reels, setReels] = useState<Post[]>([]);
  const containerRef = useRef<HTMLDivElement>(null);
  const [visibleIdx, setVisibleIdx] = useState(0);

  useEffect(() => {
    setReels(getPosts().filter(p => p.type === PostType.REEL));
  }, []);

  useEffect(() => {
    const observer = new IntersectionObserver(entries => {
      entries.forEach(e => {
        if (e.isIntersecting) setVisibleIdx(Number((e.target as HTMLElement).dataset.idx));
      });
    }, { threshold: 0.8 });

    const kids = containerRef.current?.children;
    if (kids) (Array.from(kids) as Element[]).forEach(k => observer.observe(k));
    return () => observer.disconnect();
  }, [reels]);

  const handleFollow = (id: string) => {
    toggleFollowUser(currentUser.id, id);
    refreshUser();
  };

  return (
    <div ref={containerRef} className="fixed inset-0 top-[72px] bg-black overflow-y-auto snap-y snap-mandatory no-scrollbar">
      {reels.map((r, i) => (
        <div key={r.id} data-idx={i} className="h-full w-full snap-start">
          <ReelVideo 
            post={r} 
            currentUser={currentUser} 
            onNavigate={onNavigate} 
            onFollowToggle={handleFollow} 
            refreshUser={refreshUser} 
            isIntersecting={i === visibleIdx}
            onPostUpdate={() => setReels(getPosts().filter(p => p.type === PostType.REEL))}
          />
        </div>
      ))}
    </div>
  );
};

export default ReelsPage;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { User, Post, AdCampaign, PostType, Story, UserType } from '../types';
import { getPosts, getAds, getStories, getUsers, toggleFollowUser } from '../services/storageService';
import { DEFAULT_PROFILE_PIC } from '../constants';
import PostCard from './PostCard';
import CreatePost from './CreatePost';
import AdCard from './AdCard';
import StoryViewerModal from './StoryViewerModal';
import CreateStoryModal from './CreateStoryModal';
import { 
  PlusIcon, ArrowPathIcon, UserPlusIcon, CheckBadgeIcon, SparklesIcon
} from '@heroicons/react/24/outline';

interface FeedPageProps {
  currentUser: User;
  onNavigate: (page: string, params?: Record<string, string>) => void;
  refreshUser: () => void;
}

const ITEMS_PER_PAGE = 5;

const FeedPage: React.FC<FeedPageProps> = ({ currentUser, onNavigate, refreshUser }) => {
  const [allItems, setAllItems] = useState<(Post | AdCampaign | { type: 'SUGGESTIONS' })[]>([]);
  const [visibleItems, setVisibleItems] = useState<(Post | AdCampaign | { type: 'SUGGESTIONS' })[]>([]);
  const [displayLimit, setDisplayLimit] = useState(ITEMS_PER_PAGE);
  const [loading, setLoading] = useState(true);
  const [loadingMore, setLoadingMore] = useState(false);
  const [suggestedUsers, setSuggestedUsers] = useState<User[]>([]);
  const [stories, setStories] = useState<Story[]>([]);

  const [selectedStoryIndex, setSelectedStoryIndex] = useState<number | null>(null);
  const [isCreatingStory, setIsCreatingStory] = useState(false);

  const observerTarget = useRef<HTMLDivElement>(null);

  const loadData = useCallback(() => {
    setLoading(true);
    // Safety check: Filter out any malformed posts from storage
    const allPosts = getPosts()
      .filter(p => p && typeof p === 'object' && p.userId)
      .sort((a, b) => {
        if (a.isPinned && !b.isPinned) return -1;
        if (!a.isPinned && b.isPinned) return 1;
        return b.timestamp - a.timestamp;
    });
    const allAds = getAds();
    const allUsers = getUsers();
    const allStories = getStories();

    setStories(allStories);

    const suggestions = allUsers
      .filter(u => u && u.id !== currentUser.id && !currentUser.followedUsers?.includes(u.id))
      .sort(() => 0.5 - Math.random())
      .slice(0, 5);

    setSuggestedUsers(suggestions);

    let combined: (Post | AdCampaign | { type: 'SUGGESTIONS' })[] = [];
    allPosts.forEach((post, idx) => {
        combined.push(post);
        if (idx === 1 && suggestions.length > 0) {
            combined.push({ type: 'SUGGESTIONS' });
        }
        if ((idx + 1) % 5 === 0 && allAds.length > 0) {
            const randomAd = allAds[Math.floor(Math.random() * allAds.length)];
            if (randomAd) combined.push(randomAd);
        }
    });

    setAllItems(combined);
    setVisibleItems(combined.slice(0, ITEMS_PER_PAGE));
    setLoading(false);
  }, [currentUser]);

  useEffect(() => { loadData(); }, [loadData]);

  const loadMoreItems = useCallback(() => {
    if (loadingMore) return;
    setLoadingMore(true);

    setTimeout(() => {
      const nextLimit = displayLimit + ITEMS_PER_PAGE;
      let updatedAllItems = [...allItems];

      if (nextLimit > allItems.length) {
        const postsOnly = allItems.filter(item => item && typeof item === 'object' && 'authorName' in item) as Post[];
        if (postsOnly.length > 0) {
          const recycledPosts: Post[] = postsOnly
            .sort(() => Math.random() - 0.5)
            .slice(0, 5)
            .map(p => ({
              ...p,
              id: `recycled-${Date.now()}-${Math.random()}`,
              timestamp: Date.now() - Math.random() * 1000000,
              likes: [],
              comments: []
            }));

          updatedAllItems = [...allItems, ...recycledPosts];
          setAllItems(updatedAllItems);
        }
      }

      setDisplayLimit(nextLimit);
      setVisibleItems(updatedAllItems.slice(0, nextLimit));
      setLoadingMore(false);
    }, 1000);
  }, [displayLimit, allItems, loadingMore]);

  useEffect(() => {
    const observer = new IntersectionObserver(
      entries => {
        if (entries[0].isIntersecting && !loading && !loadingMore) {
          loadMoreItems();
        }
      },
      { threshold: 0.1, rootMargin: '200px' }
    );

    if (observerTarget.current) observer.observe(observerTarget.current);
    return () => observer.disconnect();
  }, [loading, loadingMore, loadMoreItems]);

  const handleFollow = (userId: string) => {
    toggleFollowUser(currentUser.id, userId);
    refreshUser();
    setSuggestedUsers(prev => prev.filter(u => u.id !== userId));
  };

  return (
    <div className="w-full max-w-[1400px] mx-auto px-2 md:px-6 lg:px-10 py-4 md:py-8">

      {/* Stories Section */}
      <section className="mb-8 bg-white dark:bg-darkcard rounded-[2rem] p-4 shadow-sm border dark:border-white/10 overflow-hidden">
        <div className="flex gap-4 overflow-x-auto pb-2 no-scrollbar scroll-smooth">
          <div 
            onClick={() => setIsCreatingStory(true)}
            className="flex-shrink-0 flex flex-col items-center gap-2 cursor-pointer group"
          >
            <div className="relative p-0.5 rounded-full border-2 border-dashed border-blue-400 group-hover:border-blue-600 transition-colors">
              <img src={currentUser.profilePicture || DEFAULT_PROFILE_PIC} className="w-14 h-14 rounded-full object-cover shadow-sm" />
              <div className="absolute bottom-0 right-0 bg-blue-600 text-white rounded-full p-1 border-2 border-white dark:border-darkcard">
                <PlusIcon className="w-3 h-3 stroke-[4]" />
              </div>
            </div>
            <span className="text-[9px] font-black dark:text-white uppercase">Novo</span>
          </div>
          {stories.map((s, i) => (
            <div key={i} onClick={() => setSelectedStoryIndex(i)} className="flex-shrink-0 flex flex-col items-center gap-2 cursor-pointer group">
              <div className="p-1 rounded-full bg-gradient-to-tr from-blue-500 to-purple-600 shadow-md group-hover:scale-105 transition-transform">
                <div className="p-0.5 bg-white dark:bg-darkcard rounded-full">
                  <img src={s.userProfilePic || DEFAULT_PROFILE_PIC} className="w-14 h-14 rounded-full object-cover" />
                </div>
              </div>
              <span className="text-[9px] font-black dark:text-white truncate w-14 text-center">{s.userName.split(' ')[0]}</span>
            </div>
          ))}
        </div>
      </section>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
        <main className="col-span-1 lg:col-span-8 space-y-8">
          <CreatePost currentUser={currentUser} onPostCreated={loadData} refreshUser={refreshUser} />

          <div className="space-y-8">
            {loading ? (
              <div className="py-20 text-center flex flex-col items-center gap-4">
                <div className="w-12 h-12 border-4 border-blue-600 border-t-transparent rounded-full animate-spin"></div>
                <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Sincronizando Feed...</p>
              </div>
            ) : (
              <>
                {visibleItems.map((item, idx) => {
                  if (!item) return null;

                  if ('authorName' in item) {
                    return (
                      <div key={(item as Post).id || idx} className="animate-fade-in">
                        <PostCard 
                          post={item as Post} 
                          currentUser={currentUser} 
                          onNavigate={onNavigate} 
                          onFollowToggle={handleFollow} 
                          refreshUser={refreshUser} 
                          onPostUpdatedOrDeleted={loadData} 
                          onPinToggle={() => {}} 
                        />
                      </div>
                    );
                  }

                  if ('type' in item && item.type === 'SUGGESTIONS') {
                    return (
                      <div key="suggestions-card" className="bg-white dark:bg-darkcard rounded-[2.5rem] p-8 border border-blue-50 dark:border-white/10 shadow-sm animate-fade-in">
                        <div className="flex items-center gap-3 mb-6">
                           <SparklesIcon className="h-6 w-6 text-blue-600" />
                           <h4 className="font-black text-gray-900 dark:text-white uppercase text-xs tracking-widest">Professores Sugeridos</h4>
                        </div>
                        <div className="flex gap-4 overflow-x-auto pb-4 no-scrollbar">
                           {suggestedUsers.map(user => (
                             <div key={user.id} className="flex-shrink-0 w-40 bg-gray-50 dark:bg-darkbg rounded-3xl p-5 flex flex-col items-center text-center border border-gray-100 dark:border-white/5 transition-all hover:bg-white dark:hover:bg-darkcard hover:shadow-lg group">
                                <div className="relative mb-3">
                                  <img src={user.profilePicture || DEFAULT_PROFILE_PIC} className="w-16 h-16 rounded-2xl object-cover shadow-md transition-transform group-hover:scale-105" />
                                  {user.userType === UserType.CREATOR && <CheckBadgeIcon className="h-4 w-4 text-blue-600 absolute -top-1 -right-1 fill-white dark:fill-darkcard" />}
                                </div>
