import React, { useState, useRef, useEffect } from 'react';
import { Post, PostType, User, UserType, Comment } from '../types';
import { DEFAULT_PROFILE_PIC } from '../constants';
import { 
  findUserById, 
  updatePostLikes, 
  updatePostShares, 
  updatePostSaves, 
  deletePost, 
  pinPost,
  unpinPost
} from '../services/storageService';
import {
  HeartIcon as HeartIconOutline, 
  ChatBubbleOvalLeftIcon as ChatIconOutline, 
  BookmarkIcon as BookmarkIconOutline, 
  EllipsisHorizontalIcon, 
  TrashIcon, 
  CheckBadgeIcon,
  FlagIcon,
  PaperAirplaneIcon,
  MapPinIcon as PinIconOutline,
  VideoCameraIcon,
  SignalIcon,
  ArrowsPointingOutIcon
} from '@heroicons/react/24/outline';
import { 
  HeartIcon as HeartIconSolid, 
  BookmarkIcon as BookmarkIconSolid,
  MapPinIcon as PinIconSolid,
  PlayIcon
} from '@heroicons/react/24/solid';
import IndicateModal from './IndicateModal';
import PostDetailModal from './PostDetailModal';

interface PostCardProps {
  post: Post;
  currentUser: User;
  onNavigate: (page: string, params?: Record<string, string>) => void;
  onFollowToggle: (userIdToFollow: string) => void;
  refreshUser: () => void;
  onPostUpdatedOrDeleted: () => void;
  onPinToggle: (postId: string, isCurrentlyPinned: boolean) => void;
}

const PostCard: React.FC<PostCardProps> = ({ 
  post, 
  currentUser, 
  onNavigate, 
  onFollowToggle,
  refreshUser, 
  onPostUpdatedOrDeleted,
  onPinToggle
}) => {
  // Safety guard robusto
  if (!post || !currentUser || !post.id) return null;

  const postAuthor = findUserById(post.userId);
  const [showOptions, setShowOptions] = useState(false);
  const [showIndicateModal, setShowIndicateModal] = useState(false);
  const [showDetailModal, setShowDetailModal] = useState(false);

  const optionsRef = useRef<HTMLDivElement>(null);
  const hasLiked = post.likes?.includes(currentUser.id) || false;
  const hasSaved = post.saves?.includes(currentUser.id) || false;
  const isAuthor = currentUser.id === post.userId;
  const isFollowing = currentUser.followedUsers?.includes(post.userId) || false;

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (optionsRef.current && !optionsRef.current.contains(event.target as Node)) setShowOptions(false);
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const handleLike = (e: React.MouseEvent) => {
    e.stopPropagation();
    updatePostLikes(post.id, currentUser.id);
    onPostUpdatedOrDeleted();
  };

  const handleDelete = (e: React.MouseEvent) => {
    e.stopPropagation();
    if (window.confirm('Excluir esta publicação?')) {
      deletePost(post.id);
      onPostUpdatedOrDeleted();
    }
  };

  const handlePin = (e: React.MouseEvent) => {
    e.stopPropagation();
    if (post.isPinned) unpinPost(post.id, currentUser.id);
    else pinPost(post.id, currentUser.id);
    onPostUpdatedOrDeleted();
    setShowOptions(false);
  };

  if (!postAuthor) return null;

  return (
    <>
      <div 
        onClick={() => post.type !== PostType.LIVE && setShowDetailModal(true)}
        className={`bg-white dark:bg-darkcard rounded-[2rem] md:rounded-[2.5rem] shadow-sm border border-gray-100 dark:border-white/5 overflow-hidden w-full relative mb-6 transition-all hover:shadow-md animate-fade-in ${post.type !== PostType.LIVE ? 'cursor-pointer' : ''}`}
      >

        {/* HEADER */}
        <div className="p-4 md:p-5 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="relative cursor-pointer" onClick={(e) => { e.stopPropagation(); onNavigate('profile', { userId: post.userId }); }}>
              <img src={postAuthor.profilePicture || DEFAULT_PROFILE_PIC} className="w-10 h-10 md:w-11 md:h-11 rounded-xl object-cover shadow-sm" />
              {postAuthor.userType === UserType.CREATOR && (
                <div className="absolute -bottom-1 -right-1 bg-blue-600 rounded-lg p-0.5 border-2 border-white dark:border-darkcard">
                  <CheckBadgeIcon className="h-3 w-3 text-white" />
                </div>
              )}
            </div>
            <div>
              <div className="flex items-center gap-2">
                <h4 className="font-black text-gray-900 dark:text-white text-xs md:text-sm leading-tight hover:underline cursor-pointer" onClick={(e) => { e.stopPropagation(); onNavigate('profile', { userId: post.userId }); }}>
                    {postAuthor.firstName} {postAuthor.lastName}
                </h4>
                {post.isPinned && <PinIconSolid className="h-3 w-3 text-blue-500" />}
              </div>
              <p className="text-[9px] font-bold text-gray-400 uppercase tracking-wider">{new Date(post.timestamp).toLocaleDateString()}</p>
            </div>
          </div>

          <div className="relative" ref={optionsRef}>
            <button onClick={(e) => { e.stopPropagation(); setShowOptions(!showOptions); }} className="p-2 text-gray-300 hover:text-blue-600 transition-colors">
              <EllipsisHorizontalIcon className="h-6 w-6" />
            </button>
            {showOptions && (
              <div className="absolute right-0 mt-1 w-48 bg-white dark:bg-darkcard rounded-2xl shadow-2xl py-2 z-20 border dark:border-white/10 animate-fade-in" onClick={e => e.stopPropagation()}>
                {isAuthor ? (
                  <>
                    <button onClick={handlePin} className="flex items-center w-full px-4 py-3 text-[10px] font-black text-gray-700 dark:text-gray-300 hover:bg-gray-50 dark:hover:bg-white/5">
                      {post.isPinned ? <><PinIconSolid className="h-4 w-4 mr-3 text-blue-500" /> Desafixar</> : <><PinIconOutline className="h-4 w-4 mr-3 text-blue-500" /> Fixar</>}
                    </button>
                    <button onClick={handleDelete} className="flex items-center w-full px-4 py-3 text-[10px] font-black text-red-600 hover:bg-red-50 dark:hover:bg-red-900/10">
                      <TrashIcon className="h-4 w-4 mr-3" /> Excluir
                    </button>
                  </>
                ) : (
                  <>
                    {!isFollowing && (
                      <button onClick={(e) => { e.stopPropagation(); onFollowToggle(post.userId); setShowOptions(false); }} className="flex items-center w-full px-4 py-3 text-[10px] font-black text-blue-600 hover:bg-blue-50 dark:hover:bg-blue-900/10">
                        Seguir Professor
                      </button>
                    )}
                    <button onClick={(e) => e.stopPropagation()} className="flex items-center w-full px-4 py-3 text-[10px] font-black text-orange-600 hover:bg-orange-50">
                      <FlagIcon className="h-4 w-4 mr-3" /> Denunciar
                    </button>
                  </>
                )}
              </div>
            )}
          </div>
        </div>

        {/* CONTENT */}
        <div className="px-4 md:px-5 pb-4">
          {post.type === PostType.LIVE && post.liveStream ? (
             <div className="rounded-[2.5rem] overflow-hidden bg-gray-900 text-white p-6 md:p-8 relative shadow-2xl border-4 border-blue-600/30">
                <div className="absolute top-4 left-4 z-10">
                   <div className="bg-red-600 px-3 py-1.5 rounded-lg text-[8px] md:text-[9px] font-black flex items-center gap-2 shadow-lg animate-pulse uppercase tracking-widest">
                      <SignalIcon className="h-3 w-3" /> Ao Vivo
                   </div>
                </div>
                <div className="relative z-10 py-6 md:py-10 flex flex-col items-center text-center">
                   <div className="w-16 h-16 md:w-20 md:h-20 bg-blue-600/20 rounded-full flex items-center justify-center mb-6 border border-blue-500/30">
                      <VideoCameraIcon className="h-8 w-8 md:h-10 md:w-10 text-blue-400" />
                   </div>
                   <h3 className="text-xl md:text-2xl font-black mb-3 tracking-tighter leading-tight uppercase">{post.liveStream.title}</h3>
                   <p className="text-gray-400 text-xs md:text-sm max-w-sm mb-8 font-medium">{post.liveStream.description}</p>
                   <button 
                      onClick={(e) => { e.stopPropagation(); onNavigate('live', { postId: post.id }); }}
                      className="bg-blue-600 hover:bg-blue-700 text-white px-8 py-3.5 md:px-10 md:py-4 rounded-2xl font-black text-xs uppercase tracking-[0.2em] shadow-xl active:scale-95 transition-all flex items-center justify-center gap-3"
                   >
                      <PlayIcon className="h-5 w-5" /> Assistir Aula
                   </button>
                </div>
             </div>
          ) : (
            <>
              {post.content && <p className="text-gray-700 dark:text-gray-300 text-sm font-medium leading-relaxed mb-4 whitespace-pre-wrap line-clamp-3">{post.content}</p>}
              {post.imageUrl && (
                <div className="rounded-[1.5rem] md:rounded-[2rem] overflow-hidden border dark:border-white/5 bg-gray-50 dark:bg-darkbg relative group">
                   <img src={post.imageUrl} className="w-full h-auto object-cover max-h-[500px]" alt="Post" />
                   <div className="absolute inset-0 bg-black/5 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center">
                      <div className="bg-white/90 p-3 rounded-2xl shadow-xl">
                        <ArrowsPointingOutIcon className="h-6 w-6 text-blue-600" />
                      </div>
                   </div>
                </div>
              )}
            </>
          )}
        </div>

        {/* ACTIONS */}
        <div className="px-4 md:px-5 py-3 flex items-center justify-between border-t dark:border-white/5">
          <div className="flex items-center gap-1 md:gap-2">
            <button onClick={handleLike} className={`flex items-center gap-2 px-3 py-2 rounded-xl transition-all active:scale-90 ${hasLiked ? 'text-blue-600 bg-blue-50 dark:bg-blue-500/10 font-black' : 'text-gray-400 hover:bg-gray-50 dark:hover:bg-white/5'}`}>
              {hasLiked ? <HeartIconSolid className="h-5 w-5" /> : <HeartIconOutline className="h-5 w-5" />}
              <span className="text-xs font-black">{post.likes?.length || 0}</span>
            </button>

            <button onClick={(e) => { e.stopPropagation(); setShowDetailModal(true); }} className="flex items-center gap-2 px-3 py-2 rounded-xl text-gray-400 hover:bg-gray-50 dark:hover:bg-white/5 transition-all">
              <ChatIconOutline className="h-5 w-5" />
              <span className="font-black text-xs">{post.comments?.length || 0}</span>
            </button>

            <button onClick={(e) => { e.stopPropagation(); setShowIndicateModal(true); }} className="flex items-center gap-2 px-3 py-2 rounded-xl text-gray-400 hover:bg-gray-50 dark:hover:bg-white/5">
              <PaperAirplaneIcon className="h-5 w-5 -rotate-45" />
            </button>
          </div>

          <button onClick={(e) => { e.stopPropagation(); updatePostSaves(post.id, currentUser.id); onPostUpdatedOrDeleted(); }} className={`p-2.5 rounded-xl transition-all ${hasSaved ? 'text-blue-600 bg-blue-50 dark:bg-blue-900/20' : 'text-gray-300 hover:bg-gray-50 dark:hover:bg-white/5'}`}>
            {hasSaved ? <BookmarkIconSolid className="h-5 w-5" /> : <BookmarkIconOutline className="h-5 w-5" />}
          </button>
        </div>
      </div>

      {showDetailModal && (
        <PostDetailModal
          post={post}
          currentUser={currentUser}
          onClose={() => setShowDetailModal(false)}
          onUpdate={onPostUpdatedOrDeleted}
          onNavigate={onNavigate}
          refreshUser={refreshUser}
        />
      )}

      {showIndicateModal && (
        <IndicateModal 
          post={post} 
          currentUser={currentUser} 
          onClose={() => setShowIndicateModal(false)} 
          onPostUpdated={onPostUpdatedOrDeleted}
        />
      )}
    </>
  );
};

export default PostCard;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { User, Post, AdCampaign, PostType, Story, UserType } from '../types';
import { getPosts, getAds, getStories, getUsers, toggleFollowUser } from '../services/storageService';
import { DEFAULT_PROFILE_PIC } from '../constants';
import PostCard from './PostCard';
import CreatePost from './CreatePost';
import AdCard from './AdCard';
import StoryViewerModal from './StoryViewerModal';
import CreateStoryModal from './CreateStoryModal';
import { 
  PlusIcon, ArrowPathIcon, UserPlusIcon, CheckBadgeIcon, SparklesIcon
} from '@heroicons/react/24/outline';

interface FeedPageProps {
  currentUser: User;
  onNavigate: (page: string, params?: Record<string, string>) => void;
  refreshUser: () => void;
}

const ITEMS_PER_PAGE = 5;

const FeedPage: React.FC<FeedPageProps> = ({ currentUser, onNavigate, refreshUser }) => {
  const [allItems, setAllItems] = useState<(Post | AdCampaign | { type: 'SUGGESTIONS' })[]>([]);
  const [visibleItems, setVisibleItems] = useState<(Post | AdCampaign | { type: 'SUGGESTIONS' })[]>([]);
  const [displayLimit, setDisplayLimit] = useState(ITEMS_PER_PAGE);
  const [loading, setLoading] = useState(true);
  const [loadingMore, setLoadingMore] = useState(false);
  const [suggestedUsers, setSuggestedUsers] = useState<User[]>([]);
  const [stories, setStories] = useState<Story[]>([]);

  const [selectedStoryIndex, setSelectedStoryIndex] = useState<number | null>(null);
  const [isCreatingStory, setIsCreatingStory] = useState(false);

  const observerTarget = useRef<HTMLDivElement>(null);

  const loadData = useCallback(() => {
    setLoading(true);
    // Safety check: Filter out any malformed posts from storage
    const allPosts = getPosts()
      .filter(p => p && typeof p === 'object' && p.userId)
      .sort((a, b) => {
        if (a.isPinned && !b.isPinned) return -1;
        if (!a.isPinned && b.isPinned) return 1;
        return b.timestamp - a.timestamp;
    });
    const allAds = getAds();
    const allUsers = getUsers();
    const allStories = getStories();

    setStories(allStories);

    const suggestions = allUsers
      .filter(u => u && u.id !== currentUser.id && !currentUser.followedUsers?.includes(u.id))
      .sort(() => 0.5 - Math.random())
      .slice(0, 5);

    setSuggestedUsers(suggestions);

    let combined: (Post | AdCampaign | { type: 'SUGGESTIONS' })[] = [];
    allPosts.forEach((post, idx) => {
        combined.push(post);
        if (idx === 1 && suggestions.length > 0) {
            combined.push({ type: 'SUGGESTIONS' });
        }
        if ((idx + 1) % 5 === 0 && allAds.length > 0) {
            const randomAd = allAds[Math.floor(Math.random() * allAds.length)];
            if (randomAd) combined.push(randomAd);
        }
    });

    setAllItems(combined);
    setVisibleItems(combined.slice(0, ITEMS_PER_PAGE));
    setLoading(false);
  }, [currentUser]);

  useEffect(() => { loadData(); }, [loadData]);

  const loadMoreItems = useCallback(() => {
    if (loadingMore || visibleItems.length >= allItems.length) return;
    setLoadingMore(true);

    // Simula latência de rede para o spinner ficar visível
    setTimeout(() => {
      const nextLimit = displayLimit + ITEMS_PER_PAGE;
      const nextItems = allItems.slice(0, nextLimit);

      // Se chegamos no fim dos itens reais, podemos "reciclar" conteúdo educacional (opcional)
      // para criar a sensação de feed infinito exploratório.
      if (nextLimit > allItems.length && allItems.length > 0) {
         const postsOnly = allItems.filter(i => 'authorName' in i) as Post[];
         if (postsOnly.length > 0) {
            const recycled: Post[] = postsOnly
              .sort(() => Math.random() - 0.5)
              .slice(0, 3)
              .map(p => ({...p, id: `recycled-${Date.now()}-${Math.random()}`}));
            setAllItems(prev => [...prev, ...recycled]);
         }
      }

      setDisplayLimit(nextLimit);
      setVisibleItems(nextItems);
      setLoadingMore(false);
    }, 1200);
  }, [displayLimit, allItems, loadingMore, visibleItems.length]);

  useEffect(() => {
    const observer = new IntersectionObserver(
      entries => {
        if (entries[0].isIntersecting && !loading && !loadingMore) {
          loadMoreItems();
        }
      },
      { threshold: 0.1, rootMargin: '100px' }
    );

    if (observerTarget.current) observer.observe(observerTarget.current);
    return () => observer.disconnect();
  }, [loading, loadingMore, loadMoreItems]);

  const handleFollow = (userId: string) => {
    toggleFollowUser(currentUser.id, userId);
    refreshUser();
    setSuggestedUsers(prev => prev.filter(u => u.id !== userId));
  };

  return (
    <div className="w-full max-w-[1400px] mx-auto px-2 md:px-6 lg:px-10 py-4 md:py-8">

      {/* Stories Section */}
      <section className="mb-8 bg-white dark:bg-darkcard rounded-[2rem] p-4 shadow-sm border dark:border-white/10 overflow-hidden">
        <div className="flex gap-4 overflow-x-auto pb-2 no-scrollbar scroll-smooth">
          <div 
            onClick={() => setIsCreatingStory(true)}
            className="flex-shrink-0 flex flex-col items-center gap-2 cursor-pointer group"
          >
            <div className="relative p-0.5 rounded-full border-2 border-dashed border-blue-400 group-hover:border-blue-600 transition-colors">
              <img src={currentUser.profilePicture || DEFAULT_PROFILE_PIC} className="w-14 h-14 rounded-full object-cover shadow-sm" />
              <div className="absolute bottom-0 right-0 bg-blue-600 text-white rounded-full p-1 border-2 border-white dark:border-darkcard">
                <PlusIcon className="w-3 h-3 stroke-[4]" />
              </div>
            </div>
            <span className="text-[9px] font-black dark:text-white uppercase">Novo</span>
          </div>
          {stories.map((s, i) => (
            <div key={i} onClick={() => setSelectedStoryIndex(i)} className="flex-shrink-0 flex flex-col items-center gap-2 cursor-pointer group">
              <div className="p-1 rounded-full bg-gradient-to-tr from-blue-500 to-purple-600 shadow-md group-hover:scale-105 transition-transform">
                <div className="p-0.5 bg-white dark:bg-darkcard rounded-full">
                  <img src={s.userProfilePic || DEFAULT_PROFILE_PIC} className="w-14 h-14 rounded-full object-cover" />
                </div>
              </div>
              <span className="text-[9px] font-black dark:text-white truncate w-14 text-center">{s.userName.split(' ')[0]}</span>
            </div>
          ))}
        </div>
      </section>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
        <main className="col-span-1 lg:col-span-8 space-y-8">
          <CreatePost currentUser={currentUser} onPostCreated={loadData} refreshUser={refreshUser} />

          <div className="space-y-8">
            {loading ? (
              <div className="py-20 text-center flex flex-col items-center gap-4">
                <div className="w-12 h-12 border-4 border-blue-600 border-t-transparent rounded-full animate-spin"></div>
                <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Sincronizando Feed...</p>
              </div>
            ) : (
              <>
                {visibleItems.map((item, idx) => {
                  if (!item) return null;

                  if ('authorName' in item) {
                    return (
                      <div key={(item as Post).id || idx} className="animate-fade-in">
                        <PostCard 
                          post={item as Post} 
                          currentUser={currentUser} 
                          onNavigate={onNavigate} 
                          onFollowToggle={handleFollow} 
                          refreshUser={refreshUser} 
                          onPostUpdatedOrDeleted={loadData} 
                          onPinToggle={() => {}} 
                        />
                      </div>
                    );
                  }

                  if ('type' in item && item.type === 'SUGGESTIONS') {
                    return (
                      <div key="suggestions-card" className="bg-white dark:bg-darkcard rounded-[2.5rem] p-8 border border-blue-50 dark:border-white/10 shadow-sm animate-fade-in">
                        <div className="flex items-center gap-3 mb-6">
                           <SparklesIcon className="h-6 w-6 text-blue-600" />
                           <h4 className="font-black text-gray-900 dark:text-white uppercase text-xs tracking-widest">Professores Sugeridos</h4>
                        </div>
                        <div className="flex gap-4 overflow-x-auto pb-4 no-scrollbar">
                           {suggestedUsers.map(user => (
                             <div key={user.id} className="flex-shrink-0 w-40 bg-gray-50 dark:bg-darkbg rounded-3xl p-5 flex flex-col items-center text-center border border-gray-100 dark:border-white/5 transition-all hover:bg-white dark:hover:bg-darkcard hover:shadow-lg group">
                                <div className="relative mb-3">
                                  <img src={user.profilePicture || DEFAULT_PROFILE_PIC} className="w-16 h-16 rounded-2xl object-cover shadow-md transition-transform group-hover:scale-105" />
                                  {user.userType === UserType.CREATOR && <CheckBadgeIcon className="h-4 w-4 text-blue-600 absolute -top-1 -right-1 fill-white dark:fill-darkcard" />}
                                </div>
                                <p className="font-black text-[11px] dark:text-white truncate w-full">{user.firstName}</p>
                                <p className="text-[8px] font-bold text-gray-400 uppercase mb-4 truncate w-full h-3">{user.credentials || 'Especialista'}</p>
                                <button 
                                  onClick={() => handleFollow(user.id)}
                                  className="w-full py-2 bg-blue-600 text-white rounded-xl text-[9px] font-black uppercase tracking-widest hover:bg-blue-700 transition-colors shadow-md"
                                >
                                  Seguir
                                </button>
                             </div>
                           ))}
                        </div>
                      </div>
                    );
                  }

                  return <AdCard key={(item as AdCampaign).id || idx} ad={item as AdCampaign} />;
                })}

                {/* INFINITE SCROLL TARGET & LOADING INDICATOR */}
                <div ref={observerTarget} className="py-12 w-full flex flex-col items-center justify-center gap-6">
                  {loadingMore ? (
                    <div className="flex flex-col items-center gap-5 animate-fade-in">
                       <div className="relative w-14 h-14">
                         {/* Spinner Outer Ring */}
                         <div className="absolute inset-0 border-4 border-blue-100 dark:border-white/5 rounded-full"></div>
                         {/* Spinner Active Ring */}
                         <div className="absolute inset-0 border-4 border-blue-600 border-t-transparent rounded-full animate-spin shadow-[0_0_15px_rgba(37,99,235,0.3)]"></div>
                       </div>
                       <div className="text-center space-y-1">
                          <span className="text-[10px] font-black text-blue-600 dark:text-blue-400 uppercase tracking-[0.3em] block animate-pulse">
                             Expandindo horizontes
                          </span>
                          <span className="text-[8px] font-bold text-gray-400 uppercase tracking-widest block opacity-60">
                             Buscando novos saberes...
                          </span>
                       </div>
                    </div>
                  ) : (
                    <div className="flex flex-col items-center gap-3 opacity-60 hover:opacity-100 transition-opacity">
                       <div className="h-px w-24 bg-gradient-to-r from-transparent via-gray-300 dark:via-white/20 to-transparent"></div>
                       <div className="flex items-center gap-3 bg-white dark:bg-white/5 px-6 py-3 rounded-2xl border border-gray-100 dark:border-white/5 shadow-sm">
                         <SparklesIcon className="h-4 w-4 text-blue-500" />
                         <p className="text-[9px] font-black text-gray-500 dark:text-gray-400 uppercase tracking-[0.2em]">Fluxo Contínuo Ativo</p>
                       </div>
                    </div>
                  )}
                </div>
              </>
            )}
          </div>
        </main>

        <aside className="hidden lg:block lg:col-span-4">
           <div className="sticky top-24 space-y-6">
              <div className="bg-white dark:bg-darkcard rounded-[2.5rem] p-8 shadow-sm border dark:border-white/10 flex flex-col items-center">
                 <img src={currentUser.profilePicture || DEFAULT_PROFILE_PIC} className="w-20 h-20 rounded-[1.8rem] border-4 border-blue-50 shadow-lg object-cover mb-4" />
                 <h3 className="font-black text-gray-900 dark:text-white text-lg leading-tight">{currentUser.firstName} {currentUser.lastName}</h3>
                 <p className="text-[9px] font-black text-blue-600 uppercase tracking-widest mt-1">
                   {currentUser.userType === UserType.CREATOR ? 'Professor Autor' : 'Membro CyBer'}
                 </p>
                 <div className="mt-6 w-full pt-6 border-t border-gray-50 dark:border-white/5 flex justify-around">
                    <div className="text-center">
                       <p className="text-lg font-black dark:text-white">{currentUser.followers?.length || 0}</p>
                       <p className="text-[8px] font-black text-gray-400 uppercase">Alunos</p>
                    </div>
                    <div className="text-center">
                       <p className="text-lg font-black dark:text-white">{currentUser.followedUsers?.length || 0}</p>
                       <p className="text-[8px] font-black text-gray-400 uppercase">Seguindo</p>
                    </div>
                 </div>
              </div>
           </div>
        </aside>
      </div>

      {selectedStoryIndex !== null && (
        <StoryViewerModal 
          stories={stories} 
          initialIndex={selectedStoryIndex} 
          onClose={() => setSelectedStoryIndex(null)} 
        />
      )}

      {isCreatingStory && (
        <CreateStoryModal 
          currentUser={currentUser} 
          onClose={() => setIsCreatingStory(false)} 
          onStoryCreated={() => {
            setIsCreatingStory(false);
            loadData();
          }}
        />
      )}
    </div>
  );
};

