import { 
  XMarkIcon, 
  ArrowDownTrayIcon, 
  UserCircleIcon,
  CheckBadgeIcon,
  ChatBubbleOvalLeftIcon,
  ShareIcon,
  EllipsisHorizontalIcon,
  ArrowLeftIcon,
  PaperAirplaneIcon,
  HeartIcon as HeartIconOutline
} from '@heroicons/react/24/outline';
import { 
  HeartIcon as HeartIconSolid,
  BookmarkIcon as BookmarkIconSolid
} from '@heroicons/react/24/solid';

interface PostDetailModalProps {
  post: Post;
  currentUser: User;
  onClose: () => void;
  onUpdate: () => void;
  onNavigate: (page: string, params?: Record<string, string>) => void;
  refreshUser: () => void;
}

const PostDetailModal: React.FC<PostDetailModalProps> = ({ post, currentUser, onClose, onUpdate, onNavigate, refreshUser }) => {
  const [showLightbox, setShowLightbox] = useState(false);
  const [commentText, setCommentText] = useState('');
  const author = findUserById(post.userId);
  const isOwner = currentUser.id === post.userId;
  const hasLiked = post.likes?.includes(currentUser.id);

  const handleLike = (e: React.MouseEvent) => {
    e.stopPropagation();
    updatePostLikes(post.id, currentUser.id);
    onUpdate();
  };

  const handleDownload = (e: React.MouseEvent) => {
    e.stopPropagation();
    if (!post.imageUrl) return;
    const link = document.createElement('a');
    link.href = post.imageUrl;
    link.download = `cyberphone_${post.id}.jpg`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const handleSetProfilePic = (e: React.MouseEvent) => {
    e.stopPropagation();
    if (!post.imageUrl) return;
    updateUser({ ...currentUser, profilePicture: post.imageUrl });
    refreshUser();
    alert("Nova foto de perfil definida!");
  };

  const handleSendComment = (e: React.FormEvent) => {
    e.preventDefault();
    if (!commentText.trim()) return;
    addPostComment(post.id, {
      id: `comment-${Date.now()}`,
      userId: currentUser.id,
      userName: currentUser.firstName,
      profilePic: currentUser.profilePicture,
      text: commentText,
      timestamp: Date.now()
    });
    setCommentText('');
    onUpdate();
  };

  return (
    <>
      <div className="fixed inset-0 z-[200] bg-black/90 md:bg-black/80 backdrop-blur-sm flex items-center justify-center animate-fade-in" onClick={onClose}>
        <div 
          className="bg-white dark:bg-darkcard w-full h-full md:w-[95%] md:h-[90%] md:rounded-[1.5rem] overflow-hidden flex flex-col md:flex-row shadow-2xl relative" 
          onClick={e => e.stopPropagation()}
        >
          {/* BOTÃO VOLTAR MOBILE */}
          <button onClick={onClose} className="absolute top-4 left-4 z-50 md:hidden p-2 bg-black/20 rounded-full text-white">
            <ArrowLeftIcon className="h-6 w-6" />
          </button>

          {/* ÁREA DA MÍDIA (LADO ESQUERDO) */}
          <div 
            className={`w-full h-[40vh] md:h-full md:flex-1 bg-black flex items-center justify-center relative group ${post.imageUrl ? 'cursor-zoom-in' : 'hidden'}`}
            onClick={() => setShowLightbox(true)}
          >
            {post.imageUrl && (
              <img src={post.imageUrl} className="max-w-full max-h-full object-contain" alt="Post" />
            )}
            <div className="absolute inset-0 bg-black/20 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center pointer-events-none">
                <span className="bg-black/60 text-white px-4 py-2 rounded-full text-xs font-bold uppercase tracking-widest border border-white/20">Clique para expandir</span>
            </div>
          </div>

          {/* BARRA LATERAL (LADO DIREITO - INFOS E COMENTÁRIOS) */}
          <div className="flex-1 md:w-[450px] md:flex-none flex flex-col bg-white dark:bg-darkcard h-full overflow-hidden border-l border-gray-100 dark:border-white/5">

            {/* CABEÇALHO DO POST */}
            <div className="p-4 md:p-6 border-b border-gray-50 dark:border-white/5 flex items-center justify-between">
              <div className="flex items-center gap-3 cursor-pointer" onClick={() => { onClose(); onNavigate('profile', { userId: post.userId }); }}>
                <div className="relative">
                  <img src={author?.profilePicture || DEFAULT_PROFILE_PIC} className="w-10 h-10 md:w-12 md:h-12 rounded-full object-cover border dark:border-white/10" />
                  {author?.userType === UserType.CREATOR && <CheckBadgeIcon className="h-4 w-4 text-blue-600 absolute -bottom-1 -right-1 fill-white dark:fill-darkcard" />}
