import React, { useState, useRef, useEffect } from 'react';
import { Post, PostType, User, UserType, Comment } from '../types';
import { DEFAULT_PROFILE_PIC } from '../constants';
import { 
  findUserById, 
  updatePostLikes, 
  updatePostShares, 
  updatePostSaves, 
  deletePost, 
  pinPost,
  unpinPost
} from '../services/storageService';
import {
  HeartIcon as HeartIconOutline, 
  ChatBubbleOvalLeftIcon as ChatIconOutline, 
  BookmarkIcon as BookmarkIconOutline, 
  EllipsisHorizontalIcon, 
  TrashIcon, 
  CheckBadgeIcon,
  FlagIcon,
  PaperAirplaneIcon,
  MapPinIcon as PinIconOutline,
  VideoCameraIcon,
  SignalIcon,
  ArrowsPointingOutIcon
} from '@heroicons/react/24/outline';
import { 
  HeartIcon as HeartIconSolid, 
  BookmarkIcon as BookmarkIconSolid,
  MapPinIcon as PinIconSolid,
  PlayIcon
} from '@heroicons/react/24/solid';
import IndicateModal from './IndicateModal';
import PostDetailModal from './PostDetailModal';

interface PostCardProps {
  post: Post;
  currentUser: User;
  onNavigate: (page: string, params?: Record<string, string>) => void;
  onFollowToggle: (userIdToFollow: string) => void;
  refreshUser: () => void;
  onPostUpdatedOrDeleted: () => void;
  onPinToggle: (postId: string, isCurrentlyPinned: boolean) => void;
}

const PostCard: React.FC<PostCardProps> = ({ 
  post, 
  currentUser, 
  onNavigate, 
  onFollowToggle,
  refreshUser, 
  onPostUpdatedOrDeleted,
  onPinToggle
}) => {
  // Safety guard robusto
  if (!post || !currentUser || !post.id) return null;

  const postAuthor = findUserById(post.userId);
  const [showOptions, setShowOptions] = useState(false);
  const [showIndicateModal, setShowIndicateModal] = useState(false);
  const [showDetailModal, setShowDetailModal] = useState(false);

  const optionsRef = useRef<HTMLDivElement>(null);
  const hasLiked = post.likes?.includes(currentUser.id) || false;
  const hasSaved = post.saves?.includes(currentUser.id) || false;
  const isAuthor = currentUser.id === post.userId;
  const isFollowing = currentUser.followedUsers?.includes(post.userId) || false;

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (optionsRef.current && !optionsRef.current.contains(event.target as Node)) setShowOptions(false);
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const handleLike = (e: React.MouseEvent) => {
    e.stopPropagation();
    updatePostLikes(post.id, currentUser.id);
    onPostUpdatedOrDeleted();
  };

  const handleDelete = (e: React.MouseEvent) => {
    e.stopPropagation();
    if (window.confirm('Excluir esta publicação?')) {
      deletePost(post.id);
      onPostUpdatedOrDeleted();
    }
  };

  const handlePin = (e: React.MouseEvent) => {
    e.stopPropagation();
    if (post.isPinned) unpinPost(post.id, currentUser.id);
    else pinPost(post.id, currentUser.id);
    onPostUpdatedOrDeleted();
    setShowOptions(false);
  };

  if (!postAuthor) return null;

  return (
    <>
      <div 
        onClick={() => post.type !== PostType.LIVE && setShowDetailModal(true)}
        className={`bg-white dark:bg-darkcard rounded-[2rem] md:rounded-[2.5rem] shadow-sm border border-gray-100 dark:border-white/5 overflow-hidden w-full relative mb-6 transition-all hover:shadow-md animate-fade-in ${post.type !== PostType.LIVE ? 'cursor-pointer' : ''}`}
      >

        {/* HEADER */}
        <div className="p-4 md:p-5 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="relative cursor-pointer" onClick={(e) => { e.stopPropagation(); onNavigate('profile', { userId: post.userId }); }}>
              <img src={postAuthor.profilePicture || DEFAULT_PROFILE_PIC} className="w-10 h-10 md:w-11 md:h-11 rounded-xl object-cover shadow-sm" />
              {postAuthor.userType === UserType.CREATOR && (
                <div className="absolute -bottom-1 -right-1 bg-blue-600 rounded-lg p-0.5 border-2 border-white dark:border-darkcard">
                  <CheckBadgeIcon className="h-3 w-3 text-white" />
                </div>
              )}
            </div>
            <div>
              <div className="flex items-center gap-2">
                <h4 className="font-black text-gray-900 dark:text-white text-xs md:text-sm leading-tight hover:underline cursor-pointer" onClick={(e) => { e.stopPropagation(); onNavigate('profile', { userId: post.userId }); }}>
                    {postAuthor.firstName} {postAuthor.lastName}
                </h4>
                {post.isPinned && <PinIconSolid className="h-3 w-3 text-blue-500" />}
              </div>
              <p className="text-[9px] font-bold text-gray-400 uppercase tracking-wider">{new Date(post.timestamp).toLocaleDateString()}</p>
            </div>
          </div>

          <div className="relative" ref={optionsRef}>
            <button onClick={(e) => { e.stopPropagation(); setShowOptions(!showOptions); }} className="p-2 text-gray-300 hover:text-blue-600 transition-colors">
              <EllipsisHorizontalIcon className="h-6 w-6" />
            </button>
            {showOptions && (
              <div className="absolute right-0 mt-1 w-48 bg-white dark:bg-darkcard rounded-2xl shadow-2xl py-2 z-20 border dark:border-white/10 animate-fade-in" onClick={e => e.stopPropagation()}>
                {isAuthor ? (
                  <>
                    <button onClick={handlePin} className="flex items-center w-full px-4 py-3 text-[10px] font-black text-gray-700 dark:text-gray-300 hover:bg-gray-50 dark:hover:bg-white/5">
                      {post.isPinned ? <><PinIconSolid className="h-4 w-4 mr-3 text-blue-500" /> Desafixar</> : <><PinIconOutline className="h-4 w-4 mr-3 text-blue-500" /> Fixar</>}
                    </button>
                    <button onClick={handleDelete} className="flex items-center w-full px-4 py-3 text-[10px] font-black text-red-600 hover:bg-red-50 dark:hover:bg-red-900/10">
                      <TrashIcon className="h-4 w-4 mr-3" /> Excluir
                    </button>
                  </>
                ) : (
                  <>
                    {!isFollowing && (
                      <button onClick={(e) => { e.stopPropagation(); onFollowToggle(post.userId); setShowOptions(false); }} className="flex items-center w-full px-4 py-3 text-[10px] font-black text-blue-600 hover:bg-blue-50 dark:hover:bg-blue-900/10">
                        Seguir Professor
                      </button>
                    )}
                    <button onClick={(e) => e.stopPropagation()} className="flex items-center w-full px-4 py-3 text-[10px] font-black text-orange-600 hover:bg-orange-50">
                      <FlagIcon className="h-4 w-4 mr-3" /> Denunciar
                    </button>
                  </>
                )}
              </div>
            )}
          </div>
        </div>

        {/* CONTENT */}
        <div className="px-4 md:px-5 pb-4">
          {post.type === PostType.LIVE && post.liveStream ? (
             <div className="rounded-[2.5rem] overflow-hidden bg-gray-900 text-white p-6 md:p-8 relative shadow-2xl border-4 border-blue-600/30">
                <div className="absolute top-4 left-4 z-10">
                   <div className="bg-red-600 px-3 py-1.5 rounded-lg text-[8px] md:text-[9px] font-black flex items-center gap-2 shadow-lg animate-pulse uppercase tracking-widest">
                      <SignalIcon className="h-3 w-3" /> Ao Vivo
                   </div>
                </div>
                <div className="relative z-10 py-6 md:py-10 flex flex-col items-center text-center">
                   <div className="w-16 h-16 md:w-20 md:h-20 bg-blue-600/20 rounded-full flex items-center justify-center mb-6 border border-blue-500/30">
                      <VideoCameraIcon className="h-8 w-8 md:h-10 md:w-10 text-blue-400" />
                   </div>
                   <h3 className="text-xl md:text-2xl font-black mb-3 tracking-tighter leading-tight uppercase">{post.liveStream.title}</h3>
                   <p className="text-gray-400 text-xs md:text-sm max-w-sm mb-8 font-medium">{post.liveStream.description}</p>
                   <button 
                      onClick={(e) => { e.stopPropagation(); onNavigate('live', { postId: post.id }); }}
                      className="bg-blue-600 hover:bg-blue-700 text-white px-8 py-3.5 md:px-10 md:py-4 rounded-2xl font-black text-xs uppercase tracking-[0.2em] shadow-xl active:scale-95 transition-all flex items-center justify-center gap-3"
                   >
                      <PlayIcon className="h-5 w-5" /> Assistir Aula
                   </button>
                </div>
             </div>
          ) : (
            <>
              {post.content && <p className="text-gray-700 dark:text-gray-300 text-sm font-medium leading-relaxed mb-4 whitespace-pre-wrap line-clamp-3">{post.content}</p>}
              {post.imageUrl && (
                <div className="rounded-[1.5rem] md:rounded-[2rem] overflow-hidden border dark:border-white/5 bg-gray-50 dark:bg-darkbg relative group">
                   <img src={post.imageUrl} className="w-full h-auto object-cover max-h-[500px]" alt="Post" />
                   <div className="absolute inset-0 bg-black/5 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center">
                      <div className="bg-white/90 p-3 rounded-2xl shadow-xl">
                        <ArrowsPointingOutIcon className="h-6 w-6 text-blue-600" />
                      </div>
                   </div>
                </div>
              )}
            </>
          )}
        </div>

        {/* ACTIONS */}
        <div className="px-4 md:px-5 py-3 flex items-center justify-between border-t dark:border-white/5">
          <div className="flex items-center gap-1 md:gap-2">
            <button onClick={handleLike} className={`flex items-center gap-2 px-3 py-2 rounded-xl transition-all active:scale-90 ${hasLiked ? 'text-blue-600 bg-blue-50 dark:bg-blue-500/10 font-black' : 'text-gray-400 hover:bg-gray-50 dark:hover:bg-white/5'}`}>
              {hasLiked ? <HeartIconSolid className="h-5 w-5" /> : <HeartIconOutline className="h-5 w-5" />}
              <span className="text-xs font-black">{post.likes?.length || 0}</span>
            </button>

            <button onClick={(e) => { e.stopPropagation(); setShowDetailModal(true); }} className="flex items-center gap-2 px-3 py-2 rounded-xl text-gray-400 hover:bg-gray-50 dark:hover:bg-white/5 transition-all">
              <ChatIconOutline className="h-5 w-5" />
              <span className="font-black text-xs">{post.comments?.length || 0}</span>
            </button>

            <button onClick={(e) => { e.stopPropagation(); setShowIndicateModal(true); }} className="flex items-center gap-2 px-3 py-2 rounded-xl text-gray-400 hover:bg-gray-50 dark:hover:bg-white/5">
              <PaperAirplaneIcon className="h-5 w-5 -rotate-45" />
            </button>
          </div>

          <button onClick={(e) => { e.stopPropagation(); updatePostSaves(post.id, currentUser.id); onPostUpdatedOrDeleted(); }} className={`p-2.5 rounded-xl transition-all ${hasSaved ? 'text-blue-600 bg-blue-50 dark:bg-blue-900/20' : 'text-gray-300 hover:bg-gray-50 dark:hover:bg-white/5'}`}>
            {hasSaved ? <BookmarkIconSolid className="h-5 w-5" /> : <BookmarkIconOutline className="h-5 w-5" />}
          </button>
        </div>
      </div>

      {showDetailModal && (
        <PostDetailModal
          post={post}
          currentUser={currentUser}
          onClose={() => setShowDetailModal(false)}
          onUpdate={onPostUpdatedOrDeleted}
          onNavigate={onNavigate}
          refreshUser={refreshUser}
        />
      )}

      {showIndicateModal && (
        <IndicateModal 
          post={post} 
          currentUser={currentUser} 
          onClose={() => setShowIndicateModal(false)} 
          onPostUpdated={onPostUpdatedOrDeleted}
        />
      )}
    </>
  );
};

export default PostCard;

import React, { useState, useEffect } from 'react';
import { Post, User, UserType } from '../types';
import { findUserById, updateUser, addPostComment, updatePostLikes, updatePostSaves, toggleFollowUser } from '../services/storageService';
import { DEFAULT_PROFILE_PIC } from '../constants';
import { 
  XMarkIcon, 
  ArrowDownTrayIcon, 
  UserCircleIcon,
  CheckBadgeIcon,
  ChatBubbleOvalLeftIcon,
  ShareIcon,
  ArrowLeftIcon,
  PaperAirplaneIcon,
  UserPlusIcon,
  HeartIcon as HeartIconOutline,
  BookmarkIcon as BookmarkIconOutline
} from '@heroicons/react/24/outline';
import { 
  HeartIcon as HeartIconSolid,
  BookmarkIcon as BookmarkIconSolid
} from '@heroicons/react/24/solid';

interface PostDetailModalProps {
  post: Post;
  currentUser: User;
  onClose: () => void;
  onUpdate: () => void;
  onNavigate: (page: string, params?: Record<string, string>) => void;
  refreshUser: () => void;
}

const PostDetailModal: React.FC<PostDetailModalProps> = ({ post, currentUser, onClose, onUpdate, onNavigate, refreshUser }) => {
  const [showLightbox, setShowLightbox] = useState(false);
  const [commentText, setCommentText] = useState('');
  const author = findUserById(post.userId);
  const isOwner = currentUser.id === post.userId;
  const isFollowing = currentUser.followedUsers?.includes(post.userId);

  const hasLiked = post.likes?.includes(currentUser.id);
  const hasSaved = post.saves?.includes(currentUser.id);

  // Bloqueia o scroll do body ao abrir
  useEffect(() => {
    document.body.style.overflow = 'hidden';
    return () => { document.body.style.overflow = 'auto'; };
  }, []);

  const handleLike = (e: React.MouseEvent) => {
    e.stopPropagation();
    updatePostLikes(post.id, currentUser.id);
    onUpdate();
  };

  const handleSave = (e: React.MouseEvent) => {
    e.stopPropagation();
    updatePostSaves(post.id, currentUser.id);
    onUpdate();
  };

  const handleFollow = (e: React.MouseEvent) => {
    e.stopPropagation();
    toggleFollowUser(currentUser.id, post.userId);
    refreshUser();
    onUpdate();
  };

  const handleDownload = (e: React.MouseEvent) => {
    e.stopPropagation();
    if (!post.imageUrl) return;
    const link = document.createElement('a');
    link.href = post.imageUrl;
    link.download = `cyberphone_${post.id}.jpg`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const handleSendComment = (e: React.FormEvent) => {
    e.preventDefault();
    if (!commentText.trim()) return;
    addPostComment(post.id, {
      id: `comment-${Date.now()}`,
      userId: currentUser.id,
      userName: `${currentUser.firstName} ${currentUser.lastName}`,
      profilePic: currentUser.profilePicture,
      text: commentText,
      timestamp: Date.now()
    });
    setCommentText('');
    onUpdate();
  };

  return (
    <>
      <div className="fixed inset-0 z-[300] bg-black md:bg-black/95 flex items-center justify-center animate-fade-in">

        {/* BOTÃO FECHAR DESKTOP (FLUTUANTE) */}
        <button 
          onClick={onClose} 
          className="absolute top-6 right-6 z-[310] hidden md:flex p-3 bg-white/10 hover:bg-white/20 text-white rounded-full transition-all backdrop-blur-md"
        >
          <XMarkIcon className="h-8 w-8" />
        </button>

        <div className="w-full h-full flex flex-col md:flex-row bg-white dark:bg-darkcard overflow-hidden md:shadow-2xl">

          {/* BOTÃO VOLTAR MOBILE */}
          <div className="md:hidden flex items-center p-4 border-b dark:border-white/5 bg-white dark:bg-darkcard">
             <button onClick={onClose} className="p-2 -ml-2 text-gray-500 dark:text-white">
                <ArrowLeftIcon className="h-6 w-6" />
             </button>
             <span className="ml-4 font-black text-xs uppercase tracking-widest dark:text-white">Publicação</span>
          </div>

          {/* ÁREA DA MÍDIA (LADO ESQUERDO) */}
          <div 
            className={`w-full h-[45vh] md:h-full md:flex-1 bg-[#050505] flex items-center justify-center relative group ${post.imageUrl ? 'cursor-zoom-in' : 'hidden md:flex bg-gray-100 dark:bg-darkbg'}`}
            onClick={() => post.imageUrl && setShowLightbox(true)}
          >
            {post.imageUrl ? (
              <img src={post.imageUrl} className="max-w-full max-h-full object-contain" alt="Post" />
            ) : (
              <div className="text-center p-10 opacity-20">
                 <ChatBubbleOvalLeftIcon className="h-20 w-20 mx-auto mb-4 dark:text-white" />
                 <p className="font-black text-xs uppercase tracking-widest dark:text-white">Conteúdo apenas em texto</p>
              </div>
            )}

            {post.imageUrl && (
              <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center pointer-events-none">
                  <span className="bg-white/10 text-white px-6 py-2.5 rounded-full text-xs font-black uppercase tracking-[0.2em] border border-white/20 backdrop-blur-md">Clique para Expandir</span>
              </div>
            )}
          </div>

          {/* BARRA LATERAL DE INFOS (LADO DIREITO) */}
          <div className="flex-1 md:w-[500px] md:flex-none flex flex-col bg-white dark:bg-darkcard h-full overflow-hidden border-l border-gray-100 dark:border-white/5 shadow-2xl">

            {/* CABEÇALHO DO AUTOR */}
            <div className="p-5 md:p-6 border-b border-gray-50 dark:border-white/5 flex items-center justify-between sticky top-0 bg-white dark:bg-darkcard z-20">
              <div className="flex items-center gap-3 cursor-pointer group" onClick={() => { onClose(); onNavigate('profile', { userId: post.userId }); }}>
                <div className="relative">
                  <img src={author?.profilePicture || DEFAULT_PROFILE_PIC} className="w-11 h-11 md:w-12 md:h-12 rounded-2xl object-cover border-2 border-transparent group-hover:border-blue-600 transition-all shadow-sm" />
                  {author?.userType === UserType.CREATOR && <CheckBadgeIcon className="h-4 w-4 text-blue-600 absolute -top-1 -right-1 fill-white dark:fill-darkcard" />}
                </div>
                <div>
                  <h4 className="font-black text-sm md:text-base dark:text-white leading-tight group-hover:text-blue-600 transition-colors">{author?.firstName} {author?.lastName}</h4>
                  <p className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">{new Date(post.timestamp).toLocaleDateString()}</p>
                </div>
              </div>

              {!isOwner && (
                <button 
                  onClick={handleFollow}
                  className={`px-4 py-2 rounded-xl font-black text-[10px] uppercase transition-all flex items-center gap-2 ${isFollowing ? 'text-gray-400 bg-gray-50 dark:bg-white/5' : 'text-blue-600 bg-blue-50 dark:bg-blue-600/10'}`}
                >
                  {isFollowing ? 'Seguindo' : <><UserPlusIcon className="h-4 w-4" /> Seguir</>}
                </button>
              )}
            </div>

            {/* ÁREA DE SCROLL (TEXTO + COMENTÁRIOS) */}
            <div className="flex-1 overflow-y-auto custom-scrollbar p-5 md:p-8 space-y-8 bg-gray-50/30 dark:bg-black/10">

              {/* CONTEÚDO TEXTUAL */}
              {post.content && (
                <div className="bg-white dark:bg-darkcard p-6 rounded-[2rem] shadow-sm border dark:border-white/5">
                  <p className="text-gray-800 dark:text-gray-200 text-sm md:text-lg leading-relaxed font-medium whitespace-pre-wrap">
                    {post.content}
                  </p>
                </div>
              )}

              {/* STATS RÁPIDOS */}
              <div className="flex items-center gap-6 pb-4 px-2">
                 <div className="flex items-center gap-2">
                    <div className="bg-blue-600 p-1.5 rounded-full"><HeartIconSolid className="h-3 w-3 text-white" /></div>
                    <span className="text-[11px] font-black text-gray-600 dark:text-gray-300 uppercase tracking-widest">{post.likes?.length || 0} curtidas</span>
                 </div>
                 <div className="flex items-center gap-2">
                    <div className="bg-gray-200 dark:bg-white/10 p-1.5 rounded-full"><ChatBubbleOvalLeftIcon className="h-3 w-3 text-gray-600 dark:text-white" /></div>
                    <span className="text-[11px] font-black text-gray-600 dark:text-gray-300 uppercase tracking-widest">{post.comments?.length || 0} comentários</span>
                 </div>
              </div>

              {/* LISTA DE COMENTÁRIOS */}
              <div className="space-y-6">
                <h5 className="text-[10px] font-black text-gray-400 uppercase tracking-[0.3em] ml-2">Debate na Aula</h5>

                {(!post.comments || post.comments.length === 0) ? (
                  <div className="text-center py-12 opacity-30">
                    <ChatBubbleOvalLeftIcon className="h-12 w-12 mx-auto mb-3" />
                    <p className="text-[10px] font-black uppercase tracking-widest">Inicie a discussão sobre este tema</p>
                  </div>
                ) : (
                  post.comments.map((c, idx) => (
                    <div key={c.id} className="flex gap-4 animate-fade-in group" style={{ animationDelay: `${idx * 0.05}s` }}>
                       <img src={c.profilePic || DEFAULT_PROFILE_PIC} className="w-9 h-9 rounded-xl object-cover shadow-sm border dark:border-white/10" />
                       <div className="flex-1">
                          <div className="bg-white dark:bg-white/5 p-4 rounded-2xl rounded-tl-none border border-gray-100 dark:border-white/5 shadow-sm group-hover:shadow-md transition-all">
                             <div className="flex justify-between items-start mb-1">
                                <p className="text-[11px] font-black text-blue-600 dark:text-blue-400 uppercase tracking-tighter">{c.userName}</p>
                             </div>
                             <p className="text-xs md:text-sm text-gray-700 dark:text-gray-300 font-medium leading-relaxed">{c.text}</p>
                          </div>
                          <p className="text-[8px] font-black text-gray-400 uppercase mt-2 ml-2 tracking-widest">{new Date(c.timestamp).toLocaleTimeString([], {hour:'2-digit', minute:'2-digit'})}</p>
                       </div>
                    </div>
                  ))
                )}
              </div>
            </div>

            {/* RODAPÉ INTERATIVO (FIXO NA LATERAL) */}
            <div className="p-5 md:p-6 border-t border-gray-100 dark:border-white/5 bg-white dark:bg-darkcard">
               {/* BOTÕES DE AÇÃO */}
               <div className="flex items-center gap-3 mb-6">
                  <button onClick={handleLike} className={`flex-1 flex items-center justify-center gap-2 py-4 rounded-2xl transition-all active:scale-90 ${hasLiked ? 'text-blue-600 bg-blue-50 dark:bg-blue-600/10 font-black' : 'text-gray-500 bg-gray-50 dark:bg-white/5 font-bold'}`}>
                     {hasLiked ? <HeartIconSolid className="h-6 w-6" /> : <HeartIconOutline className="h-6 w-6" />}
                     <span className="text-xs uppercase tracking-widest">Curtir</span>
                  </button>
                  <button onClick={handleSave} className={`p-4 rounded-2xl transition-all ${hasSaved ? 'text-yellow-500 bg-yellow-50 dark:bg-yellow-500/10' : 'text-gray-400 bg-gray-50 dark:bg-white/5'}`}>
                     {hasSaved ? <BookmarkIconSolid className="h-6 w-6" /> : <BookmarkIconOutline className="h-6 w-6" />}
                  </button>
                  <button className="p-4 bg-gray-50 dark:bg-white/5 text-gray-400 rounded-2xl hover:text-blue-600 transition-colors">
                     <ShareIcon className="h-6 w-6" />
                  </button>
               </div>

               {/* FORMULÁRIO DE COMENTÁRIO */}
               <form onSubmit={handleSendComment} className="flex items-center gap-3">
                  <img src={currentUser.profilePicture || DEFAULT_PROFILE_PIC} className="w-10 h-10 rounded-xl hidden md:block border shadow-sm" />
                  <div className="flex-1 relative group">
                    <input 
                      type="text" 
                      value={commentText}
                      onChange={e => setCommentText(e.target.value)}
                      placeholder="Diga algo sobre este post..." 
                      className="w-full pl-5 pr-14 py-4 bg-gray-50 dark:bg-darkbg border-2 border-transparent focus:border-blue-500 rounded-2xl text-xs md:text-sm font-bold dark:text-white outline-none transition-all shadow-inner"
                    />
                    <button type="submit" disabled={!commentText.trim()} className="absolute right-2 top-1/2 -translate-y-1/2 p-2 bg-blue-600 text-white rounded-xl shadow-lg active:scale-90 transition-all disabled:opacity-30">
                       <PaperAirplaneIcon className="h-5 w-5 -rotate-45" />
                    </button>
                  </div>
               </form>
            </div>
          </div>
        </div>
      </div>

      {/* LIGHTBOX FULLSCREEN (Z-INDEX ALTÍSSIMO) */}
      {showLightbox && post.imageUrl && (
        <div className="fixed inset-0 z-[1000] bg-black flex flex-col animate-fade-in" onClick={() => setShowLightbox(false)}>
           {/* CONTROLES DO LIGHTBOX */}
           <div className="absolute top-0 left-0 w-full p-6 md:p-10 flex justify-between items-center z-[1010] bg-gradient-to-b from-black/80 to-transparent">
              <button onClick={() => setShowLightbox(false)} className="p-4 bg-white/10 hover:bg-white/20 rounded-full text-white backdrop-blur-md transition-all shadow-2xl">
                 <XMarkIcon className="h-8 w-8" />
              </button>

              <div className="flex gap-3">
                 <button onClick={handleDownload} className="flex items-center gap-3 bg-white/10 hover:bg-white/20 px-8 py-4 rounded-2xl text-xs font-black uppercase text-white backdrop-blur-md transition-all border border-white/10">
                    <ArrowDownTrayIcon className="h-5 w-5" /> Download
