           {/* RODAPÉ DO LIGHTBOX */}
           <div className="absolute bottom-0 left-0 w-full p-10 text-white bg-gradient-to-t from-black/80 to-transparent pointer-events-none">
              <p className="text-[10px] font-black text-gray-400 uppercase tracking-[0.3em] mb-2">Obra de</p>
              <p className="text-2xl font-black">{author?.firstName} {author?.lastName}</p>
