import React, { useState, useRef, useEffect } from 'react';
import { Post, PostType, User, UserType, Comment } from '../types';
import { DEFAULT_PROFILE_PIC } from '../constants';
import { 
  findUserById, 
  updatePostLikes, 
  updatePostShares, 
  updatePostSaves, 
  deletePost, 
  pinPost,
  unpinPost
} from '../services/storageService';
import {
  HeartIcon as HeartIconOutline, 
  ChatBubbleOvalLeftIcon as ChatIconOutline, 
  BookmarkIcon as BookmarkIconOutline, 
  EllipsisHorizontalIcon, 
  TrashIcon, 
  CheckBadgeIcon,
  FlagIcon,
  PaperAirplaneIcon,
  MapPinIcon as PinIconOutline,
  VideoCameraIcon,
  SignalIcon,
  ArrowsPointingOutIcon
} from '@heroicons/react/24/outline';
import { 
  HeartIcon as HeartIconSolid, 
  BookmarkIcon as BookmarkIconSolid,
  MapPinIcon as PinIconSolid,
  PlayIcon
} from '@heroicons/react/24/solid';
import IndicateModal from './IndicateModal';
import PostDetailModal from './PostDetailModal';

interface PostCardProps {
  post: Post;
  currentUser: User;
  onNavigate: (page: string, params?: Record<string, string>) => void;
  onFollowToggle: (userIdToFollow: string) => void;
  refreshUser: () => void;
  onPostUpdatedOrDeleted: () => void;
  onPinToggle: (postId: string, isCurrentlyPinned: boolean) => void;
}

const PostCard: React.FC<PostCardProps> = ({ 
  post, 
  currentUser, 
  onNavigate, 
  onFollowToggle,
  refreshUser, 
  onPostUpdatedOrDeleted,
  onPinToggle
}) => {
  // Safety guard robusto
  if (!post || !currentUser || !post.id) return null;

  const postAuthor = findUserById(post.userId);
  const [showOptions, setShowOptions] = useState(false);
  const [showIndicateModal, setShowIndicateModal] = useState(false);
  const [showDetailModal, setShowDetailModal] = useState(false);

  const optionsRef = useRef<HTMLDivElement>(null);
  const hasLiked = post.likes?.includes(currentUser.id) || false;
  const hasSaved = post.saves?.includes(currentUser.id) || false;
  const isAuthor = currentUser.id === post.userId;
  const isFollowing = currentUser.followedUsers?.includes(post.userId) || false;

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (optionsRef.current && !optionsRef.current.contains(event.target as Node)) setShowOptions(false);
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const handleLike = (e: React.MouseEvent) => {
    e.stopPropagation();
    updatePostLikes(post.id, currentUser.id);
    onPostUpdatedOrDeleted();
  };

  const handleDelete = (e: React.MouseEvent) => {
    e.stopPropagation();
    if (window.confirm('Excluir esta publicação?')) {
      deletePost(post.id);
      onPostUpdatedOrDeleted();
    }
  };

  const handlePin = (e: React.MouseEvent) => {
    e.stopPropagation();
    if (post.isPinned) unpinPost(post.id, currentUser.id);
    else pinPost(post.id, currentUser.id);
    onPostUpdatedOrDeleted();
    setShowOptions(false);
  };

  if (!postAuthor) return null;

  return (
    <>
      <div 
        onClick={() => post.type !== PostType.LIVE ? setShowDetailModal(true) : onNavigate('live', { postId: post.id })}
        className={`bg-white dark:bg-darkcard rounded-[2rem] md:rounded-[2.5rem] shadow-sm border border-gray-100 dark:border-white/5 overflow-hidden w-full relative mb-6 transition-all hover:shadow-md animate-fade-in cursor-pointer`}
      >

        {/* HEADER */}
        <div className="p-4 md:p-5 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="relative cursor-pointer" onClick={(e) => { e.stopPropagation(); onNavigate('profile', { userId: post.userId }); }}>
              <img src={postAuthor.profilePicture || DEFAULT_PROFILE_PIC} className="w-10 h-10 md:w-11 md:h-11 rounded-xl object-cover shadow-sm" />
              {postAuthor.userType === UserType.CREATOR && (
                <div className="absolute -bottom-1 -right-1 bg-blue-600 rounded-lg p-0.5 border-2 border-white dark:border-darkcard">
                  <CheckBadgeIcon className="h-3 w-3 text-white" />
                </div>
              )}
            </div>
            <div>
              <div className="flex items-center gap-2">
                <h4 className="font-black text-gray-900 dark:text-white text-xs md:text-sm leading-tight hover:underline cursor-pointer" onClick={(e) => { e.stopPropagation(); onNavigate('profile', { userId: post.userId }); }}>
                    {postAuthor.firstName} {postAuthor.lastName}
                </h4>
                {post.isPinned && <PinIconSolid className="h-3 w-3 text-blue-500" />}
              </div>
              <p className="text-[9px] font-bold text-gray-400 uppercase tracking-wider">{new Date(post.timestamp).toLocaleDateString()}</p>
            </div>
          </div>

          <div className="relative" ref={optionsRef}>
            <button onClick={(e) => { e.stopPropagation(); setShowOptions(!showOptions); }} className="p-2 text-gray-300 hover:text-blue-600 transition-colors">
              <EllipsisHorizontalIcon className="h-6 w-6" />
            </button>
            {showOptions && (
              <div className="absolute right-0 mt-1 w-48 bg-white dark:bg-darkcard rounded-2xl shadow-2xl py-2 z-20 border dark:border-white/10 animate-fade-in" onClick={e => e.stopPropagation()}>
                {isAuthor ? (
                  <>
                    <button onClick={handlePin} className="flex items-center w-full px-4 py-3 text-[10px] font-black text-gray-700 dark:text-gray-300 hover:bg-gray-50 dark:hover:bg-white/5">
                      {post.isPinned ? <><PinIconSolid className="h-4 w-4 mr-3 text-blue-500" /> Desafixar</> : <><PinIconOutline className="h-4 w-4 mr-3 text-blue-500" /> Fixar</>}
                    </button>
                    <button onClick={handleDelete} className="flex items-center w-full px-4 py-3 text-[10px] font-black text-red-600 hover:bg-red-50 dark:hover:bg-red-900/10">
                      <TrashIcon className="h-4 w-4 mr-3" /> Excluir
                    </button>
                  </>
                ) : (
                  <>
                    {!isFollowing && (
                      <button onClick={(e) => { e.stopPropagation(); onFollowToggle(post.userId); setShowOptions(false); }} className="flex items-center w-full px-4 py-3 text-[10px] font-black text-blue-600 hover:bg-blue-50 dark:hover:bg-blue-900/10">
                        Seguir Professor
                      </button>
                    )}
                    <button onClick={(e) => { e.stopPropagation(); onNavigate('report-user', { userId: post.userId }); }} className="flex items-center w-full px-4 py-3 text-[10px] font-black text-orange-600 hover:bg-orange-50">
                      <FlagIcon className="h-4 w-4 mr-3" /> Denunciar
                    </button>
                  </>
                )}
              </div>
            )}
          </div>
        </div>

        {/* CONTENT */}
        <div className="px-4 md:px-5 pb-4">
          {post.type === PostType.LIVE && post.liveStream ? (
             <div className="rounded-[2.5rem] overflow-hidden bg-gray-900 text-white p-6 md:p-8 relative shadow-2xl border-4 border-blue-600/30">
                <div className="absolute top-4 left-4 z-10">
                   <div className="bg-red-600 px-3 py-1.5 rounded-lg text-[8px] md:text-[9px] font-black flex items-center gap-2 shadow-lg animate-pulse uppercase tracking-widest">
                      <SignalIcon className="h-3 w-3" /> Ao Vivo
                   </div>
                </div>
                <div className="relative z-10 py-6 md:py-10 flex flex-col items-center text-center">
                   <div className="w-16 h-16 md:w-20 md:h-20 bg-blue-600/20 rounded-full flex items-center justify-center mb-6 border border-blue-500/30">
                      <VideoCameraIcon className="h-8 w-8 md:h-10 md:w-10 text-blue-400" />
                   </div>
                   <h3 className="text-xl md:text-2xl font-black mb-3 tracking-tighter leading-tight uppercase">{post.liveStream.title}</h3>
                   <p className="text-gray-400 text-xs md:text-sm max-w-sm mb-8 font-medium">{post.liveStream.description}</p>
                   <button 
                      onClick={(e) => { e.stopPropagation(); onNavigate('live', { postId: post.id }); }}
                      className="bg-blue-600 hover:bg-blue-700 text-white px-8 py-3.5 md:px-10 md:py-4 rounded-2xl font-black text-xs uppercase tracking-[0.2em] shadow-xl active:scale-95 transition-all flex items-center justify-center gap-3"
                   >
                      <PlayIcon className="h-5 w-5" /> Assistir Aula
                   </button>
                </div>
             </div>
          ) : (
            <>
              {post.content && <p className="text-gray-700 dark:text-gray-300 text-sm font-medium leading-relaxed mb-4 whitespace-pre-wrap line-clamp-3">{post.content}</p>}
              {post.imageUrl && (
                <div className="rounded-[1.5rem] md:rounded-[2rem] overflow-hidden border dark:border-white/5 bg-gray-50 dark:bg-darkbg relative group">
                   <img src={post.imageUrl} className="w-full h-auto object-cover max-h-[500px]" alt="Post" />
                   <div className="absolute inset-0 bg-black/5 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center">
                      <div className="bg-white/90 p-3 rounded-2xl shadow-xl">
                        <ArrowsPointingOutIcon className="h-6 w-6 text-blue-600" />
                      </div>
                   </div>
                </div>
              )}
            </>
          )}
        </div>

        {/* ACTIONS */}
        <div className="px-4 md:px-5 py-3 flex items-center justify-between border-t dark:border-white/5">
          <div className="flex items-center gap-1 md:gap-2">
            <button onClick={handleLike} className={`flex items-center gap-2 px-3 py-2 rounded-xl transition-all active:scale-90 ${hasLiked ? 'text-blue-600 bg-blue-50 dark:bg-blue-500/10 font-black' : 'text-gray-400 hover:bg-gray-50 dark:hover:bg-white/5'}`}>
              {hasLiked ? <HeartIconSolid className="h-5 w-5" /> : <HeartIconOutline className="h-5 w-5" />}
              <span className="text-xs font-black">{post.likes?.length || 0}</span>
            </button>

            <button onClick={(e) => { e.stopPropagation(); setShowDetailModal(true); }} className="flex items-center gap-2 px-3 py-2 rounded-xl text-gray-400 hover:bg-gray-50 dark:hover:bg-white/5 transition-all">
              <ChatIconOutline className="h-5 w-5" />
              <span className="font-black text-xs">{post.comments?.length || 0}</span>
            </button>

            <button onClick={(e) => { e.stopPropagation(); setShowIndicateModal(true); }} className="flex items-center gap-2 px-3 py-2 rounded-xl text-gray-400 hover:bg-gray-50 dark:hover:bg-white/5">
              <PaperAirplaneIcon className="h-5 w-5 -rotate-45" />
            </button>
          </div>

          <button onClick={(e) => { e.stopPropagation(); updatePostSaves(post.id, currentUser.id); onPostUpdatedOrDeleted(); }} className={`p-2.5 rounded-xl transition-all ${hasSaved ? 'text-blue-600 bg-blue-50 dark:bg-blue-900/20' : 'text-gray-300 hover:bg-gray-50 dark:hover:bg-white/5'}`}>
            {hasSaved ? <BookmarkIconSolid className="h-5 w-5" /> : <BookmarkIconOutline className="h-5 w-5" />}
          </button>
        </div>
      </div>

      {showDetailModal && (
        <PostDetailModal
          post={post}
          currentUser={currentUser}
          onClose={() => setShowDetailModal(false)}
          onUpdate={onPostUpdatedOrDeleted}
          onNavigate={onNavigate}
          refreshUser={refreshUser}
        />
      )}

      {showIndicateModal && (
        <IndicateModal 
          post={post} 
          currentUser={currentUser} 
          onClose={() => setShowIndicateModal(false)} 
          onPostUpdated={onPostUpdatedOrDeleted}
        />
      )}
    </>
  );
};

export default PostCard;

import React, { useState, useEffect } from 'react';
import { Post, User, UserType } from '../types';
import { findUserById, updateUser, addPostComment, updatePostLikes, updatePostSaves, toggleFollowUser } from '../services/storageService';
import { DEFAULT_PROFILE_PIC } from '../constants';
import { 
  XMarkIcon, 
  ArrowDownTrayIcon, 
  UserCircleIcon,
  CheckBadgeIcon,
  ChatBubbleOvalLeftIcon,
  ShareIcon,
  ArrowLeftIcon,
  PaperAirplaneIcon,
  UserPlusIcon,
  HeartIcon as HeartIconOutline,
  BookmarkIcon as BookmarkIconOutline
} from '@heroicons/react/24/outline';
import { 
  HeartIcon as HeartIconSolid,
  BookmarkIcon as BookmarkIconSolid
} from '@heroicons/react/24/solid';

interface PostDetailModalProps {
  post: Post;
  currentUser: User;
  onClose: () => void;
  onUpdate: () => void;
  onNavigate: (page: string, params?: Record<string, string>) => void;
  refreshUser: () => void;
}

const PostDetailModal: React.FC<PostDetailModalProps> = ({ post, currentUser, onClose, onUpdate, onNavigate, refreshUser }) => {
  const [showLightbox, setShowLightbox] = useState(false);
  const [commentText, setCommentText] = useState('');
  const author = findUserById(post.userId);
  const isOwner = currentUser.id === post.userId;
  const isFollowing = currentUser.followedUsers?.includes(post.userId);

  const hasLiked = post.likes?.includes(currentUser.id);
  const hasSaved = post.saves?.includes(currentUser.id);

  // Bloqueia o scroll do body ao abrir
  useEffect(() => {
    document.body.style.overflow = 'hidden';
    return () => { document.body.style.overflow = 'auto'; };
  }, []);

  const handleLike = (e: React.MouseEvent) => {
    e.stopPropagation();
    updatePostLikes(post.id, currentUser.id);
    onUpdate();
  };

  const handleSave = (e: React.MouseEvent) => {
    e.stopPropagation();
    updatePostSaves(post.id, currentUser.id);
    onUpdate();
  };

  const handleFollow = (e: React.MouseEvent) => {
    e.stopPropagation();
    toggleFollowUser(currentUser.id, post.userId);
    refreshUser();
    onUpdate();
  };

  const handleDownload = (e: React.MouseEvent) => {
    e.stopPropagation();
    if (!post.imageUrl) return;
    const link = document.createElement('a');
    link.href = post.imageUrl;
    link.download = `cyberphone_${post.id}.jpg`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const handleSendComment = (e: React.FormEvent) => {
    e.preventDefault();
    if (!commentText.trim()) return;
    addPostComment(post.id, {
      id: `comment-${Date.now()}`,
      userId: currentUser.id,
      userName: `${currentUser.firstName} ${currentUser.lastName}`,
      profilePic: currentUser.profilePicture,
      text: commentText,
      timestamp: Date.now()
    });
    setCommentText('');
    onUpdate();
  };

  return (
    <>
      <div className="fixed inset-0 z-[300] bg-black tablet:bg-black/95 flex items-center justify-center animate-fade-in overflow-hidden">

        {/* BOTÃO FECHAR DESKTOP (FLUTUANTE) */}
        <button 
          onClick={onClose} 
          className="absolute top-6 right-6 z-[310] hidden tablet:flex p-3 bg-white/10 hover:bg-white/20 text-white rounded-full transition-all backdrop-blur-md"
        >
          <XMarkIcon className="h-8 w-8" />
        </button>

