          <div 
            className={`w-full h-[45vh] tablet:h-full tablet:flex-1 bg-[#050505] flex items-center justify-center relative group ${post.imageUrl ? 'cursor-zoom-in' : 'hidden tablet:flex bg-gray-100 dark:bg-darkbg'}`}
