                  {author?.userType === UserType.CREATOR && <CheckBadgeIcon className="h-4 w-4 text-blue-600 absolute -top-1 -right-1 fill-white dark:fill-darkcard" />}
                </div>
                <div>
                  <h4 className="font-black text-sm tablet:text-base dark:text-white leading-tight group-hover:text-blue-600 transition-colors">{author?.firstName} {author?.lastName}</h4>
                  <p className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">{new Date(post.timestamp).toLocaleDateString()}</p>
