              </div>

              {!isOwner && (
                <button 
                  onClick={handleFollow}
                  className={`px-4 py-2 rounded-xl font-black text-[10px] uppercase transition-all flex items-center gap-2 ${isFollowing ? 'text-gray-400 bg-gray-50 dark:bg-white/5' : 'text-blue-600 bg-blue-50 dark:bg-blue-600/10'}`}
