            {/* ÁREA DE SCROLL (TEXTO + COMENTÁRIOS) */}
            <div className="flex-1 overflow-y-auto custom-scrollbar p-5 tablet:p-8 space-y-8 bg-gray-50/30 dark:bg-black/10 pb-32 tablet:pb-8">

