                    <div className="bg-blue-600 p-1.5 rounded-full"><HeartIconSolid className="h-3 w-3 text-white" /></div>
                    <span className="text-[11px] font-black text-gray-600 dark:text-gray-300 uppercase tracking-widest">{post.likes?.length || 0} curtidas</span>
                 </div>
                 <div className="flex items-center gap-2">
                    <div className="bg-gray-200 dark:bg-white/10 p-1.5 rounded-full"><ChatBubbleOvalLeftIcon className="h-3 w-3 text-gray-600 dark:text-white" /></div>
                    <span className="text-[11px] font-black text-gray-600 dark:text-gray-300 uppercase tracking-widest">{post.comments?.length || 0} comentários</span>
                 </div>
              </div>

              {/* LISTA DE COMENTÁRIOS */}
              <div className="space-y-6">
                <h5 className="text-[10px] font-black text-gray-400 uppercase tracking-[0.3em] ml-2">Debate na Aula</h5>

                {(!post.comments || post.comments.length === 0) ? (
                  <div className="text-center py-12 opacity-30">
                    <ChatBubbleOvalLeftIcon className="h-12 w-12 mx-auto mb-3" />
                    <p className="text-[10px] font-black uppercase tracking-widest">Inicie a discussão sobre este tema</p>
                  </div>
                ) : (
                  post.comments.map((c, idx) => (
                    <div key={c.id} className="flex gap-4 animate-fade-in group" style={{ animationDelay: `${idx * 0.05}s` }}>
                       <img src={c.profilePic || DEFAULT_PROFILE_PIC} className="w-9 h-9 rounded-xl object-cover shadow-sm border dark:border-white/10" />
                       <div className="flex-1">
