                    </div>
                  ))
                )}
              </div>
            </div>

            {/* RODAPÉ INTERATIVO (FIXO NA LATERAL) */}
            <div className="p-5 tablet:p-6 border-t border-gray-100 dark:border-white/5 bg-white dark:bg-darkcard sticky bottom-0 tablet:static">
               {/* BOTÕES DE AÇÃO */}
               <div className="flex items-center gap-3 mb-6">
                  <button onClick={handleLike} className={`flex-1 flex items-center justify-center gap-2 py-4 rounded-2xl transition-all active:scale-90 ${hasLiked ? 'text-blue-600 bg-blue-50 dark:bg-blue-600/10 font-black' : 'text-gray-500 bg-gray-50 dark:bg-white/5 font-bold'}`}>
                     {hasLiked ? <HeartIconSolid className="h-6 w-6" /> : <HeartIconOutline className="h-6 w-6" />}
                     <span className="text-xs uppercase tracking-widest">Curtir</span>
                  </button>
                  <button onClick={handleSave} className={`p-4 rounded-2xl transition-all ${hasSaved ? 'text-yellow-500 bg-yellow-50 dark:bg-yellow-500/10' : 'text-gray-400 bg-gray-50 dark:bg-white/5'}`}>
                     {hasSaved ? <BookmarkIconSolid className="h-6 w-6" /> : <BookmarkIconOutline className="h-6 w-6" />}
                  </button>
                  <button className="p-4 bg-gray-50 dark:bg-white/5 text-gray-400 rounded-2xl hover:text-blue-600 transition-colors">
                     <ShareIcon className="h-6 w-6" />
                  </button>
               </div>

               {/* FORMULÁRIO DE COMENTÁRIO */}
               <form onSubmit={handleSendComment} className="flex items-center gap-3">
                  <img src={currentUser.profilePicture || DEFAULT_PROFILE_PIC} className="w-10 h-10 rounded-xl hidden tablet:block border shadow-sm" />
