                    <button type="submit" disabled={!commentText.trim()} className="absolute right-2 top-1/2 -translate-y-1/2 p-2 bg-blue-600 text-white rounded-xl shadow-lg active:scale-90 transition-all disabled:opacity-30">
                       <PaperAirplaneIcon className="h-5 w-5 -rotate-45" />
                    </button>
                  </div>
               </form>
            </div>
          </div>
        </div>
      </div>

      {/* LIGHTBOX FULLSCREEN (Z-INDEX ALTÍSSIMO) */}
      {showLightbox && post.imageUrl && (
        <div className="fixed inset-0 z-[1000] bg-black flex flex-col animate-fade-in" onClick={() => setShowLightbox(false)}>
           {/* CONTROLES DO LIGHTBOX */}
           <div className="absolute top-0 left-0 w-full p-6 tablet:p-10 flex justify-between items-center z-[1010] bg-gradient-to-b from-black/80 to-transparent">
              <button onClick={() => setShowLightbox(false)} className="p-4 bg-white/10 hover:bg-white/20 rounded-full text-white backdrop-blur-md transition-all shadow-2xl">
                 <XMarkIcon className="h-8 w-8" />
              </button>

              <div className="flex gap-3">
                 <button onClick={handleDownload} className="flex items-center gap-3 bg-white/10 hover:bg-white/20 px-8 py-4 rounded-2xl text-xs font-black uppercase text-white backdrop-blur-md transition-all border border-white/10">
                    <ArrowDownTrayIcon className="h-5 w-5" /> Download
                 </button>
                 {isOwner && (
                    <button onClick={(e) => { e.stopPropagation(); updateUser({...currentUser, profilePicture: post.imageUrl}); refreshUser(); alert("Perfil Atualizado!"); }} className="flex items-center gap-3 bg-blue-600 hover:bg-blue-700 px-8 py-4 rounded-2xl text-xs font-black uppercase text-white transition-all shadow-2xl">
                       <UserCircleIcon className="h-5 w-5" /> Usar no Perfil
                    </button>
