           {/* IMAGEM CENTRALIZADA COM ZOOM */}
           <div className="flex-1 flex items-center justify-center p-4">
              <img 
                src={post.imageUrl} 
                className="max-w-full max-h-full object-contain shadow-[0_0_120px_rgba(0,0,0,0.8)] animate-scale-up" 
                onClick={e => e.stopPropagation()} 
