import React, { useState, useEffect, useRef } from 'react';
import { Post, User, UserType } from '../types';
import { findUserById, addPostComment, updatePostLikes, updatePostSaves, toggleFollowUser } from '../services/storageService';
import { DEFAULT_PROFILE_PIC } from '../constants';
import { 
  XMarkIcon, 
  CheckBadgeIcon,
  ChatBubbleOvalLeftIcon,
  ArrowLeftIcon,
  PaperAirplaneIcon,
  UserPlusIcon,
  HeartIcon as HeartIconOutline,
  BookmarkIcon as BookmarkIconOutline
} from '@heroicons/react/24/outline';
import { 
  HeartIcon as HeartIconSolid,
  BookmarkIcon as BookmarkIconSolid
} from '@heroicons/react/24/solid';

interface PostDetailModalProps {
  post: Post;
  currentUser: User;
  onClose: () => void;
  onUpdate: () => void;
  onNavigate: (page: string, params?: Record<string, string>) => void;
  refreshUser: () => void;
}

const PostDetailModal: React.FC<PostDetailModalProps> = ({ post, currentUser, onClose, onUpdate, onNavigate, refreshUser }) => {
  const [commentText, setCommentText] = useState('');
  const scrollRef = useRef<HTMLDivElement>(null);

  const author = findUserById(post.userId);
  const isOwner = currentUser.id === post.userId;
  const isFollowing = currentUser.followedUsers?.includes(post.userId);
  const hasLiked = post.likes?.includes(currentUser.id);
  const hasSaved = post.saves?.includes(currentUser.id);

  // Trava o scroll do body e garante que o modal inicie no topo
  useEffect(() => {
    document.body.style.overflow = 'hidden';
    window.scrollTo(0, 0);
    return () => { document.body.style.overflow = 'auto'; };
  }, []);

  // Auto-scroll suave para o fim dos comentários quando um novo é adicionado
  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [post.comments]);

  const handleLike = (e: React.MouseEvent) => {
    e.stopPropagation();
    updatePostLikes(post.id, currentUser.id);
    onUpdate();
  };

  const handleSave = (e: React.MouseEvent) => {
    e.stopPropagation();
    updatePostSaves(post.id, currentUser.id);
    onUpdate();
  };

  const handleFollow = (e: React.MouseEvent) => {
    e.stopPropagation();
    toggleFollowUser(currentUser.id, post.userId);
    refreshUser();
    onUpdate();
  };

  const handleSendComment = (e: React.FormEvent) => {
    e.preventDefault();
    if (!commentText.trim()) return;

    addPostComment(post.id, {
      id: `comment-${Date.now()}`,
      userId: currentUser.id,
      userName: `${currentUser.firstName} ${currentUser.lastName}`,
      profilePic: currentUser.profilePicture,
      text: commentText,
      timestamp: Date.now()
    });

    setCommentText('');
    onUpdate();
  };

  if (!author) return null;

  return (
    <div className="fixed inset-0 z-[9999] bg-white dark:bg-darkbg flex flex-col animate-fade-in overflow-hidden">

      {/* HEADER: Fixo e responsivo */}
      <header className="h-[64px] tablet:h-[72px] border-b border-gray-100 dark:border-white/10 flex items-center justify-between px-4 tablet:px-8 bg-white dark:bg-darkcard shrink-0">
        <div className="flex items-center gap-4">
          <button onClick={onClose} className="p-2 -ml-2 text-gray-900 dark:text-white hover:bg-gray-100 dark:hover:bg-white/5 rounded-full transition-all">
            <ArrowLeftIcon className="h-6 w-6" />
          </button>
          <div className="flex items-center gap-3 cursor-pointer group" onClick={() => { onClose(); onNavigate('profile', { userId: post.userId }); }}>
            <div className="relative">
              <img src={author.profilePicture || DEFAULT_PROFILE_PIC} className="w-8 h-8 tablet:w-10 tablet:h-10 rounded-xl object-cover border dark:border-white/10 group-hover:border-blue-500 transition-colors" />
              {author.userType === UserType.CREATOR && (
                <div className="absolute -bottom-1 -right-1 bg-blue-600 rounded-full p-0.5 border-2 border-white dark:border-darkcard">
                  <CheckBadgeIcon className="h-3 w-3 text-white" />
                </div>
              )}
            </div>
            <div>
              <h4 className="font-black text-xs tablet:text-sm dark:text-white leading-none group-hover:text-blue-500 transition-colors">{author.firstName} {author.lastName}</h4>
              <p className="text-[9px] font-bold text-gray-400 uppercase tracking-widest mt-1">Aula Publicada</p>
            </div>
          </div>
        </div>

        <div className="flex items-center gap-2">
          {!isOwner && (
            <button 
              onClick={handleFollow}
              className={`hidden tablet:flex px-4 py-2 rounded-xl font-black text-[10px] uppercase transition-all ${isFollowing ? 'text-gray-400 bg-gray-50 dark:bg-white/5' : 'text-blue-600 bg-blue-50 dark:bg-blue-600/10'}`}
            >
              {isFollowing ? 'Seguindo' : <><UserPlusIcon className="h-4 w-4 mr-1"/> Seguir</>}
            </button>
          )}
          <button onClick={onClose} className="p-2 text-gray-400 hover:text-red-500 transition-colors" aria-label="Fechar">
            <XMarkIcon className="h-7 w-7" />
          </button>
        </div>
      </header>

      {/* ÁREA DE CONTEÚDO PRINCIPAL: Split View Desktop, Stacked Mobile */}
      <div className="flex-1 flex flex-col tablet:flex-row overflow-hidden bg-gray-50 dark:bg-black/20">

        {/* MÍDIA (LADO ESQUERDO) */}
        <div className={`w-full tablet:flex-1 bg-[#050505] flex items-center justify-center relative overflow-hidden ${post.imageUrl ? 'h-[40vh] tablet:h-full' : 'hidden tablet:flex'}`}>
          {post.imageUrl ? (
            <img src={post.imageUrl} className="max-w-full max-h-full object-contain shadow-2xl" alt="Conteúdo Visual" />
          ) : (
            <div className="text-center opacity-20 text-white p-10">
              <ChatBubbleOvalLeftIcon className="h-24 w-24 mx-auto mb-4" />
              <p className="font-black text-xs uppercase tracking-widest">Publicação em Texto</p>
            </div>
          )}
        </div>

        {/* INTERAÇÃO E DISCUSSÃO (LADO DIREITO) */}
        <div className="w-full tablet:w-[450px] lg:w-[550px] flex flex-col bg-white dark:bg-darkcard border-l border-gray-100 dark:border-white/5 h-full relative overflow-hidden">

          {/* ÁREA DE SCROLL INDEPENDENTE */}
          <div ref={scrollRef} className="flex-1 overflow-y-auto p-5 tablet:p-8 custom-scrollbar space-y-8">

            {/* Texto do Post */}
            {post.content && (
              <div className="mb-6">
                <p className="text-gray-800 dark:text-gray-100 text-base tablet:text-lg leading-relaxed font-medium whitespace-pre-wrap">
                  {post.content}
                </p>
                <p className="text-[10px] font-bold text-gray-400 uppercase tracking-widest mt-4">Postado em {new Date(post.timestamp).toLocaleDateString()}</p>
              </div>
            )}

            {/* Ações e Estatísticas */}
            <div className="flex items-center justify-between border-y border-gray-50 dark:border-white/5 py-5">
               <div className="flex gap-6">
                  <button onClick={handleLike} className={`flex items-center gap-2 group transition-all active:scale-90 ${hasLiked ? 'text-blue-600' : 'text-gray-400'}`}>
                    {hasLiked ? <HeartIconSolid className="h-6 w-6" /> : <HeartIconOutline className="h-6 w-6 group-hover:text-blue-600" />}
                    <span className="text-[11px] font-black uppercase tracking-widest">{post.likes?.length || 0} Curtidas</span>
                  </button>
                  <div className="flex items-center gap-2 text-gray-400">
                    <ChatBubbleOvalLeftIcon className="h-6 w-6" />
                    <span className="text-[11px] font-black uppercase tracking-widest">{post.comments?.length || 0} Comentários</span>
                  </div>
               </div>
               <button onClick={handleSave} className={`transition-all active:scale-90 ${hasSaved ? 'text-blue-600' : 'text-gray-300'}`}>
                 {hasSaved ? <BookmarkIconSolid className="h-6 w-6" /> : <BookmarkIconOutline className="h-6 w-6" />}
               </button>
            </div>

            {/* Lista de Comentários Completa */}
            <div className="space-y-6 pb-24">
               <h5 className="text-[10px] font-black text-gray-400 uppercase tracking-[0.3em] mb-6">Debate da Turma</h5>

               {(!post.comments || post.comments.length === 0) ? (
                 <div className="text-center py-12 bg-gray-50 dark:bg-white/5 rounded-[2rem] border-2 border-dashed border-gray-100 dark:border-white/5">
                   <p className="text-[10px] font-black uppercase tracking-widest text-gray-400">Sem comentários. Inicie a conversa!</p>
                 </div>
               ) : (
                 post.comments.map((c) => (
                   <div key={c.id} className="flex gap-4 animate-fade-in group">
                      <img src={c.profilePic || DEFAULT_PROFILE_PIC} className="w-9 h-9 rounded-xl object-cover shrink-0 border dark:border-white/10" alt="" />
                      <div className="flex-1 min-w-0">
                         <div className="bg-gray-50 dark:bg-white/5 p-4 rounded-2xl rounded-tl-none border border-gray-100 dark:border-white/5 group-hover:border-blue-500/30 transition-colors shadow-sm">
                            <p className="text-[10px] font-black text-blue-600 dark:text-blue-400 uppercase mb-1 truncate">{c.userName}</p>
                            <p className="text-sm text-gray-700 dark:text-gray-300 font-medium leading-relaxed break-words">{c.text}</p>
                         </div>
                         <p className="text-[8px] font-black text-gray-400 uppercase mt-2 ml-1">{new Date(c.timestamp).toLocaleTimeString([], {hour:'2-digit', minute:'2-digit'})}</p>
                      </div>
                   </div>
                 ))
               )}
            </div>
          </div>

          {/* INPUT FIXO NO RODAPÉ DO PAINEL DIREITO */}
          <div className="p-4 tablet:p-6 border-t border-gray-100 dark:border-white/5 bg-white dark:bg-darkcard shrink-0 shadow-[0_-10px_20px_rgba(0,0,0,0.02)]">
             <form onSubmit={handleSendComment} className="flex items-center gap-3">
                <img src={currentUser.profilePicture || DEFAULT_PROFILE_PIC} className="w-10 h-10 rounded-xl hidden tablet:block border dark:border-white/10 object-cover" alt="" />
                <div className="flex-1 relative group">
                  <input 
                    type="text" 
                    value={commentText}
                    onChange={e => setCommentText(e.target.value)}
                    placeholder="Tire sua dúvida ou colabore..." 
                    className="w-full pl-5 pr-14 py-4 bg-gray-50 dark:bg-darkbg border-2 border-transparent focus:border-blue-500 rounded-2xl text-xs tablet:text-sm font-bold dark:text-white outline-none transition-all shadow-inner"
                  />
                  <button 
                    type="submit" 
                    disabled={!commentText.trim()} 
                    className="absolute right-2 top-1/2 -translate-y-1/2 p-2 bg-blue-600 text-white rounded-xl shadow-lg active:scale-90 transition-all disabled:opacity-30 disabled:grayscale"
                  >
                    <PaperAirplaneIcon className="h-5 w-5 -rotate-45" />
                  </button>
                </div>
             </form>
          </div>

        </div>
      </div>

      <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 4px; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: rgba(0,0,0,0.1); border-radius: 10px; }
        .dark .custom-scrollbar::-webkit-scrollbar-thumb { background: rgba(255,255,255,0.05); }
        @keyframes fade-in { from { opacity: 0; } to { opacity: 1; } }
        .animate-fade-in { animation: fade-in 0.3s ease-out forwards; }
      `}</style>
    </div>
  );
};

