import React, { useState, useEffect, useMemo, useRef } from 'react';
import { AdCampaign, User, AdLocation } from '../types';
import { saveAds, getAds, updateUserBalance } from '../services/storageService';
import { generateAdCopy } from '../services/geminiService';
import { MIN_DAILY_AD_BUDGET_USD, DEFAULT_PROFILE_PIC } from '../constants';
import { 
  RocketLaunchIcon, 
  MegaphoneIcon, 
  EyeIcon, 
  CursorArrowRaysIcon, 
  PhotoIcon, 
  CurrencyDollarIcon,
  ChevronRightIcon,
  ChevronLeftIcon,
  SparklesIcon,
  CheckCircleIcon,
  MapPinIcon,
  GlobeAltIcon,
  XMarkIcon,
  PlusIcon,
  InformationCircleIcon,
  UserGroupIcon,
  CalendarIcon,
  ArrowUpTrayIcon,
  TrashIcon,
  ExclamationTriangleIcon,
  ShieldCheckIcon,
  PresentationChartLineIcon
} from '@heroicons/react/24/solid';

interface AdCampaignPageProps {
  currentUser: User;
  refreshUser: () => void;
  onNavigate?: (page: string) => void;
}

type Step = 'objective' | 'creative' | 'targeting' | 'budget';

const AdCampaignPage: React.FC<AdCampaignPageProps> = ({ currentUser, refreshUser }) => {
  const [currentStep, setCurrentStep] = useState<Step>('objective');
  const [loading, setLoading] = useState(false);
  const [aiLoading, setAiLoading] = useState(false);

  // Form States
  const [objective, setObjective] = useState<'traffic' | 'awareness' | 'engagement'>('traffic');
  const [title, setTitle] = useState('');
  const [description, setDescription] = useState('');
  const [imageUrl, setImageUrl] = useState('');
  const [linkUrl, setLinkUrl] = useState('');
  const [ctaText, setCtaText] = useState('Saiba Mais');
  const [targetAudience, setTargetAudience] = useState('');
  const [durationDays, setDurationDays] = useState<number>(7);
  const [dailyReachGoal, setDailyReachGoal] = useState<number>(5000);
  const [locations, setLocations] = useState<string[]>(['Brasil']);
  const [newLoc, setNewLoc] = useState('');

  const fileInputRef = useRef<HTMLInputElement>(null);

  // Pricing Logic
  const COST_PER_1K_REACH = 0.50; 
  const calculatedTotalBudget = useMemo(() => {
    const costPerDay = (dailyReachGoal / 1000) * COST_PER_1K_REACH;
    return Math.max(costPerDay * durationDays, durationDays * MIN_DAILY_AD_BUDGET_USD);
  }, [dailyReachGoal, durationDays]);

  const hasBalance = (currentUser.balance || 0) >= calculatedTotalBudget;

  const handleAiGenerate = async () => {
    if (!targetAudience) {
      alert("Descreva brevemente o público ou curso para a IA te ajudar.");
      return;
    }
    setAiLoading(true);
    try {
      const copy = await generateAdCopy(`Curso para: ${targetAudience}`);
      // A IA do serviço retorna "Título: ... Texto: ..."
      const parts = copy.split('Texto:');
      if (parts.length > 1) {
        setTitle(parts[0].replace('Título:', '').trim());
        setDescription(parts[1].trim());
      } else {
        setDescription(copy);
      }
    } catch (e) {
      console.error(e);
    } finally {
      setAiLoading(false);
    }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => setImageUrl(reader.result as string);
      reader.readAsDataURL(file);
    }
  };

  const handlePublish = () => {
    if (!hasBalance) return;
    setLoading(true);
    setTimeout(() => {
      const newAd: AdCampaign = {
        id: `ad-${Date.now()}`,
        professorId: currentUser.id,
        title,
        description,
        targetAudience,
        budget: calculatedTotalBudget,
        isActive: true,
        imageUrl,
        linkUrl: linkUrl || '#',
        ctaText,
        timestamp: Date.now()
      };

      updateUserBalance(currentUser.id, -calculatedTotalBudget);
      saveAds([...getAds(), newAd]);
      alert("Campanha lançada com sucesso!");
      window.location.reload(); 
    }, 2000);
  };

  const addLocation = () => {
    if (newLoc.trim()) {
      setLocations([...locations, newLoc.trim()]);
      setNewLoc('');
    }
  };

  return (
    <div className="min-h-screen bg-gray-50 dark:bg-[#080a0f] pt-24 pb-32 px-4">
      <div className="max-w-7xl mx-auto">

        {/* HEADER & PROGRESS */}
        <div className="flex flex-col md:flex-row md:items-center justify-between mb-10 gap-6">
          <div>
