  PlayIcon
} from '@heroicons/react/24/solid';
import IndicateModal from './IndicateModal';
import PostDetailModal from './PostDetailModal';

interface PostCardProps {
  post: Post;
  currentUser: User;
  onNavigate: (page: string, params?: Record<string, string>) => void;
  onFollowToggle: (userIdToFollow: string) => void;
  refreshUser: () => void;
  onPostUpdatedOrDeleted: () => void;
  onPinToggle: (postId: string, isCurrentlyPinned: boolean) => void;
}

const PostCard: React.FC<PostCardProps> = ({ 
  post, 
  currentUser, 
  onNavigate, 
  onFollowToggle,
  refreshUser, 
  onPostUpdatedOrDeleted,
  onPinToggle
}) => {
  if (!post || !currentUser || !post.id) return null;

  const postAuthor = findUserById(post.userId);
  const [showOptions, setShowOptions] = useState(false);
  const [showIndicateModal, setShowIndicateModal] = useState(false);
  const [showDetailModal, setShowDetailModal] = useState(false);

  const optionsRef = useRef<HTMLDivElement>(null);
  const hasLiked = post.likes?.includes(currentUser.id) || false;
  const hasSaved = post.saves?.includes(currentUser.id) || false;
  const isAuthor = currentUser.id === post.userId;
  const isFollowing = currentUser.followedUsers?.includes(post.userId) || false;

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (optionsRef.current && !optionsRef.current.contains(event.target as Node)) setShowOptions(false);
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const handleLike = (e: React.MouseEvent) => {
    e.stopPropagation();
    updatePostLikes(post.id, currentUser.id);
    onPostUpdatedOrDeleted();
  };

  const handleSave = (e: React.MouseEvent) => {
    e.stopPropagation();
    updatePostSaves(post.id, currentUser.id);
    onPostUpdatedOrDeleted();
  };

  const handleShare = async (e: React.MouseEvent) => {
    e.stopPropagation();
    const shareData = {
      title: `Aula de ${post.authorName}`,
      text: post.content || 'Confira este conteúdo no CyBerPhone!',
      url: window.location.href + `?post=${post.id}`
    };

    try {
      if (navigator.share) {
        await navigator.share(shareData);
      } else {
        await navigator.clipboard.writeText(shareData.url);
        alert('Link copiado para a área de transferência!');
      }
      updatePostShares(post.id, currentUser.id);
      onPostUpdatedOrDeleted();
    } catch (err) {
      console.log('Share cancelled or failed', err);
    }
  };

  const handleDelete = (e: React.MouseEvent) => {
    e.stopPropagation();
    if (window.confirm('Excluir esta publicação?')) {
      deletePost(post.id);
      onPostUpdatedOrDeleted();
    }
  };

  const handlePin = (e: React.MouseEvent) => {
    e.stopPropagation();
    if (post.isPinned) unpinPost(post.id, currentUser.id);
    else pinPost(post.id, currentUser.id);
    onPostUpdatedOrDeleted();
    setShowOptions(false);
  };

  const handleCardClick = () => {
    if (post.type === PostType.LIVE) {
        onNavigate('live', { postId: post.id });
    } else {
        setShowDetailModal(true);
    }
  };

  if (!postAuthor) return null;

  return (
    <>
      <div 
        onClick={handleCardClick}
        className={`bg-white dark:bg-darkcard rounded-[2rem] md:rounded-[2.5rem] shadow-sm border border-gray-100 dark:border-white/5 overflow-hidden w-full relative mb-6 transition-all hover:shadow-md animate-fade-in cursor-pointer group`}
      >

        {/* HEADER */}
        <div className="p-4 md:p-5 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="relative cursor-pointer" onClick={(e) => { e.stopPropagation(); onNavigate('profile', { userId: post.userId }); }}>
              <img src={postAuthor.profilePicture || DEFAULT_PROFILE_PIC} className="w-10 h-10 md:w-11 md:h-11 rounded-xl object-cover shadow-sm" />
              {postAuthor.userType === UserType.CREATOR && (
                <div className="absolute -bottom-1 -right-1 bg-blue-600 rounded-lg p-0.5 border-2 border-white dark:border-darkcard">
                  <CheckBadgeIcon className="h-3 w-3 text-white" />
                </div>
              )}
            </div>
            <div>
              <div className="flex items-center gap-2">
                <h4 className="font-black text-gray-900 dark:text-white text-xs md:text-sm leading-tight hover:underline cursor-pointer" onClick={(e) => { e.stopPropagation(); onNavigate('profile', { userId: post.userId }); }}>
                    {postAuthor.firstName} {postAuthor.lastName}
                </h4>
                {post.isPinned && <PinIconSolid className="h-3 w-3 text-blue-500" />}
              </div>
              <p className="text-[9px] font-bold text-gray-400 uppercase tracking-wider">{new Date(post.timestamp).toLocaleDateString()}</p>
            </div>
          </div>

          <div className="relative" ref={optionsRef}>
            <button onClick={(e) => { e.stopPropagation(); setShowOptions(!showOptions); }} className="p-2 text-gray-300 hover:text-blue-600 transition-colors">
              <EllipsisHorizontalIcon className="h-6 w-6" />
            </button>
            {showOptions && (
              <div className="absolute right-0 mt-1 w-48 bg-white dark:bg-darkcard rounded-2xl shadow-2xl py-2 z-20 border dark:border-white/10 animate-fade-in" onClick={e => e.stopPropagation()}>
                {isAuthor ? (
                  <>
                    <button onClick={handlePin} className="flex items-center w-full px-4 py-3 text-[10px] font-black text-gray-700 dark:text-gray-300 hover:bg-gray-50 dark:hover:bg-white/5">
                      {post.isPinned ? <><PinIconSolid className="h-4 w-4 mr-3 text-blue-500" /> Desafixar</> : <><PinIconOutline className="h-4 w-4 mr-3 text-blue-500" /> Fixar</>}
                    </button>
                    <button onClick={handleDelete} className="flex items-center w-full px-4 py-3 text-[10px] font-black text-red-600 hover:bg-red-50 dark:hover:bg-red-900/10">
                      <TrashIcon className="h-4 w-4 mr-3" /> Excluir
                    </button>
                  </>
                ) : (
                  <>
                    {!isFollowing && (
                      <button onClick={(e) => { e.stopPropagation(); onFollowToggle(post.userId); setShowOptions(false); }} className="flex items-center w-full px-4 py-3 text-[10px] font-black text-blue-600 hover:bg-blue-50 dark:hover:bg-red-900/10">
                        Seguir Professor
                      </button>
                    )}
                    <button onClick={(e) => { e.stopPropagation(); onNavigate('report-user', { userId: post.userId }); }} className="flex items-center w-full px-4 py-3 text-[10px] font-black text-orange-600 hover:bg-orange-50">
                      <FlagIcon className="h-4 w-4 mr-3" /> Denunciar
                    </button>
                  </>
                )}
              </div>
            )}
          </div>
        </div>

        {/* CONTENT */}
        <div className="px-4 md:px-5 pb-4">
          {post.type === PostType.LIVE && post.liveStream ? (
             <div className="rounded-[2.5rem] overflow-hidden bg-gray-900 text-white p-6 md:p-8 relative shadow-2xl border-4 border-blue-600/30">
                <div className="absolute top-4 left-4 z-10">
                   <div className="bg-red-600 px-3 py-1.5 rounded-lg text-[8px] md:text-[9px] font-black flex items-center gap-2 shadow-lg animate-pulse uppercase tracking-widest">
                      <SignalIcon className="h-3 w-3" /> Ao Vivo
                   </div>
                </div>
                <div className="relative z-10 py-6 md:py-10 flex flex-col items-center text-center">
                   <div className="w-16 h-16 md:w-20 md:h-20 bg-blue-600/20 rounded-full flex items-center justify-center mb-6 border border-blue-500/30">
                      <VideoCameraIcon className="h-8 w-8 md:h-10 md:w-10 text-blue-400" />
                   </div>
                   <h3 className="text-xl md:text-2xl font-black mb-3 tracking-tighter leading-tight uppercase">{post.liveStream.title}</h3>
                   <p className="text-gray-400 text-xs md:text-sm max-w-sm mb-8 font-medium">{post.liveStream.description}</p>
                   <button 
                      onClick={(e) => { e.stopPropagation(); onNavigate('live', { postId: post.id }); }}
                      className="bg-blue-600 hover:bg-blue-700 text-white px-8 py-3.5 md:px-10 md:py-4 rounded-2xl font-black text-xs uppercase tracking-[0.2em] shadow-xl active:scale-95 transition-all flex items-center justify-center gap-3"
                   >
                      <PlayIcon className="h-5 w-5" /> Assistir Aula
                   </button>
                </div>
             </div>
          ) : (
            <>
              {post.content && <p className="text-gray-700 dark:text-gray-300 text-sm font-medium leading-relaxed mb-4 whitespace-pre-wrap line-clamp-3 group-hover:text-blue-600 transition-colors">{post.content}</p>}
              {post.imageUrl && (
                <div className="rounded-[1.5rem] md:rounded-[2rem] overflow-hidden border dark:border-white/5 bg-gray-50 dark:bg-darkbg relative group/img">
                   <img src={post.imageUrl} className="w-full h-auto object-cover max-h-[500px]" alt="Post" />
                   <div className="absolute inset-0 bg-black/10 opacity-0 group-hover/img:opacity-100 transition-opacity flex items-center justify-center">
                      <div className="bg-white/90 p-3 rounded-2xl shadow-xl">
                        <ArrowsPointingOutIcon className="h-6 w-6 text-blue-600" />
                      </div>
                   </div>
                </div>
              )}
            </>
          )}
        </div>

        {/* ACTIONS */}
        <div className="px-4 md:px-5 py-3 flex items-center justify-between border-t dark:border-white/5">
          <div className="flex items-center gap-1 md:gap-2">
            <button onClick={handleLike} className={`flex items-center gap-2 px-3 py-2 rounded-xl transition-all active:scale-90 ${hasLiked ? 'text-blue-600 bg-blue-50 dark:bg-blue-500/10 font-black' : 'text-gray-400 hover:bg-gray-50 dark:hover:bg-white/5'}`}>
              {hasLiked ? <HeartIconSolid className="h-5 w-5" /> : <HeartIconOutline className="h-5 w-5" />}
              <span className="text-xs font-black">{post.likes?.length || 0}</span>
            </button>

            <button onClick={(e) => { e.stopPropagation(); setShowDetailModal(true); }} className="flex items-center gap-2 px-3 py-2 rounded-xl text-gray-400 hover:bg-gray-50 dark:hover:bg-white/5 transition-all">
              <ChatIconOutline className="h-5 w-5" />
              <span className="font-black text-xs">{post.comments?.length || 0}</span>
            </button>

            <button onClick={handleShare} className="flex items-center gap-2 px-3 py-2 rounded-xl text-gray-400 hover:bg-gray-50 dark:hover:bg-white/5">
              <ShareIcon className="h-5 w-5" />
              <span className="font-black text-xs">{post.shares?.length || 0}</span>
            </button>

            <button onClick={(e) => { e.stopPropagation(); setShowIndicateModal(true); }} className="flex items-center gap-2 px-3 py-2 rounded-xl text-gray-400 hover:bg-gray-50 dark:hover:bg-white/5">
              <PaperAirplaneIcon className="h-5 w-5 -rotate-45" />
            </button>
          </div>

          <button onClick={handleSave} className={`p-2.5 rounded-xl transition-all ${hasSaved ? 'text-blue-600 bg-blue-50 dark:bg-blue-900/20' : 'text-gray-300 hover:bg-gray-50 dark:hover:bg-white/5'}`}>
            {hasSaved ? <BookmarkIconSolid className="h-5 w-5" /> : <BookmarkIconOutline className="h-5 w-5" />}
          </button>
        </div>
      </div>

      {showDetailModal && (
        <PostDetailModal
          post={post}
          currentUser={currentUser}
          onClose={() => setShowDetailModal(false)}
          onUpdate={onPostUpdatedOrDeleted}
          onNavigate={onNavigate}
          refreshUser={refreshUser}
        />
      )}

      {showIndicateModal && (
        <IndicateModal 
          post={post} 
          currentUser={currentUser} 
          onClose={() => setShowIndicateModal(false)} 
          onPostUpdated={onPostUpdatedOrDeleted}
        />
      )}
    </>
  );
};

export default PostCard;

import React, { useState, useEffect, useRef } from 'react';
import { createPortal } from 'react-dom';
import { Post, User, UserType } from '../types';
import { findUserById, addPostComment, updatePostLikes, updatePostSaves, updatePostShares, toggleFollowUser } from '../services/storageService';
import { DEFAULT_PROFILE_PIC } from '../constants';
import { 
  XMarkIcon, 
  ChatBubbleOvalLeftIcon,
  HeartIcon as HeartIconOutline,
  BookmarkIcon as BookmarkIconOutline,
  ShareIcon,
  EllipsisHorizontalIcon,
  ArrowPathRoundedSquareIcon,
  ChartBarIcon,
  ArrowLeftIcon
} from '@heroicons/react/24/outline';
import { 
  HeartIcon as HeartIconSolid,
  BookmarkIcon as BookmarkIconSolid,
  CheckBadgeIcon
} from '@heroicons/react/24/solid';

interface PostDetailModalProps {
  post: Post;
  currentUser: User;
  onClose: () => void;
  onUpdate: () => void;
  onNavigate: (page: string, params?: Record<string, string>) => void;
  refreshUser: () => void;
}

const PostDetailModal: React.FC<PostDetailModalProps> = ({ post, currentUser, onClose, onUpdate, onNavigate, refreshUser }) => {
  const [commentText, setCommentText] = useState('');
  const scrollRef = useRef<HTMLDivElement>(null);

  const author = findUserById(post.userId);
  const isOwner = currentUser.id === post.userId;
  const isFollowing = currentUser.followedUsers?.includes(post.userId);
  const hasLiked = post.likes?.includes(currentUser.id);
  const hasSaved = post.saves?.includes(currentUser.id);

  useEffect(() => {
    document.body.style.overflow = 'hidden';
    return () => { document.body.style.overflow = 'auto'; };
  }, []);

  const handleLike = (e: React.MouseEvent) => {
    e.stopPropagation();
    updatePostLikes(post.id, currentUser.id);
    onUpdate();
  };

  const handleSave = (e: React.MouseEvent) => {
    e.stopPropagation();
    updatePostSaves(post.id, currentUser.id);
    onUpdate();
  };

  const handleShare = async (e: React.MouseEvent) => {
    e.stopPropagation();
    const shareData = {
      title: `Aula de ${post.authorName}`,
      text: post.content || 'Confira este conteúdo no CyBerPhone!',
      url: window.location.href + `?post=${post.id}`
    };

    try {
      if (navigator.share) {
        await navigator.share(shareData);
      } else {
        await navigator.clipboard.writeText(shareData.url);
        alert('Link copiado para a área de transferência!');
      }
      updatePostShares(post.id, currentUser.id);
      onUpdate();
    } catch (err) {
      console.log('Share cancelled', err);
    }
  };

  const handleFollow = (e: React.MouseEvent) => {
    e.stopPropagation();
    toggleFollowUser(currentUser.id, post.userId);
    refreshUser();
    onUpdate();
  };

  const handleSendComment = (e: React.FormEvent) => {
    e.preventDefault();
    if (!commentText.trim()) return;

    addPostComment(post.id, {
      id: `comment-${Date.now()}`,
      userId: currentUser.id,
      userName: `${currentUser.firstName} ${currentUser.lastName}`,
      profilePic: currentUser.profilePicture,
      text: commentText,
      timestamp: Date.now()
    });

    setCommentText('');
    onUpdate();
  };

  if (!author) return null;

  return createPortal(
    <div className="fixed inset-0 z-[10000] bg-black flex items-center justify-center animate-fade-in overflow-hidden">

      <div className="w-full h-full md:h-[95vh] md:max-w-6xl md:rounded-2xl bg-white dark:bg-black flex flex-col tablet:flex-row overflow-hidden relative shadow-2xl">

        <div className="absolute top-0 left-0 w-full h-14 flex items-center px-4 md:hidden z-[101] bg-white/90 dark:bg-black/90 backdrop-blur-md">
           <button onClick={onClose} className="p-2 -ml-2 text-gray-900 dark:text-white">
             <ArrowLeftIcon className="h-6 w-6" />
           </button>
           <span className="ml-4 font-black text-sm uppercase dark:text-white">Postagem</span>
        </div>

        <button 
          onClick={onClose} 
          className="hidden md:flex absolute top-4 left-4 z-[101] p-2 bg-black/50 hover:bg-black/70 text-white rounded-full transition-all backdrop-blur-sm"
        >
          <XMarkIcon className="h-6 w-6" />
        </button>

        <div className={`w-full tablet:flex-1 bg-black flex items-center justify-center relative overflow-hidden ${!post.imageUrl ? 'hidden tablet:flex' : 'h-[40vh] tablet:h-full mt-14 tablet:mt-0'}`}>
          {post.imageUrl && (
            <img 
              src={post.imageUrl} 
              className="max-w-full max-h-full object-contain" 
              alt="Mídia"
            />
          )}
        </div>

        <div className="flex-1 tablet:w-[450px] flex flex-col h-full bg-white dark:bg-black border-l border-gray-100 dark:border-white/10 relative">

          <div className="p-4 border-b border-gray-50 dark:border-white/10 flex items-center justify-between shrink-0 hidden tablet:flex">
             <div className="flex items-center gap-3 cursor-pointer group" onClick={() => { onClose(); onNavigate('profile', { userId: post.userId }); }}>
                <img src={author.profilePicture || DEFAULT_PROFILE_PIC} className="w-10 h-10 rounded-full object-cover" />
                <div>
                   <div className="flex items-center gap-1">
                      <span className="font-bold text-sm dark:text-white group-hover:underline">{author.firstName} {author.lastName}</span>
                      {author.userType === UserType.CREATOR && <CheckBadgeIcon className="h-4 w-4 text-blue-500" />}
                   </div>
                   <span className="text-gray-500 text-xs">@{author.firstName.toLowerCase()}</span>
                </div>
             </div>
             {!isOwner && (
               <button 
                 onClick={handleFollow}
                 className={`px-4 py-1.5 rounded-full font-black text-xs transition-all ${isFollowing ? 'border border-gray-300 dark:text-white' : 'bg-blue-600 text-white'}`}
               >
                 {isFollowing ? 'Seguindo' : 'Seguir'}
               </button>
             )}
          </div>

          <div ref={scrollRef} className="flex-1 overflow-y-auto custom-scrollbar p-4 space-y-4">
             <div className="tablet:hidden flex items-center justify-between mb-4">
                <div className="flex items-center gap-3">
                   <img src={author.profilePicture || DEFAULT_PROFILE_PIC} className="w-10 h-10 rounded-full object-cover" />
                   <div className="flex flex-col">
                      <div className="flex items-center gap-1">
                         <span className="font-bold text-sm dark:text-white">{author.firstName} {author.lastName}</span>
                         {author.userType === UserType.CREATOR && <CheckBadgeIcon className="h-4 w-4 text-blue-500" />}
                      </div>
                      <span className="text-gray-500 text-xs">@{author.firstName.toLowerCase()}</span>
                   </div>
                </div>
             </div>

             <div className="space-y-4">
                <p className="text-lg md:text-xl dark:text-white leading-snug whitespace-pre-wrap">{post.content}</p>
                <div className="text-gray-500 text-sm border-b border-gray-50 dark:border-white/10 pb-4">
                   {new Date(post.timestamp).toLocaleTimeString([], {hour:'2-digit', minute:'2-digit'})} · {new Date(post.timestamp).toLocaleDateString()}
                </div>
             </div>

             <div className="flex items-center justify-between py-2 border-b border-gray-50 dark:border-white/10 text-gray-500">
                <button onClick={handleLike} className={`flex items-center gap-2 group transition-colors ${hasLiked ? 'text-pink-600' : 'hover:text-pink-600'}`}>
                   <div className="p-2 rounded-full group-hover:bg-pink-600/10">
                    {hasLiked ? <HeartIconSolid className="h-5 w-5" /> : <HeartIconOutline className="h-5 w-5" />}
                   </div>
                   <span className="text-xs font-bold">{post.likes?.length || 0}</span>
                </button>
                <div className="flex items-center gap-2 group hover:text-blue-500 transition-colors">
                   <div className="p-2 rounded-full group-hover:bg-blue-500/10">
                    <ChatBubbleOvalLeftIcon className="h-5 w-5" />
                   </div>
                   <span className="text-xs font-bold">{post.comments?.length || 0}</span>
                </div>
                <button onClick={handleSave} className={`flex items-center gap-2 group transition-colors ${hasSaved ? 'text-blue-600' : 'hover:text-blue-600'}`}>
                   <div className="p-2 rounded-full group-hover:bg-blue-500/10">
                    {hasSaved ? <BookmarkIconSolid className="h-5 w-5" /> : <BookmarkIconOutline className="h-5 w-5" />}
                   </div>
                </button>
                <button onClick={handleShare} className="flex items-center gap-2 group hover:text-green-500 transition-colors">
                   <div className="p-2 rounded-full group-hover:bg-green-500/10">
                    <ShareIcon className="h-5 w-5" />
                   </div>
                   <span className="text-xs font-bold">{post.shares?.length || 0}</span>
                </button>
             </div>

             <div className="space-y-6 pt-4 pb-20">
                {post.comments?.map((c) => (
                  <div key={c.id} className="flex gap-3">
                     <img src={c.profilePic || DEFAULT_PROFILE_PIC} className="w-8 h-8 rounded-full object-cover shrink-0" />
                     <div className="flex-1 min-w-0">
                        <div className="flex items-center gap-1 mb-0.5">
                           <span className="font-bold text-sm dark:text-white">{c.userName}</span>
                           <span className="text-gray-500 text-xs">· {new Date(c.timestamp).toLocaleTimeString([], {hour:'2-digit', minute:'2-digit'})}</span>
                        </div>
                        <p className="text-sm dark:text-gray-200">{c.text}</p>
                     </div>
                  </div>
                ))}
             </div>
          </div>

          <div className="absolute bottom-0 left-0 w-full p-3 bg-white dark:bg-black border-t border-gray-100 dark:border-white/10 z-[105]">
             <form onSubmit={handleSendComment} className="flex items-start gap-3">
                <img src={currentUser.profilePicture || DEFAULT_PROFILE_PIC} className="w-9 h-9 rounded-full object-cover hidden sm:block" />
                <div className="flex-1 flex flex-col gap-2">
                   <textarea 
                    value={commentText}
                    onChange={e => setCommentText(e.target.value)}
                    placeholder="Poste sua resposta"
                    className="w-full bg-transparent dark:text-white outline-none resize-none text-base placeholder-gray-500 pt-1"
                    rows={commentText.length > 50 ? 3 : 1}
                   />
                   <div className="flex justify-end items-center">
                      <button 
                        type="submit" 
                        disabled={!commentText.trim()}
                        className="bg-blue-600 disabled:opacity-50 text-white px-5 py-1.5 rounded-full font-bold text-sm transition-all"
                      >
                        Responder
                      </button>
                   </div>
                </div>
             </form>
             <div className="h-2 md:hidden"></div>
          </div>
        </div>
      </div>

      <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 0px; }
        @keyframes fadeIn { from { opacity: 0; } to { opacity: 1; } }
        .animate-fade-in { animation: fadeIn 0.2s ease-out forwards; }
      `}</style>
    </div>,
    document.body
  );
};

export default PostDetailModal;

export enum UserType {
  STANDARD = 'STANDARD',
  CREATOR = 'CREATOR',
}

export enum TransactionType {
  DEPOSIT = 'DEPOSIT',
  WITHDRAWAL = 'WITHDRAWAL',
  PURCHASE = 'PURCHASE',
  SALE = 'SALE',
  UPGRADE = 'UPGRADE'
}

export interface Transaction {
  id: string;
  type: TransactionType;
  amount: number;
  description: string;
  timestamp: number;
}

export interface PaymentCard {
  cardNumber: string;
  holderName: string;
  expiryDate: string;
  cvv: string;
  type: 'DEBIT' | 'CREDIT';
}

export interface User {
  id: string;
  userType: UserType;
  firstName: string;
  lastName: string;
  email: string;
  phone: string;
  documentId: string;
  profilePicture?: string;
  followedUsers: string[]; 
  followers: string[];     
  profileIndicatedTo?: string[];
  balance?: number;
  credentials?: string;
  bio?: string;
  verificationFileUrl?: string;
  storeId?: string;
  transactions?: Transaction[];
  card?: PaymentCard;
  isAdmin?: boolean; // Novo campo para identificar administradores
}

export enum PostType {
  TEXT = 'TEXT',
  IMAGE = 'IMAGE',
  LIVE = 'LIVE',
  REEL = 'REEL',
}

export interface LiveStreamDetails {
  title: string;
