      <header className="bg-white/90 dark:bg-darkbg/90 backdrop-blur-md shadow-sm px-3 md:px-6 py-2 md:py-4 flex justify-between items-center fixed top-0 left-0 w-full z-50 border-b border-gray-100 dark:border-white/5 h-[64px] md:h-[72px]">
        <div className="flex items-center gap-1 md:gap-2">
          <h1 
            className="text-lg md:text-2xl font-black text-blue-600 cursor-pointer tracking-tighter flex-shrink-0 mr-1 md:mr-6" 
            onClick={() => onNavigate('feed')}
