            >
              <ShoppingCartIcon className="h-5 w-5 md:h-6 md:w-6" />
              {cartItemCount > 0 && (
                <span className="absolute top-0 right-0 bg-blue-600 text-white text-[7px] md:text-[8px] font-black rounded-full h-3 md:h-3.5 w-3 md:w-3.5 flex items-center justify-center">
                  {cartItemCount}
                </span>
              )}
            </button>

            <button
              onClick={() => onNavigate('notifications')}
              className="p-1.5 md:p-2 rounded-xl text-gray-600 dark:text-gray-400 hover:bg-gray-100 dark:hover:bg-white/5 relative transition-colors"
            >
              <BellIcon className="h-5 w-5 md:h-6 md:w-6" />
              {unreadNotificationsCount > 0 && (
                <span className="absolute top-0 right-0 bg-red-600 text-white text-[7px] md:text-[8px] font-black rounded-full h-3 md:h-3.5 w-3 md:w-3.5 flex items-center justify-center animate-pulse">
                  {unreadNotificationsCount > 9 ? '9+' : unreadNotificationsCount}
                </span>
              )}
            </button>

            <img
              src={currentUser.profilePicture || DEFAULT_PROFILE_PIC}
              alt="Profile"
              className="w-7 h-7 md:w-10 md:h-10 rounded-lg md:rounded-xl object-cover cursor-pointer border-2 border-transparent hover:border-blue-600 transition-all shadow-sm"
              onClick={() => onNavigate('profile')}
            />
          </div>
        ) : (
          <button
            onClick={() => onNavigate('auth')}
            className="bg-blue-600 hover:bg-blue-700 text-white px-3 py-1.5 md:px-4 md:py-2 rounded-xl text-[10px] md:text-xs font-black uppercase tracking-widest transition-all"
          >
            Entrar
          </button>
        )}
      </header>

      {isMobileSearchOpen && (
        <div className="fixed inset-0 z-[100] bg-white dark:bg-darkbg animate-fade-in md:hidden">
          <div className="flex items-center p-4 border-b border-gray-100 dark:border-white/5">
            <button 
              onClick={() => setIsMobileSearchOpen(false)}
              className="p-2 text-gray-500 dark:text-gray-400 mr-2"
            >
              <ArrowLeftIcon className="h-6 w-6" />
            </button>
            <form onSubmit={handleSearchSubmit} className="flex-1">
              <input
                autoFocus
                type="text"
                placeholder="O que você procura?"
                className="w-full bg-transparent text-lg font-bold outline-none dark:text-white"
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
              />
