import React, { useState, useRef, useEffect } from 'react';
import { Post, PostType, User, UserType, Comment } from '../types';
import { DEFAULT_PROFILE_PIC } from '../constants';
import { 
  findUserById, 
  updatePostLikes, 
  updatePostShares, 
  updatePostSaves, 
  deletePost, 
  pinPost,
  unpinPost
} from '../services/storageService';
import {
  HeartIcon as HeartIconOutline, 
  ChatBubbleOvalLeftIcon as ChatIconOutline, 
  BookmarkIcon as BookmarkIconOutline, 
  EllipsisHorizontalIcon, 
  TrashIcon, 
  CheckBadgeIcon,
  FlagIcon,
  PaperAirplaneIcon,
  MapPinIcon as PinIconOutline,
  VideoCameraIcon,
  SignalIcon,
  ArrowsPointingOutIcon,
  ShareIcon
} from '@heroicons/react/24/outline';
import { 
  HeartIcon as HeartIconSolid, 
  BookmarkIcon as BookmarkIconSolid,
  MapPinIcon as PinIconSolid,
  PlayIcon
} from '@heroicons/react/24/solid';
import IndicateModal from './IndicateModal';
import PostDetailModal from './PostDetailModal';

interface PostCardProps {
  post: Post;
  currentUser: User;
  onNavigate: (page: string, params?: Record<string, string>) => void;
  onFollowToggle: (userIdToFollow: string) => void;
  refreshUser: () => void;
  onPostUpdatedOrDeleted: () => void;
  onPinToggle: (postId: string, isCurrentlyPinned: boolean) => void;
}

const PostCard: React.FC<PostCardProps> = ({ 
  post, 
  currentUser, 
  onNavigate, 
  onFollowToggle,
  refreshUser, 
  onPostUpdatedOrDeleted,
  onPinToggle
}) => {
  if (!post || !currentUser || !post.id) return null;

  const postAuthor = findUserById(post.userId);
  const [showOptions, setShowOptions] = useState(false);
  const [showIndicateModal, setShowIndicateModal] = useState(false);
  const [showDetailModal, setShowDetailModal] = useState(false);

  const optionsRef = useRef<HTMLDivElement>(null);
  const hasLiked = post.likes?.includes(currentUser.id) || false;
  const hasSaved = post.saves?.includes(currentUser.id) || false;
  const isAuthor = currentUser.id === post.userId;
  const isFollowing = currentUser.followedUsers?.includes(post.userId) || false;

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (optionsRef.current && !optionsRef.current.contains(event.target as Node)) setShowOptions(false);
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const handleLike = (e: React.MouseEvent) => {
    e.stopPropagation();
    updatePostLikes(post.id, currentUser.id);
    onPostUpdatedOrDeleted();
  };

  const handleSave = (e: React.MouseEvent) => {
    e.stopPropagation();
    updatePostSaves(post.id, currentUser.id);
    onPostUpdatedOrDeleted();
  };

  const handleShare = async (e: React.MouseEvent) => {
    e.stopPropagation();
    const shareData = {
      title: `Aula de ${post.authorName}`,
      text: post.content || 'Confira este conteúdo no CyBerPhone!',
      url: window.location.href + `?post=${post.id}`
    };

    try {
      if (navigator.share) {
        await navigator.share(shareData);
      } else {
        await navigator.clipboard.writeText(shareData.url);
        alert('Link copiado para a área de transferência!');
      }
      updatePostShares(post.id, currentUser.id);
      onPostUpdatedOrDeleted();
    } catch (err) {
      console.log('Share cancelled or failed', err);
    }
  };

  const handleDelete = (e: React.MouseEvent) => {
    e.stopPropagation();
    if (window.confirm('Excluir esta publicação?')) {
      deletePost(post.id);
      onPostUpdatedOrDeleted();
    }
  };

  const handlePin = (e: React.MouseEvent) => {
    e.stopPropagation();
    if (post.isPinned) unpinPost(post.id, currentUser.id);
    else pinPost(post.id, currentUser.id);
    onPostUpdatedOrDeleted();
    setShowOptions(false);
  };

  const handleCardClick = () => {
    if (post.type === PostType.LIVE) {
        onNavigate('live', { postId: post.id });
    } else {
        setShowDetailModal(true);
    }
  };

  if (!postAuthor) return null;

  return (
    <>
      <div 
        onClick={handleCardClick}
        className={`bg-white dark:bg-darkcard rounded-[1.5rem] md:rounded-[2.5rem] shadow-sm border border-gray-100 dark:border-white/5 overflow-hidden w-full relative mb-4 md:mb-6 transition-all hover:shadow-md animate-fade-in cursor-pointer group`}
      >

        {/* HEADER */}
        <div className="p-3 md:p-5 flex items-center justify-between">
          <div className="flex items-center gap-2 md:gap-3">
            <div className="relative cursor-pointer" onClick={(e) => { e.stopPropagation(); onNavigate('profile', { userId: post.userId }); }}>
              <img src={postAuthor.profilePicture || DEFAULT_PROFILE_PIC} className="w-8 h-8 md:w-11 md:h-11 rounded-lg md:rounded-xl object-cover shadow-sm" />
              {postAuthor.userType === UserType.CREATOR && (
                <div className="absolute -bottom-1 -right-1 bg-blue-600 rounded-lg p-0.5 border border-white dark:border-darkcard">
                  <CheckBadgeIcon className="h-2 w-2 md:h-3 md:w-3 text-white" />
                </div>
              )}
            </div>
            <div>
              <div className="flex items-center gap-1 md:gap-2">
                <h4 className="font-black text-gray-900 dark:text-white text-[11px] md:text-sm leading-tight hover:underline cursor-pointer" onClick={(e) => { e.stopPropagation(); onNavigate('profile', { userId: post.userId }); }}>
                    {postAuthor.firstName} {postAuthor.lastName}
                </h4>
                {post.isPinned && <PinIconSolid className="h-2.5 w-2.5 md:h-3 md:w-3 text-blue-500" />}
              </div>
              <p className="text-[7px] md:text-[9px] font-bold text-gray-400 uppercase tracking-wider">{new Date(post.timestamp).toLocaleDateString()}</p>
            </div>
          </div>

          <div className="relative" ref={optionsRef}>
            <button onClick={(e) => { e.stopPropagation(); setShowOptions(!showOptions); }} className="p-1.5 md:p-2 text-gray-300 hover:text-blue-600 transition-colors">
              <EllipsisHorizontalIcon className="h-5 w-5 md:h-6 md:w-6" />
            </button>
            {showOptions && (
              <div className="absolute right-0 mt-1 w-40 md:w-48 bg-white dark:bg-darkcard rounded-2xl shadow-2xl py-2 z-20 border dark:border-white/10 animate-fade-in" onClick={e => e.stopPropagation()}>
                {isAuthor ? (
                  <>
                    <button onClick={handlePin} className="flex items-center w-full px-4 py-3 text-[10px] font-black text-gray-700 dark:text-gray-300 hover:bg-gray-50 dark:hover:bg-white/5">
                      {post.isPinned ? <><PinIconSolid className="h-4 w-4 mr-3 text-blue-500" /> Desafixar</> : <><PinIconOutline className="h-4 w-4 mr-3 text-blue-500" /> Fixar</>}
                    </button>
                    <button onClick={handleDelete} className="flex items-center w-full px-4 py-3 text-[10px] font-black text-red-600 hover:bg-red-50 dark:hover:bg-red-900/10">
                      <TrashIcon className="h-4 w-4 mr-3" /> Excluir
                    </button>
                  </>
                ) : (
                  <>
                    {!isFollowing && (
                      <button onClick={(e) => { e.stopPropagation(); onFollowToggle(post.userId); setShowOptions(false); }} className="flex items-center w-full px-4 py-3 text-[10px] font-black text-blue-600 hover:bg-blue-50 dark:hover:bg-red-900/10">
                        Seguir Professor
                      </button>
                    )}
                    <button onClick={(e) => { e.stopPropagation(); onNavigate('report-user', { userId: post.userId }); }} className="flex items-center w-full px-4 py-3 text-[10px] font-black text-orange-600 hover:bg-orange-50">
                      <FlagIcon className="h-4 w-4 mr-3" /> Denunciar
                    </button>
                  </>
                )}
              </div>
            )}
          </div>
        </div>

        {/* CONTENT */}
        <div className="px-3 md:px-5 pb-3 md:pb-4">
          {post.type === PostType.LIVE && post.liveStream ? (
             <div className="rounded-[1.5rem] md:rounded-[2.5rem] overflow-hidden bg-gray-900 text-white p-4 md:p-8 relative shadow-2xl border-2 md:border-4 border-blue-600/30">
                <div className="absolute top-3 left-3 z-10">
                   <div className="bg-red-600 px-2 py-1 rounded-md text-[7px] md:text-[9px] font-black flex items-center gap-1.5 shadow-lg animate-pulse uppercase tracking-widest">
                      <SignalIcon className="h-2.5 w-2.5" /> Ao Vivo
                   </div>
                </div>
                <div className="relative z-10 py-4 md:py-10 flex flex-col items-center text-center">
                   <div className="w-12 h-12 md:w-20 md:h-20 bg-blue-600/20 rounded-full flex items-center justify-center mb-4 md:mb-6 border border-blue-500/30">
                      <VideoCameraIcon className="h-6 w-6 md:h-10 md:w-10 text-blue-400" />
                   </div>
                   <h3 className="text-sm md:text-2xl font-black mb-2 tracking-tighter leading-tight uppercase">{post.liveStream.title}</h3>
                   <p className="text-gray-400 text-[10px] md:text-sm max-w-sm mb-6 md:mb-8 font-medium line-clamp-2">{post.liveStream.description}</p>
                   <button 
                      onClick={(e) => { e.stopPropagation(); onNavigate('live', { postId: post.id }); }}
                      className="bg-blue-600 hover:bg-blue-700 text-white px-6 py-2.5 md:px-10 md:py-4 rounded-xl md:rounded-2xl font-black text-[10px] md:text-xs uppercase tracking-[0.1em] md:tracking-[0.2em] shadow-xl active:scale-95 transition-all flex items-center justify-center gap-2 md:gap-3"
                   >
                      <PlayIcon className="h-4 w-4 md:h-5 md:w-5" /> Assistir Aula
                   </button>
                </div>
             </div>
          ) : (
            <>
              {post.content && <p className="text-gray-700 dark:text-gray-300 text-xs md:text-sm font-medium leading-relaxed mb-3 md:mb-4 whitespace-pre-wrap line-clamp-3 group-hover:text-blue-600 transition-colors">{post.content}</p>}
              {post.imageUrl && (
                <div className="rounded-[1rem] md:rounded-[2rem] overflow-hidden border dark:border-white/5 bg-gray-50 dark:bg-darkbg relative group/img">
                   <img src={post.imageUrl} className="w-full h-auto object-cover max-h-[400px] md:max-h-[500px]" alt="Post" />
                   <div className="absolute inset-0 bg-black/10 opacity-0 group-hover/img:opacity-100 transition-opacity flex items-center justify-center">
                      <div className="bg-white/90 p-2 md:p-3 rounded-xl md:rounded-2xl shadow-xl">
                        <ArrowsPointingOutIcon className="h-5 w-5 md:h-6 md:w-6 text-blue-600" />
                      </div>
                   </div>
                </div>
              )}
            </>
          )}
        </div>

        {/* ACTIONS */}
        <div className="px-2 md:px-5 py-2 md:py-3 flex items-center justify-between border-t dark:border-white/5">
          <div className="flex items-center gap-0.5 md:gap-2">
            <button onClick={handleLike} className={`flex items-center gap-1.5 px-2 md:px-3 py-1.5 md:py-2 rounded-lg md:rounded-xl transition-all active:scale-90 ${hasLiked ? 'text-blue-600 bg-blue-50 dark:bg-blue-500/10 font-black' : 'text-gray-400 hover:bg-gray-50 dark:hover:bg-white/5'}`}>
              {hasLiked ? <HeartIconSolid className="h-4 w-4 md:h-5 md:w-5" /> : <HeartIconOutline className="h-4 w-4 md:h-5 md:w-5" />}
              <span className="text-[10px] md:text-xs font-black">{post.likes?.length || 0}</span>
            </button>

            <button onClick={(e) => { e.stopPropagation(); setShowDetailModal(true); }} className="flex items-center gap-1.5 px-2 md:px-3 py-1.5 md:py-2 rounded-lg md:rounded-xl text-gray-400 hover:bg-gray-50 dark:hover:bg-white/5 transition-all">
              <ChatIconOutline className="h-4 w-4 md:h-5 md:w-5" />
              <span className="font-black text-[10px] md:text-xs">{post.comments?.length || 0}</span>
            </button>

            <button onClick={handleShare} className="flex items-center gap-1.5 px-2 md:px-3 py-1.5 md:py-2 rounded-lg md:rounded-xl text-gray-400 hover:bg-gray-50 dark:hover:bg-white/5">
              <ShareIcon className="h-4 w-4 md:h-5 md:w-5" />
            </button>

            <button onClick={(e) => { e.stopPropagation(); setShowIndicateModal(true); }} className="flex items-center gap-1.5 px-2 md:px-3 py-1.5 md:py-2 rounded-lg md:rounded-xl text-gray-400 hover:bg-gray-50 dark:hover:bg-white/5">
              <PaperAirplaneIcon className="h-4 w-4 md:h-5 md:w-5 -rotate-45" />
            </button>
          </div>

          <button onClick={handleSave} className={`p-2 md:p-2.5 rounded-lg md:rounded-xl transition-all ${hasSaved ? 'text-blue-600 bg-blue-50 dark:bg-blue-900/20' : 'text-gray-300 hover:bg-gray-50 dark:hover:bg-white/5'}`}>
            {hasSaved ? <BookmarkIconSolid className="h-4 w-4 md:h-5 md:w-5" /> : <BookmarkIconOutline className="h-4 w-4 md:h-5 md:w-5" />}
          </button>
        </div>
      </div>

      {showDetailModal && (
        <PostDetailModal
          post={post}
          currentUser={currentUser}
          onClose={() => setShowDetailModal(false)}
          onUpdate={onPostUpdatedOrDeleted}
          onNavigate={onNavigate}
          refreshUser={refreshUser}
        />
      )}

      {showIndicateModal && (
        <IndicateModal 
          post={post} 
          currentUser={currentUser} 
          onClose={() => setShowIndicateModal(false)} 
          onPostUpdated={onPostUpdatedOrDeleted}
        />
      )}
    </>
  );
};

