import React, { useState, useEffect, useMemo } from 'react';
import { User, Post, AdCampaign, UserType, Transaction, PostType } from '../types';
import { 
  getUsers, 
  getPosts, 
  getAds, 
  deleteUser, 
  deletePost, 
  saveAds, 
  updateUser, 
  getAffiliateSales 
} from '../services/storageService';
import { 
  UsersIcon, 
  NewspaperIcon, 
  MegaphoneIcon, 
  BanknotesIcon, 
  ShieldCheckIcon, 
  TrashIcon, 
  NoSymbolIcon, 
  ChartBarIcon,
  CheckCircleIcon,
  ArrowPathIcon,
  ExclamationCircleIcon,
  EyeIcon,
  AcademicCapIcon
} from '@heroicons/react/24/solid';

interface AdminDashboardProps {
  currentUser: User;
  onNavigate: (page: string, params?: any) => void;
}

type AdminTab = 'overview' | 'users' | 'content' | 'ads' | 'finance';

const AdminDashboard: React.FC<AdminDashboardProps> = ({ currentUser, onNavigate }) => {
  const [activeTab, setActiveTab] = useState<AdminTab>('overview');
  const [users, setUsers] = useState<User[]>([]);
  const [posts, setPosts] = useState<Post[]>([]);
  const [ads, setAds] = useState<AdCampaign[]>([]);
  const [sales, setSales] = useState<any[]>([]);
  const [loading, setLoading] = useState(false);

  const loadAllData = () => {
    setLoading(true);
    setUsers(getUsers());
    setPosts(getPosts());
    setAds(getAds());
    setSales(getAffiliateSales());
    setTimeout(() => setLoading(false), 500);
  };

  useEffect(() => {
    loadAllData();
  }, []);

  const stats = useMemo(() => {
    const totalBalance = users.reduce((acc, u) => acc + (u.balance || 0), 0);
    const platformRevenue = sales.reduce((acc, s) => acc + (s.saleAmount * 0.1), 0);
    return {
      totalUsers: users.length,
      creators: users.filter(u => u.userType === UserType.CREATOR).length,
      totalPosts: posts.length,
      activeAds: ads.filter(a => a.isActive).length,
      totalMoney: totalBalance,
      estimatedRevenue: platformRevenue
    };
  }, [users, posts, ads, sales]);

  const handleToggleAd = (adId: string) => {
    const updatedAds = ads.map(ad => ad.id === adId ? { ...ad, isActive: !ad.isActive } : ad);
    saveAds(updatedAds);
    setAds(updatedAds);
  };

  const handleVerifyUser = (userId: string) => {
    const user = users.find(u => u.id === userId);
    if (user) {
      updateUser({ ...user, userType: UserType.CREATOR });
      loadAllData();
    }
  };

  return (
    <div className="min-h-screen bg-[#05070a] text-white pt-20 md:pt-24 pb-32 px-3 md:px-10">
      <div className="max-w-7xl mx-auto">

        {/* TOP BAR */}
        <div className="flex flex-col md:flex-row md:items-center justify-between mb-6 md:mb-12 gap-4">
           <div>
              <div className="flex items-center gap-2">
                 <div className="w-2 h-2 bg-red-500 rounded-full animate-pulse shadow-[0_0_8px_red]"></div>
                 <h1 className="text-xl md:text-5xl font-black tracking-tighter uppercase">Command Center</h1>
              </div>
              <p className="text-gray-500 font-bold uppercase text-[7px] md:text-[10px] tracking-[0.2em] mt-0.5">CyBer Pro Oversight</p>
           </div>

           <div className="flex items-center justify-between md:justify-end gap-3 bg-white/5 p-2.5 md:p-4 rounded-xl md:rounded-[2rem] border border-white/10 backdrop-blur-md">
              <div className="text-left md:text-right">
                 <p className="text-[6px] md:text-[8px] font-black text-gray-500 uppercase">Status</p>
                 <p className="text-[9px] md:text-xs font-black text-green-400">ONLINE</p>
              </div>
              <button onClick={loadAllData} className="p-2 md:p-3 bg-white/10 rounded-lg md:rounded-2xl hover:bg-white/20 transition-all">
                 <ArrowPathIcon className={`h-4 w-4 md:h-5 md:w-5 ${loading ? 'animate-spin' : ''}`} />
              </button>
           </div>
        </div>

        {/* TABS MENU - Horizontal Scroll with better indicators */}
        <div className="flex gap-2 overflow-x-auto no-scrollbar mb-6 pb-2 -mx-3 px-3 md:mx-0 md:px-0 scroll-smooth">
           {[
             { id: 'overview', label: 'Início', icon: ChartBarIcon },
