export default AdminDashboard;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { User, Post, AdCampaign, PostType, Story, UserType } from '../types';
import { getPosts, getAds, getStories, getUsers, toggleFollowUser } from '../services/storageService';
import { DEFAULT_PROFILE_PIC } from '../constants';
import PostCard from './PostCard';
import CreatePost from './CreatePost';
import AdCard from './AdCard';
import StoryViewerModal from './StoryViewerModal';
import CreateStoryModal from './CreateStoryModal';
import { 
  PlusIcon, ArrowPathIcon, UserPlusIcon, CheckBadgeIcon, SparklesIcon
} from '@heroicons/react/24/outline';

interface FeedPageProps {
  currentUser: User;
  onNavigate: (page: string, params?: Record<string, string>) => void;
  refreshUser: () => void;
}

const ITEMS_PER_PAGE = 5;

const FeedPage: React.FC<FeedPageProps> = ({ currentUser, onNavigate, refreshUser }) => {
  const [allItems, setAllItems] = useState<(Post | AdCampaign | { type: 'SUGGESTIONS' })[]>([]);
  const [visibleItems, setVisibleItems] = useState<(Post | AdCampaign | { type: 'SUGGESTIONS' })[]>([]);
  const [displayLimit, setDisplayLimit] = useState(ITEMS_PER_PAGE);
  const [loading, setLoading] = useState(true);
  const [loadingMore, setLoadingMore] = useState(false);
  const [suggestedUsers, setSuggestedUsers] = useState<User[]>([]);
  const [stories, setStories] = useState<Story[]>([]);

  const [selectedStoryIndex, setSelectedStoryIndex] = useState<number | null>(null);
  const [isCreatingStory, setIsCreatingStory] = useState(false);

  const observerTarget = useRef<HTMLDivElement>(null);

  const loadData = useCallback(() => {
    setLoading(true);
    // Safety check: Filter out any malformed posts from storage
    const allPosts = getPosts()
      .filter(p => p && typeof p === 'object' && p.userId)
      .sort((a, b) => {
        if (a.isPinned && !b.isPinned) return -1;
        if (!a.isPinned && b.isPinned) return 1;
        return b.timestamp - a.timestamp;
    });
    const allAds = getAds();
    const allUsers = getUsers();
    const allStories = getStories();

    setStories(allStories);

    const suggestions = allUsers
      .filter(u => u && u.id !== currentUser.id && !currentUser.followedUsers?.includes(u.id))
      .sort(() => 0.5 - Math.random())
      .slice(0, 5);

    setSuggestedUsers(suggestions);

    let combined: (Post | AdCampaign | { type: 'SUGGESTIONS' })[] = [];
    allPosts.forEach((post, idx) => {
        combined.push(post);
        if (idx === 1 && suggestions.length > 0) {
            combined.push({ type: 'SUGGESTIONS' });
        }
        if ((idx + 1) % 5 === 0 && allAds.length > 0) {
            const randomAd = allAds[Math.floor(Math.random() * allAds.length)];
            if (randomAd) combined.push(randomAd);
        }
    });

    setAllItems(combined);
    setVisibleItems(combined.slice(0, ITEMS_PER_PAGE));
    setLoading(false);
  }, [currentUser]);

  useEffect(() => { loadData(); }, [loadData]);

  const loadMoreItems = useCallback(() => {
    if (loadingMore || visibleItems.length >= allItems.length) return;
    setLoadingMore(true);

    // Simula latência de rede para o spinner ficar visível
    setTimeout(() => {
      const nextLimit = displayLimit + ITEMS_PER_PAGE;
      const nextItems = allItems.slice(0, nextLimit);

      // Se chegamos no fim dos itens reais, podemos "reciclar" conteúdo educacional (opcional)
      // para criar a sensação de feed infinito exploratório.
      if (nextLimit > allItems.length && allItems.length > 0) {
         const postsOnly = allItems.filter(i => 'authorName' in i) as Post[];
         if (postsOnly.length > 0) {
            const recycled: Post[] = postsOnly
              .sort(() => Math.random() - 0.5)
              .slice(0, 3)
              .map(p => ({...p, id: `recycled-${Date.now()}-${Math.random()}`}));
            setAllItems(prev => [...prev, ...recycled]);
         }
      }

      setDisplayLimit(nextLimit);
      setVisibleItems(nextItems);
      setLoadingMore(false);
    }, 1200);
  }, [displayLimit, allItems, loadingMore, visibleItems.length]);

  useEffect(() => {
    const observer = new IntersectionObserver(
      entries => {
        if (entries[0].isIntersecting && !loading && !loadingMore) {
          loadMoreItems();
        }
      },
      { threshold: 0.1, rootMargin: '100px' }
    );

    if (observerTarget.current) observer.observe(observerTarget.current);
    return () => observer.disconnect();
  }, [loading, loadingMore, loadMoreItems]);

  const handleFollow = (userId: string) => {
    toggleFollowUser(currentUser.id, userId);
    refreshUser();
    setSuggestedUsers(prev => prev.filter(u => u.id !== userId));
  };

  return (
    <div className="w-full max-w-[1400px] mx-auto px-1 md:px-6 lg:px-10 py-3 md:py-8">

      {/* Stories Section - Optimized for < 500px */}
      <section className="mb-4 md:mb-8 bg-white dark:bg-darkcard rounded-[1.2rem] md:rounded-[2rem] p-3 md:p-4 shadow-sm border dark:border-white/10 overflow-hidden">
        <div className="flex gap-3 md:gap-4 overflow-x-auto pb-1 no-scrollbar scroll-smooth">
          <div 
            onClick={() => setIsCreatingStory(true)}
            className="flex-shrink-0 flex flex-col items-center gap-1.5 cursor-pointer group"
          >
            <div className="relative p-0.5 rounded-full border-2 border-dashed border-blue-400 group-hover:border-blue-600 transition-colors">
              <img src={currentUser.profilePicture || DEFAULT_PROFILE_PIC} className="w-12 h-12 md:w-14 md:h-14 rounded-full object-cover shadow-sm" />
              <div className="absolute bottom-0 right-0 bg-blue-600 text-white rounded-full p-0.5 border-2 border-white dark:border-darkcard">
                <PlusIcon className="w-2.5 h-2.5 stroke-[4]" />
              </div>
            </div>
            <span className="text-[8px] font-black dark:text-white uppercase tracking-tighter">Novo</span>
          </div>
          {stories.map((s, i) => (
            <div key={i} onClick={() => setSelectedStoryIndex(i)} className="flex-shrink-0 flex flex-col items-center gap-1.5 cursor-pointer group">
              <div className="p-0.5 md:p-1 rounded-full bg-gradient-to-tr from-blue-500 to-purple-600 shadow-md group-hover:scale-105 transition-transform">
                <div className="p-0.5 bg-white dark:bg-darkcard rounded-full">
                  <img src={s.userProfilePic || DEFAULT_PROFILE_PIC} className="w-12 h-12 md:w-14 md:h-14 rounded-full object-cover" />
                </div>
              </div>
              <span className="text-[8px] font-black dark:text-white truncate w-12 text-center">{s.userName.split(' ')[0]}</span>
            </div>
          ))}
        </div>
      </section>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-4 md:gap-8">
        <main className="col-span-1 lg:col-span-8 space-y-4 md:space-y-8">
          <CreatePost currentUser={currentUser} onPostCreated={loadData} refreshUser={refreshUser} />

          <div className="space-y-4 md:space-y-8">
            {loading ? (
              <div className="py-20 text-center flex flex-col items-center gap-4">
                <div className="w-10 h-10 border-4 border-blue-600 border-t-transparent rounded-full animate-spin"></div>
                <p className="text-[9px] font-black text-gray-400 uppercase tracking-widest">Sincronizando...</p>
              </div>
            ) : (
              <>
                {visibleItems.map((item, idx) => {
                  if (!item) return null;

                  if ('authorName' in item) {
                    return (
                      <div key={(item as Post).id || idx} className="animate-fade-in">
                        <PostCard 
                          post={item as Post} 
                          currentUser={currentUser} 
                          onNavigate={onNavigate} 
                          onFollowToggle={handleFollow} 
                          refreshUser={refreshUser} 
                          onPostUpdatedOrDeleted={loadData} 
                          onPinToggle={() => {}} 
                        />
                      </div>
                    );
                  }

                  if ('type' in item && item.type === 'SUGGESTIONS') {
                    return (
                      <div key="suggestions-card" className="bg-white dark:bg-darkcard rounded-[1.5rem] md:rounded-[2.5rem] p-5 md:p-8 border border-blue-50 dark:border-white/10 shadow-sm animate-fade-in overflow-hidden">
                        <div className="flex items-center gap-2 md:gap-3 mb-5 md:mb-6">
                           <SparklesIcon className="h-5 w-5 md:h-6 md:w-6 text-blue-600" />
                           <h4 className="font-black text-gray-900 dark:text-white uppercase text-[10px] md:text-xs tracking-widest">Para Você</h4>
                        </div>
                        <div className="flex gap-3 overflow-x-auto pb-2 no-scrollbar">
                           {suggestedUsers.map(user => (
                             <div key={user.id} className="flex-shrink-0 w-32 md:w-40 bg-gray-50 dark:bg-darkbg rounded-2xl p-4 flex flex-col items-center text-center border border-gray-100 dark:border-white/5 group">
                                <div className="relative mb-2">
                                  <img src={user.profilePicture || DEFAULT_PROFILE_PIC} className="w-12 h-12 md:w-16 md:h-16 rounded-xl md:rounded-2xl object-cover shadow-md" />
                                  {user.userType === UserType.CREATOR && <CheckBadgeIcon className="h-3 w-3 text-blue-600 absolute -top-1 -right-1 fill-white dark:fill-darkcard" />}
                                </div>
                                <p className="font-black text-[10px] md:text-[11px] dark:text-white truncate w-full">{user.firstName}</p>
                                <p className="text-[7px] md:text-[8px] font-bold text-gray-400 uppercase mb-3 truncate w-full">{user.credentials || 'Expert'}</p>
                                <button 
                                  onClick={() => handleFollow(user.id)}
                                  className="w-full py-1.5 bg-blue-600 text-white rounded-lg text-[8px] font-black uppercase tracking-widest"
                                >
                                  Seguir
                                </button>
                             </div>
                           ))}
                        </div>
                      </div>
                    );
                  }

                  return <AdCard key={(item as AdCampaign).id || idx} ad={item as AdCampaign} />;
                })}

                <div ref={observerTarget} className="py-8 md:py-12 w-full flex flex-col items-center justify-center">
                  {loadingMore ? (
                    <div className="flex flex-col items-center gap-3 animate-fade-in">
                       <div className="w-8 h-8 border-4 border-blue-600 border-t-transparent rounded-full animate-spin"></div>
                       <span className="text-[8px] font-black text-blue-600 dark:text-blue-400 uppercase tracking-widest">
                          Buscando novos saberes...
                       </span>
                    </div>
                  ) : (
                    <div className="flex items-center gap-2 bg-white dark:bg-white/5 px-4 py-2 rounded-xl border border-gray-100 dark:border-white/5">
                      <SparklesIcon className="h-3.5 w-3.5 text-blue-500" />
                      <p className="text-[8px] font-black text-gray-400 uppercase tracking-widest">Fim do Conteúdo</p>
                    </div>
                  )}
                </div>
              </>
            )}
          </div>
        </main>

        <aside className="hidden lg:block lg:col-span-4">
           <div className="sticky top-24 space-y-6">
              <div className="bg-white dark:bg-darkcard rounded-[2.5rem] p-8 shadow-sm border dark:border-white/10 flex flex-col items-center">
                 <img src={currentUser.profilePicture || DEFAULT_PROFILE_PIC} className="w-20 h-20 rounded-[1.8rem] border-4 border-blue-50 shadow-lg object-cover mb-4" />
                 <h3 className="font-black text-gray-900 dark:text-white text-lg leading-tight">{currentUser.firstName} {currentUser.lastName}</h3>
                 <p className="text-[9px] font-black text-blue-600 uppercase tracking-widest mt-1">
                   {currentUser.userType === UserType.CREATOR ? 'Professor Autor' : 'Membro CyBer'}
                 </p>
                 <div className="mt-6 w-full pt-6 border-t border-gray-50 dark:border-white/5 flex justify-around">
                    <div className="text-center">
                       <p className="text-lg font-black dark:text-white">{currentUser.followers?.length || 0}</p>
                       <p className="text-[8px] font-black text-gray-400 uppercase">Alunos</p>
                    </div>
                    <div className="text-center">
                       <p className="text-lg font-black dark:text-white">{currentUser.followedUsers?.length || 0}</p>
                       <p className="text-[8px] font-black text-gray-400 uppercase">Seguindo</p>
                    </div>
                 </div>
              </div>
           </div>
        </aside>
      </div>

      {selectedStoryIndex !== null && (
        <StoryViewerModal 
          stories={stories} 
          initialIndex={selectedStoryIndex} 
          onClose={() => setSelectedStoryIndex(null)} 
        />
      )}

      {isCreatingStory && (
        <CreateStoryModal 
          currentUser={currentUser} 
          onClose={() => setIsCreatingStory(false)} 
          onStoryCreated={() => {
            setIsCreatingStory(false);
            loadData();
          }}
        />
      )}
    </div>
  );
};

export default FeedPage;

import React, { useState, useEffect, useCallback } from 'react';
import { User, CartItem } from './types';
import {
    getCurrentUserId,
    findUserById,
    saveCurrentUser,
    getNotificationsForUser,
    markNotificationsAsRead,
    getCart,
    addToCart,
    removeFromCart,
    updateCartItemQuantity,
    clearCart,
    deleteUser
} from './services/storageService';
import Header from './components/Header';
import Footer from './components/Footer';
import AuthPage from './components/AuthPage';
import FeedPage from './components/FeedPage';
import ProfilePage from './components/ProfilePage';
import ChatPage from './components/ChatPage';
import AdCampaignPage from './components/AdCampaignPage';
import LiveStreamViewer from './components/LiveStreamViewer';
import { StorePage } from './components/StorePage';
import StoreManagerPage from './components/StoreManagerPage';
import CreatePost from './components/CreatePost';
import ReelsPage from './components/ReelsPage';
import SearchResultsPage from './components/SearchResultsPage';
import NotificationsPage from './components/NotificationsPage';
import CartModal from './components/CartModal';
import ReportUserPage from './components/ReportUserPage';
import SettingsPage from './components/SettingsPage';
import AdminDashboard from './components/AdminDashboard';

type Page = 'auth' | 'feed' | 'profile' | 'chat' | 'ads' | 'live' | 'store' | 'manage-store' | 'edit-post' | 'create-post' | 'reels-page' | 'search-results' | 'notifications' | 'report-user' | 'settings' | 'admin';

const App: React.FC = () => {
    const [currentUser, setCurrentUser] = useState<User | null>(null);
    const [darkMode, setDarkMode] = useState(() => localStorage.getItem('cyberphone_theme') === 'dark');
    const [currentPage, setCurrentPage] = useState<Page>(() => {
        return getCurrentUserId() ? 'feed' : 'auth';
    });
    const [pageParams, setPageParams] = useState<Record<string, string>>({});
    const [unreadNotificationsCount, setUnreadNotificationsCount] = useState(0);
    const [cartItems, setCartItems] = useState<CartItem[]>(getCart());
    const [isCartModalOpen, setIsCartModalOpen] = useState(false);

    const toggleTheme = useCallback(() => {
        setDarkMode(prev => {
            const newVal = !prev;
            localStorage.setItem('cyberphone_theme', newVal ? 'dark' : 'light');
            return newVal;
        });
    }, []);

    useEffect(() => {
        if (darkMode) document.documentElement.classList.add('dark');
        else document.documentElement.classList.remove('dark');
    }, [darkMode]);

    const refreshCurrentUser = useCallback(() => {
        const userId = getCurrentUserId();
        if (userId) {
            const user = findUserById(userId);
            setCurrentUser(user || null);
            if (user) {
                const notifications = getNotificationsForUser(user.id);
                setUnreadNotificationsCount(notifications.filter(n => !n.isRead).length);
            }
        } else {
            setCurrentUser(null);
            setUnreadNotificationsCount(0);
        }
    }, []);

    const refreshCart = useCallback(() => {
        setCartItems(getCart());
    }, []);

    useEffect(() => {
        refreshCurrentUser();
        refreshCart();
    }, [refreshCurrentUser, refreshCart]);

    const handleLoginSuccess = useCallback((user: User) => {
        setCurrentUser(user);
        saveCurrentUser(user.id);
        refreshCurrentUser();
        refreshCart();
        setCurrentPage('feed');
        setUnreadNotificationsCount(0);
    }, [refreshCurrentUser, refreshCart]);

    const handleLogout = useCallback(() => {
        setCurrentUser(null);
        saveCurrentUser(null);
        setCurrentPage('auth');
        setUnreadNotificationsCount(0);
        clearCart();
        refreshCart();
    }, [refreshCart]);

    const handleDeleteAccount = useCallback(() => {
        if (currentUser) {
            deleteUser(currentUser.id);
            handleLogout();
        }
    }, [currentUser, handleLogout]);

    const handleNavigate = useCallback((page: Page, params: Record<string, string> = {}) => {
        if (page === 'notifications' && currentUser) {
            markNotificationsAsRead(currentUser.id);
            refreshCurrentUser();
        }
        setCurrentPage(page);
        setPageParams(params);
        window.scrollTo(0, 0);
    }, [currentUser, refreshCurrentUser]);

    const handleAddToCart = (productId: string, quantity: number = 1, selectedColor?: string) => {
        addToCart(productId, quantity, selectedColor);
        refreshCart();
    };

    const cartItemCount = cartItems.reduce((sum, item) => sum + item.quantity, 0);

    const renderPage = () => {
        if (!currentUser) return <AuthPage onLoginSuccess={handleLoginSuccess} />;
        switch (currentPage) {
            case 'feed': return <FeedPage currentUser={currentUser} onNavigate={handleNavigate} refreshUser={refreshCurrentUser} />;
            case 'reels-page': return <ReelsPage currentUser={currentUser} onNavigate={handleNavigate} refreshUser={refreshCurrentUser} />;
            case 'profile': return <ProfilePage currentUser={currentUser} onNavigate={handleNavigate} refreshUser={refreshCurrentUser} userId={pageParams.userId} />;
            case 'chat': return <ChatPage currentUser={currentUser} />;
            case 'settings': return <SettingsPage currentUser={currentUser} onNavigate={handleNavigate} darkMode={darkMode} toggleTheme={toggleTheme} refreshUser={refreshCurrentUser} onLogout={handleLogout} onDeleteAccount={handleDeleteAccount} />;
            case 'ads': return <AdCampaignPage currentUser={currentUser} refreshUser={refreshCurrentUser} />;
            case 'admin': return <AdminDashboard currentUser={currentUser} onNavigate={handleNavigate} />;
            case 'live':
                if (pageParams.postId) return <LiveStreamViewer currentUser={currentUser} postId={pageParams.postId} onNavigate={handleNavigate} refreshUser={refreshCurrentUser} />;
                return <FeedPage currentUser={currentUser} onNavigate={handleNavigate} refreshUser={refreshCurrentUser} />;
            case 'store': return <StorePage currentUser={currentUser} onNavigate={handleNavigate} refreshUser={refreshCurrentUser} storeId={pageParams.storeId} onAddToCart={handleAddToCart} onOpenCart={() => setIsCartModalOpen(true)} />;
            case 'manage-store': return <StoreManagerPage currentUser={currentUser} refreshUser={refreshCurrentUser} onNavigate={handleNavigate} />;
            case 'create-post': return <CreatePost currentUser={currentUser} onPostCreated={() => handleNavigate('feed')} refreshUser={refreshCurrentUser} />;
            case 'edit-post':
                if (pageParams.postId) return <CreatePost currentUser={currentUser} onPostCreated={() => handleNavigate('feed')} refreshUser={refreshCurrentUser} postId={pageParams.postId} />;
                return <FeedPage currentUser={currentUser} onNavigate={handleNavigate} refreshUser={refreshCurrentUser} />;
            case 'search-results': return <SearchResultsPage currentUser={currentUser} query={pageParams.query || ''} onNavigate={handleNavigate} refreshUser={refreshCurrentUser} />;
            case 'notifications': return <NotificationsPage currentUser={currentUser} onNavigate={handleNavigate} refreshUser={refreshCurrentUser} />;
            case 'report-user': return <ReportUserPage currentUser={currentUser} targetUserId={pageParams.userId} onNavigate={handleNavigate} />;
            default: return <FeedPage currentUser={currentUser} onNavigate={handleNavigate} refreshUser={refreshCurrentUser} />;
        }
    };

    return (
        <div className="min-h-screen flex flex-col bg-gray-50 dark:bg-darkbg text-gray-900 dark:text-gray-100 transition-colors duration-300 w-full overflow-x-hidden">
            <Header
                currentUser={currentUser}
                onNavigate={handleNavigate}
                unreadNotificationsCount={unreadNotificationsCount}
                cartItemCount={cartItemCount}
                onOpenCart={() => setIsCartModalOpen(true)}
            />
            <div className="flex flex-1 w-full overflow-x-hidden">
                {currentUser && (
                    <Footer currentUser={currentUser} onNavigate={handleNavigate} activePage={currentPage} onLogout={handleLogout} />
                )}
                <main className={`flex-grow pt-[64px] md:pt-[72px] pb-[72px] md:pb-8 transition-all duration-300 w-full ${currentUser ? 'md:ml-64 px-0 md:px-8' : 'px-0'}`}>
                    <div className="max-w-7xl mx-auto w-full">
                        {renderPage()}
                    </div>
                </main>
            </div>
            {currentUser && (
              <CartModal 
                isOpen={isCartModalOpen}
                onClose={() => setIsCartModalOpen(false)}
                currentUser={currentUser}
                onCartUpdate={refreshCart}
                refreshUser={refreshCurrentUser}
              />
            )}
        </div>
    );
};

export default App;

import React, { useState, useRef, useEffect } from 'react';
import { Post, PostType, User, UserType, Comment } from '../types';
import { DEFAULT_PROFILE_PIC } from '../constants';
import { 
  findUserById, 
  updatePostLikes, 
  updatePostShares, 
  updatePostSaves, 
  deletePost, 
  pinPost,
  unpinPost
} from '../services/storageService';
import {
  HeartIcon as HeartIconOutline, 
  ChatBubbleOvalLeftIcon as ChatIconOutline, 
  BookmarkIcon as BookmarkIconOutline, 
  EllipsisHorizontalIcon, 
  TrashIcon, 
  CheckBadgeIcon,
  FlagIcon,
  PaperAirplaneIcon,
  MapPinIcon as PinIconOutline,
  VideoCameraIcon,
  SignalIcon,
  ArrowsPointingOutIcon,
  ShareIcon
} from '@heroicons/react/24/outline';
import { 
  HeartIcon as HeartIconSolid, 
  BookmarkIcon as BookmarkIconSolid,
  MapPinIcon as PinIconSolid,
  PlayIcon
} from '@heroicons/react/24/solid';
import IndicateModal from './IndicateModal';
import PostDetailModal from './PostDetailModal';

interface PostCardProps {
  post: Post;
  currentUser: User;
  onNavigate: (page: string, params?: Record<string, string>) => void;
  onFollowToggle: (userIdToFollow: string) => void;
  refreshUser: () => void;
  onPostUpdatedOrDeleted: () => void;
  onPinToggle: (postId: string, isCurrentlyPinned: boolean) => void;
}

const PostCard: React.FC<PostCardProps> = ({ 
  post, 
  currentUser, 
  onNavigate, 
  onFollowToggle,
  refreshUser, 
  onPostUpdatedOrDeleted,
  onPinToggle
}) => {
  if (!post || !currentUser || !post.id) return null;

  const postAuthor = findUserById(post.userId);
  const [showOptions, setShowOptions] = useState(false);
  const [showIndicateModal, setShowIndicateModal] = useState(false);
  const [showDetailModal, setShowDetailModal] = useState(false);

  const optionsRef = useRef<HTMLDivElement>(null);
  const hasLiked = post.likes?.includes(currentUser.id) || false;
  const hasSaved = post.saves?.includes(currentUser.id) || false;
  const isAuthor = currentUser.id === post.userId;
  const isFollowing = currentUser.followedUsers?.includes(post.userId) || false;

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (optionsRef.current && !optionsRef.current.contains(event.target as Node)) setShowOptions(false);
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const handleLike = (e: React.MouseEvent) => {
    e.stopPropagation();
    updatePostLikes(post.id, currentUser.id);
    onPostUpdatedOrDeleted();
  };

  const handleSave = (e: React.MouseEvent) => {
    e.stopPropagation();
    updatePostSaves(post.id, currentUser.id);
    onPostUpdatedOrDeleted();
  };

  const handleShare = async (e: React.MouseEvent) => {
    e.stopPropagation();
    const shareData = {
      title: `Aula de ${post.authorName}`,
      text: post.content || 'Confira este conteúdo no CyBerPhone!',
      url: window.location.href + `?post=${post.id}`
    };

    try {
      if (navigator.share) {
        await navigator.share(shareData);
      } else {
        await navigator.clipboard.writeText(shareData.url);
        alert('Link copiado para a área de transferência!');
      }
      updatePostShares(post.id, currentUser.id);
      onPostUpdatedOrDeleted();
    } catch (err) {
      console.log('Share cancelled or failed', err);
    }
  };

  const handleDelete = (e: React.MouseEvent) => {
    e.stopPropagation();
    if (window.confirm('Excluir esta publicação?')) {
      deletePost(post.id);
      onPostUpdatedOrDeleted();
    }
  };

  const handlePin = (e: React.MouseEvent) => {
    e.stopPropagation();
    if (post.isPinned) unpinPost(post.id, currentUser.id);
    else pinPost(post.id, currentUser.id);
    onPostUpdatedOrDeleted();
    setShowOptions(false);
  };

  const handleCardClick = () => {
    if (post.type === PostType.LIVE) {
        onNavigate('live', { postId: post.id });
    } else {
        setShowDetailModal(true);
    }
  };

  if (!postAuthor) return null;

  return (
    <>
      <div 
        onClick={handleCardClick}
        className={`bg-white dark:bg-darkcard rounded-[1.2rem] md:rounded-[2.5rem] shadow-sm border border-gray-100 dark:border-white/5 overflow-hidden w-full relative mb-4 transition-all hover:shadow-md animate-fade-in cursor-pointer group`}
      >

        {/* HEADER */}
        <div className="p-3 md:p-5 flex items-center justify-between">
          <div className="flex items-center gap-2 md:gap-3">
            <div className="relative cursor-pointer" onClick={(e) => { e.stopPropagation(); onNavigate('profile', { userId: post.userId }); }}>
              <img src={postAuthor.profilePicture || DEFAULT_PROFILE_PIC} className="w-8 h-8 md:w-11 md:h-11 rounded-lg md:rounded-xl object-cover shadow-sm" />
              {postAuthor.userType === UserType.CREATOR && (
                <div className="absolute -bottom-1 -right-1 bg-blue-600 rounded-lg p-0.5 border border-white dark:border-darkcard">
                  <CheckBadgeIcon className="h-2 w-2 md:h-3 md:w-3 text-white" />
                </div>
              )}
            </div>
            <div className="min-w-0">
              <div className="flex items-center gap-1">
                <h4 className="font-black text-gray-900 dark:text-white text-[11px] md:text-sm truncate leading-tight hover:underline cursor-pointer" onClick={(e) => { e.stopPropagation(); onNavigate('profile', { userId: post.userId }); }}>
                    {postAuthor.firstName}
                </h4>
                {post.isPinned && <PinIconSolid className="h-2.5 w-2.5 md:h-3 md:w-3 text-blue-500 shrink-0" />}
              </div>
              <p className="text-[7px] md:text-[9px] font-bold text-gray-400 uppercase tracking-wider">{new Date(post.timestamp).toLocaleDateString()}</p>
            </div>
          </div>

          <div className="relative" ref={optionsRef}>
            <button onClick={(e) => { e.stopPropagation(); setShowOptions(!showOptions); }} className="p-1.5 md:p-2 text-gray-300 hover:text-blue-600 transition-colors">
              <EllipsisHorizontalIcon className="h-5 w-5 md:h-6 md:w-6" />
            </button>
            {showOptions && (
              <div className="absolute right-0 mt-1 w-40 md:w-48 bg-white dark:bg-darkcard rounded-2xl shadow-2xl py-2 z-20 border dark:border-white/10 animate-fade-in" onClick={e => e.stopPropagation()}>
                {isAuthor ? (
                  <>
                    <button onClick={handlePin} className="flex items-center w-full px-4 py-3 text-[10px] font-black text-gray-700 dark:text-gray-300 hover:bg-gray-50 dark:hover:bg-white/5">
                      {post.isPinned ? <><PinIconSolid className="h-4 w-4 mr-3 text-blue-500" /> Desafixar</> : <><PinIconOutline className="h-4 w-4 mr-3 text-blue-500" /> Fixar</>}
                    </button>
                    <button onClick={handleDelete} className="flex items-center w-full px-4 py-3 text-[10px] font-black text-red-600 hover:bg-red-50 dark:hover:bg-red-900/10">
                      <TrashIcon className="h-4 w-4 mr-3" /> Excluir
                    </button>
                  </>
                ) : (
                  <>
                    {!isFollowing && (
                      <button onClick={(e) => { e.stopPropagation(); onFollowToggle(post.userId); setShowOptions(false); }} className="flex items-center w-full px-4 py-3 text-[10px] font-black text-blue-600 hover:bg-blue-50 dark:hover:bg-red-900/10">
                        Seguir Professor
                      </button>
                    )}
                    <button onClick={(e) => { e.stopPropagation(); onNavigate('report-user', { userId: post.userId }); }} className="flex items-center w-full px-4 py-3 text-[10px] font-black text-orange-600 hover:bg-orange-50">
                      <FlagIcon className="h-4 w-4 mr-3" /> Denunciar
                    </button>
                  </>
                )}
              </div>
            )}
          </div>
        </div>

        {/* CONTENT */}
        <div className="px-3 md:px-5 pb-3 md:pb-4">
          {post.type === PostType.LIVE && post.liveStream ? (
             <div className="rounded-[1rem] md:rounded-[2.5rem] overflow-hidden bg-gray-900 text-white p-3 md:p-8 relative shadow-2xl border-2 md:border-4 border-blue-600/30">
                <div className="absolute top-2 left-2 z-10">
                   <div className="bg-red-600 px-1.5 py-0.5 rounded text-[6px] md:text-[9px] font-black flex items-center gap-1 shadow-lg animate-pulse uppercase tracking-widest">
                      <SignalIcon className="h-2 w-2" /> Ao Vivo
                   </div>
                </div>
                <div className="relative z-10 py-4 md:py-10 flex flex-col items-center text-center">
                   <div className="w-10 h-10 md:w-20 md:h-20 bg-blue-600/20 rounded-full flex items-center justify-center mb-3 md:mb-6 border border-blue-500/30">
                      <VideoCameraIcon className="h-5 w-5 md:h-10 md:w-10 text-blue-400" />
                   </div>
                   <h3 className="text-xs md:text-2xl font-black mb-1 md:mb-2 tracking-tighter leading-tight uppercase line-clamp-1">{post.liveStream.title}</h3>
                   <button 
                      onClick={(e) => { e.stopPropagation(); onNavigate('live', { postId: post.id }); }}
                      className="bg-blue-600 hover:bg-blue-700 text-white px-4 py-2 md:px-10 md:py-4 rounded-lg md:rounded-2xl font-black text-[8px] md:text-xs uppercase tracking-[0.1em] shadow-xl active:scale-95 transition-all flex items-center justify-center gap-1.5 md:gap-3"
                   >
                      <PlayIcon className="h-3 w-3 md:h-5 md:w-5" /> Assistir Aula
                   </button>
                </div>
             </div>
          ) : (
            <>
              {post.content && <p className="text-gray-700 dark:text-gray-300 text-[11px] md:text-sm font-medium leading-relaxed mb-3 md:mb-4 whitespace-pre-wrap line-clamp-3 group-hover:text-blue-600 transition-colors">{post.content}</p>}
              {post.imageUrl && (
                <div className="rounded-[0.8rem] md:rounded-[2rem] overflow-hidden border dark:border-white/5 bg-gray-50 dark:bg-darkbg relative">
                   <img src={post.imageUrl} className="w-full h-auto object-cover max-h-[350px] md:max-h-[500px]" alt="Post" />
                </div>
              )}
            </>
          )}
        </div>

        {/* ACTIONS */}
        <div className="px-2 md:px-5 py-2 md:py-3 flex items-center justify-between border-t dark:border-white/5">
          <div className="flex items-center gap-0.5 md:gap-2">
            <button onClick={handleLike} className={`flex items-center gap-1 px-2 md:px-3 py-1.5 md:py-2 rounded-lg transition-all active:scale-90 ${hasLiked ? 'text-blue-600 bg-blue-50 dark:bg-blue-500/10 font-black' : 'text-gray-400'}`}>
              {hasLiked ? <HeartIconSolid className="h-4 w-4 md:h-5 md:w-5" /> : <HeartIconOutline className="h-4 w-4 md:h-5 md:w-5" />}
              <span className="text-[10px] md:text-xs font-black">{post.likes?.length || 0}</span>
            </button>

            <button onClick={(e) => { e.stopPropagation(); setShowDetailModal(true); }} className="flex items-center gap-1 px-2 md:px-3 py-1.5 md:py-2 rounded-lg text-gray-400 transition-all">
              <ChatIconOutline className="h-4 w-4 md:h-5 md:w-5" />
              <span className="font-black text-[10px] md:text-xs">{post.comments?.length || 0}</span>
            </button>

            <button onClick={handleShare} className="p-2 rounded-lg text-gray-400">
              <ShareIcon className="h-4 w-4 md:h-5 md:w-5" />
            </button>
          </div>

          <button onClick={handleSave} className={`p-2 rounded-lg transition-all ${hasSaved ? 'text-blue-600 bg-blue-50 dark:bg-blue-900/20' : 'text-gray-300'}`}>
            {hasSaved ? <BookmarkIconSolid className="h-4 w-4 md:h-5 md:w-5" /> : <BookmarkIconOutline className="h-4 w-4 md:h-5 md:w-5" />}
          </button>
        </div>
      </div>

      {showDetailModal && (
        <PostDetailModal
          post={post}
          currentUser={currentUser}
          onClose={() => setShowDetailModal(false)}
          onUpdate={onPostUpdatedOrDeleted}
          onNavigate={onNavigate}
          refreshUser={refreshUser}
        />
      )}

      {showIndicateModal && (
        <IndicateModal 
          post={post} 
          currentUser={currentUser} 
          onClose={() => setShowIndicateModal(false)} 
          onPostUpdated={onPostUpdatedOrDeleted}
        />
      )}
    </>
  );
};

export default PostCard;

import React from 'react';
import { User } from '../types';
import { 
    HomeIcon, 
    ChatBubbleLeftRightIcon, 
    UserCircleIcon, 
    BuildingStorefrontIcon, 
    FilmIcon,
    ArrowRightOnRectangleIcon,
    Cog6ToothIcon,
    MegaphoneIcon,
    ShieldExclamationIcon
