  return (
    <>
      {/* MOBILE NAV */}
      <nav className="fixed bottom-0 left-0 w-full z-[60] bg-white/95 dark:bg-darkcard/95 backdrop-blur-xl border-t border-gray-100 dark:border-white/10 flex justify-around items-center h-16 md:hidden px-1 shadow-[0_-4px_20px_rgba(0,0,0,0.08)]">
