            <button
              key={item.page}
              onClick={() => onNavigate(item.page)}
              className={`flex flex-col items-center justify-center flex-1 h-full transition-all duration-300 relative group ${isActive ? 'text-blue-600' : 'text-gray-400 dark:text-gray-500'}`}
              aria-label={item.name}
            >
              <div className={`p-2 rounded-xl transition-all ${isActive ? 'bg-blue-50 dark:bg-blue-500/10 scale-110' : 'active:scale-90'}`}>
                <IconComponent className="h-5 w-5" />
              </div>
              {isActive && <span className="absolute bottom-1 w-1 h-1 bg-blue-600 rounded-full"></span>}
            </button>
          );
        })}
      </nav>

      {/* DESKTOP SIDEBAR */}
      <aside className="hidden md:flex flex-col fixed left-0 top-[72px] w-64 h-[calc(100vh-72px)] bg-white dark:bg-darkcard border-r border-gray-100 dark:border-white/10 z-20 overflow-y-auto p-4 custom-scrollbar shadow-[4px_0_12px_rgba(0,0,0,0.02)]">
        <div className="space-y-2 flex-grow">
