// Added missing indicatePostToUser function to support Post recommendation features
export const indicatePostToUser = (postId: string, actorId: string, targetUserId: string) => {
  const posts = getPosts();
  const post = posts.find(p => p.id === postId);
  if (post) {
    if (!post.indicatedUserIds) post.indicatedUserIds = [];
    // Only add if not already indicated to this specific user to prevent duplicate notifications
    if (post.indicatedUserIds.includes(targetUserId)) return false;

    post.indicatedUserIds.push(targetUserId);
    createNotification({
      type: NotificationType.POST_INDICATION,
      recipientId: targetUserId,
      actorId: actorId,
      postId: postId,
      timestamp: Date.now()
    });
    set(KEYS.POSTS, posts);
    return true;
  }
  return false;
};

