import React, { useState, useEffect } from 'react';
import { User, UserType, Store, Product, ProductType } from '../types';
import { 
  getStores, 
  updateUser, 
  getProducts, 
  updateUserBalance,
  saveProducts,
  saveStores,
  findStoreById
} from '../services/storageService';
import { sourceDropshippingProducts } from '../services/geminiService';
import { 
  PlusIcon, 
  ArchiveBoxIcon,
  TrashIcon,
  UsersIcon,
  SparklesIcon,
  CheckBadgeIcon,
  BoltIcon,
  XMarkIcon,
  ExclamationTriangleIcon,
  MagnifyingGlassIcon,
  ArrowDownTrayIcon,
  ArrowTopRightOnSquareIcon
} from '@heroicons/react/24/solid';
import CryptomusPaymentForm from './CryptomusPaymentForm';

interface StoreManagerPageProps {
  currentUser: User;
  refreshUser: () => void;
  onNavigate: (page: any, params?: any) => void;
}

const StoreManagerPage: React.FC<StoreManagerPageProps> = ({ currentUser, refreshUser, onNavigate }) => {
  const [userStore, setUserStore] = useState<Store | null>(null);
  const [storeProducts, setStoreProducts] = useState<Product[]>([]);
  const [activeTab, setActiveTab] = useState<'inventory' | 'sourcing'>('inventory');

  // Sourcing State
  const [searchQuery, setSearchQuery] = useState('');
  const [sourcingResults, setSourcingResults] = useState<any[]>([]);
  const [isSourcing, setIsSourcing] = useState(false);
  const [markup, setMarkup] = useState(1.5); // 50% de lucro padrão

  useEffect(() => {
    const stores = getStores();
    const myStore = stores.find(s => s.professorId === currentUser.id);
    if (myStore) {
      setUserStore(myStore);
      setStoreProducts(getProducts().filter(p => p.storeId === myStore.id));
    }
  }, [currentUser.id]);

  const handleSource = async () => {
    if (!searchQuery) return;
    setIsSourcing(true);
    const results = await sourceDropshippingProducts(searchQuery);
    setSourcingResults(results);
    setIsSourcing(false);
  };

  const handleImport = (sourceProd: any) => {
    if (!userStore) return;

    const newProduct: Product = {
      id: `prod-drop-${Date.now()}`,
      storeId: userStore.id,
      name: sourceProd.name,
      description: sourceProd.description,
      price: sourceProd.originalPrice * markup,
      imageUrls: [sourceProd.imageUrl],
      affiliateCommissionRate: 0.1,
      type: ProductType.PHYSICAL,
      ratings: [],
      averageRating: 5,
      ratingCount: 0,
      isDropshipping: true,
      externalProviderId: sourceProd.externalProviderId,
      originalPrice: sourceProd.originalPrice
    };

    const allProducts = getProducts();
    saveProducts([...allProducts, newProduct]);

    const updatedStore = { ...userStore, productIds: [...userStore.productIds, newProduct.id] };
    const allStores = getStores().map(s => s.id === userStore.id ? updatedStore : s);
    saveStores(allStores);

    setUserStore(updatedStore);
    setStoreProducts([...storeProducts, newProduct]);
    alert('Produto importado com sucesso!');
  };

  if (currentUser.userType === UserType.STANDARD) {
    return (
      <div className="container mx-auto px-4 pt-20 pb-20 max-w-4xl animate-fade-in text-center">
        <h2 className="text-4xl md:text-6xl font-black mb-12 tracking-tighter dark:text-white">Torne-se <span className="text-blue-600">Profissional.</span></h2>
        <p className="text-gray-500 mb-8">Libere sua loja e ferramentas de dropshipping.</p>
        <button onClick={() => onNavigate('settings')} className="bg-blue-600 text-white px-10 py-4 rounded-2xl font-black">Configurar Conta</button>
      </div>
    );
  }

  return (
    <div className="container mx-auto px-4 pt-24 pb-24 max-w-6xl">
       <div className="flex flex-col md:flex-row items-center justify-between mb-12 gap-6">
          <div className="flex items-center gap-4">
            <div className="bg-blue-600 p-3 rounded-2xl shadow-lg">
              <CheckBadgeIcon className="h-8 w-8 text-white" />
            </div>
            <div className="text-left">
              <h2 className="text-3xl font-black dark:text-white uppercase tracking-tighter">Gerenciar Negócio</h2>
              <p className="text-gray-500 text-[10px] font-black uppercase tracking-widest">Loja: {userStore?.name || 'Carregando...'}</p>
            </div>
          </div>

          <div className="flex bg-gray-100 dark:bg-white/5 p-1 rounded-2xl">
             <button onClick={() => setActiveTab('inventory')} className={`px-6 py-2.5 rounded-xl font-black text-[10px] uppercase transition-all ${activeTab === 'inventory' ? 'bg-white dark:bg-darkcard text-blue-600 shadow-md' : 'text-gray-500'}`}>Estoque</button>
             <button onClick={() => setActiveTab('sourcing')} className={`px-6 py-2.5 rounded-xl font-black text-[10px] uppercase transition-all ${activeTab === 'sourcing' ? 'bg-white dark:bg-darkcard text-blue-600 shadow-md' : 'text-gray-500'}`}>Dropshipping (DSers)</button>
          </div>
       </div>

       {activeTab === 'inventory' && (
         <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 animate-fade-in">
            {storeProducts.map(p => (
              <div key={p.id} className="bg-white dark:bg-darkcard rounded-3xl p-6 border border-gray-100 dark:border-white/5 shadow-sm">
                 <img src={p.imageUrls[0]} className="w-full h-40 object-cover rounded-2xl mb-4" />
                 <div className="flex items-center justify-between mb-2">
                    <h4 className="font-black text-sm truncate dark:text-white uppercase">{p.name}</h4>
                    {p.isDropshipping && <span className="bg-orange-500/10 text-orange-500 text-[8px] font-black px-2 py-0.5 rounded uppercase">Drop</span>}
                 </div>
                 <p className="text-2xl font-black text-blue-600 mb-4">${p.price.toFixed(2)}</p>
                 <div className="flex gap-2">
                    <button className="flex-1 bg-gray-100 dark:bg-white/5 py-2.5 rounded-xl text-[10px] font-black uppercase dark:text-white">Editar</button>
                    <button className="p-2.5 bg-red-500/10 text-red-500 rounded-xl"><TrashIcon className="h-4 w-4"/></button>
                 </div>
              </div>
            ))}
            <button className="border-4 border-dashed border-gray-100 dark:border-white/5 rounded-3xl p-10 flex flex-col items-center justify-center text-gray-300 hover:border-blue-500 hover:text-blue-500 transition-all">
               <PlusIcon className="h-10 w-10 mb-2" />
               <span className="font-black text-xs uppercase">Novo Produto Manual</span>
            </button>
         </div>
       )}

       {activeTab === 'sourcing' && (
         <div className="space-y-8 animate-fade-in">
            <div className="bg-white dark:bg-darkcard p-8 rounded-[2.5rem] shadow-xl border border-gray-100 dark:border-white/5">
               <div className="flex items-center gap-4 mb-8">
                  <div className="p-3 bg-orange-500 rounded-2xl shadow-lg"><BoltIcon className="h-6 w-6 text-white" /></div>
                  <div className="text-left">
                    <h3 className="text-xl font-black dark:text-white uppercase tracking-tighter">Buscar no Fornecedor</h3>
                    <p className="text-gray-500 text-[10px] font-black uppercase">Conectado via CyBer Sourcing Cloud</p>
                  </div>
               </div>

               <div className="flex gap-3">
                  <div className="flex-1 relative">
                    <MagnifyingGlassIcon className="h-5 w-5 absolute left-4 top-1/2 -translate-y-1/2 text-gray-400" />
                    <input 
                      type="text" 
                      value={searchQuery}
                      onChange={e => setSearchQuery(e.target.value)}
                      placeholder="Ex: Microfone Condensador, Livro de Medicina..." 
                      className="w-full pl-12 pr-4 py-4 bg-gray-50 dark:bg-white/5 rounded-2xl outline-none font-bold dark:text-white focus:ring-2 focus:ring-blue-600"
                    />
                  </div>
                  <button 
                    onClick={handleSource}
                    disabled={isSourcing}
                    className="bg-blue-600 text-white px-8 rounded-2xl font-black uppercase text-xs shadow-xl active:scale-95 disabled:opacity-50 transition-all"
                  >
                    {isSourcing ? 'Buscando...' : 'Pesquisar'}
                  </button>
               </div>
            </div>

            {sourcingResults.length > 0 && (
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                {sourcingResults.map((res, i) => (
                  <div key={i} className="bg-white dark:bg-darkcard rounded-[2rem] p-6 flex gap-6 border border-gray-100 dark:border-white/5 shadow-md group">
                     <img src={res.imageUrl} className="w-32 h-32 rounded-2xl object-cover shadow-sm group-hover:scale-105 transition-transform" />
                     <div className="flex-1 text-left flex flex-col">
                        <h4 className="font-black text-sm dark:text-white mb-1 leading-tight uppercase">{res.name}</h4>
