import { User, Post, UserType, Product, AffiliateSale, Notification, CartItem, TransactionType } from '../types';

const KEYS = {
  USERS: 'cyber_users',
  POSTS: 'cyber_posts',
  STORES: 'cyber_stores',
  PRODUCTS: 'cyber_products',
  SALES: 'cyber_sales',
  CHATS: 'cyber_chats',
  NOTIFICATIONS: 'cyber_notifications',
  CURRENT_USER: 'cyber_current_user_id',
  PLATFORM_STATS: 'cyber_platform_revenue'
};

const PLATFORM_TAX_RATE = 0.10; // 10% de taxa para o dono do app

const get = <T>(key: string, fallback: T): T => {
  const data = localStorage.getItem(key);
  return data ? JSON.parse(data) : fallback;
};

const set = (key: string, data: any) => localStorage.setItem(key, JSON.stringify(data));

// Função para o Dono ver quanto lucrou
export const getPlatformRevenue = () => get<number>(KEYS.PLATFORM_STATS, 0);
const addPlatformRevenue = (amount: number) => {
  const current = getPlatformRevenue();
  set(KEYS.PLATFORM_STATS, current + amount);
};

export const getUsers = (): User[] => get(KEYS.USERS, []);
export const findUserById = (id: string) => getUsers().find(u => u.id === id);
export const getCurrentUserId = () => localStorage.getItem(KEYS.CURRENT_USER);

export const updateUserBalance = (userId: string, amount: number) => {
  const users = getUsers();
  const user = users.find(u => u.id === userId);
  if (user) {
    user.balance = (user.balance || 0) + amount;
    if (amount > 0) user.totalEarned = (user.totalEarned || 0) + amount;
    else user.totalSpent = (user.totalSpent || 0) + Math.abs(amount);
    set(KEYS.USERS, users);
    return true;
  }
  return false;
};

// Nova lógica de compra com Taxa para o Dono
export const processProductPurchase = (cartItems: CartItem[], buyerId: string) => {
  const users = getUsers();
  const sales = get<AffiliateSale[]>(KEYS.SALES, []);
  const products = get<Product[]>(KEYS.PRODUCTS, []);
  const stores = get<any[]>(KEYS.STORES, []);

  for (const item of cartItems) {
    const product = products.find(p => p.id === item.productId);
    if (!product) continue;

    const store = stores.find(s => s.id === product.storeId);
    const sellerId = store?.professorId;
    const totalAmount = product.price * item.quantity;

    // Cálculos de divisão de dinheiro
    const ownerTax = totalAmount * PLATFORM_TAX_RATE;
    const sellerRevenue = totalAmount - ownerTax;

    // Atualiza vendedor
    if (sellerId) updateUserBalance(sellerId, sellerRevenue);

    // Lucro do Dono (Você)
    addPlatformRevenue(ownerTax);

    sales.push({
      id: `sale-${Date.now()}`,
      productId: product.id,
      buyerId,
      affiliateUserId: '',
      storeId: product.storeId,
      commissionEarned: 0,
      platformFee: ownerTax,
      saleAmount: totalAmount,
      timestamp: Date.now(),
      status: 'DELIVERED'
    });
  }

  set(KEYS.SALES, sales);
  return true;
};

// Assinatura Premium / Verificação
export const buyPremiumSubscription = (userId: string) => {
  const cost = 29.90; // Exemplo de preço
  const user = findUserById(userId);
  if (user && (user.balance || 0) >= cost) {
    updateUserBalance(userId, -cost);
    addPlatformRevenue(cost); // 100% do valor da assinatura é do dono
    user.isPremium = true;
    user.isVerified = true;
    user.premiumExpiry = Date.now() + (30 * 24 * 60 * 60 * 1000); // 30 dias
    const allUsers = getUsers().map(u => u.id === userId ? { ...u, ...user } : u);
    set(KEYS.USERS, allUsers);
    return true;
  }
  return false;
};

// Pagamento de Chat
export const payForChatAccess = (buyerId: string, professionalId: string) => {
  const professional = findUserById(professionalId);
  const price = professional?.chatPrice || 0;

  if (price > 0 && updateUserBalance(buyerId, -price)) {
    const tax = price * PLATFORM_TAX_RATE;
    updateUserBalance(professionalId, price - tax);
    addPlatformRevenue(tax);
    return true;
  }
  return false;
};

