      setProfile(findUserById(profileId) || null);
    } else {
      alert("Saldo insuficiente. Adicione fundos.");
    }
  };

  const handleSaveChatPrice = () => {
    if (profile) {
      const updated = { ...profile, chatPrice: chatPriceInput };
      updateUser(updated);
      alert("Preço do chat atualizado!");
      refreshUser();
    }
  };

  if (!profile) return null;

  const isOwnProfile = currentUser.id === profile.id;

  return (
    <div className="container mx-auto px-4 pt-24 pb-24 max-w-5xl animate-fade-in">
