             <div className="flex justify-between items-start mb-8">
                <div>
                   <h2 className="text-4xl font-black dark:text-white flex items-center gap-2">
                      {profile.firstName} {profile.lastName}
                      {profile.isVerified && <CheckBadgeIcon className="h-8 w-8 text-blue-500" />}
                      {profile.isPremium && <StarIcon className="h-8 w-8 text-yellow-500" />}
                   </h2>
                   <p className="text-gray-500 font-bold uppercase tracking-widest text-xs mt-1">{profile.credentials || 'Membro da Comunidade'}</p>
                </div>

                {isOwnProfile && !profile.isPremium && (
                   <button onClick={handleUpgrade} className="bg-yellow-500 text-black px-6 py-3 rounded-2xl font-black text-xs uppercase flex items-center gap-2 shadow-xl hover:scale-105 transition-all">
                      <TrophyIcon className="h-5 w-5" /> Virar Premium
