                   <p className="text-2xl font-black text-green-600">${(profile.totalEarned || 0).toFixed(2)}</p>
                </div>
                <div className="bg-gray-50 dark:bg-white/5 p-6 rounded-3xl text-center">
                   <p className="text-[10px] font-black text-gray-400 uppercase mb-1">Investimentos</p>
                   <p className="text-2xl font-black text-blue-600">${(profile.totalSpent || 0).toFixed(2)}</p>
                </div>
                <div className="bg-gray-50 dark:bg-white/5 p-6 rounded-3xl text-center">
                   <p className="text-[10px] font-black text-gray-400 uppercase mb-1">Saldo Atual</p>
                   <p className="text-2xl font-black text-gray-900 dark:text-white">${(profile.balance || 0).toFixed(2)}</p>
