                     <div className="relative flex-1">
                        <span className="absolute left-4 top-1/2 -translate-y-1/2 font-black text-blue-500">$</span>
                        <input 
                           type="number" 
                           value={chatPriceInput} 
                           onChange={e => setChatPriceInput(Number(e.target.value))}
