  const stories = getStories();
  const userStory = stories.find(s => s.userId === userId);
  const newItem = { id: `story-${Date.now()}`, timestamp: Date.now(), ...item };
  if (userStory) userStory.items.push(newItem);
  else {
    const user = findUserById(userId);
    stories.push({ userId, userName: `${user?.firstName} ${user?.lastName}`, userProfilePic: user?.profilePicture, items: [newItem] });
