export const addToCart = (productId: string, quantity: number = 1, selectedColor?: string) => {
  const cart = getCart();
  const item = cart.find(i => i.productId === productId && i.selectedColor === selectedColor);
  if (item) item.quantity += quantity;
  else cart.push({ productId, quantity, selectedColor });
  set(KEYS.CART, cart);
};
export const removeFromCart = (productId: string) => set(KEYS.CART, getCart().filter(i => i.productId !== productId));
export const updateCartItemQuantity = (productId: string, quantity: number) => {
  const cart = getCart();
  const item = cart.find(i => i.productId === productId);
  if (item) item.quantity = Math.max(0, quantity);
  set(KEYS.CART, cart.filter(i => i.quantity > 0));
};
export const clearCart = () => set(KEYS.CART, []);

export const processProductPurchase = (cartItems: CartItem[], buyerId: string, affiliateUserId: string | null = null, shippingAddress?: ShippingAddress) => {
  const products = getProducts();
  const sales = get<AffiliateSale[]>(KEYS.SALES, []);

  for (const item of cartItems) {
    const product = products.find(p => p.id === item.productId);
    if (!product) continue;
    const store = findStoreById(product.storeId);
    const sellerId = store?.professorId;
    const totalAmount = product.price * item.quantity;
    const tax = totalAmount * PLATFORM_TAX_RATE;
    const sellerRevenue = totalAmount - tax;

    if (sellerId) updateUserBalance(sellerId, sellerRevenue);
    addPlatformRevenue(tax);

    sales.push({
      id: `sale-${Date.now()}`,
      productId: product.id,
      buyerId,
      affiliateUserId: affiliateUserId || '',
      storeId: product.storeId,
      commissionEarned: 0,
      saleAmount: totalAmount,
      timestamp: Date.now(),
      status: OrderStatus.DELIVERED,
      shippingAddress
    });
  }
  set(KEYS.SALES, sales);
  clearCart();
  return true;
};

