  const cost = 29.90;
  const user = findUserById(userId);
  if (user && (user.balance || 0) >= cost) {
    updateUserBalance(userId, -cost);
    addPlatformRevenue(cost);
    user.isPremium = true;
    user.isVerified = true;
    user.premiumExpiry = Date.now() + (30 * 24 * 60 * 60 * 1000);
    updateUser(user);
    return true;
  }
  return false;
};

import React, { useState, useEffect, useRef } from 'react';
// Fix: Removed LiveStreamDetails from the import list as it is not exported from types.ts and not used in this file.
import { Post, PostType, User, UserType, AudioTrack } from '../types';
import { savePosts, getPosts, findAudioTrackById, updatePost, addPost } from '../services/storageService';
import { 
  SparklesIcon, 
  VideoCameraIcon, 
  PhotoIcon, 
  CalendarDaysIcon, 
  XMarkIcon,
  DocumentTextIcon,
  LockClosedIcon,
  FilmIcon,
  MusicalNoteIcon,
  CurrencyDollarIcon,
  ArrowUpTrayIcon,
  TrashIcon,
  ChevronRightIcon
} from '@heroicons/react/24/solid';
import AudioSelectionModal from './AudioSelectionModal';
import RecordReelModal from './RecordReelModal';

interface CreatePostProps {
  currentUser: User;
  onPostCreated: () => void;
  refreshUser: () => void;
  postId?: string;
}

const CreatePost: React.FC<CreatePostProps> = ({ currentUser, onPostCreated, refreshUser, postId }) => {
  const [isExpanded, setIsExpanded] = useState(!!postId);
  const [postType, setPostType] = useState<PostType>(PostType.TEXT);
  const [content, setContent] = useState('');
  const [imageUrl, setImageUrl] = useState('');
  const [videoUrl, setVideoUrl] = useState('');
  const [liveDescription, setLiveDescription] = useState('');
  const [isLivePaid, setIsLivePaid] = useState(false);
  const [livePrice, setLivePrice] = useState('0');
  const [selectedAudioTrackId, setSelectedAudioTrackId] = useState<string | undefined>(undefined);
  const [showAudioModal, setShowAudioModal] = useState(false);
  const [showRecorder, setShowRecorder] = useState(false);
  const [aiEffectPrompt, setAiEffectPrompt] = useState('');
  const [activeFilter, setActiveFilter] = useState<string | undefined>(undefined);

  const [isScheduled, setIsScheduled] = useState(false);
  const [scheduledDate, setScheduledDate] = useState('');
  const [scheduledTime, setScheduledTime] = useState('');
  const [showScheduleForm, setShowScheduleForm] = useState(false);

  const [loading, setLoading] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const isEditing = !!postId;
  const isCreator = currentUser.userType === UserType.CREATOR;

  useEffect(() => {
    if (postId) {
      const posts = getPosts();
      const postToEdit = posts.find(p => p.id === postId);
      if (postToEdit) {
        setPostType(postToEdit.type);
        setContent(postToEdit.content || '');
        setImageUrl(postToEdit.imageUrl || '');
        if (postToEdit.type === PostType.REEL && postToEdit.reel) {
          setVideoUrl(postToEdit.reel.videoUrl || '');
          setSelectedAudioTrackId(postToEdit.reel.audioTrackId);
          setContent(postToEdit.reel.description || '');
          setAiEffectPrompt(postToEdit.reel.aiEffectPrompt || '');
          setActiveFilter(postToEdit.reel.filter);
        }
        if (postToEdit.type === PostType.LIVE && postToEdit.liveStream) {
          setContent(postToEdit.liveStream.title);
          setLiveDescription(postToEdit.liveStream.description);
          setIsLivePaid(postToEdit.liveStream.isPaid);
          setLivePrice(postToEdit.liveStream.price?.toString() || '0');
        }
      }
    }
  }, [postId]);

  const handleRecordSave = (blob: Blob, audioId?: string, prompt?: string, filter?: string) => {
    const url = URL.createObjectURL(blob);
    setVideoUrl(url);
    setSelectedAudioTrackId(audioId);
    setAiEffectPrompt(prompt || '');
    setActiveFilter(filter);
    setShowRecorder(false);
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        if (postType === PostType.IMAGE) setImageUrl(reader.result as string);
        else if (postType === PostType.REEL) setVideoUrl(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);

    let scheduledTimestamp: number | undefined = undefined;
    if (isScheduled && scheduledDate && scheduledTime) {
       scheduledTimestamp = new Date(`${scheduledDate}T${scheduledTime}`).getTime();
    }

    try {
      const postData: Post = {
        id: isEditing ? postId! : `post-${Date.now()}`,
        userId: currentUser.id,
        authorName: `${currentUser.firstName} ${currentUser.lastName}`,
        authorProfilePic: currentUser.profilePicture,
        type: postType,
        timestamp: Date.now(),
        scheduledAt: scheduledTimestamp,
        content: (postType === PostType.TEXT || postType === PostType.IMAGE) ? content : undefined,
        imageUrl: postType === PostType.IMAGE ? imageUrl : undefined,
        reel: postType === PostType.REEL ? {
          title: content.split('\n')[0] || 'Novo Reel',
          description: content,
          videoUrl: videoUrl,
          audioTrackId: selectedAudioTrackId,
          aiEffectPrompt: aiEffectPrompt,
          filter: activeFilter
        } : undefined,
        liveStream: postType === PostType.LIVE ? {
          title: content,
          description: liveDescription,
          isPaid: isLivePaid,
          price: isLivePaid ? parseFloat(livePrice) : 0
        } : undefined,
        likes: [],
        comments: [],
        shares: [],
        saves: [],
        indicatedUserIds: [],
      };

      if (isEditing) updatePost(postData);
      else addPost(postData);

      onPostCreated();
      if (!isEditing) setIsExpanded(false);
    } catch (err) {
      alert('Erro ao salvar.');
    } finally {
      setLoading(false);
    }
  };

  if (showRecorder) {
    return <RecordReelModal onClose={() => setShowRecorder(false)} onSave={handleRecordSave} />;
  }

  if (!isExpanded && !isEditing) {
    return (
      <div className="bg-white dark:bg-darkcard rounded-[2rem] shadow-sm p-4 border border-gray-100 dark:border-white/10 flex flex-col gap-3">
         <div className="flex items-start gap-3">
            <img src={currentUser.profilePicture} className="w-10 h-10 rounded-xl object-cover shrink-0" />
            <button onClick={() => setIsExpanded(true)} className="flex-1 text-left px-4 py-2.5 bg-slate-50 dark:bg-white/5 rounded-xl text-gray-400 font-bold text-xs md:text-sm">
              O que você quer compartilhar hoje, {currentUser.firstName}?
            </button>
         </div>
         <div className="flex items-center gap-6 px-1 border-t border-gray-50 dark:border-white/5 pt-2">
            <button onClick={() => { setIsExpanded(true); setPostType(PostType.IMAGE); }} className="flex items-center gap-2 text-gray-500 hover:text-blue-600 transition-all">
               <PhotoIcon className="h-5 w-5 text-blue-500" />
               <span className="text-[10px] font-black uppercase tracking-widest">Imagem</span>
            </button>
            <button onClick={() => { setIsExpanded(true); setPostType(PostType.REEL); }} className="flex items-center gap-2 text-gray-500 hover:text-purple-600 transition-all">
               <FilmIcon className="h-5 w-5 text-purple-500" />
               <span className="text-[10px] font-black uppercase tracking-widest">Reel</span>
            </button>
            <button onClick={() => { if(isCreator) { setIsExpanded(true); setPostType(PostType.LIVE); } }} className={`flex items-center gap-2 transition-all ${isCreator ? 'text-gray-500 hover:text-red-600' : 'text-gray-300 opacity-50 cursor-not-allowed'}`}>
               <VideoCameraIcon className="h-5 w-5 text-red-500" />
               <span className="text-[10px] font-black uppercase tracking-widest">Live</span>
            </button>
         </div>
      </div>
    );
  }

  return (
    <div className="bg-white dark:bg-darkcard rounded-[2.5rem] shadow-2xl p-6 md:p-8 border border-blue-50 dark:border-white/5 animate-fade-in relative overflow-hidden">
      <div className="absolute top-0 left-0 w-2 h-full bg-blue-600"></div>

      <div className="flex items-center justify-between mb-8">
        <div className="flex items-center gap-4">
           <div className={`p-3 text-white rounded-2xl shadow-lg ${postType === PostType.REEL ? 'bg-purple-600' : postType === PostType.LIVE ? 'bg-red-600' : 'bg-blue-600'}`}>
             {postType === PostType.REEL ? <FilmIcon className="h-6 w-6" /> : postType === PostType.LIVE ? <VideoCameraIcon className="h-6 w-6" /> : <SparklesIcon className="h-6 w-6" />}
           </div>
           <div>
              <h3 className="font-black text-gray-900 dark:text-white uppercase text-[10px] tracking-[0.2em]">{isEditing ? 'Editar Post' : 'Novo Conteúdo'}</h3>
              <p className="text-[8px] text-blue-500 font-black uppercase mt-0.5 tracking-widest">Compartilhe conhecimento</p>
           </div>
        </div>
        <button onClick={() => setIsExpanded(false)} className="p-2 text-gray-300 hover:text-red-500 transition-colors"><XMarkIcon className="h-6 w-6" /></button>
      </div>

      <form onSubmit={handleSubmit} className="space-y-6">
        <div className="flex flex-wrap gap-2 p-1.5 bg-slate-50 dark:bg-white/5 rounded-2xl w-fit">
           {[
             { id: PostType.TEXT, icon: DocumentTextIcon, label: 'Texto', locked: false },
             { id: PostType.IMAGE, icon: PhotoIcon, label: 'Imagem', locked: false },
             { id: PostType.REEL, icon: FilmIcon, label: 'Reel', locked: false },
             { id: PostType.LIVE, icon: VideoCameraIcon, label: 'Aula', locked: !isCreator }
           ].map(t => (
             <button key={t.id} type="button" disabled={t.locked} onClick={() => setPostType(t.id)} className={`flex items-center gap-2 px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${postType === t.id ? 'bg-white dark:bg-white/10 text-blue-600 dark:text-white shadow-sm' : 'text-gray-400'} ${t.locked ? 'opacity-30' : ''}`}>
                {t.locked ? <LockClosedIcon className="h-3 w-3" /> : <t.icon className="h-4 w-4" />} {t.label}
             </button>
           ))}
        </div>

        <input
          type="text"
          value={content}
          onChange={(e) => setContent(e.target.value)}
          className="w-full p-6 bg-slate-50 dark:bg-white/5 border-2 border-transparent focus:border-blue-500 rounded-2xl outline-none font-bold text-lg dark:text-white"
          placeholder={postType === PostType.LIVE ? "Título da Aula..." : postType === PostType.REEL ? "Descrição do Reel..." : "O que você quer ensinar?"}
        />

        {postType === PostType.REEL && (
          <div className="space-y-4 animate-fade-in">
             {!videoUrl ? (
               <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <button type="button" onClick={() => setShowRecorder(true)} className="p-10 border-2 border-dashed border-purple-200 dark:border-white/10 rounded-3xl flex flex-col items-center gap-4 hover:bg-purple-50 dark:hover:bg-white/5 transition-all">
                     <VideoCameraIcon className="h-10 w-10 text-purple-600" />
