import { 
  User, Post, UserType, Product, AffiliateSale, Notification, CartItem, 
  TransactionType, ChatConversation, AdCampaign, AudioTrack, Store, 
  Comment, NotificationType, ProductType, ShippingAddress, OrderStatus, 
  PaymentCard, CyberEvent, Story 
} from '../types';
import { 
  DEFAULT_USERS, DEFAULT_POSTS, DEFAULT_STORES, DEFAULT_PRODUCTS, 
  DEFAULT_AFFILIATE_SALES, DEFAULT_AUDIO_TRACKS, DEFAULT_ADS, DEFAULT_STORIES 
} from '../constants';

const KEYS = {
  USERS: 'cyber_users',
  POSTS: 'cyber_posts',
  STORES: 'cyber_stores',
  PRODUCTS: 'cyber_products',
  SALES: 'cyber_sales',
  CHATS: 'cyber_chats',
  NOTIFICATIONS: 'cyber_notifications',
  CURRENT_USER: 'cyber_current_user_id',
  PLATFORM_STATS: 'cyber_platform_revenue',
  ADS: 'cyber_ads',
  AUDIO: 'cyber_audio',
  EVENTS: 'cyber_events',
  STORIES: 'cyber_stories',
  CART: 'cyber_cart'
};

const PLATFORM_TAX_RATE = 0.10;

const get = <T>(key: string, fallback: T): T => {
  const data = localStorage.getItem(key);
  return data ? JSON.parse(data) : fallback;
};

const set = (key: string, data: any) => localStorage.setItem(key, JSON.stringify(data));

// Initialization logic
const initialize = () => {
  if (!localStorage.getItem(KEYS.USERS)) set(KEYS.USERS, DEFAULT_USERS);
  if (!localStorage.getItem(KEYS.POSTS)) set(KEYS.POSTS, DEFAULT_POSTS);
  if (!localStorage.getItem(KEYS.STORES)) set(KEYS.STORES, DEFAULT_STORES);
  if (!localStorage.getItem(KEYS.PRODUCTS)) set(KEYS.PRODUCTS, DEFAULT_PRODUCTS);
  if (!localStorage.getItem(KEYS.ADS)) set(KEYS.ADS, DEFAULT_ADS);
  if (!localStorage.getItem(KEYS.AUDIO)) set(KEYS.AUDIO, DEFAULT_AUDIO_TRACKS);
  if (!localStorage.getItem(KEYS.STORIES)) set(KEYS.STORIES, DEFAULT_STORIES);

  const storedUsers = get<User[]>(KEYS.USERS, []);
  let changed = false;
  const updatedUsers = storedUsers.map(u => {
    const defaultU = DEFAULT_USERS.find(du => du.email === u.email);
    if (defaultU && defaultU.isAdmin !== u.isAdmin) {
      changed = true;
      return { ...u, isAdmin: defaultU.isAdmin };
    }
    return u;
  });
  if (changed) set(KEYS.USERS, updatedUsers);
};

initialize();

// Platform Revenue Admin
export const getPlatformRevenue = () => get<number>(KEYS.PLATFORM_STATS, 0);
const addPlatformRevenue = (amount: number) => {
  const current = getPlatformRevenue();
  set(KEYS.PLATFORM_STATS, current + amount);
};

// Admin Commands
export const adminVerifyUser = (userId: string, status: boolean) => {
  const users = getUsers();
  const user = users.find(u => u.id === userId);
  if (user) {
    user.isVerified = status;
    set(KEYS.USERS, users);
    return true;
  }
  return false;
};

export const adminSetBalance = (userId: string, newBalance: number) => {
  const users = getUsers();
  const user = users.find(u => u.id === userId);
  if (user) {
    user.balance = newBalance;
    set(KEYS.USERS, users);
    return true;
  }
  return false;
};

// Users
export const getUsers = (): User[] => get(KEYS.USERS, []);
export const findUserById = (id: string) => getUsers().find(u => u.id === id);
export const getCurrentUserId = () => localStorage.getItem(KEYS.CURRENT_USER);
export const saveCurrentUser = (id: string | null) => id ? localStorage.setItem(KEYS.CURRENT_USER, id) : localStorage.removeItem(KEYS.CURRENT_USER);

export const updateUser = (updatedUser: User) => {
  const users = getUsers().map(u => u.id === updatedUser.id ? updatedUser : u);
  set(KEYS.USERS, users);
};

export const updateUserBalance = (userId: string, amount: number) => {
  const users = getUsers();
  const user = users.find(u => u.id === userId);
  if (user) {
    user.balance = (user.balance || 0) + amount;
    if (amount > 0) user.totalEarned = (user.totalEarned || 0) + amount;
    else user.totalSpent = (user.totalSpent || 0) + Math.abs(amount);
    set(KEYS.USERS, users);
    return true;
  }
  return false;
};

export const loginUser = async (email: string, password: string): Promise<User> => {
  const users = getUsers();
  return users.find(u => u.email === email) || Promise.reject('Erro');
};

export const registerUser = async (userData: any): Promise<User> => {
  const users = getUsers();
  const newUser: User = { ...userData, id: `user-${Date.now()}`, followedUsers: [], followers: [], balance: 0, isAdmin: false };
  set(KEYS.USERS, [...users, newUser]);
  return newUser;
};

export const deleteUser = (userId: string) => {
  const users = getUsers().filter(u => u.id !== userId);
  set(KEYS.USERS, users);
};

export const getPosts = (): Post[] => get(KEYS.POSTS, []);
export const savePosts = (posts: Post[]) => set(KEYS.POSTS, posts);
export const addPost = (post: Post) => set(KEYS.POSTS, [post, ...getPosts()]);
export const deletePost = (postId: string) => set(KEYS.POSTS, getPosts().filter(p => p.id !== postId));
export const updatePost = (updatedPost: Post) => set(KEYS.POSTS, getPosts().map(p => p.id === updatedPost.id ? updatedPost : p));

export const updatePostLikes = (postId: string, userId: string) => {
  const posts = getPosts();
  const post = posts.find(p => p.id === postId);
  if (post) {
    if (post.likes.includes(userId)) post.likes = post.likes.filter(id => id !== userId);
    else post.likes.push(userId);
    set(KEYS.POSTS, posts);
  }
};

export const getStores = (): Store[] => get(KEYS.STORES, []);
export const getProducts = (): Product[] => get(KEYS.PRODUCTS, []);
export const saveProducts = (prods: Product[]) => set(KEYS.PRODUCTS, prods);
export const saveStores = (stores: Store[]) => set(KEYS.STORES, stores);
export const findStoreById = (id: string) => getStores().find(s => s.id === id);

export const getCart = (): CartItem[] => get(KEYS.CART, []);
export const addToCart = (pId: string, q = 1) => set(KEYS.CART, [...getCart(), { productId: pId, quantity: q }]);
export const clearCart = () => set(KEYS.CART, []);

export const getNotificationsForUser = (uId: string) => get<any[]>(KEYS.NOTIFICATIONS, []).filter(n => n.recipientId === uId);
export const markNotificationsAsRead = (uId: string) => set(KEYS.NOTIFICATIONS, get<any[]>(KEYS.NOTIFICATIONS, []).map(n => n.recipientId === uId ? { ...n, isRead: true } : n));

export const buyPremiumSubscription = (userId: string) => {
  const cost = 29.90;
  const user = findUserById(userId);
  if (user && (user.balance || 0) >= cost) {
    updateUserBalance(userId, -cost);
    addPlatformRevenue(cost);
    user.isPremium = true;
    user.isVerified = true;
    updateUser(user);
    return true;
  }
  return false;
};

export const getAds = (): AdCampaign[] => get(KEYS.ADS, []);
export const saveAds = (ads: AdCampaign[]) => set(KEYS.ADS, ads);
export const getAudioTracks = (): AudioTrack[] => get(KEYS.AUDIO, DEFAULT_AUDIO_TRACKS);
export const findAudioTrackById = (id: string) => getAudioTracks().find(a => a.id === id);
export const getStories = (): Story[] => get(KEYS.STORIES, DEFAULT_STORIES);
export const getChats = (): ChatConversation[] => get(KEYS.CHATS, []);
export const saveChats = (chats: ChatConversation[]) => set(KEYS.CHATS, chats);
export const toggleFollowUser = (cId: string, fId: string) => {
  const users = getUsers();
  const u1 = users.find(u => u.id === cId);
  const u2 = users.find(u => u.id === fId);
  if (u1 && u2) {
    if (u1.followedUsers.includes(fId)) u1.followedUsers = u1.followedUsers.filter(x => x !== fId);
    else u1.followedUsers.push(fId);
    set(KEYS.USERS, users);
  }
};
export const getPurchasesByBuyerId = (uId: string) => get<any[]>(KEYS.SALES, []).filter(s => s.buyerId === uId);
export const getSalesByAffiliateId = (uId: string) => get<any[]>(KEYS.SALES, []).filter(s => s.affiliateUserId === uId);
export const getSalesByStoreId = (sId: string) => get<any[]>(KEYS.SALES, []).filter(s => s.storeId === sId);

