// Fix: Added missing processProductPurchase
export const processProductPurchase = (
  cartItems: CartItem[],
  buyerId: string,
  affiliateUserId: string | null,
  shippingAddress?: ShippingAddress,
) => {
  const products = getProducts();
  const stores = getStores();
  const sales = get<AffiliateSale[]>(KEYS.SALES, []);

  for (const item of cartItems) {
    const product = products.find(p => p.id === item.productId);
    if (!product) continue;

    const store = stores.find(s => s.id === product.storeId);
    if (!store) continue;

    const amount = product.price * item.quantity;
    const commission = affiliateUserId ? amount * product.affiliateCommissionRate : 0;
    const netAmount = amount - commission;

    updateUserBalance(store.professorId, netAmount);
    if (affiliateUserId) {
      updateUserBalance(affiliateUserId, commission);
    }

    const newSale: AffiliateSale = {
      id: `sale-${Date.now()}-${item.productId}`,
      productId: item.productId,
      buyerId,
      affiliateUserId: affiliateUserId || '',
      storeId: product.storeId,
      commissionEarned: commission,
      saleAmount: amount,
      timestamp: Date.now(),
      status: OrderStatus.WAITLIST,
      shippingAddress,
      digitalContentUrl: product.digitalContentUrl,
      digitalDownloadInstructions: product.digitalDownloadInstructions
    };
    sales.push(newSale);
  }
  set(KEYS.SALES, sales);
  clearCart();
  return true;
};

