    if (!post.indicatedUserIds.includes(toUserId)) {
      post.indicatedUserIds.push(toUserId);
      set(KEYS.POSTS, posts);
      return true;
    }
  }
  return false;
};

import React, { useState, useEffect, useRef } from 'react';
// Fix: Removed LiveStreamDetails from the import list as it is not exported from types.ts and not used in this file.
import { Post, PostType, User, UserType, AudioTrack } from '../types';
import { savePosts, getPosts, findAudioTrackById, updatePost, addPost } from '../services/storageService';
import { 
  SparklesIcon, 
  VideoCameraIcon, 
  PhotoIcon, 
  CalendarDaysIcon, 
  XMarkIcon,
  DocumentTextIcon,
  LockClosedIcon,
  FilmIcon,
  MusicalNoteIcon,
  CurrencyDollarIcon,
  ArrowUpTrayIcon,
  TrashIcon,
  ChevronRightIcon
} from '@heroicons/react/24/solid';
import AudioSelectionModal from './AudioSelectionModal';
import RecordReelModal from './RecordReelModal';

interface CreatePostProps {
  currentUser: User;
  onPostCreated: () => void;
  refreshUser: () => void;
  postId?: string;
}

const CreatePost: React.FC<CreatePostProps> = ({ currentUser, onPostCreated, refreshUser, postId }) => {
  const [isExpanded, setIsExpanded] = useState(!!postId);
  const [postType, setPostType] = useState<PostType>(PostType.TEXT);
  const [content, setContent] = useState('');
  const [imageUrl, setImageUrl] = useState('');
  const [videoUrl, setVideoUrl] = useState('');
  const [liveDescription, setLiveDescription] = useState('');
  const [isLivePaid, setIsLivePaid] = useState(false);
  const [livePrice, setLivePrice] = useState('0');
  const [selectedAudioTrackId, setSelectedAudioTrackId] = useState<string | undefined>(undefined);
  const [showAudioModal, setShowAudioModal] = useState(false);
  const [showRecorder, setShowRecorder] = useState(false);
  const [aiEffectPrompt, setAiEffectPrompt] = useState('');
  const [activeFilter, setActiveFilter] = useState<string | undefined>(undefined);

  const [isScheduled, setIsScheduled] = useState(false);
  const [scheduledDate, setScheduledDate] = useState('');
  const [scheduledTime, setScheduledTime] = useState('');
  const [showScheduleForm, setShowScheduleForm] = useState(false);

  const [loading, setLoading] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const isEditing = !!postId;
  const isCreator = currentUser.userType === UserType.CREATOR;

  useEffect(() => {
    if (postId) {
      const posts = getPosts();
      const postToEdit = posts.find(p => p.id === postId);
      if (postToEdit) {
        setPostType(postToEdit.type);
        setContent(postToEdit.content || '');
        setImageUrl(postToEdit.imageUrl || '');
        if (postToEdit.type === PostType.REEL && postToEdit.reel) {
          setVideoUrl(postToEdit.reel.videoUrl || '');
          setSelectedAudioTrackId(postToEdit.reel.audioTrackId);
          setContent(postToEdit.reel.description || '');
          setAiEffectPrompt(postToEdit.reel.aiEffectPrompt || '');
          setActiveFilter(postToEdit.reel.filter);
        }
        if (postToEdit.type === PostType.LIVE && postToEdit.liveStream) {
          setContent(postToEdit.liveStream.title);
          setLiveDescription(postToEdit.liveStream.description);
          setIsLivePaid(postToEdit.liveStream.isPaid);
          setLivePrice(postToEdit.liveStream.price?.toString() || '0');
        }
      }
    }
  }, [postId]);

  const handleRecordSave = (blob: Blob, audioId?: string, prompt?: string, filter?: string) => {
    const url = URL.createObjectURL(blob);
    setVideoUrl(url);
    setSelectedAudioTrackId(audioId);
    setAiEffectPrompt(prompt || '');
    setActiveFilter(filter);
    setShowRecorder(false);
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        if (postType === PostType.IMAGE) setImageUrl(reader.result as string);
        else if (postType === PostType.REEL) setVideoUrl(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);

    let scheduledTimestamp: number | undefined = undefined;
    if (isScheduled && scheduledDate && scheduledTime) {
       scheduledTimestamp = new Date(`${scheduledDate}T${scheduledTime}`).getTime();
    }

    try {
      const postData: Post = {
        id: isEditing ? postId! : `post-${Date.now()}`,
        userId: currentUser.id,
        authorName: `${currentUser.firstName} ${currentUser.lastName}`,
        authorProfilePic: currentUser.profilePicture,
        type: postType,
        timestamp: Date.now(),
        scheduledAt: scheduledTimestamp,
        content: (postType === PostType.TEXT || postType === PostType.IMAGE) ? content : undefined,
        imageUrl: postType === PostType.IMAGE ? imageUrl : undefined,
        reel: postType === PostType.REEL ? {
          title: content.split('\n')[0] || 'Novo Reel',
          description: content,
          videoUrl: videoUrl,
          audioTrackId: selectedAudioTrackId,
          aiEffectPrompt: aiEffectPrompt,
          filter: activeFilter
        } : undefined,
        liveStream: postType === PostType.LIVE ? {
          title: content,
          description: liveDescription,
          isPaid: isLivePaid,
          price: isLivePaid ? parseFloat(livePrice) : 0
        } : undefined,
        likes: [],
        comments: [],
        shares: [],
        saves: [],
        indicatedUserIds: [],
      };

      if (isEditing) updatePost(postData);
      else addPost(postData);

      onPostCreated();
      if (!isEditing) setIsExpanded(false);
    } catch (err) {
      alert('Erro ao salvar.');
    } finally {
      setLoading(false);
    }
  };

  if (showRecorder) {
    return <RecordReelModal onClose={() => setShowRecorder(false)} onSave={handleRecordSave} />;
  }

  if (!isExpanded && !isEditing) {
    return (
      <div className="bg-white dark:bg-darkcard rounded-[2rem] shadow-sm p-4 border border-gray-100 dark:border-white/10 flex flex-col gap-3">
         <div className="flex items-start gap-3">
            <img src={currentUser.profilePicture} className="w-10 h-10 rounded-xl object-cover shrink-0" />
            <button onClick={() => setIsExpanded(true)} className="flex-1 text-left px-4 py-2.5 bg-slate-50 dark:bg-white/5 rounded-xl text-gray-400 font-bold text-xs md:text-sm">
              O que você quer compartilhar hoje, {currentUser.firstName}?
            </button>
         </div>
         <div className="flex items-center gap-6 px-1 border-t border-gray-50 dark:border-white/5 pt-2">
            <button onClick={() => { setIsExpanded(true); setPostType(PostType.IMAGE); }} className="flex items-center gap-2 text-gray-500 hover:text-blue-600 transition-all">
               <PhotoIcon className="h-5 w-5 text-blue-500" />
               <span className="text-[10px] font-black uppercase tracking-widest">Imagem</span>
            </button>
            <button onClick={() => { setIsExpanded(true); setPostType(PostType.REEL); }} className="flex items-center gap-2 text-gray-500 hover:text-purple-600 transition-all">
               <FilmIcon className="h-5 w-5 text-purple-500" />
               <span className="text-[10px] font-black uppercase tracking-widest">Reel</span>
            </button>
            <button onClick={() => { if(isCreator) { setIsExpanded(true); setPostType(PostType.LIVE); } }} className={`flex items-center gap-2 transition-all ${isCreator ? 'text-gray-500 hover:text-red-600' : 'text-gray-300 opacity-50 cursor-not-allowed'}`}>
               <VideoCameraIcon className="h-5 w-5 text-red-500" />
               <span className="text-[10px] font-black uppercase tracking-widest">Live</span>
            </button>
         </div>
      </div>
    );
  }

  return (
    <div className="bg-white dark:bg-darkcard rounded-[2.5rem] shadow-2xl p-6 md:p-8 border border-blue-50 dark:border-white/5 animate-fade-in relative overflow-hidden">
      <div className="absolute top-0 left-0 w-2 h-full bg-blue-600"></div>

      <div className="flex items-center justify-between mb-8">
        <div className="flex items-center gap-4">
           <div className={`p-3 text-white rounded-2xl shadow-lg ${postType === PostType.REEL ? 'bg-purple-600' : postType === PostType.LIVE ? 'bg-red-600' : 'bg-blue-600'}`}>
             {postType === PostType.REEL ? <FilmIcon className="h-6 w-6" /> : postType === PostType.LIVE ? <VideoCameraIcon className="h-6 w-6" /> : <SparklesIcon className="h-6 w-6" />}
           </div>
           <div>
              <h3 className="font-black text-gray-900 dark:text-white uppercase text-[10px] tracking-[0.2em]">{isEditing ? 'Editar Post' : 'Novo Conteúdo'}</h3>
              <p className="text-[8px] text-blue-500 font-black uppercase mt-0.5 tracking-widest">Compartilhe conhecimento</p>
           </div>
        </div>
        <button onClick={() => setIsExpanded(false)} className="p-2 text-gray-300 hover:text-red-500 transition-colors"><XMarkIcon className="h-6 w-6" /></button>
      </div>

      <form onSubmit={handleSubmit} className="space-y-6">
        <div className="flex flex-wrap gap-2 p-1.5 bg-slate-50 dark:bg-white/5 rounded-2xl w-fit">
           {[
             { id: PostType.TEXT, icon: DocumentTextIcon, label: 'Texto', locked: false },
             { id: PostType.IMAGE, icon: PhotoIcon, label: 'Imagem', locked: false },
             { id: PostType.REEL, icon: FilmIcon, label: 'Reel', locked: false },
             { id: PostType.LIVE, icon: VideoCameraIcon, label: 'Aula', locked: !isCreator }
           ].map(t => (
             <button key={t.id} type="button" disabled={t.locked} onClick={() => setPostType(t.id)} className={`flex items-center gap-2 px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${postType === t.id ? 'bg-white dark:bg-white/10 text-blue-600 dark:text-white shadow-sm' : 'text-gray-400'} ${t.locked ? 'opacity-30' : ''}`}>
                {t.locked ? <LockClosedIcon className="h-3 w-3" /> : <t.icon className="h-4 w-4" />} {t.label}
             </button>
           ))}
        </div>

        <input
          type="text"
          value={content}
          onChange={(e) => setContent(e.target.value)}
          className="w-full p-6 bg-slate-50 dark:bg-white/5 border-2 border-transparent focus:border-blue-500 rounded-2xl outline-none font-bold text-lg dark:text-white"
          placeholder={postType === PostType.LIVE ? "Título da Aula..." : postType === PostType.REEL ? "Descrição do Reel..." : "O que você quer ensinar?"}
        />

        {postType === PostType.REEL && (
          <div className="space-y-4 animate-fade-in">
             {!videoUrl ? (
               <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <button type="button" onClick={() => setShowRecorder(true)} className="p-10 border-2 border-dashed border-purple-200 dark:border-white/10 rounded-3xl flex flex-col items-center gap-4 hover:bg-purple-50 dark:hover:bg-white/5 transition-all">
                     <VideoCameraIcon className="h-10 w-10 text-purple-600" />
                     <span className="text-[10px] font-black uppercase text-purple-600">Gravar Agora</span>
                  </button>
                  <button type="button" onClick={() => fileInputRef.current?.click()} className="p-10 border-2 border-dashed border-gray-200 dark:border-white/10 rounded-3xl flex flex-col items-center gap-4 hover:bg-gray-50 dark:hover:bg-white/5 transition-all">
                     <ArrowUpTrayIcon className="h-10 w-10 text-gray-400" />
                     <span className="text-[10px] font-black uppercase text-gray-500">Subir Arquivo</span>
                  </button>
                  <input ref={fileInputRef} type="file" accept="video/*" className="hidden" onChange={handleFileChange} />
               </div>
             ) : (
               <div className="relative rounded-3xl overflow-hidden border-4 border-purple-500 shadow-2xl aspect-[9/16] max-h-[400px] mx-auto group">
                  <video src={videoUrl} className="w-full h-full object-cover" style={{ filter: activeFilter || 'none' }} controls />
                  <button onClick={() => { setVideoUrl(''); setActiveFilter(undefined); }} className="absolute top-4 right-4 p-2 bg-red-600 text-white rounded-full opacity-0 group-hover:opacity-100 transition-opacity"><TrashIcon className="h-5 w-5"/></button>
                  {aiEffectPrompt && (
                    <div className="absolute bottom-4 left-4 bg-purple-600/90 text-white px-3 py-1 rounded-lg text-[8px] font-black uppercase backdrop-blur-md">
                      Prompt IA: {aiEffectPrompt}
                    </div>
                  )}
               </div>
             )}
          </div>
        )}

        {postType === PostType.IMAGE && (
          <div className="space-y-4 animate-fade-in">
             <input type="file" ref={fileInputRef} onChange={handleFileChange} accept="image/*" className="hidden" />
             {!imageUrl ? (
               <div onClick={() => fileInputRef.current?.click()} className="w-full h-64 border-2 border-dashed border-gray-200 dark:border-white/10 rounded-3xl flex flex-col items-center justify-center gap-4 cursor-pointer hover:border-blue-500 transition-all group">
                  <ArrowUpTrayIcon className="h-8 w-8 text-gray-400 group-hover:text-blue-600" />
                  <span className="text-[10px] font-black text-gray-400 uppercase">Escolher Imagem</span>
               </div>
             ) : (
               <div className="relative rounded-3xl overflow-hidden border-2 border-blue-500 group">
                  <img src={imageUrl} className="w-full h-auto max-h-[400px] object-cover" alt="Preview" />
                  <button onClick={() => setImageUrl('')} className="absolute top-4 right-4 p-2 bg-red-600 text-white rounded-full opacity-0 group-hover:opacity-100 transition-opacity"><TrashIcon className="h-5 w-5"/></button>
               </div>
             )}
          </div>
        )}

        <div className="flex justify-end gap-3 pt-6 border-t dark:border-white/5">
           <button type="submit" disabled={loading || !content} className="bg-blue-600 text-white px-10 py-4 rounded-2xl font-black text-xs uppercase shadow-xl hover:bg-blue-700 active:scale-95 transition-all flex items-center gap-2">
              {loading ? 'Publicando...' : 'Publicar'} <ChevronRightIcon className="h-4 w-4" />
           </button>
        </div>
      </form>
    </div>
  );
};

export default CreatePost;

import { 
  User, Post, UserType, Product, AffiliateSale, Notification, CartItem, 
  TransactionType, ChatConversation, AdCampaign, AudioTrack, Store, 
  Comment, NotificationType, ProductType, ShippingAddress, OrderStatus, 
  PaymentCard, CyberEvent, Story, StoryItem, ProductRating
} from '../types';
import { 
  DEFAULT_USERS, DEFAULT_POSTS, DEFAULT_STORES, DEFAULT_PRODUCTS, 
  DEFAULT_AFFILIATE_SALES, DEFAULT_AUDIO_TRACKS, DEFAULT_ADS, DEFAULT_STORIES 
} from '../constants';

const KEYS = {
  USERS: 'cyber_users',
  POSTS: 'cyber_posts',
  STORES: 'cyber_stores',
  PRODUCTS: 'cyber_products',
  SALES: 'cyber_sales',
  CHATS: 'cyber_chats',
  NOTIFICATIONS: 'cyber_notifications',
  CURRENT_USER: 'cyber_current_user_id',
  PLATFORM_STATS: 'cyber_platform_revenue',
  ADS: 'cyber_ads',
  AUDIO: 'cyber_audio',
  EVENTS: 'cyber_events',
  STORIES: 'cyber_stories',
  CART: 'cyber_cart'
};

const PLATFORM_TAX_RATE = 0.10;

const get = <T>(key: string, fallback: T): T => {
  const data = localStorage.getItem(key);
  return data ? JSON.parse(data) : fallback;
};

const set = (key: string, data: any) => localStorage.setItem(key, JSON.stringify(data));

// Initialization logic
const initialize = () => {
  if (!localStorage.getItem(KEYS.USERS)) set(KEYS.USERS, DEFAULT_USERS);
  if (!localStorage.getItem(KEYS.POSTS)) set(KEYS.POSTS, DEFAULT_POSTS);
  if (!localStorage.getItem(KEYS.STORES)) set(KEYS.STORES, DEFAULT_STORES);
  if (!localStorage.getItem(KEYS.PRODUCTS)) set(KEYS.PRODUCTS, DEFAULT_PRODUCTS);
  if (!localStorage.getItem(KEYS.ADS)) set(KEYS.ADS, DEFAULT_ADS);
  if (!localStorage.getItem(KEYS.AUDIO)) set(KEYS.AUDIO, DEFAULT_AUDIO_TRACKS);
  if (!localStorage.getItem(KEYS.STORIES)) set(KEYS.STORIES, DEFAULT_STORIES);

  const storedUsers = get<User[]>(KEYS.USERS, []);
  let changed = false;
  const updatedUsers = storedUsers.map(u => {
    const defaultU = DEFAULT_USERS.find(du => du.email === u.email);
    if (defaultU && defaultU.isAdmin !== u.isAdmin) {
      changed = true;
      return { ...u, isAdmin: defaultU.isAdmin };
    }
    return u;
  });
  if (changed) set(KEYS.USERS, updatedUsers);
};

initialize();

// Platform Revenue Admin
export const getPlatformRevenue = () => get<number>(KEYS.PLATFORM_STATS, 0);
const addPlatformRevenue = (amount: number) => {
  const current = getPlatformRevenue();
  set(KEYS.PLATFORM_STATS, current + amount);
};

// --- ADMIN TOTAL CONTROL FUNCTIONS ---

export const adminUpdateUserType = (userId: string, newType: UserType) => {
  const users = getUsers();
  const user = users.find(u => u.id === userId);
  if (user) {
    user.userType = newType;
    if (newType === UserType.CREATOR && !user.storeId) {
      user.storeId = `store-${Date.now()}`;
      const stores = getStores();
      stores.push({ id: user.storeId, professorId: user.id, name: `Loja de ${user.firstName}`, description: 'Nova Loja', productIds: [] });
      set(KEYS.STORES, stores);
    }
    set(KEYS.USERS, users);
    return true;
  }
  return false;
};

export const adminVerifyUser = (userId: string, status: boolean) => {
  const users = getUsers();
  const user = users.find(u => u.id === userId);
  if (user) {
    user.isVerified = status;
    set(KEYS.USERS, users);
    return true;
  }
  return false;
};

export const adminSetBalance = (userId: string, newBalance: number) => {
  const users = getUsers();
  const user = users.find(u => u.id === userId);
  if (user) {
    user.balance = newBalance;
    set(KEYS.USERS, users);
    return true;
  }
  return false;
};

export const adminDeletePost = (postId: string) => {
  const posts = getPosts().filter(p => p.id !== postId);
  set(KEYS.POSTS, posts);
};

export const adminDeleteProduct = (productId: string) => {
  const products = getProducts().filter(p => p.id !== productId);
  set(KEYS.PRODUCTS, products);
};

export const adminToggleAd = (adId: string) => {
  const ads = getAds().map(ad => ad.id === adId ? { ...ad, isActive: !ad.isActive } : ad);
  set(KEYS.ADS, ads);
};

// --- END ADMIN FUNCTIONS ---

// Users
export const getUsers = (): User[] => get(KEYS.USERS, []);
export const findUserById = (id: string) => getUsers().find(u => u.id === id);
export const getCurrentUserId = () => localStorage.getItem(KEYS.CURRENT_USER);
export const saveCurrentUser = (id: string | null) => id ? localStorage.setItem(KEYS.CURRENT_USER, id) : localStorage.removeItem(KEYS.CURRENT_USER);

export const updateUser = (updatedUser: User) => {
  const users = getUsers().map(u => u.id === updatedUser.id ? updatedUser : u);
  set(KEYS.USERS, users);
};

export const updateUserBalance = (userId: string, amount: number) => {
  const users = getUsers();
  const user = users.find(u => u.id === userId);
  if (user) {
    user.balance = (user.balance || 0) + amount;
    if (amount > 0) user.totalEarned = (user.totalEarned || 0) + amount;
    else user.totalSpent = (user.totalSpent || 0) + Math.abs(amount);
    set(KEYS.USERS, users);
    return true;
  }
  return false;
};

export const loginUser = async (email: string, password: string): Promise<User> => {
  const users = getUsers();
  return users.find(u => u.email === email) || Promise.reject('Erro');
};

export const registerUser = async (userData: any): Promise<User> => {
  const users = getUsers();
  const newUser: User = { ...userData, id: `user-${Date.now()}`, followedUsers: [], followers: [], balance: 0, isAdmin: false };
  set(KEYS.USERS, [...users, newUser]);
  return newUser;
};

export const deleteUser = (userId: string) => {
  const users = getUsers().filter(u => u.id !== userId);
  set(KEYS.USERS, users);
};

export const getPosts = (): Post[] => get(KEYS.POSTS, []);
export const savePosts = (posts: Post[]) => set(KEYS.POSTS, posts);
export const addPost = (post: Post) => set(KEYS.POSTS, [post, ...getPosts()]);
export const deletePost = (postId: string) => set(KEYS.POSTS, getPosts().filter(p => p.id !== postId));
export const updatePost = (updatedPost: Post) => set(KEYS.POSTS, getPosts().map(p => p.id === updatedPost.id ? updatedPost : p));

export const updatePostLikes = (postId: string, userId: string) => {
  const posts = getPosts();
  const post = posts.find(p => p.id === postId);
  if (post) {
    if (post.likes.includes(userId)) post.likes = post.likes.filter(id => id !== userId);
    else post.likes.push(userId);
    set(KEYS.POSTS, posts);
  }
};

export const updatePostShares = (postId: string, userId: string) => {
  const posts = getPosts();
  const post = posts.find(p => p.id === postId);
  if (post) {
    if (!post.shares.includes(userId)) post.shares.push(userId);
    set(KEYS.POSTS, posts);
  }
  return 0;
};

export const updatePostSaves = (postId: string, userId: string) => {
  const posts = getPosts();
  const post = posts.find(p => p.id === postId);
  if (post) {
    if (post.saves.includes(userId)) post.saves = post.saves.filter(id => id !== userId);
    else post.saves.push(userId);
    set(KEYS.POSTS, posts);
  }
  return [];
};

export const getStores = (): Store[] => get(KEYS.STORES, []);
export const getProducts = (): Product[] => get(KEYS.PRODUCTS, []);
export const saveProducts = (prods: Product[]) => set(KEYS.PRODUCTS, prods);
export const saveStores = (stores: Store[]) => set(KEYS.STORES, stores);
export const findStoreById = (id: string) => getStores().find(s => s.id === id);
export const findProductById = (id: string) => getProducts().find(p => p.id === id);

export const getCart = (): CartItem[] => get(KEYS.CART, []);
export const addToCart = (pId: string, q = 1) => set(KEYS.CART, [...getCart(), { productId: pId, quantity: q }]);
export const clearCart = () => set(KEYS.CART, []);

export const getNotificationsForUser = (uId: string) => get<any[]>(KEYS.NOTIFICATIONS, []).filter(n => n.recipientId === uId);
export const markNotificationsAsRead = (uId: string) => set(KEYS.NOTIFICATIONS, get<any[]>(KEYS.NOTIFICATIONS, []).map(n => n.recipientId === uId ? { ...n, isRead: true } : n));

export const buyPremiumSubscription = (userId: string) => {
  const cost = 29.90;
  const user = findUserById(userId);
  if (user && (user.balance || 0) >= cost) {
    updateUserBalance(userId, -cost);
    addPlatformRevenue(cost);
    user.isPremium = true;
    user.isVerified = true;
    updateUser(user);
    return true;
  }
  return false;
};

export const getAds = (): AdCampaign[] => get(KEYS.ADS, []);
export const saveAds = (ads: AdCampaign[]) => set(KEYS.ADS, ads);
export const getAudioTracks = (): AudioTrack[] => get(KEYS.AUDIO, DEFAULT_AUDIO_TRACKS);
export const getStories = (): Story[] => get(KEYS.STORIES, DEFAULT_STORIES);
export const getChats = (): ChatConversation[] => get(KEYS.CHATS, []);
export const saveChats = (chats: ChatConversation[]) => set(KEYS.CHATS, chats);

export const toggleFollowUser = (cId: string, fId: string) => {
  const users = getUsers();
  const u1 = users.find(u => u.id === cId);
  const u2 = users.find(u => u.id === fId);
  if (u1 && u2) {
    if (u1.followedUsers.includes(fId)) u1.followedUsers = u1.followedUsers.filter(x => x !== fId);
    else u1.followedUsers.push(fId);
    set(KEYS.USERS, users);
  }
};

export const processProductPurchase = (cartItems: CartItem[], buyerId: string, affiliateUserId: string | null = null) => {
  const products = getProducts();
  for (const item of cartItems) {
    const product = products.find(p => p.id === item.productId);
    if (product) {
      const store = findStoreById(product.storeId);
      if (store) {
        const total = product.price * item.quantity;
        const tax = total * PLATFORM_TAX_RATE;
        updateUserBalance(store.professorId, total - tax);
        addPlatformRevenue(tax);
      }
    }
  }
  clearCart();
  return true;
};

export const getPurchasesByBuyerId = (uId: string) => get<any[]>(KEYS.SALES, []).filter(s => s.buyerId === uId);
export const getSalesByAffiliateId = (uId: string) => get<any[]>(KEYS.SALES, []).filter(s => s.affiliateUserId === uId);
export const getSalesByStoreId = (sId: string) => get<any[]>(KEYS.SALES, []).filter(s => s.storeId === sId);

export const addPostComment = (pId: string, c: Comment) => {
  const posts = getPosts();
  const post = posts.find(p => p.id === pId);
  if (post) {
    post.comments.push(c);
    set(KEYS.POSTS, posts);
  }
  return [];
};

