// Fix: Updated processProductPurchase signature and implementation
export const processProductPurchase = (
  cartItems: CartItem[], 
  buyerId: string, 
  affiliateUserId: string | null = null, 
  shippingAddress?: ShippingAddress
) => {
  const products = getProducts();
  const sales = get<AffiliateSale[]>(KEYS.SALES, []);
  for (const item of cartItems) {
    const product = products.find(p => p.id === item.productId);
    if (product) {
      const store = findStoreById(product.storeId);
      if (store) {
        const total = product.price * item.quantity;
        const tax = total * PLATFORM_TAX_RATE;
        updateUserBalance(store.professorId, total - tax);
        addPlatformRevenue(tax);

        const newSale: AffiliateSale = {
          id: `sale-${Date.now()}-${Math.random()}`,
          productId: product.id,
          buyerId,
          affiliateUserId: affiliateUserId || '',
          storeId: product.storeId,
          commissionEarned: affiliateUserId ? (total * product.affiliateCommissionRate) : 0,
          saleAmount: total,
          timestamp: Date.now(),
          status: OrderStatus.WAITLIST,
          shippingAddress
        };
        sales.push(newSale);

        if (affiliateUserId) {
          updateUserBalance(affiliateUserId, newSale.commissionEarned);
        }
      }
    }
  }
  set(KEYS.SALES, sales);
  clearCart();
  return true;
};

