    setSettings(getGlobalSettings());
  };

  // User Actions
  const handleToggleVerify = (uId: string, current: boolean) => {
    adminVerifyUser(uId, !current);
    refreshData();
  };

  const handleUpdateUserType = (uId: string, current: UserType) => {
    const next = current === UserType.STANDARD ? UserType.CREATOR : UserType.STANDARD;
    if (confirm(`Mudar usuário para ${next}?`)) {
      adminUpdateUserType(uId, next);
      refreshData();
    }
  };

  const handleEditBalance = (uId: string) => {
    const amount = prompt("Defina o novo saldo para este usuário ($):");
    if (amount !== null) {
      adminSetBalance(uId, parseFloat(amount));
      refreshData();
    }
  };

  const handleDeleteUser = (uId: string) => {
    if (confirm("EXCLUIR USUÁRIO PERMANENTEMENTE? Esta ação não pode ser desfeita.")) {
      deleteUser(uId);
      refreshData();
    }
  };

  // Content Actions
  const handleAdminDeletePost = (pId: string) => {
    if (confirm("Remover esta publicação da rede?")) {
      adminDeletePost(pId);
      refreshData();
    }
  };

  // Market Actions
  const handleAdminDeleteProduct = (prodId: string) => {
    if (confirm("Remover este produto do marketplace?")) {
      adminDeleteProduct(prodId);
      refreshData();
    }
  };

  const handleToggleAdStatus = (adId: string) => {
    adminToggleAd(adId);
    refreshData();
  };

  // System Actions
  const handleSaveSettings = () => {
    updateGlobalSettings(settings);
    alert('Configurações do ecossistema aplicadas com sucesso!');
    refreshData();
  };

  const handleSendBroadcast = () => {
    if (!broadcastTitle || !broadcastMsg) return;
    if (confirm(`Enviar esta mensagem para todos os ${users.length} usuários?`)) {
       adminBroadcastNotification(broadcastTitle, broadcastMsg, currentUser.id);
       setBroadcastTitle('');
       setBroadcastMsg('');
       alert('Broadcast enviado para toda a rede.');
    }
  };

  if (!currentUser.isAdmin) return <div className="pt-24 text-center font-black uppercase">Domínio Restrito ao Proprietário.</div>;

  return (
    <div className="container mx-auto px-4 pt-24 pb-24 max-w-7xl animate-fade-in">
       {/* Master Header */}
       <div className="flex flex-col lg:flex-row items-center justify-between mb-12 gap-8">
          <div>
            <h2 className="text-6xl font-black dark:text-white uppercase tracking-tighter leading-none">CyBer <span className="text-red-600">Command</span></h2>
            <p className="text-gray-500 font-bold uppercase tracking-[0.3em] text-[10px] mt-2">Plataforma de Controle de Domínio Total</p>
          </div>

          <div className="flex flex-wrap justify-center bg-gray-100 dark:bg-white/5 p-1.5 rounded-[2rem] shadow-inner">
             {[
               { id: 'financial', label: 'Financeiro', icon: ChartPieIcon },
               { id: 'users', label: 'Membros', icon: UserGroupIcon },
               { id: 'content', label: 'Moderação', icon: NewspaperIcon },
               { id: 'market', label: 'Mercado', icon: ShoppingBagIcon },
               { id: 'system', label: 'Sistema', icon: Cog6ToothIcon }
             ].map(tab => (
               <button 
                 key={tab.id}
                 onClick={() => setActiveTab(tab.id as AdminTab)} 
                 className={`px-6 py-3 rounded-2xl font-black text-[10px] uppercase transition-all flex items-center gap-2 ${activeTab === tab.id ? 'bg-white dark:bg-darkcard text-blue-600 shadow-xl' : 'text-gray-500 hover:text-gray-900 dark:hover:text-white'}`}
               >
                  <tab.icon className="h-4 w-4" /> {tab.label}
               </button>
             ))}
          </div>
       </div>

       {/* Search Bar for general use */}
       <div className="bg-white dark:bg-darkcard p-5 rounded-3xl border border-gray-100 dark:border-white/5 shadow-xl flex items-center gap-4 mb-8">
          <MagnifyingGlassIcon className="h-6 w-6 text-gray-400" />
          <input 
            type="text" 
            placeholder="Pesquisar em todo o ecossistema..." 
            className="flex-1 bg-transparent outline-none font-bold dark:text-white text-lg"
            value={searchTerm}
            onChange={e => setSearchTerm(e.target.value)}
          />
       </div>

       {/* Tab Content: FINANCIAL */}
       {activeTab === 'financial' && (
         <div className="animate-fade-in space-y-10">
            <div className="bg-gradient-to-br from-indigo-900 to-black p-12 rounded-[4rem] shadow-2xl text-white flex flex-col md:flex-row items-center justify-between gap-12 relative overflow-hidden group">
               <div className="absolute top-0 right-0 w-96 h-96 bg-blue-600/10 rounded-full blur-[100px]"></div>
               <div className="relative z-10 text-center md:text-left">
                  <p className="text-[11px] font-black uppercase tracking-[0.4em] text-blue-400 mb-4">Plataform Net Profit</p>
                  <p className="text-8xl font-black tracking-tighter">${revenue.toFixed(2)}</p>
                  <div className="mt-6 flex gap-3 justify-center md:justify-start">
                     <span className="bg-white/10 px-4 py-2 rounded-xl text-[10px] font-black uppercase border border-white/10">Tax Active: {(settings.platformTax * 100).toFixed(1)}%</span>
                     <span className="bg-green-500/20 text-green-400 px-4 py-2 rounded-xl text-[10px] font-black uppercase border border-green-500/20">Status: Lucid</span>
                  </div>
               </div>
               <div className="grid grid-cols-2 gap-4 relative z-10">
                  <div className="bg-white/5 backdrop-blur-xl p-6 rounded-3xl border border-white/10">
                     <p className="text-[9px] font-black text-gray-400 uppercase mb-1">Circulação</p>
                     <p className="text-2xl font-black">${users.reduce((a,b) => a + (b.balance || 0), 0).toFixed(0)}</p>
                  </div>
                  <div className="bg-white/5 backdrop-blur-xl p-6 rounded-3xl border border-white/10">
                     <p className="text-[9px] font-black text-gray-400 uppercase mb-1">Premium</p>
                     <p className="text-2xl font-black">{users.filter(u => u.isPremium).length}</p>
                  </div>
               </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
               {[
                 { label: 'Total Usuários', val: users.length, icon: UserGroupIcon, col: 'text-blue-600' },
                 { label: 'Total Posts', val: posts.length, icon: NewspaperIcon, col: 'text-purple-600' },
                 { label: 'Total Produtos', val: products.length, icon: ShoppingBagIcon, col: 'text-green-600' },
                 { label: 'Anúncios Ativos', val: ads.filter(a => a.isActive).length, icon: MegaphoneIcon, col: 'text-orange-600' }
               ].map(stat => (
                 <div key={stat.label} className="bg-white dark:bg-darkcard p-8 rounded-[2.5rem] border border-gray-100 dark:border-white/5 shadow-sm">
                    <stat.icon className={`h-8 w-8 ${stat.col} mb-4`} />
                    <p className="text-4xl font-black dark:text-white">{stat.val}</p>
                    <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mt-1">{stat.label}</p>
                 </div>
               ))}
            </div>
         </div>
       )}

       {/* Tab Content: USERS */}
       {activeTab === 'users' && (
         <div className="animate-fade-in space-y-6">
            <div className="bg-white dark:bg-darkcard rounded-[3rem] overflow-hidden border border-gray-100 dark:border-white/5 shadow-xl">
               <div className="divide-y divide-gray-50 dark:divide-white/5">
                  {users.filter(u => u.email.includes(searchTerm) || u.firstName.toLowerCase().includes(searchTerm.toLowerCase())).map(u => (
                     <div key={u.id} className="p-6 flex flex-col md:flex-row items-center justify-between hover:bg-gray-50 dark:hover:bg-white/5 transition-all gap-6">
                        <div className="flex items-center gap-4">
                           <div className="relative">
                              <img src={u.profilePicture} className="w-16 h-16 rounded-[1.5rem] object-cover" />
                              {u.isVerified && <CheckBadgeIcon className="h-6 w-6 text-blue-600 absolute -top-2 -right-2 border-2 border-white dark:border-darkcard rounded-full" />}
                           </div>
                           <div>
                              <div className="flex items-center gap-2">
                                 <p className="font-black text-lg dark:text-white">{u.firstName} {u.lastName}</p>
                                 <button onClick={() => handleUpdateUserType(u.id, u.userType)} className={`text-[8px] font-black uppercase px-2 py-0.5 rounded-md transition-all ${u.userType === UserType.CREATOR ? 'bg-purple-100 text-purple-600 hover:bg-purple-200' : 'bg-blue-100 text-blue-600 hover:bg-blue-200'}`}>{u.userType}</button>
                              </div>
                              <p className="text-[10px] font-bold text-gray-400 uppercase">{u.email} • ID: {u.id}</p>
                           </div>
                        </div>

                        <div className="flex items-center gap-6">
                           <div className="text-center md:text-right">
                              <p className="text-2xl font-black text-green-600">${(u.balance || 0).toFixed(2)}</p>
                              <p className="text-[9px] font-black text-gray-400 uppercase">Balance Account</p>
                           </div>

                           <div className="flex gap-2">
                              <button onClick={() => handleEditBalance(u.id)} className="p-3 bg-gray-100 dark:bg-white/5 rounded-xl hover:text-green-600 transition-all" title="Ajustar Saldo"><CurrencyDollarIcon className="h-5 w-5" /></button>
                              <button onClick={() => handleToggleVerify(u.id, !!u.isVerified)} className={`p-3 rounded-xl transition-all ${u.isVerified ? 'bg-blue-600 text-white' : 'bg-gray-100 dark:bg-white/5 text-gray-400 hover:text-blue-600'}`} title="Selo de Verificado"><ShieldCheckIcon className="h-5 w-5" /></button>
                              {!u.isAdmin && <button onClick={() => handleDeleteUser(u.id)} className="p-3 bg-red-100 text-red-600 rounded-xl hover:bg-red-600 hover:text-white transition-all" title="Banir Usuário"><NoSymbolIcon className="h-5 w-5" /></button>}
                           </div>
                        </div>
                     </div>
                  ))}
               </div>
            </div>
         </div>
       )}

       {/* Tab Content: CONTENT MODERATION */}
       {activeTab === 'content' && (
         <div className="animate-fade-in space-y-6">
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
               {posts.filter(p => p.content?.toLowerCase().includes(searchTerm.toLowerCase())).map(p => (
                 <div key={p.id} className="bg-white dark:bg-darkcard rounded-3xl p-6 border border-gray-100 dark:border-white/5 shadow-sm flex flex-col relative group">
                    <div className="flex items-center gap-3 mb-4">
                       <img src={p.authorProfilePic} className="w-8 h-8 rounded-lg object-cover" />
                       <div>
                          <p className="text-[10px] font-black dark:text-white uppercase truncate max-w-[120px]">{p.authorName}</p>
                          <p className="text-[8px] text-gray-400 font-bold uppercase">{new Date(p.timestamp).toLocaleDateString()}</p>
                       </div>
                       <span className="ml-auto bg-gray-100 dark:bg-white/5 px-2 py-0.5 rounded text-[8px] font-black uppercase text-gray-500">{p.type}</span>
                    </div>
                    {p.imageUrl && <img src={p.imageUrl} className="w-full h-32 object-cover rounded-xl mb-3" />}
                    <p className="text-xs text-gray-600 dark:text-gray-400 line-clamp-3 font-medium mb-6">{p.content || 'Live/Reel sem texto'}</p>

                    <div className="mt-auto flex justify-between items-center">
                       <div className="flex gap-3 text-[9px] font-black text-gray-400">
                          <span>❤️ {p.likes.length}</span>
                          <span>💬 {p.comments.length}</span>
                       </div>
                       <button onClick={() => handleAdminDeletePost(p.id)} className="p-2 text-red-500 hover:bg-red-50 rounded-lg transition-all"><TrashIcon className="h-4 w-4"/></button>
                    </div>
                 </div>
               ))}
            </div>
         </div>
       )}

       {/* Tab Content: MARKETPLACE & ADS */}
       {activeTab === 'market' && (
         <div className="animate-fade-in space-y-12">
            <section>
               <h3 className="text-xs font-black text-gray-400 uppercase tracking-widest mb-6 ml-4">Anúncios Patrocinados</h3>
               <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                  {ads.map(ad => (
                    <div key={ad.id} className="bg-white dark:bg-darkcard p-6 rounded-[2.5rem] border border-gray-100 dark:border-white/5 flex gap-6 items-center shadow-sm">
                       <img src={ad.imageUrl} className="w-24 h-24 rounded-2xl object-cover" />
                       <div className="flex-1">
                          <div className="flex justify-between items-start">
                             <h4 className="font-black text-sm dark:text-white uppercase leading-tight">{ad.title}</h4>
                             <button 
                               onClick={() => handleToggleAdStatus(ad.id)}
                               className={`px-3 py-1 rounded-lg text-[8px] font-black uppercase transition-all ${ad.isActive ? 'bg-green-100 text-green-600' : 'bg-red-100 text-red-600'}`}
                             >
                                {ad.isActive ? 'Ativo' : 'Pausado'}
                             </button>
                          </div>
                          <p className="text-[10px] text-gray-500 mt-1 line-clamp-1">{ad.description}</p>
                          <p className="text-blue-600 font-black text-xs mt-3">Investimento: ${ad.budget.toFixed(2)}</p>
                       </div>
                    </div>
                  ))}
               </div>
            </section>

            <section>
               <h3 className="text-xs font-black text-gray-400 uppercase tracking-widest mb-6 ml-4">Catálogo de Produtos</h3>
               <div className="bg-white dark:bg-darkcard rounded-[3rem] overflow-hidden border border-gray-100 dark:border-white/5">
                  <div className="divide-y divide-gray-50 dark:divide-white/5">
                     {products.filter(p => p.name.toLowerCase().includes(searchTerm.toLowerCase())).map(p => (
                        <div key={p.id} className="p-6 flex items-center justify-between hover:bg-gray-50 dark:hover:bg-white/5 transition-colors">
                           <div className="flex items-center gap-4">
                              <img src={p.imageUrls[0]} className="w-12 h-12 rounded-xl object-cover" />
                              <div>
                                 <p className="font-black dark:text-white text-sm uppercase">{p.name}</p>
                                 <p className="text-[9px] font-bold text-gray-400 uppercase">Loja ID: {p.storeId} • Preço: ${p.price.toFixed(2)}</p>
                              </div>
                           </div>
                           <button onClick={() => handleAdminDeleteProduct(p.id)} className="p-3 text-red-500 hover:bg-red-50 rounded-xl transition-all"><TrashIcon className="h-5 w-5" /></button>
                        </div>
                     ))}
                  </div>
               </div>
            </section>
         </div>
       )}

       {/* Tab Content: SYSTEM SETTINGS (GLOBAL DOMAIN) */}
       {activeTab === 'system' && (
         <div className="animate-fade-in grid grid-cols-1 lg:grid-cols-2 gap-10 pb-20">
            {/* Global Params */}
            <div className="bg-white dark:bg-darkcard p-10 rounded-[3rem] shadow-xl border border-gray-100 dark:border-white/5 flex flex-col h-fit">
               <div className="flex items-center gap-4 mb-8">
                  <div className="p-3 bg-blue-600 text-white rounded-2xl shadow-lg"><GlobeAltIcon className="h-6 w-6" /></div>
                  <h3 className="text-xl font-black dark:text-white uppercase">Regras de Negócio</h3>
               </div>

               <div className="space-y-6">
                  <div>
                    <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1 mb-2 block">Taxa da Plataforma (Decimal 0.10 = 10%)</label>
                    <input 
                      type="number" 
                      step="0.01" 
                      value={settings.platformTax} 
                      onChange={e => setSettings({...settings, platformTax: parseFloat(e.target.value)})}
                      className="w-full p-4 bg-gray-50 dark:bg-white/5 rounded-2xl dark:text-white font-black outline-none border-2 border-transparent focus:border-blue-600" 
                    />
                  </div>
                  <div>
                    <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1 mb-2 block">Custo de Upgrade para Professor ($)</label>
                    <input 
                      type="number" 
                      value={settings.upgradeCost} 
                      onChange={e => setSettings({...settings, upgradeCost: parseFloat(e.target.value)})}
                      className="w-full p-4 bg-gray-50 dark:bg-white/5 rounded-2xl dark:text-white font-black outline-none border-2 border-transparent focus:border-blue-600" 
                    />
                  </div>
                  <div>
                    <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1 mb-2 block">Saque Mínimo ($)</label>
                    <input 
                      type="number" 
                      value={settings.minWithdrawal} 
                      onChange={e => setSettings({...settings, minWithdrawal: parseFloat(e.target.value)})}
                      className="w-full p-4 bg-gray-50 dark:bg-white/5 rounded-2xl dark:text-white font-black outline-none border-2 border-transparent focus:border-blue-600" 
                    />
                  </div>

                  <div className="flex items-center justify-between p-4 bg-red-50 dark:bg-red-900/10 rounded-2xl border border-red-100">
                     <div className="flex items-center gap-3">
                        <PowerIcon className="h-5 w-5 text-red-600" />
                        <span className="text-[10px] font-black text-red-900 dark:text-red-400 uppercase">Modo de Manutenção</span>
                     </div>
                     <button 
                       onClick={() => setSettings({...settings, maintenanceMode: !settings.maintenanceMode})}
                       className={`w-12 h-6 rounded-full transition-all relative ${settings.maintenanceMode ? 'bg-red-600' : 'bg-gray-300'}`}
                     >
                        <div className={`absolute top-1 w-4 h-4 bg-white rounded-full transition-all ${settings.maintenanceMode ? 'right-1' : 'left-1'}`}></div>
                     </button>
                  </div>
               </div>

               <button 
                 onClick={handleSaveSettings}
                 className="mt-10 w-full py-5 bg-blue-600 text-white rounded-[2rem] font-black text-sm uppercase shadow-2xl active:scale-95 transition-all"
               >
                 Aplicar Mudanças Globais
               </button>
            </div>

            {/* Broadcast System */}
            <div className="bg-white dark:bg-darkcard p-10 rounded-[3rem] shadow-xl border border-gray-100 dark:border-white/5">
               <div className="flex items-center gap-4 mb-8">
                  <div className="p-3 bg-purple-600 text-white rounded-2xl shadow-lg"><MegaphoneIcon className="h-6 w-6" /></div>
                  <h3 className="text-xl font-black dark:text-white uppercase">Transmissão em Massa</h3>
               </div>

               <p className="text-xs text-gray-500 mb-6 font-medium leading-relaxed">Envie uma notificação importante para todos os membros da rede. Útil para anúncios de novas funcionalidades ou regras.</p>

               <div className="space-y-6">
                  <input 
                    type="text" 
                    placeholder="Assunto da Notificação..." 
                    value={broadcastTitle}
                    onChange={e => setBroadcastTitle(e.target.value)}
                    className="w-full p-4 bg-gray-50 dark:bg-white/5 rounded-2xl dark:text-white font-bold outline-none" 
                  />
                  <textarea 
                    placeholder="Sua mensagem para a comunidade..." 
                    value={broadcastMsg}
                    onChange={e => setBroadcastMsg(e.target.value)}
                    className="w-full p-4 bg-gray-50 dark:bg-white/5 rounded-2xl dark:text-white font-medium outline-none h-44 resize-none" 
                  />
               </div>

               <button 
                 onClick={handleSendBroadcast}
                 className="mt-10 w-full py-5 bg-purple-600 text-white rounded-[2rem] font-black text-sm uppercase shadow-2xl active:scale-95 transition-all flex items-center justify-center gap-3"
               >
                 <BellAlertIcon className="h-5 w-5" /> Disparar Broadcast
               </button>

               <div className="mt-8 p-4 bg-blue-50 dark:bg-blue-900/10 rounded-2xl flex gap-3">
                  <ExclamationTriangleIcon className="h-5 w-5 text-blue-600 shrink-0" />
                  <p className="text-[9px] text-blue-800 dark:text-blue-300 font-bold uppercase leading-tight">Cuidado: Esta ação não pode ser desfeita e aparecerá na caixa de entrada de todos os usuários.</p>
               </div>
            </div>
         </div>
       )}
    </div>
  );
};

export default AdminDashboard;

