import React, { useState, useEffect, useCallback, useRef } from 'react';
import { User, Post, AdCampaign, PostType, Story, UserType, CyberEvent } from '../types';
import { getPosts, getAds, getStories, getUsers, toggleFollowUser, getEvents } from '../services/storageService';
import { DEFAULT_PROFILE_PIC } from '../constants';
import PostCard from './PostCard';
import CreatePost from './CreatePost';
import AdCard from './AdCard';
import StoryViewerModal from './StoryViewerModal';
import CreateStoryModal from './CreateStoryModal';
import { 
  PlusIcon, ArrowPathIcon, UserPlusIcon, CheckBadgeIcon, SparklesIcon, CalendarIcon, VideoCameraIcon, BookmarkSquareIcon, FireIcon
} from '@heroicons/react/24/outline';

interface FeedPageProps {
  currentUser: User;
  onNavigate: (page: string, params?: Record<string, string>) => void;
  refreshUser: () => void;
}

const ITEMS_PER_PAGE = 5;

const FeedPage: React.FC<FeedPageProps> = ({ currentUser, onNavigate, refreshUser }) => {
  const [allItems, setAllItems] = useState<(Post | AdCampaign | { type: 'SUGGESTIONS' })[]>([]);
  const [visibleItems, setVisibleItems] = useState<(Post | AdCampaign | { type: 'SUGGESTIONS' })[]>([]);
  const [displayLimit, setDisplayLimit] = useState(ITEMS_PER_PAGE);
  const [loading, setLoading] = useState(true);
  const [loadingMore, setLoadingMore] = useState(false);
  const [suggestedUsers, setSuggestedUsers] = useState<User[]>([]);
  const [stories, setStories] = useState<Story[]>([]);
  const [upcomingEvents, setUpcomingEvents] = useState<CyberEvent[]>([]);

  const [selectedStoryIndex, setSelectedStoryIndex] = useState<number | null>(null);
  const [isCreatingStory, setIsCreatingStory] = useState(false);

  const observerTarget = useRef<HTMLDivElement>(null);

  const loadData = useCallback(() => {
    setLoading(true);
    const allPosts = getPosts()
      .filter(p => p && typeof p === 'object' && p.userId)
      .sort((a, b) => {
        if (a.isPinned && !b.isPinned) return -1;
        if (!a.isPinned && b.isPinned) return 1;
        return b.timestamp - a.timestamp;
    });
    const allAds = getAds();
    const allUsers = getUsers();
    const allStories = getStories();
    const allEvents = getEvents().filter(e => e.dateTime > Date.now()).slice(0, 3);

    setStories(allStories);
    setUpcomingEvents(allEvents);

    const suggestions = allUsers
      .filter(u => u && u.id !== currentUser.id && !currentUser.followedUsers?.includes(u.id))
      .sort(() => 0.5 - Math.random())
      .slice(0, 5);

    setSuggestedUsers(suggestions);

    let combined: (Post | AdCampaign | { type: 'SUGGESTIONS' })[] = [];
    allPosts.forEach((post, idx) => {
        combined.push(post);
        if (idx === 1 && suggestions.length > 0) {
            combined.push({ type: 'SUGGESTIONS' });
        }
        if ((idx + 1) % 5 === 0 && allAds.length > 0) {
            const randomAd = allAds[Math.floor(Math.random() * allAds.length)];
            if (randomAd) combined.push(randomAd);
        }
    });

    setAllItems(combined);
    setVisibleItems(combined.slice(0, ITEMS_PER_PAGE));
    setLoading(false);
  }, [currentUser]);

  useEffect(() => { loadData(); }, [loadData]);

  const loadMoreItems = useCallback(() => {
    if (loadingMore || visibleItems.length >= allItems.length) return;
    setLoadingMore(true);
    setTimeout(() => {
      const nextLimit = displayLimit + ITEMS_PER_PAGE;
      setDisplayLimit(nextLimit);
      setVisibleItems(allItems.slice(0, nextLimit));
      setLoadingMore(false);
    }, 1200);
  }, [displayLimit, allItems, loadingMore, visibleItems.length]);

  useEffect(() => {
    const observer = new IntersectionObserver(entries => {
      if (entries[0].isIntersecting && !loading && !loadingMore) loadMoreItems();
    }, { threshold: 0.1 });
    if (observerTarget.current) observer.observe(observerTarget.current);
    return () => observer.disconnect();
  }, [loading, loadingMore, loadMoreItems]);

  return (
    <div className="w-full max-w-[1400px] mx-auto px-4 md:px-6 lg:px-8 py-4 md:py-8">

      {/* Stories Section: Estilo Instagram/Facebook */}
      <section className="mb-8 bg-white dark:bg-[#1a1c23] rounded-[2rem] p-4 shadow-sm border border-gray-100 dark:border-white/5">
        <div className="flex gap-4 overflow-x-auto pb-2 no-scrollbar scroll-smooth">
          <div onClick={() => setIsCreatingStory(true)} className="flex-shrink-0 flex flex-col items-center gap-1.5 cursor-pointer group">
            <div className="relative p-0.5 rounded-full border-2 border-dashed border-blue-500">
              <img src={currentUser.profilePicture || DEFAULT_PROFILE_PIC} className="w-14 h-14 md:w-16 md:h-16 rounded-full object-cover" />
              <div className="absolute bottom-0 right-0 bg-blue-600 text-white rounded-full p-1 border-2 border-white dark:border-[#1a1c23]">
                <PlusIcon className="w-3 h-3 stroke-[4]" />
              </div>
            </div>
            <span className="text-[10px] font-black dark:text-gray-400 uppercase tracking-tighter">History</span>
          </div>
          {stories.map((s, i) => (
            <div key={i} onClick={() => setSelectedStoryIndex(i)} className="flex-shrink-0 flex flex-col items-center gap-1.5 cursor-pointer">
              <div className="p-[2.5px] rounded-full bg-gradient-to-tr from-blue-500 via-indigo-500 to-purple-600">
                <div className="p-0.5 bg-white dark:bg-[#1a1c23] rounded-full">
                  <img src={s.userProfilePic || DEFAULT_PROFILE_PIC} className="w-14 h-14 md:w-16 md:h-16 rounded-full object-cover" />
                </div>
              </div>
              <span className="text-[10px] font-black dark:text-gray-400 truncate w-14 text-center">{s.userName.split(' ')[0]}</span>
            </div>
          ))}
        </div>
      </section>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
        {/* Main Feed: 2/3 da tela */}
        <main className="lg:col-span-8 space-y-6">
          <CreatePost currentUser={currentUser} onPostCreated={loadData} refreshUser={refreshUser} />

          <div className="space-y-6">
            {loading ? (
              <div className="py-20 text-center"><div className="w-10 h-10 border-4 border-blue-600 border-t-transparent rounded-full animate-spin mx-auto"></div></div>
            ) : (
              <>
                {visibleItems.map((item, idx) => {
                  if ('authorName' in item) return <PostCard key={(item as Post).id} post={item as Post} currentUser={currentUser} onNavigate={onNavigate} onFollowToggle={() => {}} refreshUser={refreshUser} onPostUpdatedOrDeleted={loadData} onPinToggle={() => {}} />;
                  if ('type' in item && item.type === 'SUGGESTIONS') return (
                    <div key="sugg" className="bg-blue-600 rounded-[2.5rem] p-8 text-white shadow-xl relative overflow-hidden">
                       <SparklesIcon className="absolute -right-10 -bottom-10 w-64 h-64 opacity-10" />
                       <h4 className="font-black text-xl mb-6 flex items-center gap-2"><FireIcon className="h-6 w-6" /> Conexões Sugeridas</h4>
                       <div className="flex gap-4 overflow-x-auto pb-4 no-scrollbar">
                          {suggestedUsers.map(u => (
                            <div key={u.id} className="bg-white/10 backdrop-blur-md p-4 rounded-3xl min-w-[150px] flex flex-col items-center text-center">
                               <img src={u.profilePicture} className="w-16 h-16 rounded-2xl object-cover mb-2 border-2 border-white/20" />
                               <p className="font-bold text-sm truncate w-full">{u.firstName}</p>
