import React, { useState, useEffect, useCallback } from 'react';
import { User, CartItem } from './types';
import {
    getCurrentUserId,
    findUserById,
    saveCurrentUser,
    getNotificationsForUser,
    markNotificationsAsRead,
    getCart,
    addToCart,
    removeFromCart,
    updateCartItemQuantity,
    clearCart,
    deleteUser
} from './services/storageService';
import Header from './components/Header';
import Footer from './components/Footer';
import AuthPage from './components/AuthPage';
import FeedPage from './components/FeedPage';
import ProfilePage from './components/ProfilePage';
import ChatPage from './components/ChatPage';
import AdCampaignPage from './components/AdCampaignPage';
import LiveStreamViewer from './components/LiveStreamViewer';
import { StorePage } from './components/StorePage';
import StoreManagerPage from './components/StoreManagerPage';
import CreatePost from './components/CreatePost';
import ReelsPage from './components/ReelsPage';
import SearchResultsPage from './components/SearchResultsPage';
import NotificationsPage from './components/NotificationsPage';
import CartModal from './components/CartModal';
import WalletModal from './components/WalletModal';
import ReportUserPage from './components/ReportUserPage';
import SettingsPage from './components/SettingsPage';
import AdminDashboard from './components/AdminDashboard';
import EventsPage from './components/EventsPage';
import PurchasesPage from './components/PurchasesPage';
import AffiliatesPage from './components/AffiliatesPage';

type Page = 'auth' | 'feed' | 'profile' | 'chat' | 'ads' | 'live' | 'store' | 'manage-store' | 'edit-post' | 'create-post' | 'reels-page' | 'search-results' | 'notifications' | 'report-user' | 'settings' | 'admin' | 'events' | 'purchases' | 'affiliates';

const App: React.FC = () => {
    const [currentUser, setCurrentUser] = useState<User | null>(null);
    const [darkMode, setDarkMode] = useState(() => localStorage.getItem('cyberphone_theme') === 'dark');
    const [currentPage, setCurrentPage] = useState<Page>(() => {
        return getCurrentUserId() ? 'feed' : 'auth';
    });
    const [pageParams, setPageParams] = useState<Record<string, string>>({});
    const [unreadNotificationsCount, setUnreadNotificationsCount] = useState(0);
    const [cartItems, setCartItems] = useState<CartItem[]>(getCart());
    const [isCartModalOpen, setIsCartModalOpen] = useState(false);
    const [walletConfig, setWalletConfig] = useState<{ isOpen: boolean, mode: 'deposit' | 'withdraw' }>({ isOpen: false, mode: 'deposit' });

    const toggleTheme = useCallback(() => {
        setDarkMode(prev => {
            const newVal = !prev;
            localStorage.setItem('cyberphone_theme', newVal ? 'dark' : 'light');
            return newVal;
        });
    }, []);

    useEffect(() => {
        if (darkMode) document.documentElement.classList.add('dark');
        else document.documentElement.classList.remove('dark');
    }, [darkMode]);

    const refreshCurrentUser = useCallback(() => {
        const userId = getCurrentUserId();
        if (userId) {
            const user = findUserById(userId);
            setCurrentUser(user || null);
            if (user) {
                const notifications = getNotificationsForUser(user.id);
                setUnreadNotificationsCount(notifications.filter(n => !n.isRead).length);
            }
        } else {
            setCurrentUser(null);
            setUnreadNotificationsCount(0);
        }
    }, []);

    const refreshCart = useCallback(() => {
        setCartItems(getCart());
    }, []);

    useEffect(() => {
        refreshCurrentUser();
        refreshCart();
    }, [refreshCurrentUser, refreshCart]);

    const handleLoginSuccess = useCallback((user: User) => {
        setCurrentUser(user);
        saveCurrentUser(user.id);
        refreshCurrentUser();
        refreshCart();
        setCurrentPage('feed');
    }, [refreshCurrentUser, refreshCart]);

    const handleLogout = useCallback(() => {
        setCurrentUser(null);
        saveCurrentUser(null);
        setCurrentPage('auth');
        clearCart();
        refreshCart();
    }, [refreshCart]);

    const handleNavigate = useCallback((page: Page, params: Record<string, string> = {}) => {
        if (page === 'notifications' && currentUser) {
            markNotificationsAsRead(currentUser.id);
            refreshCurrentUser();
        }
        setCurrentPage(page);
        setPageParams(params);
        window.scrollTo(0, 0);
    }, [currentUser, refreshCurrentUser]);

    const handleAddToCart = (productId: string, quantity: number = 1, selectedColor?: string) => {
        addToCart(productId, quantity, selectedColor);
        refreshCart();
    };

    const renderPage = () => {
        if (!currentUser) return <AuthPage onLoginSuccess={handleLoginSuccess} />;
        switch (currentPage) {
            case 'feed': return <FeedPage currentUser={currentUser} onNavigate={handleNavigate} refreshUser={refreshCurrentUser} />;
            case 'reels-page': return <ReelsPage currentUser={currentUser} onNavigate={handleNavigate} refreshUser={refreshCurrentUser} />;
            case 'profile': return <ProfilePage currentUser={currentUser} onNavigate={handleNavigate} refreshUser={refreshCurrentUser} userId={pageParams.userId} onOpenWallet={(mode) => setWalletConfig({ isOpen: true, mode })} />;
            case 'chat': return <ChatPage currentUser={currentUser} />;
            case 'settings': return <SettingsPage currentUser={currentUser} onNavigate={handleNavigate} darkMode={darkMode} toggleTheme={toggleTheme} refreshUser={refreshCurrentUser} onLogout={handleLogout} onDeleteAccount={() => { deleteUser(currentUser.id); handleLogout(); }} />;
            case 'ads': return <AdCampaignPage currentUser={currentUser} refreshUser={refreshCurrentUser} onNavigate={handleNavigate} />;
            case 'admin': return <AdminDashboard currentUser={currentUser} />;
            case 'events': return <EventsPage currentUser={currentUser} />;
            case 'purchases': return <PurchasesPage currentUser={currentUser} onNavigate={handleNavigate} />;
            case 'affiliates': return <AffiliatesPage currentUser={currentUser} onNavigate={handleNavigate} />;
            case 'live':
                if (pageParams.postId) return <LiveStreamViewer currentUser={currentUser} postId={pageParams.postId} onNavigate={handleNavigate} refreshUser={refreshCurrentUser} />;
                return <FeedPage currentUser={currentUser} onNavigate={handleNavigate} refreshUser={refreshCurrentUser} />;
            case 'store': return <StorePage currentUser={currentUser} onNavigate={handleNavigate} refreshUser={refreshCurrentUser} storeId={pageParams.storeId} onAddToCart={handleAddToCart} onOpenCart={() => setIsCartModalOpen(true)} />;
            case 'manage-store': return <StoreManagerPage currentUser={currentUser} refreshUser={refreshCurrentUser} onNavigate={handleNavigate} />;
            case 'create-post': return <CreatePost currentUser={currentUser} onPostCreated={() => handleNavigate('feed')} refreshUser={refreshCurrentUser} />;
            case 'search-results': return <SearchResultsPage currentUser={currentUser} query={pageParams.query || ''} onNavigate={handleNavigate} refreshUser={refreshCurrentUser} />;
            case 'notifications': return <NotificationsPage currentUser={currentUser} onNavigate={handleNavigate} refreshUser={refreshCurrentUser} />;
            case 'report-user': return <ReportUserPage currentUser={currentUser} targetUserId={pageParams.userId} onNavigate={handleNavigate} />;
            default: return <FeedPage currentUser={currentUser} onNavigate={handleNavigate} refreshUser={refreshCurrentUser} />;
        }
    };

    return (
        <div className="min-h-screen flex flex-col bg-gray-50 dark:bg-[#0a0c10] text-gray-900 dark:text-gray-100 transition-colors duration-300 w-full overflow-x-hidden">
            <Header
                currentUser={currentUser}
                onNavigate={handleNavigate}
                unreadNotificationsCount={unreadNotificationsCount}
                cartItemCount={cartItems.reduce((sum, item) => sum + item.quantity, 0)}
                onOpenCart={() => setIsCartModalOpen(true)}
            />
            <div className="flex flex-1 w-full overflow-x-hidden">
                {currentUser && (
                    <Footer currentUser={currentUser} onNavigate={handleNavigate} activePage={currentPage} onLogout={handleLogout} />
                )}
                <main className={`flex-grow pt-[64px] md:pt-[72px] pb-[72px] md:pb-8 transition-all duration-300 w-full ${currentUser ? 'md:ml-64 px-0 md:px-8' : 'px-0'}`}>
                    <div className="max-w-7xl mx-auto w-full">
                        {renderPage()}
                    </div>
                </main>
            </div>
            {currentUser && (
              <>
                <CartModal 
                    isOpen={isCartModalOpen}
                    onClose={() => setIsCartModalOpen(false)}
                    currentUser={currentUser}
                    onCartUpdate={refreshCart}
                    refreshUser={refreshCurrentUser}
                />
                <WalletModal
                    isOpen={walletConfig.isOpen}
                    mode={walletConfig.mode}
                    onClose={() => setWalletConfig({ ...walletConfig, isOpen: false })}
                    currentUser={currentUser}
                    refreshUser={refreshCurrentUser}
                />
              </>
            )}
        </div>
    );
};

export default App;

import React from 'react';
import { User } from '../types';
import { updateUserBalance } from '../services/storageService';
import CryptomusPaymentForm from './CryptomusPaymentForm';
import { XMarkIcon, ShieldCheckIcon } from '@heroicons/react/24/solid';

interface WalletModalProps {
  isOpen: boolean;
  mode: 'deposit' | 'withdraw';
  onClose: () => void;
  currentUser: User;
  refreshUser: () => void;
}

const WalletModal: React.FC<WalletModalProps> = ({ isOpen, mode, onClose, currentUser, refreshUser }) => {
  if (!isOpen) return null;

  const handleTransaction = (data: any) => {
    const amount = data.amount;
    const finalAmount = data.mode === 'deposit' ? amount : -amount;

    if (data.mode === 'withdraw' && (currentUser.balance || 0) < amount) {
        alert("Saldo insuficiente para saque.");
        return;
    }

    updateUserBalance(currentUser.id, finalAmount);
    refreshUser();
    alert(data.mode === 'deposit' ? "Depósito confirmado! Saldo atualizado." : "Solicitação de saque enviada com sucesso!");
    onClose();
  };

  return (
    <div className="fixed inset-0 bg-black/70 backdrop-blur-md z-[200] flex items-center justify-center p-4 animate-fade-in" onClick={onClose}>
      <div 
        className="bg-white dark:bg-[#1a1c23] w-full max-w-lg rounded-[3rem] shadow-2xl p-8 relative border border-white/10"
        onClick={e => e.stopPropagation()}
      >
        <button onClick={onClose} className="absolute top-8 right-8 p-2 text-gray-400 hover:text-gray-900 dark:hover:text-white transition-all">
          <XMarkIcon className="h-6 w-6" />
        </button>

        <div className="mb-8 flex items-center gap-3">
           <div className={`p-3 rounded-2xl ${mode === 'deposit' ? 'bg-green-600' : 'bg-red-600'} text-white shadow-xl`}>
             <ShieldCheckIcon className="h-6 w-6" />
           </div>
           <div>
              <h2 className="text-xl font-black dark:text-white uppercase tracking-tighter">{mode === 'deposit' ? 'Adicionar Fundos' : 'Resgatar Saldo'}</h2>
              <p className="text-[10px] text-gray-400 font-bold uppercase tracking-widest">Ambiente Seguro CyBerPhone</p>
           </div>
        </div>

        <div className="mb-6 p-4 bg-gray-50 dark:bg-white/5 rounded-2xl flex justify-between items-center border border-gray-100 dark:border-white/5">
           <span className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Saldo Atual</span>
           <span className="text-2xl font-black text-blue-600">${(currentUser.balance || 0).toFixed(2)}</span>
        </div>

        <CryptomusPaymentForm 
           mode={mode} 
           onConfirm={handleTransaction} 
           onCancel={onClose} 
        />

        <div className="mt-8 pt-6 border-t border-gray-100 dark:border-white/5 text-center">
           <p className="text-[9px] text-gray-400 font-bold uppercase leading-relaxed tracking-widest">
             Todas as transações são monitoradas pelo CyBer Defense para evitar fraudes. <br/>
             Suporte: suporte@cyberphone.com
           </p>
        </div>
      </div>
    </div>
  );
};

