                 <p className="text-xs text-blue-100 font-medium leading-relaxed mb-6">Explore produtos e cursos exclusivos da comunidade.</p>
                 <button onClick={() => onNavigate('store')} className="bg-white text-blue-900 px-6 py-3 rounded-2xl font-black text-[10px] uppercase shadow-lg">Visitar Loja</button>
              </div>

              {/* Resumo Perfil */}
              <div className="bg-white dark:bg-[#1a1c23] rounded-[2rem] p-6 shadow-sm border border-gray-100 dark:border-white/5 flex items-center gap-4 cursor-pointer hover:bg-gray-50 dark:hover:bg-white/5 transition-all" onClick={() => onNavigate('profile')}>
                 <img src={currentUser.profilePicture} className="w-12 h-12 rounded-2xl object-cover" />
