                             <p className="text-blue-100 text-xs font-bold uppercase tracking-widest">Sugestões de Conexão CyBer</p>
                          </div>
                          <button className="bg-white/10 hover:bg-white/20 p-3 rounded-2xl transition-all"><ArrowPathIcon className="h-6 w-6"/></button>
                       </div>
                       <div className="flex gap-5 overflow-x-auto pb-4 no-scrollbar">
                          {suggestedUsers.map(u => (
                            <div key={u.id} className="bg-white/10 backdrop-blur-xl p-6 rounded-[2.5rem] min-w-[180px] flex flex-col items-center text-center border border-white/10 group">
                               <img src={u.profilePicture} className="w-20 h-20 rounded-2xl object-cover mb-3 border-2 border-white/20 shadow-xl group-hover:scale-110 transition-transform" />
                               <p className="font-black text-sm truncate w-full">{u.firstName} {u.lastName}</p>
                               <p className="text-[8px] font-black text-blue-200 uppercase mb-4 tracking-tighter">{u.credentials || 'Especialista'}</p>
                               <button onClick={() => { toggleFollowUser(currentUser.id, u.id); refreshUser(); }} className="w-full bg-white text-blue-800 py-2.5 rounded-xl font-black text-[9px] uppercase shadow-lg active:scale-95 transition-all">Seguir</button>
