import React from 'react';
import { User } from '../types';
import { updateUserBalance } from '../services/storageService';
import CryptomusPaymentForm from './CryptomusPaymentForm';
import { XMarkIcon, ShieldCheckIcon, BanknotesIcon, GlobeAltIcon } from '@heroicons/react/24/solid';

interface WalletModalProps {
  isOpen: boolean;
  mode: 'deposit' | 'withdraw';
  onClose: () => void;
  currentUser: User;
  refreshUser: () => void;
}

const WalletModal: React.FC<WalletModalProps> = ({ isOpen, mode, onClose, currentUser, refreshUser }) => {
  if (!isOpen) return null;

  const handleTransaction = (data: any) => {
    const amount = data.amount;
    const finalAmount = data.mode === 'deposit' ? amount : -amount;

    if (data.mode === 'withdraw' && (currentUser.balance || 0) < amount) {
        alert("Saldo insuficiente para realizar este saque.");
        return;
    }

    updateUserBalance(currentUser.id, finalAmount);
    refreshUser();
    alert(data.mode === 'deposit' ? "Transação processada! Seu saldo foi atualizado." : "Pedido de saque enviado! Em breve os fundos estarão na sua conta externa.");
    onClose();
  };

  return (
    <div className="fixed inset-0 bg-black/80 backdrop-blur-md z-[200] flex items-center justify-center p-4 animate-fade-in" onClick={onClose}>
      <div 
        className="bg-white dark:bg-[#111318] w-full max-w-xl rounded-[3rem] shadow-[0_32px_64px_-12px_rgba(0,0,0,0.5)] p-8 md:p-12 relative border border-white/10"
        onClick={e => e.stopPropagation()}
      >
        <button onClick={onClose} className="absolute top-8 right-8 p-3 text-gray-400 hover:text-gray-900 dark:hover:text-white hover:bg-gray-100 dark:hover:bg-white/5 rounded-full transition-all">
          <XMarkIcon className="h-6 w-6" />
        </button>

        <div className="mb-10 flex items-center gap-5">
           <div className={`p-5 rounded-[1.8rem] ${mode === 'deposit' ? 'bg-green-600 shadow-green-200' : 'bg-red-600 shadow-red-200'} text-white shadow-2xl`}>
             <BanknotesIcon className="h-8 w-8" />
           </div>
           <div>
              <h2 className="text-3xl font-black dark:text-white uppercase tracking-tighter leading-none">{mode === 'deposit' ? 'Recarregar' : 'Resgatar'} Fundos</h2>
              <p className="text-[10px] text-gray-400 font-bold uppercase tracking-[0.2em] mt-2 flex items-center gap-2">
                <ShieldCheckIcon className="h-4 w-4 text-blue-500" /> Sistema de Pagamentos CyBer
              </p>
           </div>
        </div>

        <div className="mb-8 p-6 bg-gray-50 dark:bg-white/5 rounded-[2rem] flex justify-between items-center border border-gray-100 dark:border-white/5 shadow-inner">
           <div>
              <p className="text-[9px] font-black text-gray-400 uppercase tracking-widest mb-1">Saldo Disponível</p>
              <span className="text-3xl font-black text-blue-600">${(currentUser.balance || 0).toFixed(2)}</span>
           </div>
           <div className="text-right">
              <p className="text-[9px] font-black text-gray-400 uppercase tracking-widest mb-1">Moeda Base</p>
              <span className="text-xl font-black dark:text-white uppercase">USD</span>
           </div>
        </div>

        <CryptomusPaymentForm 
           mode={mode} 
           onConfirm={handleTransaction} 
           onCancel={onClose} 
        />

        <div className="mt-10 pt-8 border-t border-gray-100 dark:border-white/5">
           <div className="flex items-center justify-center gap-6 opacity-30 grayscale">
              <GlobeAltIcon className="h-8 w-8" />
              <div className="flex gap-4">
                 <div className="w-10 h-6 bg-gray-400 rounded"></div>
                 <div className="w-10 h-6 bg-gray-400 rounded"></div>
                 <div className="w-10 h-6 bg-gray-400 rounded"></div>
              </div>
           </div>
           <p className="text-[8px] text-gray-400 font-bold uppercase text-center mt-6 tracking-[0.1em] leading-relaxed">
             Transações protegidas por criptografia de nível militar. <br/>
             O CyBerPhone não armazena chaves privadas ou dados sensíveis de cartões.
           </p>
        </div>
      </div>
    </div>
  );
};

export default WalletModal;

