                     <h3 className="font-black text-gray-400 uppercase text-[10px] tracking-widest flex items-center gap-2">
                        <MegaphoneIcon className="h-4 w-4" /> Recomendados
                     </h3>
                     <button onClick={() => onNavigate('ads')} className="text-[8px] font-black text-blue-600 uppercase hover:underline">Impulsionar meu perfil</button>
                  </div>
                  {sidebarAds.map(ad => (
                    <AdCard key={ad.id} ad={ad} isSidebar={true} />
                  ))}
                </div>
              )}

              {/* Eventos */}
              <div className="bg-white dark:bg-[#1a1c23] rounded-[2.5rem] p-8 shadow-sm border border-gray-100 dark:border-white/5">
                 <h3 className="font-black text-gray-900 dark:text-white uppercase text-[10px] tracking-[0.2em] mb-8 flex items-center gap-3">
