                 <div className="flex items-center justify-between mb-8">
                    <h3 className="font-black text-gray-900 dark:text-white uppercase text-[10px] tracking-[0.2em] flex items-center gap-3">
                       <MegaphoneIcon className="h-6 w-6 text-blue-600" /> Em Destaque
                    </h3>
                    <button onClick={() => onNavigate('ads')} className="text-[8px] font-black text-blue-600 uppercase hover:underline">Impulsionar</button>
