              </div>

              {/* Próximos Eventos */}
              <div className="bg-white dark:bg-[#1a1c23] rounded-[2.5rem] p-8 shadow-sm border border-gray-100 dark:border-white/5">
                 <h3 className="font-black text-gray-900 dark:text-white uppercase text-[10px] tracking-[0.2em] mb-8 flex items-center gap-3">
                    <CalendarIcon className="h-6 w-6 text-blue-600" /> Próximos Eventos
                 </h3>
                 <div className="space-y-6">
                    {upcomingEvents.length > 0 ? upcomingEvents.map(evt => (
                      <div key={evt.id} onClick={() => onNavigate('events')} className="flex items-center gap-5 group cursor-pointer">
