                            <p className="text-[9px] leading-none mb-1 uppercase">{new Date(evt.dateTime).toLocaleDateString('pt-BR', { month: 'short' })}</p>
                            <p className="text-xl leading-none">{new Date(evt.dateTime).getDate()}</p>
