                         <div className="min-w-0">
                            <p className="font-black text-sm text-gray-900 dark:text-white truncate group-hover:text-blue-600 transition-colors leading-tight">{evt.title}</p>
                            <p className="text-[9px] text-gray-400 font-black uppercase tracking-widest mt-1">{evt.type === 'ONLINE' ? 'Virtual' : 'Presencial'}</p>
