                 <RocketLaunchIcon className="absolute -right-8 -top-8 w-40 h-40 opacity-10 rotate-12 group-hover:scale-110 transition-transform duration-700" />
                 <h4 className="font-black text-2xl tracking-tighter mb-2 relative z-10">Marketplace</h4>
                 <p className="text-xs text-gray-400 font-medium leading-relaxed mb-8 relative z-10">Cursos, mentorias e ativos digitais exclusivos.</p>
                 <button onClick={() => onNavigate('store')} className="w-full bg-blue-600 text-white py-4 rounded-2xl font-black text-[10px] uppercase shadow-xl relative z-10 active:scale-95 transition-all">Explorar Loja</button>
