                    <img src={currentUser.profilePicture} className="w-12 h-12 rounded-xl object-cover shadow-md group-hover:scale-105 transition-transform" />
                    <div className="min-w-0">
                       <p className="font-black text-sm text-gray-900 dark:text-white truncate">{currentUser.firstName}</p>
                       <p className="text-[9px] text-blue-600 font-black uppercase tracking-widest flex items-center gap-1">
