                 </div>
                 <button className="p-2 bg-gray-100 dark:bg-white/5 rounded-xl text-gray-400 group-hover:text-blue-600 transition-colors">
                    <PlusIcon className="h-4 w-4" />
                 </button>
              </div>
           </div>
        </aside>
      </div>

      {selectedStoryIndex !== null && <StoryViewerModal stories={stories} initialIndex={selectedStoryIndex} onClose={() => setSelectedStoryIndex(null)} />}
      {isCreatingStory && <CreateStoryModal currentUser={currentUser} onClose={() => setIsCreatingStory(false)} onStoryCreated={() => { setIsCreatingStory(false); loadData(); }} />}
    </div>
  );
};

export default FeedPage;

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { AdCampaign, User, UserType } from '../types';
import { saveAds, getAds, updateUserBalance } from '../services/storageService';
import { generateAdCopy } from '../services/geminiService';
import { MIN_DAILY_AD_BUDGET_USD, DEFAULT_PROFILE_PIC } from '../constants';
import { 
  RocketLaunchIcon, 
  MegaphoneIcon, 
  EyeIcon, 
  CursorArrowRaysIcon, 
  PhotoIcon, 
  CurrencyDollarIcon,
  ChevronRightIcon,
  ChevronLeftIcon,
  SparklesIcon,
  CheckCircleIcon,
  MapPinIcon,
  GlobeAltIcon,
  XMarkIcon,
  PlusIcon,
  InformationCircleIcon,
  UserGroupIcon,
  CalendarIcon,
  ArrowUpTrayIcon,
  TrashIcon,
  ExclamationTriangleIcon,
  ShieldCheckIcon,
  PresentationChartLineIcon,
  ArrowTrendingUpIcon
} from '@heroicons/react/24/solid';

interface AdCampaignPageProps {
  currentUser: User;
  refreshUser: () => void;
  onNavigate?: (page: string) => void;
}

type Step = 'objective' | 'creative' | 'targeting' | 'budget';

const AdCampaignPage: React.FC<AdCampaignPageProps> = ({ currentUser, refreshUser, onNavigate }) => {
  const [currentStep, setCurrentStep] = useState<Step>('objective');
  const [loading, setLoading] = useState(false);
  const [aiLoading, setAiLoading] = useState(false);

  // Form States
  const [objective, setObjective] = useState<'traffic' | 'awareness' | 'engagement'>('traffic');
  const [title, setTitle] = useState('');
  const [description, setDescription] = useState('');
  const [imageUrl, setImageUrl] = useState('');
  const [linkUrl, setLinkUrl] = useState('');
  const [ctaText, setCtaText] = useState('Saiba Mais');
  const [targetAudience, setTargetAudience] = useState('');
  const [durationDays, setDurationDays] = useState<number>(7);
  const [dailyReachGoal, setDailyReachGoal] = useState<number>(5000);
  const [locations, setLocations] = useState<string[]>(['Brasil']);
  const [newLoc, setNewLoc] = useState('');

  const fileInputRef = useRef<HTMLInputElement>(null);

  const COST_PER_1K_REACH = 0.50; 
  const calculatedTotalBudget = useMemo(() => {
    const costPerDay = (dailyReachGoal / 1000) * COST_PER_1K_REACH;
    return Math.max(costPerDay * durationDays, durationDays * MIN_DAILY_AD_BUDGET_USD);
  }, [dailyReachGoal, durationDays]);

  const hasBalance = (currentUser.balance || 0) >= calculatedTotalBudget;

  const handleAiGenerate = async () => {
    if (!targetAudience) {
      alert("Descreva brevemente o público ou curso para a IA te ajudar.");
      return;
    }
    setAiLoading(true);
    try {
      const copy = await generateAdCopy(`Anúncio para público interessado em: ${targetAudience}`);
      const parts = copy.split('Texto:');
      if (parts.length > 1) {
        setTitle(parts[0].replace('Título:', '').trim());
        setDescription(parts[1].trim());
      } else {
        setDescription(copy);
      }
    } catch (e) {
      console.error(e);
    } finally {
      setAiLoading(false);
    }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => setImageUrl(reader.result as string);
      reader.readAsDataURL(file);
    }
  };

  const handlePublish = () => {
    if (!hasBalance) return;
    setLoading(true);
    setTimeout(() => {
      const newAd: AdCampaign = {
        id: `ad-${Date.now()}`,
        professorId: currentUser.id,
        title,
        description,
        targetAudience,
        budget: calculatedTotalBudget,
        isActive: true,
        imageUrl,
        linkUrl: linkUrl || '#',
        ctaText,
        timestamp: Date.now()
      };

      updateUserBalance(currentUser.id, -calculatedTotalBudget);
      saveAds([...getAds(), newAd]);
      alert("Sua campanha foi lançada! Em instantes aparecerá no feed.");
      if(onNavigate) onNavigate('feed');
      else window.location.reload(); 
    }, 2000);
  };

  const addLocation = () => {
    if (newLoc.trim()) {
      setLocations([...locations, newLoc.trim()]);
      setNewLoc('');
    }
  };

  if (currentUser.userType === UserType.STANDARD) {
    return (
      <div className="min-h-screen bg-gray-50 dark:bg-[#080a0f] pt-32 pb-32 px-4 flex items-center justify-center">
         <div className="max-w-2xl bg-white dark:bg-darkcard rounded-[4rem] p-12 text-center shadow-2xl border border-blue-500/10">
            <div className="bg-blue-600 p-6 rounded-[2.5rem] w-fit mx-auto mb-8 shadow-xl">
               <ArrowTrendingUpIcon className="h-12 w-12 text-white" />
            </div>
            <h2 className="text-4xl font-black dark:text-white uppercase tracking-tighter mb-4">Alcance mais pessoas</h2>
            <p className="text-gray-500 dark:text-gray-400 mb-10 text-lg font-medium">A criação de anúncios é uma ferramenta exclusiva para **Contas Profissionais**. Profissionalize seu perfil para começar a vender cursos e consultorias.</p>
            <button onClick={() => onNavigate?.('settings')} className="bg-blue-600 text-white px-12 py-5 rounded-[2rem] font-black text-xl uppercase shadow-2xl hover:bg-blue-700 transition-all active:scale-95">Fazer Upgrade Agora</button>
         </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-50 dark:bg-[#080a0f] pt-24 pb-32 px-4">
      <div className="max-w-7xl mx-auto">

        <div className="flex flex-col md:flex-row md:items-center justify-between mb-10 gap-6">
          <div>
            <h1 className="text-3xl md:text-5xl font-black text-gray-900 dark:text-white tracking-tighter flex items-center gap-3">
              <RocketLaunchIcon className="h-10 w-10 text-blue-600" /> Growth Center
            </h1>
            <p className="text-gray-500 dark:text-gray-400 font-bold uppercase text-[10px] tracking-widest mt-1">Sua aula no topo do feed da CyBerPhone</p>
          </div>

          <div className="flex items-center gap-4 bg-white dark:bg-darkcard p-5 rounded-[2.5rem] shadow-xl border dark:border-white/5">
             <div className="text-right">
                <p className="text-[9px] font-black text-gray-400 uppercase tracking-widest">Saldo Disponível</p>
                <p className={`text-2xl font-black ${hasBalance ? 'text-blue-600' : 'text-red-500'}`}>${(currentUser.balance || 0).toFixed(2)}</p>
             </div>
             <button onClick={() => onNavigate?.('profile')} className="p-3 bg-blue-50 dark:bg-blue-600/10 text-blue-600 rounded-2xl hover:bg-blue-600 hover:text-white transition-all shadow-md">
                <PlusIcon className="h-6 w-6" />
             </button>
          </div>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-12 gap-10">
          <main className="lg:col-span-8 space-y-8">
             <div className="flex justify-between mb-4 px-2">
                {['objective', 'creative', 'targeting', 'budget'].map((s, idx) => (
                  <div key={s} className="flex flex-col items-center gap-2 flex-1 relative">
                     <div className={`w-12 h-12 rounded-[1.2rem] flex items-center justify-center font-black text-sm z-10 transition-all ${currentStep === s ? 'bg-blue-600 text-white shadow-xl scale-110' : idx < ['objective', 'creative', 'targeting', 'budget'].indexOf(currentStep) ? 'bg-green-500 text-white' : 'bg-gray-200 dark:bg-white/10 text-gray-400'}`}>
                        {idx < ['objective', 'creative', 'targeting', 'budget'].indexOf(currentStep) ? <CheckCircleIcon className="h-6 w-6" /> : idx + 1}
                     </div>
                     {idx < 3 && <div className={`absolute top-6 left-1/2 w-full h-1 -z-0 ${idx < ['objective', 'creative', 'targeting', 'budget'].indexOf(currentStep) ? 'bg-green-500' : 'bg-gray-100 dark:bg-white/5'}`}></div>}
                  </div>
                ))}
             </div>

             <div className="bg-white dark:bg-darkcard rounded-[3.5rem] p-8 md:p-14 shadow-2xl border dark:border-white/5 min-h-[550px] flex flex-col">
                {currentStep === 'objective' && (
                  <div className="animate-fade-in space-y-10">
                    <div className="text-center max-w-lg mx-auto">
                       <h2 className="text-3xl font-black dark:text-white tracking-tight uppercase">Escolha seu Destino</h2>
                       <p className="text-gray-500 dark:text-gray-400 text-sm mt-3 font-medium">O algoritmo priorizará perfis que combinam com seu objetivo.</p>
                    </div>
                    <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                       {[
                         { id: 'traffic', label: 'Conversão', desc: 'Vendas diretas de cursos e materiais.', icon: CursorArrowRaysIcon },
                         { id: 'awareness', label: 'Marca/Autoridade', desc: 'Ser reconhecido como expert.', icon: MegaphoneIcon },
                         { id: 'engagement', label: 'Interação', desc: 'Mais comentários e likes orgânicos.', icon: UserGroupIcon }
                       ].map(obj => (
                         <button 
                           key={obj.id}
                           onClick={() => setObjective(obj.id as any)}
                           className={`p-10 rounded-[3rem] border-4 transition-all text-left flex flex-col gap-5 group ${objective === obj.id ? 'border-blue-600 bg-blue-50 dark:bg-blue-600/10 shadow-2xl' : 'border-gray-50 dark:border-white/5 hover:border-gray-200 dark:hover:border-white/10'}`}
                         >
                            <div className={`p-5 rounded-[1.5rem] w-fit shadow-lg ${objective === obj.id ? 'bg-blue-600 text-white' : 'bg-gray-100 dark:bg-white/5 text-gray-400 group-hover:text-blue-600'}`}>
                               <obj.icon className="h-8 w-8" />
                            </div>
                            <div>
                               <h4 className="font-black dark:text-white uppercase text-xs tracking-widest">{obj.label}</h4>
                               <p className="text-[11px] text-gray-500 dark:text-gray-400 mt-2 leading-relaxed font-medium">{obj.desc}</p>
                            </div>
                         </button>
                       ))}
                    </div>
                    <div className="pt-10 flex justify-end">
                       <button onClick={() => setCurrentStep('creative')} className="bg-blue-600 text-white px-12 py-5 rounded-2xl font-black text-sm uppercase flex items-center gap-3 shadow-xl active:scale-95 transition-all">Próximo: Design <ChevronRightIcon className="h-5 w-5"/></button>
                    </div>
                  </div>
                )}

                {currentStep === 'creative' && (
                  <div className="animate-fade-in space-y-10">
                    <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
                       <div>
                          <h2 className="text-3xl font-black dark:text-white tracking-tight uppercase">Design do Anúncio</h2>
                          <p className="text-sm text-gray-400 font-bold uppercase tracking-widest mt-1">Use IA para criar textos matadores</p>
                       </div>
                       <button 
                         onClick={handleAiGenerate}
                         disabled={aiLoading}
                         className="flex items-center gap-3 px-8 py-4 bg-purple-600 text-white rounded-2xl font-black text-xs uppercase shadow-xl hover:bg-purple-700 active:scale-95 transition-all disabled:opacity-50"
                       >
                          {aiLoading ? <div className="w-5 h-5 border-3 border-white border-t-transparent animate-spin rounded-full" /> : <SparklesIcon className="h-5 w-5" />}
                          Sugestão de Copy (IA)
                       </button>
                    </div>

                    <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
                       <div className="space-y-6">
                          <div className="space-y-2">
                             <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">Manchete Principal</label>
                             <input type="text" value={title} onChange={e => setTitle(e.target.value)} placeholder="Ex: Domine UI Design em 10 dias" className="w-full p-5 bg-gray-50 dark:bg-white/5 rounded-3xl dark:text-white outline-none focus:ring-2 focus:ring-blue-600 font-black text-lg shadow-inner" />
                          </div>
                          <div className="space-y-2">
                             <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">Descrição Persuasiva</label>
                             <textarea value={description} onChange={e => setDescription(e.target.value)} placeholder="Diga por que seu curso é o melhor..." className="w-full p-5 bg-gray-50 dark:bg-white/5 rounded-3xl dark:text-white outline-none focus:ring-2 focus:ring-blue-600 font-medium h-40 resize-none shadow-inner" />
                          </div>
                          <div className="space-y-2">
                             <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">Link de Destino</label>
                             <input type="url" value={linkUrl} onChange={e => setLinkUrl(e.target.value)} placeholder="https://..." className="w-full p-5 bg-gray-50 dark:bg-white/5 rounded-3xl dark:text-white outline-none focus:ring-2 focus:ring-blue-600 font-bold" />
                          </div>
                       </div>

                       <div className="space-y-8">
                          <div className="space-y-2">
                             <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">Banner da Campanha</label>
                             <div 
                               onClick={() => fileInputRef.current?.click()}
                               className={`w-full h-72 border-4 border-dashed rounded-[3rem] flex flex-col items-center justify-center gap-5 cursor-pointer transition-all overflow-hidden relative group ${imageUrl ? 'border-blue-500 shadow-2xl' : 'border-gray-100 dark:border-white/10 hover:border-blue-400'}`}
                             >
                                {imageUrl ? (
                                   <>
                                      <img src={imageUrl} className="w-full h-full object-cover" />
                                      <div className="absolute inset-0 bg-black/50 opacity-0 group-hover:opacity-100 flex items-center justify-center transition-opacity backdrop-blur-sm">
                                         <button className="bg-white text-black px-6 py-3 rounded-2xl font-black text-[10px] uppercase shadow-2xl">Mudar Imagem</button>
                                      </div>
                                   </>
