import React, { useState, useEffect, useCallback, useRef } from 'react';
import { User, Post, AdCampaign, PostType, Story, UserType, CyberEvent } from '../types';
import { getPosts, getAds, getStories, getUsers, toggleFollowUser, getEvents } from '../services/storageService';
import { DEFAULT_PROFILE_PIC, CREATOR_UPGRADE_FOLLOWERS_GOAL } from '../constants';
import PostCard from './PostCard';
import CreatePost from './CreatePost';
import AdCard from './AdCard';
import StoryViewerModal from './StoryViewerModal';
import CreateStoryModal from './CreateStoryModal';
import { 
  PlusIcon, ArrowPathIcon, UserPlusIcon, CheckBadgeIcon, SparklesIcon, CalendarIcon, VideoCameraIcon, BookmarkSquareIcon, FireIcon, RocketLaunchIcon, UserGroupIcon, WalletIcon, MegaphoneIcon, ArrowTrendingUpIcon
} from '@heroicons/react/24/outline';
import { TrophyIcon } from '@heroicons/react/24/solid';

interface FeedPageProps {
  currentUser: User;
  onNavigate: (page: string, params?: Record<string, string>) => void;
  refreshUser: () => void;
}

const ITEMS_PER_PAGE = 5;

const FeedPage: React.FC<FeedPageProps> = ({ currentUser, onNavigate, refreshUser }) => {
  const [allItems, setAllItems] = useState<(Post | AdCampaign | { type: 'SUGGESTIONS' })[]>([]);
  const [visibleItems, setVisibleItems] = useState<(Post | AdCampaign | { type: 'SUGGESTIONS' })[]>([]);
  const [displayLimit, setDisplayLimit] = useState(ITEMS_PER_PAGE);
  const [loading, setLoading] = useState(true);
  const [loadingMore, setLoadingMore] = useState(false);
  const [suggestedUsers, setSuggestedUsers] = useState<User[]>([]);
  const [stories, setStories] = useState<Story[]>([]);
  const [upcomingEvents, setUpcomingEvents] = useState<CyberEvent[]>([]);
  const [sidebarAds, setSidebarAds] = useState<AdCampaign[]>([]);

  const [selectedStoryIndex, setSelectedStoryIndex] = useState<number | null>(null);
  const [isCreatingStory, setIsCreatingStory] = useState(false);

  const observerTarget = useRef<HTMLDivElement>(null);

  const loadData = useCallback(() => {
    setLoading(true);
    const allPosts = getPosts()
      .filter(p => p && typeof p === 'object' && p.userId)
      .sort((a, b) => {
        if (a.isPinned && !b.isPinned) return -1;
        if (!a.isPinned && b.isPinned) return 1;
        return b.timestamp - a.timestamp;
    });
    const allAds = getAds().filter(a => a.isActive);
    const allUsers = getUsers();
    const allStories = getStories();
    const allEvents = getEvents().filter(e => e.dateTime > Date.now()).slice(0, 3);

    setStories(allStories);
    setUpcomingEvents(allEvents);
    setSidebarAds(allAds.slice(0, 2));

    const suggestions = allUsers
      .filter(u => u && u.id !== currentUser.id && !currentUser.followedUsers?.includes(u.id))
      .sort(() => 0.5 - Math.random())
      .slice(0, 8);

    setSuggestedUsers(suggestions);

    let combined: (Post | AdCampaign | { type: 'SUGGESTIONS' })[] = [];
    allPosts.forEach((post, idx) => {
        combined.push(post);
        if (idx === 1 && suggestions.length > 0) combined.push({ type: 'SUGGESTIONS' });
        if ((idx + 1) % 4 === 0 && allAds.length > 0) {
            const adIndex = Math.floor((idx / 4) % allAds.length);
            const ad = allAds[adIndex];
            if (ad) combined.push(ad);
        }
    });

    setAllItems(combined);
    setVisibleItems(combined.slice(0, ITEMS_PER_PAGE));
    setLoading(false);
  }, [currentUser]);

  useEffect(() => { loadData(); }, [loadData]);

  const loadMoreItems = useCallback(() => {
    if (loadingMore || visibleItems.length >= allItems.length) return;
    setLoadingMore(true);
    setTimeout(() => {
      const nextLimit = displayLimit + ITEMS_PER_PAGE;
      setDisplayLimit(nextLimit);
      setVisibleItems(allItems.slice(0, nextLimit));
      setLoadingMore(false);
    }, 1200);
  }, [displayLimit, allItems, loadingMore, visibleItems.length]);

  useEffect(() => {
    const observer = new IntersectionObserver(entries => {
      if (entries[0].isIntersecting && !loading && !loadingMore) loadMoreItems();
    }, { threshold: 0.1 });
    if (observerTarget.current) observer.observe(observerTarget.current);
    return () => observer.disconnect();
  }, [loading, loadingMore, loadMoreItems]);

  const followerCount = currentUser.followers?.length || 0;
  const progressPercent = Math.min((followerCount / CREATOR_UPGRADE_FOLLOWERS_GOAL) * 100, 100);

  return (
    <div className="w-full max-w-[1400px] mx-auto px-4 md:px-6 lg:px-8 py-4 md:py-8">

      {/* Botão de Impulsionar Flutuante para Mobile */}
      <button 
        onClick={() => onNavigate('ads')}
        className="md:hidden fixed bottom-20 right-6 z-50 bg-blue-600 text-white p-4 rounded-2xl shadow-[0_15px_30px_rgba(37,99,235,0.4)] animate-bounce active:scale-95 transition-all"
      >
        <RocketLaunchIcon className="h-7 w-7" />
      </button>

      {/* Stories Section */}
      <section className="mb-8 bg-white dark:bg-[#1a1c23] rounded-[2.5rem] p-4 shadow-sm border border-gray-100 dark:border-white/5 relative overflow-hidden">
        <div className="flex gap-5 overflow-x-auto pb-2 no-scrollbar scroll-smooth">
          <div onClick={() => setIsCreatingStory(true)} className="flex-shrink-0 flex flex-col items-center gap-2 cursor-pointer group">
            <div className="relative p-1 rounded-[1.8rem] border-2 border-dashed border-blue-500 group-hover:bg-blue-50 transition-all">
              <img src={currentUser.profilePicture || DEFAULT_PROFILE_PIC} className="w-14 h-14 md:w-16 md:h-16 rounded-[1.4rem] object-cover" />
              <div className="absolute -bottom-1 -right-1 bg-blue-600 text-white rounded-lg p-1 border-2 border-white dark:border-[#1a1c23] shadow-lg">
                <PlusIcon className="w-3 h-3 stroke-[4]" />
              </div>
            </div>
            <span className="text-[9px] font-black dark:text-gray-400 uppercase tracking-widest">History</span>
          </div>
          {stories.map((s, i) => (
            <div key={i} onClick={() => setSelectedStoryIndex(i)} className="flex-shrink-0 flex flex-col items-center gap-2 cursor-pointer">
              <div className="p-1 rounded-[1.8rem] bg-gradient-to-tr from-blue-500 via-purple-500 to-red-500">
