import React, { useState, useEffect, useRef } from 'react';
import { User, UserType, Store, Product, ProductType } from '../types';
import { 
  getStores, 
  updateUser, 
  getProducts, 
  updateUserBalance,
  saveProducts,
  saveStores,
  findStoreById,
  updateStore
} from '../services/storageService';
import { sourceDropshippingProducts } from '../services/geminiService';
import { 
  PlusIcon, 
  ArchiveBoxIcon,
  TrashIcon,
  SparklesIcon,
  CheckBadgeIcon,
  BoltIcon,
  XMarkIcon,
  MagnifyingGlassIcon,
  ArrowDownTrayIcon,
  PaintBrushIcon,
  ShoppingBagIcon,
  PhotoIcon,
  ChevronRightIcon,
  InformationCircleIcon,
  BookOpenIcon,
  VideoCameraIcon,
  AcademicCapIcon,
  TruckIcon
} from '@heroicons/react/24/solid';

interface StoreManagerPageProps {
  currentUser: User;
  refreshUser: () => void;
  onNavigate: (page: any, params?: any) => void;
}

type ManagerTab = 'inventory' | 'sourcing' | 'branding';

const BRAND_COLORS = [
  { name: 'Azul CyBer', hex: '#2563eb' },
  { name: 'Roxo Royal', hex: '#7c3aed' },
  { name: 'Verde Mint', hex: '#10b981' },
  { name: 'Preto Carbono', hex: '#0f172a' },
  { name: 'Laranja Solar', hex: '#f59e0b' },
  { name: 'Rosa Shock', hex: '#db2777' }
];

const StoreManagerPage: React.FC<StoreManagerPageProps> = ({ currentUser, refreshUser, onNavigate }) => {
  const [userStore, setUserStore] = useState<Store | null>(null);
  const [storeProducts, setStoreProducts] = useState<Product[]>([]);
  const [activeTab, setActiveTab] = useState<ManagerTab>('inventory');
  const [isAddingProduct, setIsAddingProduct] = useState(false);

  // Branding State
  const [brandName, setBrandName] = useState('');
  const [brandDesc, setBrandDesc] = useState('');
  const [brandColor, setBrandColor] = useState(BRAND_COLORS[0].hex);

  // New Product Form State
  const [pName, setPName] = useState('');
  const [pDesc, setPDesc] = useState('');
  const [pPrice, setPPrice] = useState('');
  const [pType, setPType] = useState<ProductType>(ProductType.DIGITAL_COURSE);
  const [pImg, setPImg] = useState('');
  const [pDigitalUrl, setPDigitalUrl] = useState('');

  // Sourcing State
  const [searchQuery, setSearchQuery] = useState('');
  const [sourcingResults, setSourcingResults] = useState<any[]>([]);
  const [isSourcing, setIsSourcing] = useState(false);
  const [markup, setMarkup] = useState(1.5);

  useEffect(() => {
    const stores = getStores();
    const myStore = stores.find(s => s.professorId === currentUser.id);
    if (myStore) {
      setUserStore(myStore);
      setBrandName(myStore.name);
      setBrandDesc(myStore.description);
      setBrandColor(myStore.brandColor || BRAND_COLORS[0].hex);
      setStoreProducts(getProducts().filter(p => p.storeId === myStore.id));
    }
  }, [currentUser.id]);

  const handleSaveBranding = () => {
    if (!userStore) return;
    const updated = { ...userStore, name: brandName, description: brandDesc, brandColor };
    updateStore(updated);
    setUserStore(updated);
    alert('Identidade visual da loja atualizada!');
  };

  const handleCreateProduct = (e: React.FormEvent) => {
    e.preventDefault();
    if (!userStore) return;

    const newProduct: Product = {
      id: `prod-man-${Date.now()}`,
      storeId: userStore.id,
      name: pName,
      description: pDesc,
      price: parseFloat(pPrice),
      imageUrls: [pImg || 'https://picsum.photos/400/400?random=prod'],
      affiliateCommissionRate: 0.15,
      type: pType,
      ratings: [],
      averageRating: 5,
      ratingCount: 0,
      digitalContentUrl: pType !== ProductType.PHYSICAL ? pDigitalUrl : undefined
    };

    const allProducts = getProducts();
    saveProducts([...allProducts, newProduct]);

    const updatedStore = { ...userStore, productIds: [...userStore.productIds, newProduct.id] };
    updateStore(updatedStore);

    setStoreProducts([...storeProducts, newProduct]);
    setIsAddingProduct(false);
    resetProductForm();
    alert('Produto criado com sucesso na sua loja!');
  };

  const resetProductForm = () => {
    setPName(''); setPDesc(''); setPPrice(''); setPImg(''); setPDigitalUrl('');
  };

  const handleSource = async () => {
    if (!searchQuery) return;
    setIsSourcing(true);
    const results = await sourceDropshippingProducts(searchQuery);
    setSourcingResults(results);
    setIsSourcing(false);
  };

  const handleImport = (sourceProd: any) => {
    if (!userStore) return;
    const newProduct: Product = {
      id: `prod-drop-${Date.now()}`,
      storeId: userStore.id,
      name: sourceProd.name,
      description: sourceProd.description,
      price: sourceProd.originalPrice * markup,
      imageUrls: [sourceProd.imageUrl],
      affiliateCommissionRate: 0.1,
      type: ProductType.PHYSICAL,
      ratings: [],
      averageRating: 5,
      ratingCount: 0,
      isDropshipping: true,
      externalProviderId: sourceProd.externalProviderId,
      originalPrice: sourceProd.originalPrice
    };
    saveProducts([...getProducts(), newProduct]);
    setStoreProducts([...storeProducts, newProduct]);
    alert('Importado para estoque!');
  };

  if (currentUser.userType === UserType.STANDARD) {
    return (
      <div className="container mx-auto px-4 pt-32 text-center max-w-2xl animate-fade-in">
         <div className="bg-blue-600 w-24 h-24 rounded-[2rem] flex items-center justify-center mx-auto mb-8 shadow-2xl">
            <AcademicCapIcon className="h-12 w-12 text-white" />
         </div>
         <h2 className="text-4xl font-black mb-6 tracking-tighter dark:text-white">Alcance o Nível <span className="text-blue-600">Mestre.</span></h2>
         <p className="text-gray-500 text-lg mb-10 leading-relaxed font-medium">Sua marca própria, produtos exclusivos e ferramentas de dropshipping estão bloqueados. Ganhe seguidores para desbloquear seu império educacional.</p>
         <button onClick={() => onNavigate('ads')} className="bg-blue-600 text-white px-12 py-5 rounded-2xl font-black uppercase text-sm shadow-xl active:scale-95 transition-all">Impulsionar Carreira Agora</button>
      </div>
    );
  }

  return (
    <div className="container mx-auto px-4 pt-24 pb-32 max-w-6xl animate-fade-in">

       <div className="flex flex-col md:flex-row items-center justify-between mb-12 gap-8">
          <div className="flex items-center gap-5">
            <div className="w-16 h-16 rounded-[1.5rem] shadow-xl flex items-center justify-center text-white" style={{ backgroundColor: brandColor }}>
              <CheckBadgeIcon className="h-10 w-10" />
            </div>
            <div>
              <h2 className="text-3xl font-black dark:text-white tracking-tighter uppercase">{brandName || 'Minha Loja'}</h2>
              <div className="flex items-center gap-2">
                 <p className="text-gray-500 text-[10px] font-black uppercase tracking-widest">Painel de Mestre Profissional</p>
                 <div className="w-2 h-2 bg-green-500 rounded-full animate-pulse"></div>
              </div>
            </div>
          </div>

          <div className="flex bg-gray-100 dark:bg-white/5 p-1.5 rounded-[1.8rem] shadow-inner border border-white/5">
             {[
               { id: 'inventory', label: 'Estoque', icon: ArchiveBoxIcon },
               { id: 'sourcing', label: 'Sourcing', icon: BoltIcon },
               { id: 'branding', label: 'Minha Marca', icon: PaintBrushIcon }
             ].map(t => (
               <button 
                key={t.id} 
                onClick={() => setActiveTab(t.id as any)} 
                className={`px-6 py-3 rounded-2xl font-black text-[10px] uppercase transition-all flex items-center gap-2 ${activeTab === t.id ? 'bg-white dark:bg-darkcard text-blue-600 shadow-lg' : 'text-gray-500 hover:text-gray-900 dark:hover:text-white'}`}
               >
                 <t.icon className="h-4 w-4" /> {t.label}
               </button>
             ))}
          </div>
       </div>

       {activeTab === 'inventory' && (
         <div className="space-y-8 animate-fade-in">
            <div className="flex justify-between items-center px-4">
               <h3 className="font-black text-xl dark:text-white uppercase tracking-tighter">Produtos em Venda</h3>
               <button 
                 onClick={() => setIsAddingProduct(true)}
                 className="bg-blue-600 text-white px-6 py-3 rounded-2xl font-black text-[10px] uppercase shadow-xl flex items-center gap-2 hover:bg-blue-700 transition-all active:scale-95"
               >
                 <PlusIcon className="h-4 w-4 stroke-[4]" /> Novo Produto
               </button>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
               {storeProducts.map(p => (
                 <div key={p.id} className="bg-white dark:bg-darkcard rounded-[2.5rem] overflow-hidden border border-gray-100 dark:border-white/5 shadow-sm group hover:shadow-2xl transition-all duration-500">
                    <div className="relative h-48 overflow-hidden">
                       <img src={p.imageUrls[0]} className="w-full h-full object-cover transition-transform duration-700 group-hover:scale-105" alt="" />
                       <div className="absolute top-4 left-4">
