  updateStore,
  getProducts,
  toggleFollowUser,
  saveAffiliateLink,
} from '../services/storageService';
import { DEFAULT_PROFILE_PIC } from '../constants';
import { 
  ShoppingCartIcon, 
  PencilIcon, 
  CheckIcon, 
  PlusIcon, 
  TrashIcon, 
  StarIcon, 
  UserPlusIcon, 
  UserMinusIcon, 
  ShoppingBagIcon, 
  MagnifyingGlassIcon,
  FunnelIcon,
  Squares2X2Icon,
  BookOpenIcon,
  VideoCameraIcon,
  AcademicCapIcon,
  TruckIcon,
  LinkIcon,
  ChevronDownIcon,
  BoltIcon
} from '@heroicons/react/24/outline';
